    INSERT INTO daily_question_assignments(couple_id, question_id, date)
INSERT INTO public.questions (category, difficulty, translations) VALUES
  ('communication', 1, '{"en": "What''s one thing you appreciate about how we handle daily communication?", "es": "¿Qué es algo que aprecias de cómo manejamos la comunicación diaria?", "fr": "Qu''est-ce que tu apprécies dans notre manière de gérer la communication quotidienne ?", "it": "Qual è una cosa che apprezzi di come gestiamo la comunicazione quotidiana?", "ko": "우리가 일상적인 소통을 어떻게 처리하는지에 대해 감사하게 생각하는 한 가지는 무엇인가요?", "nl": "Wat is één ding dat je waardeert aan hoe we onze dagelijkse communicatie afhandelen?", "zh": "在我们处理日常沟通的方式上，你欣赏什么？"}'),
  ('communication', 2, '{"en": "How do you feel we can improve our non-verbal communication?", "es": "¿Cómo crees que podemos mejorar nuestra comunicación no verbal?", "fr": "Comment penses-tu que nous pourrions améliorer notre communication non verbale ?", "it": "Come pensi che possiamo migliorare la nostra comunicazione non verbale?", "ko": "비언어적 의사소통을 어떻게 개선할 수 있을까요?", "nl": "Hoe denk je dat we onze non-verbale communicatie kunnen verbeteren?", "zh": "你认为我们可以如何改善我们的非语言沟通？"}'),
  ('communication', 3, '{"en": "What do you believe is the biggest barrier to effective communication in relationships, and how can we overcome it?", "es": "¿Cuál crees que es la mayor barrera para una comunicación efectiva en las relaciones y cómo podemos superarla?", "fr": "Quelle est, selon toi, la plus grande barrière à une communication efficace dans les relations, et comment pouvons-nous la surmonter ?", "it": "Qual è, secondo te, il maggiore ostacolo alla comunicazione efficace nelle relazioni e come possiamo superarlo?", "ko": "관계에서 효과적인 의사소통의 가장 큰 장벽은 무엇이라고 생각하며, 그것을 어떻게 극복할 수 있을까요?", "nl": "Wat denk je dat de grootste belemmering is voor effectieve communicatie in relaties, en hoe kunnen we die overwinnen?", "zh": "你认为有效沟通在关系中的最大障碍是什么，我们如何能克服它？"}'),
  ('intimacy', 1, '{"en": "What''s a simple gesture of affection you enjoy the most?", "es": "¿Cuál es el gesto de cariño simple que más disfrutas?", "fr": "Quel est le geste d''affection simple que tu préfères ?", "it": "Qual è il gesto di affetto semplice che ti piace di più?", "ko": "가장 즐기는 간단한 애정 표현은 무엇인가요?", "nl": "Wat is een eenvoudig gebaar van genegenheid dat je het leukst vindt?", "zh": "你最喜欢的简单爱的表现是什么？"}'),
  ('intimacy', 2, '{"en": "How do you like to express love beyond physical touch?", "es": "¿Cómo te gusta expresar el amor más allá del contacto físico?", "fr": "Comment aimes-tu exprimer l''amour au-delà du contact physique ?", "it": "Come ti piace esprimere amore al di là del contatto fisico?", "ko": "신체적 접촉을 넘어서 사랑을 어떻게 표현하나요?", "nl": "Hoe vind je het fijn om liefde te uiten buiten fysieke aanrakingen?", "zh": "除了身体接触，你喜欢如何表达爱？"}'),
  ('intimacy', 3, '{"en": "What are your deepest desires when it comes to building intimacy together?", "es": "¿Cuáles son tus deseos más profundos cuando se trata de construir la intimidad juntos?", "fr": "Quels sont tes désirs les plus profonds lorsqu''il s''agit de construire l''intimité ensemble ?", "it": "Quali sono i tuoi desideri più profondi quando si tratta di costruire l''intimità insieme?", "ko": "함께 친밀감을 쌓을 때에 대한 당신의 깊은 욕망은 무엇인가요?", "nl": "Wat zijn je diepste verlangens als het gaat om het opbouwen van intimiteit samen?", "zh": "在共同建立亲密关系时，你最深的渴望是什么？"}'),
  ('dreams', 1, '{"en": "What''s a dream destination you’d love for us to visit?", "es": "¿Cuál es un destino de ensueño que te gustaría que visitáramos?", "fr": "Quelle est une destination de rêve que tu aimerais que nous visitions ?", "it": "Qual è una destinazione da sogno che ti piacerebbe che visitassimo?", "ko": "우리가 함께 가보고 싶은 꿈의 여행지는 어디인가요?", "nl": "Wat is een droombestemming die je graag met ons zou willen bezoeken?", "zh": "你希望我们去拜访的梦想目的地是什么？"}'),
  ('dreams', 2, '{"en": "How do you see our life together evolving in the next five years?", "es": "¿Cómo ves que nuestra vida juntos evolucione en los próximos cinco años?", "fr": "Comment vois-tu notre vie ensemble évoluer au cours des cinq prochaines années ?", "it": "Come vedi la nostra vita insieme che evolve nei prossimi cinque anni?", "ko": "향후 5년 동안 우리의 삶이 어떻게 발전할 것이라고 보나요?", "nl": "Hoe zie je ons leven samen evolueren in de komende vijf jaar?", "zh": "你如何看待我们在未来五年里的共同生活的演变？"}'),
  ('dreams', 3, '{"en": "What is a long-term dream of yours you haven''t shared with me yet, and how can I support you in achieving it?", "es": "¿Cuál es un sueño a largo plazo que aún no me has compartido, y cómo puedo apoyarte para lograrlo?", "fr": "Quel est un rêve à long terme que tu n''as pas encore partagé avec moi, et comment puis-je t''aider à le réaliser ?", "it": "Qual è un sogno a lungo termine che non mi hai ancora condiviso e come posso supportarti nel realizzarlo?", "ko": "아직 나와 공유하지 않은 장기적인 꿈이 무엇이며, 그것을 이루기 위해 내가 어떻게 도와줄 수 있을까요?", "nl": "Wat is een langetermijndroom van jou die je nog niet met me hebt gedeeld, en hoe kan ik je helpen het te bereiken?", "zh": "有什么你还没有和我分享的长期梦想，我如何能在实现这个梦想的过程中支持你？"}'),
  ('memories', 1, '{"en": "What''s a funny memory from when we first met?", "es": "¿Cuál es un recuerdo divertido de cuando nos conocimos?", "fr": "Quel est un souvenir drôle de notre première rencontre ?", "it": "Qual è un ricordo divertente di quando ci siamo incontrati la prima volta?", "ko": "우리가 처음 만났을 때의 재미있는 기억은 무엇인가요?", "nl": "Wat is een grappige herinnering van toen we elkaar voor het eerst ontmoetten?", "zh": "我们第一次见面时有什么有趣的回忆？"}'),
  ('memories', 2, '{"en": "What is one of your most cherished memories from our time together?", "es": "¿Cuál es uno de tus recuerdos más preciados de nuestro tiempo juntos?", "fr": "Quel est l''un de tes souvenirs les plus précieux de notre temps ensemble ?", "it": "Qual è uno dei tuoi ricordi più preziosi del nostro tempo insieme?", "ko": "우리 함께한 시간 중 가장 소중한 기억 중 하나는 무엇인가요?", "nl": "Wat is een van je meest gekoesterde herinneringen aan onze tijd samen?", "zh": "我们在一起时间里，你最珍惜的回忆之一是什么？"}'),
  ('memories', 3, '{"en": "How have past experiences shaped the person you are today in our relationship?", "es": "¿Cómo han dado forma las experiencias pasadas a la persona que eres hoy en nuestra relación?", "fr": "Comment les expériences passées ont-elles façonné la personne que tu es aujourd''hui dans notre relation ?", "it": "Come le esperienze passate hanno plasmato la persona che sei oggi nella nostra relazione?", "ko": "과거의 경험이 우리 관계에서 오늘날의 당신을 어떻게 형성했나요?", "nl": "Hoe hebben eerdere ervaringen de persoon gevormd die je vandaag bent in onze relatie?", "zh": "过去的经历是如何塑造你在我们关系中的今天的样子的？"}'),
  ('values', 1, '{"en": "What''s a core value that you think is essential for our relationship?", "es": "¿Cuál es un valor fundamental que crees que es esencial para nuestra relación?", "fr": "Quelle est une valeur fondamentale que tu penses être essentielle pour notre relation ?", "it": "Qual è un valore fondamentale che pensi sia essenziale per la nostra relazione?", "ko": "우리의 관계에서 본질적이라고 생각하는 핵심 가치는 무엇인가요?", "nl": "Wat is een kernwaarde die je essentieel vindt voor onze relatie?", "zh": "你认为对我们关系至关重要的核心价值是什么？"}'),
  ('values', 2, '{"en": "How do our individual values complement each other in our relationship?", "es": "¿Cómo se complementan nuestros valores individuales en nuestra relación?", "fr": "Comment nos valeurs individuelles se complètent-elles dans notre relation ?", "it": "Come si complementano i nostri valori individuali nella nostra relazione?", "ko": "우리의 개별 가치가 우리 관계에서 어떻게 상호 보완되나요?", "nl": "Hoe vullen onze individuele waarden elkaar aan in onze relatie?", "zh": "我们各自的价值观在我们的关系中如何互补？"}'),
  ('values', 3, '{"en": "How do you see our values guiding us through challenges in the future?", "es": "¿Cómo ves que nuestros valores nos guiarán a través de los desafíos en el futuro?", "fr": "Comment vois-tu nos valeurs nous guider à travers les défis futurs ?", "it": "Come vedi i nostri valori guiarci attraverso le sfide future?", "ko": "우리의 가치가 미래의 도전들을 어떻게 이끌 것이라고 보나요?", "nl": "Hoe zie je onze waarden ons begeleiden door uitdagingen in de toekomst?", "zh": "你认为我们的价值观如何在未来引导我们度过挑战？"}'),
  ('fun', 1, '{"en": "What''s your favorite activity for us to do on a lazy day?", "es": "¿Cuál es tu actividad favorita para que hagamos en un día perezoso?", "fr": "Quelle est ton activité préférée à faire ensemble lors d''une journée paresseuse ?", "it": "Qual è la tua attività preferita da fare insieme in una giornata pigra?", "ko": "게으른 날에 함께 하고 싶은 당신의 좋아하는 활동은 무엇인가요?", "nl": "Wat is je favoriete activiteit voor ons op een luie dag?", "zh": "在一个悠闲的日子里，你最喜欢我们一起做什么活动？"}'),
  ('fun', 2, '{"en": "How would you plan a perfect date to incorporate something adventurous and fun?", "es": "¿Cómo planearías una cita perfecta para incorporar algo aventurero y divertido?", "fr": "Comment planifierais-tu un rendez-vous parfait pour incorporer quelque chose d''aventureux et de fun ?", "it": "Come pianificheresti un appuntamento perfetto per includere qualcosa di avventuroso e divertente?", "ko": "어떻게 하면 모험적이고 재미있는 요소를 포함한 완벽한 데이트를 계획할 수 있을까요?", "nl": "Hoe zou je een perfecte date plannen om iets avontuurlijks en leuks te verwerken?", "zh": "你会如何计划一次完美的约会，以结合冒险和有趣的元素？"}'),
  ('fun', 3, '{"en": "How do you think we can keep the playfulness alive in our relationship over the years?", "es": "¿Cómo crees que podemos mantener la diversión viva en nuestra relación a lo largo de los años?", "fr": "Comment penses-tu que nous pouvons garder notre relation vivante et ludique au fil des ans ?", "it": "Come pensi che possiamo mantenere vivo il gioco nella nostra relazione nel corso degli anni?", "ko": "어떻게 하면 여러 해에 걸쳐 우리 관계에서 장난기를 계속 유지할 수 있을까요?", "nl": "Hoe denk je dat we de speelsheid in onze relatie kunnen behouden in de loop der jaren?", "zh": "你认为我们如何能长久保持关系中的玩趣？"}'),
  ('gratitude', 1, '{"en": "What''s something small that I do that you''re grateful for?", "es": "¿Cuál es algo pequeño que hago por lo que estás agradecido?", "fr": "Quelle est une petite chose que je fais et pour laquelle tu es reconnaissant ?", "it": "Qual è una piccola cosa che faccio per cui sei grato?", "ko": "내가 하는 작은 일 중 당신이 감사하게 생각하는 것은 무엇인가요?", "nl": "Wat is iets kleins dat ik doe waar je dankbaar voor bent?", "zh": "有什么小事是我做的令你感激的？"}'),
  ('gratitude', 2, '{"en": "How does expressing gratitude impact our relationship?", "es": "¿Cómo impacta expresar gratitud en nuestra relación?", "fr": "Comment l''expression de la gratitude impacte-t-elle notre relation ?", "it": "Come influisce l''espressione della gratitudine nella nostra relazione?", "ko": "감사의 표현이 우리 관계에 어떻게 영향을 미치나요?", "nl": "Hoe beïnvloedt het uiten van dankbaarheid onze relatie?", "zh": "表达感激之情对我们的关系有何影响？"}'),
  ('gratitude', 3, '{"en": "In what ways has gratitude transformed our relationship for the better?", "es": "¿De qué maneras la gratitud ha transformado nuestra relación para mejor?", "fr": "De quelles manières la gratitude a-t-elle transformé notre relation pour le mieux ?", "it": "In che modo la gratitudine ha trasformato la nostra relazione in meglio?", "ko": "어떤 방식으로 감사가 우리 관계를 더 나은 방향으로 변화시켰나요?", "nl": "Op welke manieren heeft dankbaarheid onze relatie ten goede veranderd?", "zh": "感恩之情以何种方式使我们的关系变得更好？"}'),
  ('conflict', 1, '{"en": "What''s one way you like to be supported during a disagreement?", "es": "¿Cuál es una manera en la que te gusta ser apoyado durante un desacuerdo?", "fr": "Quelle est une manière dont tu aimes être soutenu pendant un désaccord ?", "it": "Qual è un modo in cui ti piace essere supportato durante un disaccordo?", "ko": "분쟁 중에 어떤 방식으로 지지를 받고 싶나요?", "nl": "Wat is een manier waarop je graag wordt ondersteund tijdens een meningsverschil?", "zh": "在意见不合的时候，你希望得到何种支持？"}'),
  ('conflict', 2, '{"en": "How can we create a safe space to discuss sensitive topics?", "es": "¿Cómo podemos crear un espacio seguro para discutir temas delicados?", "fr": "Comment pouvons-nous créer un espace sûr pour discuter de sujets délicats ?", "it": "Come possiamo creare uno spazio sicuro per discutere di argomenti delicati?", "ko": "민감한 주제를 논의하기 위한 안전한 공간을 어떻게 만들 수 있을까요?", "nl": "Hoe kunnen we een veilige ruimte creëren om gevoelige onderwerpen te bespreken?", "zh": "我们如何创建一个安全的空间来讨论敏感话题？"}'),
  ('conflict', 3, '{"en": "What do you think are the most constructive ways to resolve conflicts in our relationship?", "es": "¿Cuáles crees que son las maneras más constructivas de resolver conflictos en nuestra relación?", "fr": "Quelles sont, selon toi, les manières les plus constructives de résoudre les conflits dans notre relation ?", "it": "Quali pensi siano i modi più costruttivi per risolvere i conflitti nella nostra relazione?", "ko": "우리 관계에서 갈등을 해결하기 위한 가장 건설적인 방법이 무엇이라고 생각하나요?", "nl": "Wat vind je dat de meest constructieve manieren zijn om conflicten in onze relatie op te lossen?", "zh": "在我们关系中，你认为最具建设性的解决冲突的方法是什么？"}'),
  ('finances', 1, '{"en": "What''s a financial goal you''d like us to achieve together?", "es": "¿Cuál es un objetivo financiero que te gustaría que lográramos juntos?", "fr": "Quel est un objectif financier que tu aimerais que nous atteignions ensemble ?", "it": "Qual è un obiettivo finanziario che ti piacerebbe che raggiungessimo insieme?", "ko": "우리 함께 달성하고 싶은 재정 목표는 무엇인가요?", "nl": "Wat is een financieel doel dat je graag samen met ons zou willen bereiken?", "zh": "你希望我们共同实现的财务目标是什么？"}'),
  ('finances', 2, '{"en": "How do you feel about our current approach to budgeting?", "es": "¿Qué opinas sobre nuestro enfoque actual al presupuesto?", "fr": "Que penses-tu de notre approche actuelle du budget ?", "it": "Cosa pensi del nostro attuale approccio al budget?", "ko": "현재 우리의 예산 접근 방식에 대해 어떻게 생각하시나요?", "nl": "Wat vind je van onze huidige aanpak voor budgettering?", "zh": "你对我们目前的预算方法有什么看法？"}'),
  ('finances', 3, '{"en": "What financial strategies do you believe will support our long-term dreams and goals?", "es": "¿Qué estrategias financieras crees que respaldarán nuestros sueños y metas a largo plazo?", "fr": "Quelles stratégies financières penses-tu souteniront nos rêves et objectifs à long terme ?", "it": "Quali strategie finanziarie ritieni che supporteranno i nostri sogni e obiettivi a lungo termine?", "ko": "장기적인 꿈과 목표를 지원할 재정 전략은 무엇이라고 생각하시나요?", "nl": "Welke financiële strategieën denk je dat onze langetermijndromen en -doelen zullen ondersteunen?", "zh": "你认为哪些财务策略将支持我们的长期梦想和目标？"}'),
  ('growth', 1, '{"en": "What''s one personal development book or resource you''d recommend to me?", "es": "¿Cuál es un libro o recurso de desarrollo personal que me recomendarías?", "fr": "Quel est un livre ou une ressource de développement personnel que tu me recommanderais ?", "it": "Qual è un libro o una risorsa di sviluppo personale che mi consiglieresti?", "ko": "추천하고 싶은 개인 개발 서적이나 자료는 무엇인가요?", "nl": "Wat is een persoonlijk ontwikkelingsboek of -bron die je me zou aanraden?", "zh": "你会向我推荐哪一本个人发展方面的书籍或资源？"}'),
  ('growth', 2, '{"en": "In what areas do you feel we''ve grown the most together?", "es": "¿En qué áreas sientes que hemos crecido más juntos?", "fr": "Dans quels domaines sens-tu que nous avons le plus grandi ensemble ?", "it": "In quali aree senti che siamo cresciuti maggiormente insieme?", "ko": "어떤 영역에서 우리가 가장 많이 함께 성장했다고 느끼나요?", "nl": "Op welke gebieden vind je dat we het meest samen zijn gegroeid?", "zh": "在哪些方面你觉得我们共同成长最多？"}'),
  ('growth', 3, '{"en": "How can our individual personal growth journeys contribute to the strength of our relationship?", "es": "¿Cómo pueden nuestros caminos individuales de crecimiento personal contribuir a la fortaleza de nuestra relación?", "fr": "Comment nos parcours individuels de croissance personnelle peuvent-ils contribuer à la solidité de notre relation ?", "it": "Come possono i nostri percorsi individuali di crescita personale contribuire alla forza della nostra relazione?", "ko": "우리 개인의 성장 여정이 우리 관계의 강점에 어떻게 기여할 수 있을까요?", "nl": "Hoe kunnen onze individuele persoonlijke groei-reizen bijdragen aan de kracht van onze relatie?", "zh": "我们的个人成长历程如何能增强我们之间的关系？"}'),
  ('family', 1, '{"en": "What is a family tradition you would love to start together?", "es": "¿Cuál es una tradición familiar que te gustaría comenzar juntos?", "fr": "Quelle tradition familiale aimerais-tu que nous commencions ensemble ?", "it": "Qual è una tradizione familiare che ti piacerebbe iniziare insieme?", "ko": "함께 시작하고 싶은 가족 전통이 있나요?", "nl": "Welke familietraditie zou je graag samen starten?", "zh": "你希望一起开始怎样的家庭传统？"}'),
  ('family', 2, '{"en": "How can we ensure our families feel included in our lives?", "es": "¿Cómo podemos asegurarnos de que nuestras familias se sientan incluidas en nuestras vidas?", "fr": "Comment pouvons-nous nous assurer que nos familles se sentent incluses dans nos vies ?", "it": "Come possiamo assicurarci che le nostre famiglie si sentano incluse nelle nostre vite?", "ko": "우리 가족이 우리의 삶에 포함되었다고 느끼게 하려면 어떻게 해야 할까요?", "nl": "Hoe kunnen we ervoor zorgen dat onze families zich betrokken voelen bij ons leven?", "zh": "我们如何确保我们的家人觉得他们参与了我们的生活？"}'),
  ('family', 3, '{"en": "How do you envision our family life in the future, and what values do you want to pass on?", "es": "¿Cómo imaginas nuestra vida familiar en el futuro y qué valores deseas transmitir?", "fr": "Comment envisages-tu notre vie de famille à l''avenir et quelles valeurs veux-tu transmettre ?", "it": "Come immagini la nostra vita familiare in futuro e quali valori vuoi trasmettere?", "ko": "미래의 가족 생활을 어떻게 상상하고 있으며, 어떤 가치를 전하고 싶나요?", "nl": "Hoe zie je ons gezinsleven in de toekomst en welke waarden wil je doorgeven?", "zh": "你如何想象我们未来的家庭生活，你想传递什么价值观？"}'),
  ('adventure', 1, '{"en": "What''s a spontaneous adventure you''d love for us to experience together?", "es": "¿Cuál es una aventura espontánea que te encantaría que viviéramos juntos?", "fr": "Quelle aventure spontanée aimerais-tu que nous vivions ensemble ?", "it": "Qual è un''avventura spontanea che ti piacerebbe vivere insieme?", "ko": "함께 경험하고 싶은 즉흥적인 모험이 있다면 무엇인가요?", "nl": "Wat is een spontane avontuur dat je graag samen zou willen beleven?", "zh": "你希望我们一起经历什么即兴冒险？"}'),
  ('adventure', 2, '{"en": "How do you think exploring new places together strengthens our bond?", "es": "¿Cómo crees que explorar nuevos lugares juntos fortalece nuestro vínculo?", "fr": "Comment penses-tu qu''explorer de nouveaux lieux ensemble renforce notre lien ?", "it": "Come pensi che esplorare nuovi luoghi insieme rafforzi il nostro legame?", "ko": "함께 새로운 장소를 탐험하는 것이 우리의 관계를 강화한다고 생각하나요?", "nl": "Hoe denk je dat het samen verkennen van nieuwe plekken onze band versterkt?", "zh": "你认为一起探索新地方如何加强我们的联系？"}'),
  ('adventure', 3, '{"en": "What role do you think adventure plays in keeping our relationship dynamic and exciting?", "es": "¿Qué papel crees que juega la aventura en mantener nuestra relación dinámica y emocionante?", "fr": "Quel rôle penses-tu que l''aventure joue dans le maintien de notre relation dynamique et excitante ?", "it": "Che ruolo pensi che l''avventura giochi nel mantenere viva e dinamica la nostra relazione?", "ko": "모험이 우리 관계를 역동적이고 흥미롭게 유지하는 데 어떤 역할을 한다고 생각하나요?", "nl": "Welke rol denk je dat avontuur speelt in het dynamisch en spannend houden van onze relatie?", "zh": "你认为冒险在保持我们关系动态和令人兴奋方面起什么作用？"}'),
  ('communication', 1, '{"en": "What''s the funniest thing we''ve miscommunicated about?", "es": "¿Cuál es la cosa más graciosa sobre la que hemos mal comunicado?", "fr": "Quelle est la chose la plus drôle à propos de laquelle nous avons mal communiqué ?", "it": "Qual è la cosa più divertente su cui abbiamo frainteso?", "ko": "우리 사이에 가장 재미있게 오해했던 것은 무엇인가요?", "nl": "Wat is het grappigste waarover we hebben misgecommuniceerd?", "zh": "我们误解过的最有趣的事情是什么？"}'),
  ('communication', 1, '{"en": "How do you prefer to cheer each other up when feeling down?", "es": "¿Cómo prefieres animarnos cuando nos sentimos bajos?", "fr": "Comment préfères-tu nous remonter le moral quand nous nous sentons déprimés ?", "it": "Come preferisci tirare su il morale quando ci sentiamo giù?", "ko": "기운이 없을 때 서로 어떻게 기운을 북돋워 주는 것을 선호하나요?", "nl": "Hoe moedig je elkaar het liefst aan als we ons down voelen?", "zh": "在情绪低落时，你更喜欢用什么方式互相鼓励？"}'),
  ('communication', 1, '{"en": "What words do you love hearing from me the most?", "es": "¿Qué palabras te encanta escucharme decir?", "fr": "Quels mots aimes-tu le plus entendre de ma part ?", "it": "Quali parole ti piace di più sentire da me?", "ko": "내가 하는 말 중에 어떤 말을 제일 듣고 싶어하나요?", "nl": "Welke woorden hoor je het liefst van mij?", "zh": "你最喜欢听我说什么话？"}'),
  ('communication', 2, '{"en": "What have you learned about communication from our relationship?", "es": "¿Qué has aprendido sobre la comunicación en nuestra relación?", "fr": "Qu''as-tu appris sur la communication dans notre relation ?", "it": "Cosa hai imparato sulla comunicazione nella nostra relazione?", "ko": "우리 관계에서 소통에 대해 배운 것은 무엇인가요?", "nl": "Wat heb je geleerd over communicatie van onze relatie?", "zh": "从我们的关系中你学到了什么关于沟通的东西？"}'),
  ('communication', 2, '{"en": "How can we improve our communication when we disagree?", "es": "¿Cómo podemos mejorar nuestra comunicación cuando estamos en desacuerdo?", "fr": "Comment pouvons-nous améliorer notre communication lorsque nous ne sommes pas d''accord ?", "it": "Come possiamo migliorare la nostra comunicazione quando siamo in disaccordo?", "ko": "의견이 다를 때 우리의 의사소통을 어떻게 개선할 수 있을까요?", "nl": "Hoe kunnen we onze communicatie verbeteren wanneer we het niet eens zijn?", "zh": "当我们意见不一致时，我们如何改进沟通？"}'),
  ('communication', 3, '{"en": "What is a boundary in communication you''d like us to strengthen?", "es": "¿Cuál es un límite en la comunicación que te gustaría que fortalecieramos?", "fr": "Quelle est une limite de communication que tu aimerais que nous renforcions ?", "it": "Qual è un limite nella comunicazione che vorresti rafforzare?", "ko": "의사소통에서 우리가 강화해야 할 경계가 있다면 무엇인가요?", "nl": "Welke grens in communicatie zou je willen dat we versterken?", "zh": "在沟通中，你希望我们加强的界限是什么？"}'),
  ('communication', 3, '{"en": "How can I better support you in feeling understood when we talk about difficult topics?", "es": "¿Cómo puedo apoyarte mejor para que te sientas comprendido cuando hablamos de temas difíciles?", "fr": "Comment puis-je mieux te soutenir pour que tu te sentes compris lorsque nous parlons de sujets difficiles ?", "it": "Come posso supportarti meglio nel farti sentire compreso quando parliamo di argomenti difficili?", "ko": "어려운 주제에 대해 이야기할 때 내가 어떻게 하면 당신이 더 잘 이해받고 있다고 느끼게 할 수 있을까요?", "nl": "Hoe kan ik je beter steunen om je begrepen te voelen als we over moeilijke onderwerpen praten?", "zh": "当我们谈论困难话题时，我如何更好地支持你让你感到被理解？"}'),
  ('communication', 2, '{"en": "In what ways can we express more gratitude in our everyday conversations?", "es": "¿De qué maneras podemos expresar más gratitud en nuestras conversaciones diarias?", "fr": "De quelles manières pouvons-nous exprimer plus de gratitude dans nos conversations quotidiennes ?", "it": "In che modo possiamo esprimere più gratitudine nelle nostre conversazioni quotidiane?", "ko": "일상 대화에서 감사를 더 많이 표현할 수 있는 방법은 무엇일까요?", "nl": "Op welke manieren kunnen we meer dankbaarheid uiten in onze dagelijkse gesprekken?", "zh": "我们可以通过哪些方式在日常对话中表达更多的感激之情？"}'),
  ('communication', 3, '{"en": "What moments of miscommunication have taught us the most about each other?", "es": "¿Qué momentos de mala comunicación nos han enseñado más sobre cada uno de nosotros?", "fr": "Quels moments de mauvaise communication nous ont le plus appris l''un sur l''autre ?", "it": "Quali momenti di incomprensione ci hanno insegnato di più l''uno sull''altro?", "ko": "오해의 순간 중에서 우리가 서로에 대해 가장 많이 배운 순간은 무엇인가요?", "nl": "Welke momenten van miscommunicatie hebben ons het meest over elkaar geleerd?", "zh": "哪些误解的时刻让我们彼此学到最多？"}'),
  ('communication', 2, '{"en": "How do you feel our communication has evolved since we first met?", "es": "¿Cómo crees que ha evolucionado nuestra comunicación desde que nos conocimos?", "fr": "Comment ressens-tu l''évolution de notre communication depuis notre première rencontre ?", "it": "Come pensi che la nostra comunicazione sia evoluta da quando ci siamo conosciuti?", "ko": "처음 만났을 때부터 우리의 의사소통이 어떻게 발전했다고 생각하나요?", "nl": "Hoe vind je dat onze communicatie is geëvolueerd sinds we elkaar voor het eerst ontmoetten?", "zh": "你觉得自从我们第一次见面以来，我们的沟通如何演变？"}'),
  ('communication', 1, '{"en": "What is a word or phrase we say that always makes you smile?", "es": "¿Cuál es una palabra o frase que decimos que siempre te hace sonreír?", "fr": "Quel est un mot ou une phrase que nous disons qui te fait toujours sourire ?", "it": "Qual è una parola o frase che diciamo che ti fa sempre sorridere?", "ko": "우리가 하는 말 중 항상 당신을 미소 짓게 하는 말이나 구절이 있나요?", "nl": "Wat is een woord of zin die we zeggen dat je altijd doet glimlachen?", "zh": "我们常说的哪个词或短语总能让你微笑？"}'),
  ('communication', 2, '{"en": "What''s one thing I can do more to encourage you to share your thoughts?", "es": "¿Qué puedo hacer más para animarte a compartir tus pensamientos?", "fr": "Qu''est-ce que je peux faire de plus pour t''encourager à partager tes pensées ?", "it": "Cosa posso fare di più per incoraggiarti a condividere i tuoi pensieri?", "ko": "내가 당신이 생각을 공유하도록 더 격려할 수 있는 방법이 있을까요?", "nl": "Wat kan ik meer doen om je aan te moedigen je gedachten te delen?", "zh": "我能做些什么来鼓励你更多地分享你的想法？"}'),
  ('communication', 1, '{"en": "What''s your favorite way to spend quality time talking together?", "es": "¿Cuál es tu forma favorita de pasar tiempo de calidad hablando juntos?", "fr": "Quelle est ta façon préférée de passer du temps de qualité à discuter ensemble ?", "it": "Qual è il tuo modo preferito di trascorrere del tempo di qualità parlando insieme?", "ko": "함께 대화하면서 보내는 최고의 방법은 무엇인가요?", "nl": "Wat is je favoriete manier om samen quality time door te brengen met praten?", "zh": "你最喜欢以什么方式一起度过优质的谈话时间？"}'),
  ('communication', 2, '{"en": "How do you prefer we handle interruptions during intense conversations?", "es": "¿Cómo prefieres que manejemos las interrupciones durante conversaciones intensas?", "fr": "Comment préfères-tu que nous gérions les interruptions pendant les conversations intenses ?", "it": "Come preferisci gestire le interruzioni durante le conversazioni intense?", "ko": "강렬한 대화 중에 우리가 방해를 어떻게 다루는 것이 좋을까요?", "nl": "Hoe ga je het liefst om met onderbrekingen tijdens intense gesprekken?", "zh": "在激烈的谈话中，你更愿意我们如何处理中断？"}'),
  ('communication', 1, '{"en": "What non-verbal cues do you use to show love?", "es": "¿Qué señales no verbales usas para mostrar amor?", "fr": "Quels signaux non verbaux utilises-tu pour montrer de l''amour ?", "it": "Quali segnali non verbali usi per mostrare amore?", "ko": "사랑을 표현하기 위해 사용하는 비언어적 신호는 무엇인가요?", "nl": "Welke non-verbale signalen gebruik je om liefde te tonen?", "zh": "你用什么非语言信号来表达爱？"}'),
  ('communication', 2, '{"en": "What can I do to be a better listener during our talks?", "es": "¿Qué puedo hacer para ser un mejor oyente durante nuestras charlas?", "fr": "Que puis-je faire pour être un meilleur auditeur pendant nos discussions ?", "it": "Cosa posso fare per essere un miglior ascoltatore durante le nostre conversazioni?", "ko": "우리 대화 중 내가 더 좋은 청자가 되기 위해 무엇을 할 수 있을까요?", "nl": "Wat kan ik doen om een betere luisteraar te zijn tijdens onze gesprekken?", "zh": "在我们的谈话中，我该怎么做才能成为一个更好的倾听者？"}'),
  ('communication', 3, '{"en": "What past communication challenges have helped us grow the most?", "es": "¿Qué desafíos de comunicación pasados nos han ayudado a crecer más?", "fr": "Quels défis de communication passés nous ont aidés à grandir le plus ?", "it": "Quali sfide comunicative del passato ci hanno aiutato a crescere di più?", "ko": "과거의 어느 의사소통 챌린지가 우리를 가장 성장시켰나요?", "nl": "Welke communicatie-uitdagingen uit het verleden hebben ons het meest geholpen om te groeien?", "zh": "哪些过去的沟通挑战帮助我们最多地成长？"}'),
  ('intimacy', 1, '{"en": "What small gesture do you think makes me feel loved the most?", "es": "¿Qué pequeño gesto crees que me hace sentir más amado?", "fr": "Quel petit geste penses-tu qui me fait me sentir le plus aimé ?", "it": "Quale piccolo gesto pensi mi faccia sentire più amato?", "ko": "어떤 작은 제스처가 내가 가장 사랑받고 있다는 느낌을 준다고 생각하나요?", "nl": "Welke kleine gebaar denk je dat mij het meest geliefd doet voelen?", "zh": "你认为什么小动作让我感受到最多的爱？"}'),
  ('intimacy', 1, '{"en": "How do you prefer to show affection on a busy day?", "es": "¿Cómo prefieres mostrar afecto en un día ocupado?", "fr": "Comment préfères-tu montrer de l''affection lors d''une journée chargée ?", "it": "Come preferisci mostrare affetto in una giornata impegnata?", "ko": "바쁜 날에 애정을 보여주고 싶을 때 어떻게 표현하나요?", "nl": "Hoe toon je het liefst genegenheid op een drukke dag?", "zh": "在忙碌的一天中，你更喜欢如何表达感情？"}'),
  ('intimacy', 1, '{"en": "What kind of compliments make you feel cherished?", "es": "¿Qué tipo de cumplidos te hacen sentir apreciado?", "fr": "Quel genre de compliments te font te sentir chéri ?", "it": "Che tipo di complimenti ti fanno sentire amato?", "ko": "어떤 종류의 칭찬이 당신을 사랑받고 있다고 느끼게 하나요?", "nl": "Welke soort complimenten doen je geliefd voelen?", "zh": "什么样的赞美让你感到被珍惜？"}'),
  ('intimacy', 2, '{"en": "How do you think our intimacy has deepened over time?", "es": "¿Cómo crees que nuestra intimidad ha profundizado con el tiempo?", "fr": "Comment penses-tu que notre intimité s''est approfondie au fil du temps ?", "it": "Come pensi che la nostra intimità si sia approfondita col tempo?", "ko": "시간이 흐르면서 우리의 친밀함이 어떻게 깊어졌다고 생각하나요?", "nl": "Hoe denk je dat onze intimiteit in de loop van de tijd is verdiept?", "zh": "你认为我们的亲密关系随着时间的推移如何加深？"}'),
  ('intimacy', 2, '{"en": "What''s one thing I can do to help you feel more connected with me?", "es": "¿Qué puedo hacer para ayudarte a sentirte más conectado conmigo?", "fr": "Quelle est une chose que je peux faire pour t''aider à te sentir plus connecté(e) à moi ?", "it": "Qual è una cosa che posso fare per aiutarti a sentirti più connesso con me?", "ko": "당신이 나와 더 연결된 느낌을 받을 수 있도록 내가 할 수 있는 것은 무엇인가요?", "nl": "Wat is één ding dat ik kan doen om je meer verbonden met mij te laten voelen?", "zh": "我能做什么来帮助你和我感到更紧密的联系？"}'),
  ('intimacy', 3, '{"en": "What personal vulnerability can we share to strengthen our bond?", "es": "¿Qué vulnerabilidad personal podemos compartir para fortalecer nuestro vínculo?", "fr": "Quelle vulnérabilité personnelle pouvons-nous partager pour renforcer notre lien ?", "it": "Quale vulnerabilità personale possiamo condividere per rafforzare il nostro legame?", "ko": "우리의 관계를 강화하기 위해 공유할 수 있는 개인적인 취약점은 무엇인가요?", "nl": "Welke persoonlijke kwetsbaarheid kunnen we delen om onze band te versterken?", "zh": "我们可以分享哪些个人脆弱以加强我们的关系？"}'),
  ('intimacy', 2, '{"en": "What time of day do you feel closest to me?", "es": "¿A qué hora del día te sientes más cercano a mí?", "fr": "À quel moment de la journée te sens-tu le plus proche de moi ?", "it": "In quale momento della giornata ti senti più vicino a me?", "ko": "하루 중 언제 나와 가장 가까운 느낌을 받나요?", "nl": "Op welk moment van de dag voel je je het dichtst bij mij?", "zh": "一天中的哪个时刻你觉得和我最亲近？"}'),
  ('intimacy', 3, '{"en": "What creates the most emotional security in our relationship?", "es": "¿Qué genera la mayor seguridad emocional en nuestra relación?", "fr": "Qu''est-ce qui crée la sécurité émotionnelle la plus forte dans notre relation ?", "it": "Cosa crea la maggiore sicurezza emotiva nella nostra relazione?", "ko": "우리 관계에서 가장 큰 감정적 안정감을 주는 것은 무엇인가요?", "nl": "Wat zorgt voor de meeste emotionele veiligheid in onze relatie?", "zh": "在我们关系中，什么能带来最多的情感安全感？"}'),
  ('intimacy', 2, '{"en": "How do you like to show me that you deeply understand me?", "es": "¿Cómo te gusta mostrarme que me entiendes profundamente?", "fr": "Comment aimez-vous me montrer que vous me comprenez profondément ?", "it": "Come ti piace dimostrarmi che mi comprendi profondamente?", "ko": "당신이 나를 깊이 이해한다는 것을 어떻게 보여주고 싶나요?", "nl": "Hoe laat je graag zien dat je me diep begrijpt?", "zh": "你喜欢如何向我表明你深刻理解我？"}'),
  ('intimacy', 1, '{"en": "What''s a simple activity we can do to feel more intimate on a regular day?", "es": "¿Cuál es una actividad sencilla que podemos hacer para sentirnos más íntimos en un día normal?", "fr": "Quelle est une activité simple que nous pouvons faire pour nous sentir plus intimes un jour ordinaire ?", "it": "Qual è un''attività semplice che possiamo fare per sentirci più intimi in un giorno normale?", "ko": "일상적인 날에 더 친밀함을 느낄 수 있는 간단한 활동은 무엇인가요?", "nl": "Wat is een eenvoudige activiteit die we kunnen doen om ons op een gewone dag intiemer te voelen?", "zh": "在普通日子里，我们可以做什么简单的事情来增进亲密感？"}'),
  ('intimacy', 2, '{"en": "What type of moments make you feel the most at peace with each other?", "es": "¿Qué tipo de momentos te hacen sentir más en paz con el otro?", "fr": "Quel type de moments vous fait vous sentir le plus en paix l''un avec l''autre ?", "it": "Quali momenti ti fanno sentire più in pace con l''altro?", "ko": "어떤 순간들이 서로 가장 평온함을 느끼게 하나요?", "nl": "Welke momenten zorgen ervoor dat jullie je het meest op je gemak voelen bij elkaar?", "zh": "哪种时刻让你们彼此感到最和平？"}'),
  ('intimacy', 3, '{"en": "What does being intimate mean to you beyond physical closeness?", "es": "¿Qué significa para ti la intimidad más allá de la cercanía física?", "fr": "Que signifie l''intimité pour vous au-delà de la proximité physique ?", "it": "Cosa significa per te l''intimità oltre alla vicinanza fisica?", "ko": "신체적 친밀함을 넘어서는 친밀함이 당신에게 무엇을 의미하나요?", "nl": "Wat betekent intiem zijn voor jou, naast fysieke nabijheid?", "zh": "对于你来说，亲密除了身体上的亲近还有什么意义？"}'),
  ('intimacy', 1, '{"en": "What tradition can we create to mark special moments in our relationship?", "es": "¿Qué tradición podemos crear para marcar momentos especiales en nuestra relación?", "fr": "Quelle tradition pouvons-nous créer pour marquer des moments spéciaux dans notre relation ?", "it": "Quale tradizione possiamo creare per segnare momenti speciali nella nostra relazione?", "ko": "우리 관계의 특별한 순간을 기념하기 위해 어떤 전통을 만들 수 있을까요?", "nl": "Welke traditie kunnen we creëren om speciale momenten in onze relatie te markeren?", "zh": "我们可以创造什么传统来纪念我们关系中的特别时刻？"}'),
  ('intimacy', 2, '{"en": "How do you ensure our emotional intimacy stays strong?", "es": "¿Cómo aseguras que nuestra intimidad emocional se mantenga fuerte?", "fr": "Comment vous assurez-vous que notre intimité émotionnelle reste forte ?", "it": "Come ti assicuri che la nostra intimità emotiva rimanga forte?", "ko": "우리의 감정적 친밀함이 강하게 유지되도록 어떻게 보장하나요?", "nl": "Hoe zorg je ervoor dat onze emotionele intimiteit sterk blijft?", "zh": "你如何确保我们的情感亲密关系保持强大？"}'),
  ('intimacy', 3, '{"en": "What''s a deep conversation we''ve had that made you feel particularly close to me?", "es": "¿Cuál es una conversación profunda que hemos tenido que te hizo sentir particularmente cercano a mí?", "fr": "Quelle conversation profonde avons-nous eue qui vous a fait vous sentir particulièrement proche de moi ?", "it": "Qual è una conversazione profonda che abbiamo avuto che ti ha fatto sentire particolarmente vicino a me?", "ko": "우리가 나눴던 깊은 대화 중 당신이 특히 나에게 가까움을 느꼈던 대화는 무엇인가요?", "nl": "Wat is een diepgaand gesprek dat we hebben gehad en dat je je bijzonder dicht bij mij voelde?", "zh": "我们曾进行过的深刻对话中，让你感到特别亲近我的是什么？"}'),
  ('dreams', 1, '{"en": "What''s a dream vacation you envision us taking?", "es": "¿Cuál es unas vacaciones de ensueño que imaginas que tomemos?", "fr": "Quelles sont les vacances de rêve que vous nous imaginez prendre ?", "it": "Qual è una vacanza da sogno che immagini che prendiamo?", "ko": "당신이 상상하는 우리의 꿈의 휴가는 무엇인가요?", "nl": "Wat is een droomvakantie die je voor ons ziet?", "zh": "你设想过我们会进行的梦幻假期是什么？"}'),
  ('dreams', 1, '{"en": "What''s a hobby you''ve always wanted us to explore together?", "es": "¿Cuál es un hobby que siempre has querido que exploremos juntos?", "fr": "Quel est un passe-temps que vous avez toujours voulu que nous explorions ensemble ?", "it": "Qual è un hobby che hai sempre voluto che esplorassimo insieme?", "ko": "당신이 항상 우리가 함께 탐험하길 원했던 취미는 무엇인가요?", "nl": "Wat is een hobby die je altijd al samen met mij wilde verkennen?", "zh": "你一直希望我们一起探索的爱好是什么？"}'),
  ('dreams', 1, '{"en": "What kind of house would be in your dreams for us to live in?", "es": "¿Qué tipo de casa sería en tus sueños para que vivamos?", "fr": "Quel type de maison serait dans vos rêves pour que nous vivions ?", "it": "Che tipo di casa sarebbe nei tuoi sogni per noi vivere?", "ko": "우리 둘이 살고 싶은 당신의 꿈의 집은 어떤 형식인가요?", "nl": "Wat voor soort huis zou in jouw dromen zijn om samen in te wonen?", "zh": "在你的梦想中，我们会住什么样的房子？"}'),
  ('dreams', 2, '{"en": "How do you see us supporting each other''s dreams?", "es": "¿Cómo ves que nos apoyemos en los sueños de cada uno?", "fr": "Comment nous voyez-vous soutenir les rêves de chacun ?", "it": "Come vedi che ci supportiamo nei sogni di ciascuno?", "ko": "우리가 서로의 꿈을 지지하는 방법을 어떻게 보나요?", "nl": "Hoe zie je dat we elkaars dromen ondersteunen?", "zh": "你如何看待我们彼此支持对方的梦想？"}'),
  ('dreams', 2, '{"en": "What dream of yours can I support you more in achieving?", "es": "¿Qué sueño tuyo puedo apoyar más para que logres?", "fr": "Quel rêve à vous puis-je soutenir davantage pour que vous le réalisiez ?", "it": "In quale tuo sogno posso supportarti di più affinché tu lo realizzi?", "ko": "당신의 어떤 꿈에서 내가 더 많이 도와줄 수 있을까요?", "nl": "Welke droom van jou kan ik meer ondersteunen bij het bereiken?", "zh": "我可以在哪个你的梦想中给予更多支持帮助你实现？"}'),
  ('dreams', 3, '{"en": "What dream do you want to achieve that would redefine our future together?", "es": "¿Qué sueño quieres lograr que redefinirá nuestro futuro juntos?", "fr": "Quel rêve souhaitez-vous réaliser qui redéfinirait notre avenir ensemble ?", "it": "Quale sogno vuoi realizzare che ridefinirà il nostro futuro insieme?", "ko": "우리의 미래를 재정의할 당신의 꿈은 무엇인가요?", "nl": "Welke droom wil je bereiken die onze gezamenlijke toekomst zou herdefiniëren?", "zh": "你希望实现的哪个梦想会重新定义我们的未来？"}'),
  ('dreams', 2, '{"en": "How do our dreams align when it comes to our long-term goals?", "es": "¿Cómo se alinean nuestros sueños cuando se trata de nuestros objetivos a largo plazo?", "fr": "Comment nos rêves s''alignent-ils lorsqu''il s''agit de nos objectifs à long terme ?", "it": "Come si allineano i nostri sogni quando si tratta dei nostri obiettivi a lungo termine?", "ko": "장기적인 목표에 있을 때 우리의 꿈이 어떻게 맞춰지나요?", "nl": "Hoe komen onze dromen overeen als het om onze langetermijndoelen gaat?", "zh": "关于我们的长期目标，我们的梦想是如何一致的？"}'),
  ('dreams', 3, '{"en": "How do you handle the fears that come with chasing your dreams?", "es": "¿Cómo manejas los miedos que vienen con perseguir tus sueños?", "fr": "Comment gérez-vous les peurs qui accompagnent la poursuite de vos rêves ?", "it": "Come gestisci le paure che vengono con l''inseguire i tuoi sogni?", "ko": "꿈을 좇으면서 생기는 두려움을 어떻게 다루나요?", "nl": "Hoe ga je om met de angsten die gepaard gaan met het najagen van je dromen?", "zh": "你是如何应对追逐梦想过程中的恐惧的？"}'),
  ('dreams', 1, '{"en": "What''s a simple dream you want us to start working towards this year?", "es": "¿Cuál es un sueño sencillo que quieres que empecemos a trabajar hacia este año?", "fr": "Quel est un rêve simple que vous voulez que nous commencions à travailler cette année ?", "it": "Qual è un sogno semplice che vuoi che iniziamo a lavorare quest''anno?", "ko": "올해 우리가 함께 시작하길 원하는 간단한 꿈은 무엇인가요?", "nl": "Wat is een eenvoudige droom die je wilt dat we dit jaar gaan realiseren?", "zh": "你希望我们今年开始努力实现的简单梦想是什么？"}'),
  ('dreams', 2, '{"en": "How can we turn a shared fantasy into reality?", "es": "¿Cómo podemos convertir una fantasía compartida en realidad?", "fr": "Comment pouvons-nous transformer une fantaisie partagée en réalité ?", "it": "Come possiamo trasformare una fantasia condivisa in realtà?", "ko": "공유한 환상을 현실로 만들기 위해 우리는 무엇을 할 수 있을까요?", "nl": "Hoe kunnen we een gedeelde fantasie in werkelijkheid omzetten?", "zh": "我们如何将共同的幻想变为现实？"}'),
  ('dreams', 1, '{"en": "What''s a silly dream we''ve shared that always makes you smile?", "es": "¿Cuál es un sueño tonto que hemos compartido que siempre te hace sonreír?", "fr": "Quel est un rêve stupide que nous avons partagé qui vous fait toujours sourire ?", "it": "Qual è un sogno sciocco che abbiamo condiviso che ti fa sempre sorridere?", "ko": "우리 둘이 나눴던 바보같은 꿈 중 항상 미소짓게 하는 것은 무엇인가요?", "nl": "Wat is een gekke droom die we hebben gedeeld die je altijd aan het lachen maakt?", "zh": "我们共同经历过的哪个傻梦总是能让你微笑？"}'),
  ('dreams', 3, '{"en": "How do you stay hopeful about dreams we''ve set aside for practical reasons?", "es": "¿Cómo te mantienes esperanzado sobre los sueños que hemos dejado de lado por razones prácticas?", "fr": "Comment restez-vous optimiste quant aux rêves que nous avons mis de côté pour des raisons pratiques ?", "it": "Come rimani fiducioso riguardo ai sogni che abbiamo accantonato per ragioni pratiche?", "ko": "실질적인 이유로 미뤄둔 꿈들에 대해 어떻게 희망을 유지하나요?", "nl": "Hoe blijf je hoopvol over dromen die we om praktische redenen opzij hebben gezet?", "zh": "对于因现实原因搁置的梦想，你如何保持希望？"}'),
  ('dreams', 2, '{"en": "In what ways do our dreams motivate us differently?", "es": "¿De qué maneras nuestros sueños nos motivan de manera diferente?", "fr": "De quelles manières nos rêves nous motivent-ils différemment ?", "it": "In che modo i nostri sogni ci motivano in modo diverso?", "ko": "어떤 방식으로 우리의 꿈이 다른 방식으로 우리를 자극하나요?", "nl": "Op welke manieren motiveren onze dromen ons verschillend?", "zh": "我们的梦想以什么方式不同地激励着我们？"}'),
  ('dreams', 1, '{"en": "What personal dream of mine do you find most inspiring?", "es": "¿Qué sueño personal mío encuentras más inspirador?", "fr": "Quel rêve personnel à moi trouvez-vous le plus inspirant ?", "it": "Qual è un mio sogno personale che trovi più ispiratore?", "ko": "내 개인적인 꿈 중 당신이 가장 영감을 받는 것은 무엇인가요?", "nl": "Welke persoonlijke droom van mij vind je het meest inspirerend?", "zh": "你觉得我的哪个个人梦想最具启发性？"}'),
  ('dreams', 2, '{"en": "What''s a dream you''ve had since childhood that you want us to pursue?", "es": "¿Cuál es un sueño que has tenido desde la infancia que quieres que persigamos?", "fr": "Quel est un rêve que vous avez eu depuis l''enfance que vous voulez que nous poursuivions ?", "it": "Qual è un sogno che hai avuto dall''infanzia che vuoi che perseguiamo?", "ko": "어린 시절부터 가지고 있던 꿈 중 우리 둘이 이루고 싶은 것은 무엇인가요?", "nl": "Wat is een droom die je sinds je kindertijd hebt en die je wilt dat we najagen?", "zh": "你从小到大一直拥有的梦想是什么，你希望我们一起追求？"}'),
  ('memories', 1, '{"en": "What''s the silliest moment we''ve shared that you love to remember?", "es": "¿Cuál es el momento más tonto que hemos compartido que te encanta recordar?", "fr": "Quel est le moment le plus idiot que nous avons partagé et que vous aimez vous rappeler ?", "it": "Qual è il momento più sciocco che abbiamo condiviso che ami ricordare?", "ko": "함께한 바보 같은 순간 중 당신이 기억하기 좋아하는 것은 무엇인가요?", "nl": "Wat is het gekste moment dat we hebben gedeeld dat je graag herinnert?", "zh": "我们分享过的最愚蠢的时刻是什么，你喜欢回忆起来？"}'),
  ('memories', 1, '{"en": "What''s your favorite holiday memory together?", "es": "¿Cuál es tu recuerdo favorito de vacaciones juntos?", "fr": "Quel est votre souvenir de vacances préféré ensemble ?", "it": "Qual è il tuo ricordo di vacanze preferito insieme?", "ko": "함께한 가장 좋아하는 휴일 추억은 무엇인가요?", "nl": "Wat is je favoriete vakantieherinnering samen?", "zh": "你们一起度过的假期中最喜欢的回忆是什么？"}'),
  ('memories', 2, '{"en": "What''s a memory that perfectly captures our relationship?", "es": "¿Cuál es un recuerdo que captura perfectamente nuestra relación?", "fr": "Quel est un souvenir qui capture parfaitement notre relation ?", "it": "Qual è un ricordo che cattura perfettamente la nostra relazione?", "ko": "우리 관계를 완벽히 포착하는 기억은 무엇인가요?", "nl": "Wat is een herinnering die onze relatie perfect vastlegt?", "zh": "哪个回忆完美地捕捉了我们的关系？"}'),
  ('memories', 2, '{"en": "How do you preserve the memories that mean the most to you?", "es": "¿Cómo preservas los recuerdos que son más importantes para ti?", "fr": "Comment préservez-vous les souvenirs qui comptent le plus pour vous ?", "it": "Come preservi i ricordi che significano di più per te?", "ko": "가장 소중한 기억을 어떻게 간직하고 있나요?", "nl": "Hoe bewaar je de herinneringen die het meest voor je betekenen?", "zh": "你如何保存那些对你来说意义重大的记忆？"}'),
  ('memories', 3, '{"en": "What challenging memory do you believe strengthened us the most?", "es": "¿Qué recuerdo desafiante crees que nos fortaleció más?", "fr": "Quel souvenir difficile croyez-vous nous avoir le plus renforcés ?", "it": "Quale ricordo difficile credi ci abbia più rafforzato?", "ko": "힘들지만 우리를 가장 강하게 만든 기억은 무엇인가요?", "nl": "Welke uitdagende herinnering denk je dat ons het meest heeft versterkt?", "zh": "你认为哪个挑战性的回忆最增强了我们的关系？"}'),
  ('memories', 3, '{"en": "What past memory do you treasure most and why?", "es": "¿Qué recuerdo pasado valoras más y por qué?", "fr": "Quel souvenir passé chérissez-vous le plus et pourquoi ?", "it": "Qual è il ricordo passato che apprezzi di più e perché?", "ko": "가장 소중히 여기는 지난 추억은 무엇이고, 그 이유는 무엇인가요?", "nl": "Welke herinnering uit het verleden koester je het meest en waarom?", "zh": "你最珍视过去的哪个记忆，为什么？"}'),
  ('memories', 2, '{"en": "How does recalling our happy memories affect your current mood?", "es": "¿Cómo afecta tu estado de ánimo actual al recordar nuestros recuerdos felices?", "fr": "Comment le rappel de nos souvenirs heureux affecte-t-il votre humeur actuelle ?", "it": "Come influisce il ricordo dei nostri momenti felici sul tuo stato d''animo attuale?", "ko": "행복한 기억을 떠올리면 현재 기분에 어떤 영향을 미치나요?", "nl": "Hoe beïnvloedt het naar boven halen van onze gelukkige herinneringen je huidige stemming?", "zh": "回忆我们的快乐时光会如何影响你当前的心情？"}'),
  ('memories', 1, '{"en": "What''s a shared summer memory that stands out?", "es": "¿Cuál es un recuerdo de verano compartido que destaca?", "fr": "Quel souvenir d''été partagé se démarque ?", "it": "Qual è un ricordo estivo condiviso che spicca?", "ko": "눈에 띄는 공유된 여름 기억은 무엇인가요?", "nl": "Wat is een gedeelde zomerherinnering die opvalt?", "zh": "有什么特别的夏天共同回忆吗？"}'),
  ('memories', 1, '{"en": "What music brings back the best memories of us?", "es": "¿Qué música trae de vuelta los mejores recuerdos de nosotros?", "fr": "Quelle musique ramène les meilleurs souvenirs de nous ?", "it": "Quale musica riporta alla mente i migliori ricordi di noi?", "ko": "어떤 음악이 우리의 최고의 추억을 불러일으키나요?", "nl": "Welke muziek brengt de beste herinneringen aan ons terug?", "zh": "什么音乐能唤起我们最美好的回忆？"}'),
  ('memories', 2, '{"en": "What''s a memory we have that still makes you laugh out loud?", "es": "¿Cuál es un recuerdo que tenemos que todavía te hace reír a carcajadas?", "fr": "Quel souvenir avons-nous qui te fait encore rire aux éclats ?", "it": "Qual è un ricordo che abbiamo che ancora ti fa ridere a crepapelle?", "ko": "아직도 크게 웃게 만드는 우리의 기억은 무엇인가요?", "nl": "Wat is een herinnering die ons nog steeds hardop laat lachen?", "zh": "我们有什么回忆至今仍能让你哈哈大笑？"}'),
  ('memories', 3, '{"en": "What do you think is the most meaningful memory we''ve created together?", "es": "¿Cuál crees que es el recuerdo más significativo que hemos creado juntos?", "fr": "Quel est selon toi le souvenir le plus significatif que nous avons créé ensemble ?", "it": "Qual è secondo te il ricordo più significativo che abbiamo creato insieme?", "ko": "우리가 함께 만든 가장 의미 있는 기억은 무엇이라고 생각하나요?", "nl": "Wat denk je dat de meest betekenisvolle herinnering is die we samen hebben gecreëerd?", "zh": "你认为我们一起创造的最有意义的回忆是什么？"}'),
  ('memories', 2, '{"en": "How do you think our memories shape the way we view the future?", "es": "¿Cómo crees que nuestros recuerdos influyen en cómo vemos el futuro?", "fr": "Comment penses-tu que nos souvenirs influencent notre vision de l''avenir ?", "it": "Come pensi che i nostri ricordi influenzino il modo in cui vediamo il futuro?", "ko": "우리의 기억이 미래를 보는 방식에 어떻게 영향을 미친다고 생각하나요?", "nl": "Hoe denk je dat onze herinneringen de manier vormen waarop we de toekomst zien?", "zh": "你觉得我们的回忆如何影响我们对未来的看法？"}'),
  ('memories', 1, '{"en": "What''s a spontaneous adventure we took that still makes you smile?", "es": "¿Cuál es una aventura espontánea que tomamos que aún te hace sonreír?", "fr": "Quelle aventure spontanée avons-nous vécue qui te fait encore sourire ?", "it": "Qual è un''avventura spontanea che abbiamo vissuto che ancora ti fa sorridere?", "ko": "아직도 미소를 짓게 만드는 즉흥적인 모험은 무엇인가요?", "nl": "Wat is een spontane avontuur die we hebben beleefd dat je nog steeds doet glimlachen?", "zh": "我们曾有哪些自发的冒险至今仍能让你微笑？"}'),
  ('memories', 2, '{"en": "What''s a memory of ours that you''d like to recreate?", "es": "¿Cuál es un recuerdo nuestro que te gustaría recrear?", "fr": "Quel souvenir aimerais-tu revivre ?", "it": "Qual è un ricordo nostro che ti piacerebbe ricreare?", "ko": "다시 만들고 싶은 우리의 기억은 무엇인가요?", "nl": "Wat is een herinnering van ons die je opnieuw zou willen beleven?", "zh": "你希望重温我们的哪段回忆？"}'),
  ('memories', 3, '{"en": "What''s a memory that provides you with peace and comfort during tough times?", "es": "¿Cuál es un recuerdo que te brinda paz y consuelo durante tiempos difíciles?", "fr": "Quel souvenir t''apporte paix et réconfort en temps difficiles ?", "it": "Qual è un ricordo che ti dà pace e conforto nei momenti difficili?", "ko": "힘든 시기에 평화와 위안을 주는 기억은 무엇인가요?", "nl": "Wat is een herinnering die je vrede en troost biedt tijdens moeilijke tijden?", "zh": "在艰难时期，什么回忆能给你带来宁静和安慰？"}'),
  ('values', 1, '{"en": "What''s a shared value you feel defines our relationship?", "es": "¿Cuál es un valor compartido que crees que define nuestra relación?", "fr": "Quelle est la valeur partagée qui définit notre relation selon toi ?", "it": "Qual è un valore condiviso che ritieni definisca la nostra relazione?", "ko": "우리의 관계를 정의하는 공통 가치는 무엇이라고 생각하나요?", "nl": "Wat is een gedeelde waarde die je vindt dat onze relatie definieert?", "zh": "你认为什么共同价值观定义了我们的关系？"}'),
  ('values', 1, '{"en": "How do you show respect for our shared values daily?", "es": "¿Cómo muestras respeto por nuestros valores compartidos a diario?", "fr": "Comment montres-tu du respect pour nos valeurs partagées au quotidien ?", "it": "Come mostri rispetto per i nostri valori condivisi quotidianamente?", "ko": "매일 우리의 공통 가치를 어떻게 존중하나요?", "nl": "Hoe toon je dagelijks respect voor onze gedeelde waarden?", "zh": "你在日常生活中如何尊重我们的共同价值观？"}'),
  ('values', 2, '{"en": "What personal value do you think influences most of your decisions?", "es": "¿Qué valor personal crees que influye en la mayoría de tus decisiones?", "fr": "Quelle valeur personnelle penses-tu influencer la plupart de tes décisions ?", "it": "Quale valore personale pensi influenzi la maggior parte delle tue decisioni?", "ko": "대부분의 결정을 내리는 데 영향을 미치는 개인적인 가치는 무엇인가요?", "nl": "Welke persoonlijke waarde denk je dat de meeste van je beslissingen beïnvloedt?", "zh": "你认为哪个个人价值观影响了你大多数的决定？"}'),
  ('values', 2, '{"en": "What value in our relationship do you treasure most highly?", "es": "¿Qué valor en nuestra relación valoras más altamente?", "fr": "Quelle valeur de notre relation est la plus précieuse pour toi ?", "it": "Quale valore della nostra relazione apprezzi di più?", "ko": "우리의 관계에서 가장 소중히 여기는 가치는 무엇인가요?", "nl": "Welke waarde in onze relatie waardeer je het hoogst?", "zh": "在我们的关系中，你最珍视哪种价值观？"}'),
  ('values', 3, '{"en": "How do you think our values align with our future goals?", "es": "¿Cómo crees que nuestros valores se alinean con nuestros objetivos futuros?", "fr": "Comment penses-tu que nos valeurs s''alignent avec nos objectifs futurs ?", "it": "Come pensi che i nostri valori si allineino con i nostri obiettivi futuri?", "ko": "우리의 가치가 미래의 목표와 어떻게 일치한다고 생각하나요?", "nl": "Hoe denk je dat onze waarden overeenkomen met onze toekomstige doelen?", "zh": "你认为我们的价值观与未来目标如何一致？"}'),
  ('values', 2, '{"en": "What is a value you''d like us to focus more on together?", "es": "¿Cuál es un valor en el que te gustaría que nos enfocáramos más juntos?", "fr": "Quelle est la valeur sur laquelle tu voudrais que nous nous concentrions plus ensemble ?", "it": "Qual è un valore su cui vorresti che ci concentrassimo di più insieme?", "ko": "우리가 더 집중하고 싶은 가치는 무엇인가요?", "nl": "Welke waarde zou je graag willen dat we ons meer op richten samen?", "zh": "你希望我们更注重哪种价值观？"}'),
  ('values', 3, '{"en": "How do your core values guide you in our relationship?", "es": "¿Cómo te guían tus valores fundamentales en nuestra relación?", "fr": "Comment tes valeurs fondamentales te guident-elles dans notre relation?", "it": "Come ti guidano i tuoi valori fondamentali nella nostra relazione?", "ko": "기본적인 가치가 우리의 관계에서 당신을 어떻게 안내하나요?", "nl": "Hoe begeleiden je kernwaarden je in onze relatie?", "zh": "你的核心价值观如何在我们的关系中引导你？"}'),
  ('values', 2, '{"en": "How do you express your personal values through actions?", "es": "¿Cómo expresas tus valores personales a través de acciones?", "fr": "Comment exprimes-tu tes valeurs personnelles à travers tes actions ?", "it": "Come esprimi i tuoi valori personali attraverso le azioni?", "ko": "행동을 통해 개인의 가치를 어떻게 표현하나요?", "nl": "Hoe druk je je persoonlijke waarden uit door middel van daden?", "zh": "你如何通过行动表达你的个人价值观？"}'),
  ('values', 1, '{"en": "What''s a value you appreciate seeing in me?", "es": "¿Qué valor aprecias ver en mí?", "fr": "Quelle valeur apprécies-tu chez moi ?", "it": "Qual è un valore che apprezzi vedere in me?", "ko": "내가 가지고 있는 가치 중에 당신이 감사하게 여기는 것은 무엇인가요?", "nl": "Welke waarde waardeer je in mij?", "zh": "你欣赏我身上的哪个价值观？"}'),
  ('values', 3, '{"en": "What''s a way we can reconcile differences in our values?", "es": "¿Cuál es una manera en que podemos reconciliar diferencias en nuestros valores?", "fr": "Comment pouvons-nous réconcilier les différences dans nos valeurs ?", "it": "Qual è un modo in cui possiamo riconciliare le differenze nei nostri valori?", "ko": "우리의 가치 차이를 조화롭게 해결할 수 있는 방법은 무엇인가요?", "nl": "Wat is een manier waarop we verschillen in onze waarden kunnen overbruggen?", "zh": "我们如何调和彼此价值观的差异？"}'),
  ('values', 1, '{"en": "What''s a small action you take in daily life to uphold your values?", "es": "¿Cuál es una pequeña acción que realizas en la vida diaria para mantener tus valores?", "fr": "Quelle petite action fais-tu au quotidien pour soutenir tes valeurs ?", "it": "Qual è una piccola azione che compi nella vita quotidiana per sostenere i tuoi valori?", "ko": "당신의 가치를 지키기 위해 일상 생활에서 취하는 작은 행동은 무엇인가요?", "nl": "Wat is een kleine actie die je dagelijks onderneemt om je waarden hoog te houden?", "zh": "你在日常生活中采取什么小行动来坚持你的价值观？"}'),
  ('values', 2, '{"en": "How do you prioritize personal versus shared values in decision-making?", "es": "¿Cómo priorizas los valores personales versus los compartidos al tomar decisiones?", "fr": "Comment priorises-tu les valeurs personnelles par rapport aux valeurs partagées lors de la prise de décisions ?", "it": "Come dai priorità ai valori personali rispetto a quelli condivisi quando prendi decisioni?", "ko": "의사 결정에서 개인 가치와 공유 가치를 어떻게 우선시하나요?", "nl": "Hoe geef je prioriteit aan persoonlijke versus gedeelde waarden bij het nemen van beslissingen?", "zh": "在决策过程中，你如何平衡个人价值观与共同价值观？"}'),
  ('values', 3, '{"en": "What challenge in our relationship brought a deeper understanding of our values?", "es": "¿Qué desafío en nuestra relación trajo una comprensión más profunda de nuestros valores?", "fr": "Quel défi dans notre relation a apporté une compréhension plus profonde de nos valeurs ?", "it": "Quale sfida nella nostra relazione ha portato a una comprensione più profonda dei nostri valori?", "ko": "우리의 관계에서 어떤 도전이 우리의 가치를 더 깊이 이해하게 했나요?", "nl": "Welke uitdaging in onze relatie heeft een diepere begrip van onze waarden gebracht?", "zh": "我们关系中的哪个挑战让我们对彼此的价值观有了更深入的理解？"}'),
  ('values', 1, '{"en": "What''s a tradition we have that reflects our shared values?", "es": "¿Cuál es una tradición que tenemos que refleja nuestros valores compartidos?", "fr": "Quelle tradition avons-nous qui reflète nos valeurs partagées ?", "it": "Qual è una tradizione che abbiamo che riflette i nostri valori condivisi?", "ko": "우리의 공통 가치를 반영하는 전통은 무엇인가요?", "nl": "Wat is een traditie die we hebben die onze gedeelde waarden weerspiegelt?", "zh": "我们有什么传统反映了我们的共同价值观？"}'),
  ('values', 2, '{"en": "How do you handle situations where our values might clash?", "es": "¿Cómo manejas situaciones donde nuestros valores podrían chocar?", "fr": "Comment gères-tu les situations où nos valeurs pourraient entrer en conflit ?", "it": "Come gestisci le situazioni in cui i nostri valori potrebbero entrare in conflitto?", "ko": "우리의 가치가 충돌할 수 있는 상황을 어떻게 처리하나요?", "nl": "Hoe ga je om met situaties waarin onze waarden kunnen botsen?", "zh": "当我们的价值观发生冲突时，你如何处理这种情况？"}'),
  ('fun', 1, '{"en": "What''s the silliest nickname you''ve given each other?", "es": "¿Cuál es el apodo más tonto que se han dado el uno al otro?", "fr": "Quel est le surnom le plus idiot que vous vous êtes donné ?", "it": "Qual è il soprannome più sciocco che vi siete dati a vicenda?", "ko": "서로에게 지어준 가장 웃긴 별명은 무엇인가요?", "nl": "Wat is de grappigste bijnaam die jullie elkaar hebben gegeven?", "zh": "你们给彼此取过的最傻的昵称是什么？"}'),
  ('fun', 1, '{"en": "What kind of parties would you love to throw together?", "es": "¿Qué tipo de fiestas les encantaría organizar juntos?", "fr": "Quel genre de fêtes aimeriez-vous organiser ensemble ?", "it": "Che tipo di feste vi piacerebbe organizzare insieme?", "ko": "함께 어떤 종류의 파티를 열고 싶나요?", "nl": "Wat voor soort feestjes zouden jullie graag samen willen geven?", "zh": "你们想一起举办什么类型的派对？"}'),
  ('fun', 2, '{"en": "How do you make mundane activities turn into fun adventures?", "es": "¿Cómo conviertes actividades mundanas en divertidas aventuras?", "fr": "Comment transformes-tu des activités banales en aventures amusantes ?", "it": "Come trasformi le attività banali in avventure divertenti?", "ko": "일상적인 활동을 재미있는 모험으로 어떻게 바꾸나요?", "nl": "Hoe maken jullie van alledaagse activiteiten leuke avonturen?", "zh": "你如何将平凡的活动变成有趣的冒险？"}'),
  ('fun', 2, '{"en": "What''s a creative hobby you''ve always wanted us to try?", "es": "¿Cuál es un pasatiempo creativo que siempre has querido que probáramos?", "fr": "Quel passe-temps créatif as-tu toujours voulu que nous essayions ?", "it": "Qual è un hobby creativo che hai sempre voluto che provassimo?", "ko": "항상 함께 해보고 싶었던 창의적인 취미가 있나요?", "nl": "Wat is een creatieve hobby die je altijd al hebt willen proberen?", "zh": "你一直希望我们尝试什么创造性的爱好？"}'),
  ('fun', 3, '{"en": "How do you think laughter contributes to the health of our relationship?", "es": "¿Cómo crees que la risa contribuye a la salud de nuestra relación?", "fr": "Comment penses-tu que le rire contribue à la santé de notre relation ?", "it": "Come pensi che le risate contribuiscano alla salute della nostra relazione?", "ko": "웃음이 우리의 관계 건강에 어떻게 기여한다고 생각하나요?", "nl": "Hoe denk je dat lachen bijdraagt aan de gezondheid van onze relatie?", "zh": "你认为笑声如何有助于我们关系的健康？"}'),
  ('fun', 1, '{"en": "What''s a game or activity that always brings us closer?", "es": "¿Cuál es un juego o actividad que siempre nos acerca más?", "fr": "Quel jeu ou activité nous rapproche toujours ?", "it": "Qual è un gioco o un''attività che ci avvicina sempre?", "ko": "항상 우리를 더 가깝게 만드는 게임이나 활동은 무엇인가요?", "nl": "Wat is een spel of activiteit dat ons altijd dichter bij elkaar brengt?", "zh": "有哪些游戏或活动总能让我们更亲近？"}'),
  ('fun', 3, '{"en": "How do fun and playfulness enrich our lives together?", "es": "¿Cómo enriquecen nuestras vidas juntos la diversión y el juego?", "fr": "Comment l''amusement et la gaieté enrichissent-ils nos vies ensemble ?", "it": "Come arricchiscono le nostre vite insieme il divertimento e la giocosità?", "ko": "즐거움과 장난스러움이 우리의 삶을 어떻게 풍요롭게 하나요?", "nl": "Hoe verrijken plezier en speelsheid ons leven samen?", "zh": "乐趣和顽皮如何丰富我们一起的生活？"}'),
  ('fun', 1, '{"en": "What''s a fun tradition we''ve started that you love?", "es": "¿Cuál es una tradición divertida que hemos comenzado que te encanta?", "fr": "Quelle est une tradition amusante que nous avons lancée et que tu aimes?", "it": "Qual è una tradizione divertente che abbiamo iniziato e che ami?", "ko": "우리가 시작한 재미있는 전통 중 당신이 좋아하는 것은 무엇인가요?", "nl": "Wat is een leuke traditie die we zijn begonnen en die je leuk vindt?", "zh": "我们开始的你喜欢的有趣传统是什么？"}'),
  ('fun', 2, '{"en": "How do you like to surprise each other to keep the fun alive?", "es": "¿Cómo te gusta sorprendernos mutuamente para mantener la diversión viva?", "fr": "Comment aimes-tu nous surprendre mutuellement pour garder le plaisir vivant?", "it": "Come ti piace sorprenderci a vicenda per mantenere vivo il divertimento?", "ko": "어떻게 서로를 놀라게 하여 재미를 계속 유지하나요?", "nl": "Hoe verrassen we elkaar graag om de lol erin te houden?", "zh": "你喜欢如何互相惊喜来保持乐趣？"}'),
  ('fun', 1, '{"en": "What''s an inside joke that never gets old?", "es": "¿Cuál es una broma interna que nunca pasa de moda?", "fr": "Quelle est une blague interne qui ne vieillit jamais?", "it": "Qual è una battuta interna che non invecchia mai?", "ko": "전혀 식지 않는 내부 농담은 무엇인가요?", "nl": "Wat is een inside joke die nooit oud wordt?", "zh": "有什么永不过时的内部笑话吗？"}'),
  ('fun', 2, '{"en": "What''s a fun goal we can set that will make us laugh along the way?", "es": "¿Cuál es un objetivo divertido que podemos establecer y que nos hará reír en el camino?", "fr": "Quel est un objectif amusant que nous pouvons fixer et qui nous fera rire en chemin?", "it": "Qual è un obiettivo divertente che possiamo fissare che ci farà ridere lungo la strada?", "ko": "우리가 목표로 설정하면 즐겁게 웃을 수 있는 재미있는 목표는 무엇인가요?", "nl": "Wat is een leuk doel dat we kunnen stellen dat ons onderweg aan het lachen maakt?", "zh": "我们可以制定什么有趣的目标，让我们在过程中笑声不断？"}'),
  ('fun', 3, '{"en": "What do you think our ability to have fun says about us as a couple?", "es": "¿Qué crees que nuestra capacidad para divertirnos dice sobre nosotros como pareja?", "fr": "Que penses-tu que notre capacité à nous amuser dit de nous en tant que couple?", "it": "Cosa pensi che la nostra capacità di divertirci dica su di noi come coppia?", "ko": "우리의 재미를 느끼는 능력이 커플로서 우리에 대해 무엇을 말한다고 생각하나요?", "nl": "Wat denk je dat ons vermogen om plezier te hebben zegt over ons als koppel?", "zh": "你认为我们的玩乐能力对我们作为一对情侣来说意味着什么？"}'),
  ('fun', 1, '{"en": "What''s your favorite way for us to spend a rainy day at home?", "es": "¿Cuál es tu forma favorita de pasar un día lluvioso en casa?", "fr": "Quelle est ta façon préférée de passer une journée pluvieuse à la maison?", "it": "Qual è il tuo modo preferito di passare una giornata piovosa a casa?", "ko": "비 오는 날 우리가 집에서 보내는 당신이 가장 좋아하는 방법은 무엇인가요?", "nl": "Wat is jouw favoriete manier voor ons om een regenachtige dag thuis door te brengen?", "zh": "雨天在家你最喜欢我们以什么方式度过？"}'),
  ('fun', 2, '{"en": "How do we balance work and relaxation to keep life enjoyable?", "es": "¿Cómo equilibramos el trabajo y la relajación para mantener la vida agradable?", "fr": "Comment équilibrons-nous travail et détente pour garder la vie agréable?", "it": "Come bilanciamo lavoro e relax per mantenere la vita piacevole?", "ko": "삶을 즐겁게 유지하기 위해 일과 휴식을 어떻게 균형 잡나요?", "nl": "Hoe balanceren we werk en ontspanning om het leven leuk te houden?", "zh": "我们如何在工作和放松间保持平衡以保持生活乐趣？"}'),
  ('fun', 3, '{"en": "How does playfulness contribute to the way we resolve issues?", "es": "¿Cómo contribuye la diversión a la forma en que resolvemos problemas?", "fr": "Comment la plaisanterie contribue-t-elle à la façon dont nous résolvons les problèmes?", "it": "In che modo la giocosità contribuisce al modo in cui risolviamo i problemi?", "ko": "어떻게 장난기가 문제 해결에 기여하나요?", "nl": "Hoe draagt speelsheid bij aan de manier waarop we problemen oplossen?", "zh": "玩心如何帮助我们解决问题？"}'),
  ('gratitude', 1, '{"en": "What''s a small thing I did today that made you happy?", "es": "¿Cuál es una pequeña cosa que hice hoy que te hizo feliz?", "fr": "Quelle est une petite chose que j''ai faite aujourd''hui qui t''a rendu heureux?", "it": "Qual è una piccola cosa che ho fatto oggi che ti ha reso felice?", "ko": "오늘 내가 한 작은 일 중 당신을 행복하게 한 건 무엇인가요?", "nl": "Wat is iets kleins dat ik vandaag heb gedaan dat je blij maakte?", "zh": "我今天做了什么小事让你开心？"}'),
  ('gratitude', 1, '{"en": "What''s a quirky trait of mine that brings you joy?", "es": "¿Cuál es una peculiaridad mía que te trae alegría?", "fr": "Quelle est une de mes bizarreries qui te rend joyeux?", "it": "Qual è una mia particolarità che ti porta gioia?", "ko": "내 성격 중 당신에게 기쁨을 주는 특이한 점은 무엇인가요?", "nl": "Wat is een eigenaardige trek van mij die jou vreugde brengt?", "zh": "我有什么古怪的特点能让你开心？"}'),
  ('gratitude', 2, '{"en": "How do you show appreciation when words aren''t enough?", "es": "¿Cómo demuestras aprecio cuando las palabras no son suficientes?", "fr": "Comment montres-tu de la reconnaissance lorsque les mots ne suffisent pas?", "it": "Come mostri apprezzamento quando le parole non bastano?", "ko": "말로 충분치 않을 때 어떻게 감사를 표현하나요?", "nl": "Hoe toon je dankbaarheid als woorden niet genoeg zijn?", "zh": "当言语不够时，你如何表达感激？"}'),
  ('gratitude', 2, '{"en": "What everyday thing about us are you most grateful for?", "es": "¿Qué cosa cotidiana sobre nosotros te hace sentir más agradecido?", "fr": "Quelle chose quotidienne à notre sujet te rend le plus reconnaissant?", "it": "Quale cosa quotidiana su di noi ti rende più grato?", "ko": "우리의 일상 중 당신이 가장 감사하게 느끼는 것은 무엇인가요?", "nl": "Welke alledaagse zaak over ons maakt je het meest dankbaar?", "zh": "关于我们的日常事情中你最感恩的是什么？"}'),
  ('gratitude', 2, '{"en": "How has expressing gratitude improved our relationship?", "es": "¿Cómo ha mejorado nuestra relación el expresar gratitud?", "fr": "Comment exprimer de la gratitude a-t-il amélioré notre relation?", "it": "Come esprimere gratitudine ha migliorato la nostra relazione?", "ko": "감사를 표현하는 것이 우리 관계를 어떻게 개선했나요?", "nl": "Hoe heeft het uiten van dankbaarheid onze relatie verbeterd?", "zh": "表达感激如何改善了我们的关系？"}'),
  ('gratitude', 2, '{"en": "What can I do more of to show my appreciation for you?", "es": "¿Qué puedo hacer más para mostrar mi aprecio por ti?", "fr": "Que puis-je faire de plus pour te montrer mon appréciation?", "it": "Cosa posso fare di più per mostrare il mio apprezzamento per te?", "ko": "당신에게 감사를 더 잘 표현하기 위해 내가 더 할 수 있는 것은 무엇인가요?", "nl": "Wat kan ik meer doen om mijn waardering voor jou te tonen?", "zh": "我可以多做什么来表达我对你的感激？"}'),
  ('gratitude', 3, '{"en": "How do you find gratitude in challenging moments we face?", "es": "¿Cómo encuentras gratitud en los momentos difíciles que enfrentamos?", "fr": "Comment trouves-tu de la gratitude dans les moments difficiles que nous rencontrons?", "it": "Come riesci a trovare gratitudine nei momenti difficili che affrontiamo?", "ko": "우리가 직면하는 어려운 순간들 속에서 어떻게 감사를 찾나요?", "nl": "Hoe vind je dankbaarheid in moeilijke momenten die we tegenkomen?", "zh": "在我们面临的困难时刻中，你如何找到感激？"}'),
  ('gratitude', 1, '{"en": "What''s a small gift or gesture you appreciate getting from me?", "es": "¿Cuál es un pequeño regalo o gesto que aprecias recibir de mí?", "fr": "Quel est un petit cadeau ou geste que tu apprécies recevoir de moi?", "it": "Qual è un piccolo regalo o gesto che apprezzi ricevere da me?", "ko": "내가 당신에게 주는 작은 선물이이나 제스처 중 좋아하는 것은 무엇인가요?", "nl": "Wat is een klein geschenk of gebaar dat je waardeert van mij?", "zh": "有什么小礼物或举动是你珍视我给你的？"}'),
  ('gratitude', 2, '{"en": "What positive impact do you think gratitude has on our lives?", "es": "¿Qué impacto positivo crees que tiene la gratitud en nuestras vidas?", "fr": "Quel impact positif penses-tu que la gratitude a sur nos vies?", "it": "Quale impatto positivo pensi che la gratitudine abbia sulle nostre vite?", "ko": "감사가 우리의 삶에 어떤 긍정적인 영향을 준다고 생각하나요?", "nl": "Welke positieve impact denk je dat dankbaarheid heeft op ons leven?", "zh": "你认为感激对我们的生活有什么积极影响？"}'),
  ('gratitude', 3, '{"en": "What are you most thankful for about our journey together?", "es": "¿Por qué cosa estás más agradecido en nuestro camino juntos?", "fr": "Pour quoi es-tu le plus reconnaissant dans notre parcours ensemble?", "it": "Per cosa sei più grato nel nostro percorso insieme?", "ko": "우리의 여정 중 가장 감사하게 생각하는 것은 무엇인가요?", "nl": "Waar ben je het meest dankbaar voor in onze reis samen?", "zh": "关于我们的共同旅程，你最感激什么？"}'),
  ('gratitude', 1, '{"en": "What memory of us are you most grateful for and why?", "es": "¿Qué recuerdo nuestro es el que más agradeces y por qué?", "fr": "Quel souvenir de nous est celui pour lequel tu es le plus reconnaissant et pourquoi?", "it": "Qual è il ricordo di noi per cui sei più grato e perché?", "ko": "우리의 추억 중 가장 감사하게 생각하는 것은 무엇이며, 왜인가요?", "nl": "Welke herinnering van ons is degene waarvoor je het meest dankbaar bent en waarom?", "zh": "关于我们的记忆中你最感激哪个，为什么？"}'),
  ('gratitude', 2, '{"en": "In what ways do we best express gratitude to each other?", "es": "¿De qué maneras expresamos mejor la gratitud el uno al otro?", "fr": "De quelles manières exprimons-nous le mieux notre gratitude l''un envers l''autre?", "it": "In che modo esprimiamo al meglio la gratitudine l''uno verso l''altro?", "ko": "우리는 서로에게 감사를 가장 잘 표현하는 방법은 무엇인가요?", "nl": "Op welke manieren uiten we het beste onze dankbaarheid naar elkaar?", "zh": "我们以什么方式最好地互相表达感激？"}'),
  ('gratitude', 1, '{"en": "What little everyday action makes you feel most grateful?", "es": "¿Qué pequeño gesto diario te hace sentir más agradecido?", "fr": "Quelle petite action quotidienne te rend le plus reconnaissant?", "it": "Quale piccola azione quotidiana ti rende più grato?", "ko": "어떤 일상적인 작은 행동이 당신을 가장 감사하게 만드나요?", "nl": "Welk klein dagelijks gebaar maakt je het meest dankbaar?", "zh": "哪种日常小行为让你感到最感激？"}'),
  ('gratitude', 3, '{"en": "How does gratitude shape the way we interact with one another?", "es": "¿Cómo da forma la gratitud a la manera en que interactuamos mutuamente?", "fr": "Comment la gratitude façonne-t-elle la façon dont nous interagissons les uns avec les autres?", "it": "Come la gratitudine modella il modo in cui interagiamo l’uno con l’altro?", "ko": "감사가 우리가 서로 상호 작용하는 방식에 어떻게 영향을 주나요?", "nl": "Hoe vormt dankbaarheid de manier waarop we met elkaar omgaan?", "zh": "感激如何塑造我们彼此互动的方式？"}'),
  ('conflict', 1, '{"en": "What''s a constructive way we can cool off during heated moments?", "es": "¿Cuál es una forma constructiva de calmarnos durante momentos acalorados?", "fr": "Quelle est une façon constructive de nous calmer pendant les moments de tension?", "it": "Qual è un modo costruttivo per calmarci durante i momenti caldi?", "ko": "열띤 순간에 우리가 식힐 수 있는 건설적인 방법은 무엇인가요?", "nl": "Wat is een constructieve manier om af te koelen tijdens verhitte momenten?", "zh": "我们在火热时刻冷静下来的建设性方式是什么？"}'),
  ('conflict', 1, '{"en": "What''s a humorous moment we had during a disagreement?", "es": "¿Cuál es un momento humorístico que tuvimos durante un desacuerdo?", "fr": "Quel est un moment humoristique que nous avons eu lors d''un désaccord?", "it": "Qual è un momento divertente che abbiamo vissuto durante un disaccordo?", "ko": "다툼 중에 있었던 재미있는 순간은 무엇인가요?", "nl": "Wat is een humoristisch moment dat we hadden tijdens een meningsverschil?", "zh": "在争执期间我们有哪些幽默时刻？"}'),
  ('conflict', 2, '{"en": "What approach do you find most helpful during our conflicts?", "es": "¿Qué enfoque encuentras más útil durante nuestros conflictos?", "fr": "Quelle approche trouves-tu la plus utile lors de nos conflits?", "it": "Quale approccio trovi più utile durante i nostri conflitti?", "ko": "우리의 갈등 중 가장 도움이 되는 접근 방식은 무엇인가요?", "nl": "Welke aanpak vind je het meest behulpzaam tijdens onze conflicten?", "zh": "在我们的冲突期间，你发现哪种方法最有帮助？"}'),
  ('conflict', 2, '{"en": "How do you feel after a conflict has been resolved between us?", "es": "¿Cómo te sientes después de que un conflicto se ha resuelto entre nosotros?", "fr": "Comment te sens-tu après qu''un conflit a été résolu entre nous?", "it": "Come ti senti dopo che un conflitto è stato risolto tra noi?", "ko": "우리 사이에 갈등이 해결된 후 기분은 어떤가요?", "nl": "Hoe voel je je als een conflict tussen ons is opgelost?", "zh": "在我们之间的冲突解决后，你有什么感觉？"}'),
  ('conflict', 3, '{"en": "What conflict have we faced that you believe has made us closer?", "es": "¿Qué conflicto hemos enfrentado que crees que nos ha acercado más?", "fr": "Quel conflit avons-nous affronté qui, selon toi, nous a rapprochés?", "it": "Quale conflitto abbiamo affrontato che credi ci abbia reso più vicini?", "ko": "우리가 겪은 갈등 중 더 가깝게 만들었다고 생각하는 것은 무엇인가요?", "nl": "Welk conflict hebben we gehad waarvan je denkt dat het ons dichter bij elkaar heeft gebracht?", "zh": "我们面临过的哪个冲突让你认为让我们更加亲近？"}'),
  ('conflict', 2, '{"en": "What''s a conflict resolution strategy that works well for us?", "es": "¿Cuál es una estrategia de resolución de conflictos que funciona bien para nosotros?", "fr": "Quelle est une stratégie de résolution de conflits qui fonctionne bien pour nous?", "it": "Qual è una strategia di risoluzione dei conflitti che funziona bene per noi?", "ko": "우리에게 잘 맞는 갈등 해결 전략은 무엇인가요?", "nl": "Wat is een conflictoplossingsstrategie die goed voor ons werkt?", "zh": "对我们有效的冲突解决策略是什么？"}'),
  ('conflict', 3, '{"en": "How do you think conflict can be a catalyst for growth?", "es": "¿Cómo crees que el conflicto puede ser un catalizador para el crecimiento?", "fr": "Comment penses-tu que le conflit peut être un catalyseur de croissance?", "it": "Come pensi che il conflitto possa essere un catalizzatore per la crescita?", "ko": "갈등이 성장을 위한 촉매제 역할을 할 수 있다고 생각하나요?", "nl": "Hoe denk je dat conflict een katalysator voor groei kan zijn?", "zh": "你认为冲突如何成为成长的催化剂？"}'),
  ('conflict', 2, '{"en": "What''s the best way for me to approach you when tensions are high?", "es": "¿Cuál es la mejor manera de acercarme a ti cuando las tensiones son altas?", "fr": "Quelle est la meilleure façon de t''aborder lorsque les tensions sont élevées?", "it": "Qual è il modo migliore per avvicinarmi a te quando le tensioni sono alte?", "ko": "긴장이 고조될 때 내가 당신에게 다가가는 가장 좋은 방법은 무엇인가요?", "nl": "Wat is de beste manier om naar je toe te komen als de spanningen hoog zijn?", "zh": "紧张时我最好以什么方式接近你？"}'),
  ('conflict', 1, '{"en": "What''s a way we can remind each other of our love during disagreements?", "es": "¿Cuál es una forma en que podemos recordarnos mutuamente nuestro amor durante los desacuerdos?", "fr": "Quelle est une façon de nous rappeler notre amour lors de désaccords ?", "it": "Qual è un modo per ricordarci il nostro amore durante i disaccordi?", "ko": "불일치가 있을 때 서로에게 우리의 사랑을 상기시킬 수 있는 방법은 무엇인가요?", "nl": "Wat is een manier waarop we elkaar tijdens onenigheden aan onze liefde kunnen herinneren?", "zh": "在争执时，我们可以用什么方式提醒彼此我们的爱？"}'),
  ('conflict', 2, '{"en": "How do you approach forgiving each other after an argument?", "es": "¿Cómo se acercan a perdonarse mutuamente después de una discusión?", "fr": "Comment abordez-vous le pardon mutuel après une dispute ?", "it": "Come vi avvicinate al perdono reciproco dopo una discussione?", "ko": "다툼 후에 서로를 용서하는 방식을 어떻게 접근하나요?", "nl": "Hoe pakken jullie het vergeven van elkaar na een ruzie aan?", "zh": "争吵后，你们如何接纳彼此的原谅？"}'),
  ('conflict', 3, '{"en": "How can we transform our conflicts into opportunities for growth?", "es": "¿Cómo podemos transformar nuestros conflictos en oportunidades de crecimiento?", "fr": "Comment pouvons-nous transformer nos conflits en opportunités de croissance ?", "it": "Come possiamo trasformare i nostri conflitti in opportunità di crescita?", "ko": "갈등을 성장의 기회로 어떻게 변환할 수 있을까요?", "nl": "Hoe kunnen we onze conflicten omzetten in groeimogelijkheden?", "zh": "我们如何将冲突转化为成长的机会？"}'),
  ('conflict', 1, '{"en": "What''s a funny misunderstanding we''ve had?", "es": "¿Cuál es un malentendido gracioso que hemos tenido?", "fr": "Quel est un malentendu amusant que nous avons eu ?", "it": "Qual è un malinteso divertente che abbiamo avuto?", "ko": "우리가 겪었던 웃긴 오해는 무엇인가요?", "nl": "Wat is een grappig misverstand dat we hebben gehad?", "zh": "我们曾有过什么有趣的误会？"}'),
  ('conflict', 2, '{"en": "What words or actions help you feel reassured after a conflict?", "es": "¿Qué palabras o acciones te ayudan a sentirte tranquilo después de un conflicto?", "fr": "Quelles paroles ou actions vous aident à vous sentir rassuré après un conflit ?", "it": "Quali parole o azioni ti aiutano a sentirti rassicurato dopo un conflitto?", "ko": "갈등 후에 마음이 놓이게 만드는 말이나 행동은 무엇인가요?", "nl": "Welke woorden of acties helpen je om je gerustgesteld te voelen na een conflict?", "zh": "在冲突后，哪些话或行动帮助你感到安心？"}'),
  ('conflict', 3, '{"en": "What deeper issues have surfaced through our conflicts that need attention?", "es": "¿Qué problemas más profundos han surgido a través de nuestros conflictos que necesitan atención?", "fr": "Quels problèmes plus profonds ont émergé de nos conflits qui nécessitent de l''attention ?", "it": "Quali problemi più profondi sono emersi dai nostri conflitti che necessitano di attenzione?", "ko": "갈등을 통해 드러난 깊은 문제가 무엇이며 주의가 필요한가요?", "nl": "Welke diepere problemen zijn door onze conflicten naar voren gekomen die aandacht nodig hebben?", "zh": "哪些深层次的问题通过我们的冲突浮现出来，需要关注？"}'),
  ('conflict', 1, '{"en": "What makes you feel most supported during a disagreement?", "es": "¿Qué te hace sentir más apoyado durante un desacuerdo?", "fr": "Qu''est-ce qui vous fait vous sentir le plus soutenu lors d''un désaccord ?", "it": "Cosa ti fa sentire più supportato durante un disaccordo?", "ko": "불일치가 있을 때 가장 지지를 받는다고 느끼게 하는 것은 무엇인가요?", "nl": "Wat zorgt ervoor dat je je het meest gesteund voelt tijdens een meningsverschil?", "zh": "在意见不合时，是什么让你感到最大的支持？"}'),
  ('finances', 1, '{"en": "What''s a fun way we can save money together for something special?", "es": "¿Cuál es una forma divertida de ahorrar dinero juntos para algo especial?", "fr": "Quelle est une manière amusante d''économiser de l''argent ensemble pour quelque chose de spécial ?", "it": "Qual è un modo divertente per risparmiare denaro insieme per qualcosa di speciale?", "ko": "특별한 것을 위해 함께 돈을 절약할 수 있는 재미있는 방법은 무엇인가요?", "nl": "Wat is een leuke manier om samen geld te sparen voor iets speciaals?", "zh": "我们可以用什么有趣的方法一起存钱以实现特别的目标？"}'),
  ('finances', 1, '{"en": "What financial goals are you excited to achieve together?", "es": "¿Qué metas financieras estás emocionado de alcanzar juntos?", "fr": "Quels objectifs financiers êtes-vous excité de réaliser ensemble ?", "it": "Quali obiettivi finanziari sei entusiasta di raggiungere insieme?", "ko": "함께 이루고 싶은 재정적 목표는 무엇인가요?", "nl": "Welke financiële doelen ben je enthousiast om samen te bereiken?", "zh": "你期待与我一起完成哪些财务目标？"}'),
  ('finances', 2, '{"en": "How do you handle finances to ensure they align with your values?", "es": "¿Cómo manejas las finanzas para asegurarte de que se alineen con tus valores?", "fr": "Comment gérez-vous les finances pour vous assurer qu''elles sont en accord avec vos valeurs ?", "it": "Come gestisci le finanze per garantire che siano in linea con i tuoi valori?", "ko": "재정 관리를 어떻게 하여 당신의 가치관과 맞도록 하나요?", "nl": "Hoe beheers je de financiën zodat ze in lijn zijn met je waarden?", "zh": "你如何管理财务以确保其与自己的价值观一致？"}'),
  ('finances', 2, '{"en": "What''s an approach we can use to balance spending and saving?", "es": "¿Cuál es un enfoque que podemos usar para equilibrar el gasto y el ahorro?", "fr": "Quelle approche pouvons-nous utiliser pour équilibrer les dépenses et l''épargne ?", "it": "Qual è un approccio che possiamo utilizzare per bilanciare spese e risparmi?", "ko": "지출과 저축의 균형을 맞추기 위한 방법은 무엇인가요?", "nl": "Wat is een aanpak die we kunnen gebruiken om uitgaven en sparen in balans te brengen?", "zh": "我们可以采用什么方法来平衡消费和储蓄？"}'),
  ('finances', 3, '{"en": "How can financial planning strengthen our relationship?", "es": "¿Cómo puede la planificación financiera fortalecer nuestra relación?", "fr": "Comment la planification financière peut-elle renforcer notre relation ?", "it": "Come può la pianificazione finanziaria rafforzare la nostra relazione?", "ko": "재정 계획이 우리의 관계를 어떻게 강화할 수 있을까요?", "nl": "Hoe kan financiële planning onze relatie versterken?", "zh": "财务规划如何加强我们的关系？"}'),
  ('finances', 3, '{"en": "What financial philosophy will guide us to a secure future together?", "es": "¿Qué filosofía financiera nos guiará hacia un futuro seguro juntos?", "fr": "Quelle philosophie financière nous guidera vers un avenir sûr ensemble ?", "it": "Quale filosofia finanziaria ci guiderà verso un futuro sicuro insieme?", "ko": "어떤 재정 철학이 우리를 함께하는 안전한 미래로 인도할까요?", "nl": "Welke financiële filosofie zal ons naar een zekere toekomst samen leiden?", "zh": "什么样的财务哲学将指导我们共同走向安全的未来？"}'),
  ('finances', 2, '{"en": "In what ways can we improve our communication about finances?", "es": "¿De qué maneras podemos mejorar nuestra comunicación sobre finanzas?", "fr": "De quelles manières pouvons-nous améliorer notre communication sur les finances ?", "it": "In che modo possiamo migliorare la nostra comunicazione sulle finanze?", "ko": "재정에 대한 소통을 어떻게 개선할 수 있을까요?", "nl": "Op welke manieren kunnen we onze communicatie over financiën verbeteren?", "zh": "我们可以通过哪些方式改善对财务的沟通？"}'),
  ('finances', 1, '{"en": "What''s your favorite budget-friendly date idea for us?", "es": "¿Cuál es tu idea favorita para una cita económica para nosotros?", "fr": "Quelle est votre idée préférée de rendez-vous économique pour nous ?", "it": "Qual è la tua idea preferita per una serata economica per noi?", "ko": "우리에게 적합한 저렴한 데이트 아이디어는 무엇인가요?", "nl": "Wat is jouw favoriete voordelige date-idee voor ons?", "zh": "你最喜欢哪种经济实惠的约会想法？"}'),
  ('finances', 2, '{"en": "How do finances influence our lifestyle choices together?", "es": "¿Cómo influyen las finanzas en nuestras elecciones de estilo de vida juntos?", "fr": "Comment les finances influencent-elles nos choix de style de vie ensemble ?", "it": "In che modo le finanze influenzano le nostre scelte di stile di vita insieme?", "ko": "재정이 우리가 함께하는 생활 방식 선택에 어떤 영향을 미치나요?", "nl": "Hoe beïnvloeden financiën samen onze lifestylekeuzes?", "zh": "财务如何影响我们一起做出的生活方式选择？"}'),
  ('finances', 1, '{"en": "What''s a financial lesson you''ve learned that benefits us?", "es": "¿Cuál es una lección financiera que has aprendido que nos beneficia?", "fr": "Quelle leçon financière avez-vous apprise qui nous profite ?", "it": "Qual è una lezione finanziaria che hai imparato e che ci avvantaggia?", "ko": "우리를 위한 혜택이 되는 재정 교훈은 무엇인가요?", "nl": "Wat is een financiële les die je hebt geleerd waarvan wij profiteren?", "zh": "你学到的哪些财务经验对我们有益？"}'),
  ('finances', 2, '{"en": "What''s a shared expense you believe brings us joy?", "es": "¿Cuál es un gasto compartido que crees que nos trae alegría?", "fr": "Quelle dépense partagée pensez-vous qui nous apporte de la joie ?", "it": "Qual è una spesa condivisa che credi ci porti gioia?", "ko": "함께하는 비용 중에서 우리에게 기쁨을 준다고 믿는 것은 무엇인가요?", "nl": "Wat is een gezamenlijke uitgave waarvan je denkt dat het ons vreugde brengt?", "zh": "你认为哪项共同开支为我们带来了快乐？"}'),
  ('finances', 3, '{"en": "What financial decisions do you think have impacted our relationship the most?", "es": "¿Qué decisiones financieras crees que han impactado más nuestra relación?", "fr": "Quelles décisions financières pensez-vous ont le plus impacté notre relation ?", "it": "Quali decisioni finanziarie pensi abbiano maggiormente influenzato la nostra relazione?", "ko": "우리 관계에 가장 큰 영향을 미친 재정적 결정은 무엇이라고 생각하나요?", "nl": "Welke financiële beslissingen denk je dat onze relatie het meest hebben beïnvloed?", "zh": "你认为哪些财务决策对我们的关系影响最大？"}'),
  ('finances', 1, '{"en": "How do we celebrate achieving a financial milestone together?", "es": "¿Cómo celebramos haber alcanzado un hito financiero juntos?", "fr": "Comment fêtons-nous l''atteinte d''une étape financière ensemble ?", "it": "Come celebriamo insieme il raggiungimento di un traguardo finanziario?", "ko": "재정적 이정표에 도달했을 때 우리는 어떻게 기념하나요?", "nl": "Hoe vieren we het behalen van een financiële mijlpaal samen?", "zh": "我们如何庆祝一起达成的财务里程碑？"}'),
  ('finances', 2, '{"en": "What''s one finance-related area where you''d like to see us improve?", "es": "¿Cuál es un área relacionada con las finanzas en la que te gustaría que mejoráramos?", "fr": "Quel est un domaine lié aux finances où vous aimeriez nous voir nous améliorer ?", "it": "Qual è un''area legata alla finanza in cui vorresti che migliorassimo?", "ko": "재정 관련 분야 중 우리가 개선했으면 하는 한 가지는 무엇인가요?", "nl": "Wat is een financieel gerelateerd gebied waarin je ons graag zou zien verbeteren?", "zh": "你希望我们在哪个与财务相关的领域得到改善？"}'),
  ('finances', 3, '{"en": "What is a long-term financial goal you believe will transform our future?", "es": "¿Cuál es un objetivo financiero a largo plazo que crees que transformará nuestro futuro?", "fr": "Quel est un objectif financier à long terme que vous croyez transformer notre avenir ?", "it": "Qual è un obiettivo finanziario a lungo termine che credi trasformerà il nostro futuro?", "ko": "우리의 미래를 바꿀 것이라고 믿는 장기 재정 목표는 무엇인가요?", "nl": "Wat is een langetermijn financieel doel waarvan je denkt dat het onze toekomst zal transformeren?", "zh": "你认为哪项长期财务目标将改变我们的未来？"}'),
  ('growth', 1, '{"en": "What''s a skill you admire and would like to develop further?", "es": "¿Cuál es una habilidad que admiras y te gustaría desarrollar más?", "fr": "Quelle compétence admirez-vous et aimeriez-vous développer davantage ?", "it": "Qual è una competenza che ammiri e che vorresti sviluppare ulteriormente?", "ko": "어떤 능력을 존경하며 더 개발하고 싶나요?", "nl": "Wat is een vaardigheid die je bewondert en verder zou willen ontwikkelen?", "zh": "你钦佩并希望继续发展的技能是什么？"}'),
  ('growth', 1, '{"en": "How do you celebrate personal growth achievements?", "es": "¿Cómo celebras los logros de crecimiento personal?", "fr": "Comment célébrez-vous les réalisations de croissance personnelle ?", "it": "Come celebri i traguardi di crescita personale?", "ko": "개인적 성취를 어떻게 축하하나요?", "nl": "Hoe vier je persoonlijke groeiprestaties?", "zh": "你如何庆祝个人成长成就？"}'),
  ('growth', 2, '{"en": "What''s an area of personal growth you''ve focused on recently?", "es": "¿Cuál es un área de crecimiento personal en la que te has enfocado recientemente?", "fr": "Quel est un domaine de croissance personnelle sur lequel vous vous êtes concentré récemment ?", "it": "Qual è un''area di crescita personale su cui ti sei concentrato recentemente?", "ko": "최근에 집중하고 있는 개인 성장 분야는 무엇인가요?", "nl": "Wat is een gebied van persoonlijke groei waar je je onlangs op hebt gefocust?", "zh": "你最近专注于哪方面的个人成长？"}'),
  ('growth', 2, '{"en": "How have you seen us grow as a couple since the beginning?", "es": "¿Cómo nos has visto crecer como pareja desde el principio?", "fr": "Comment nous avez-vous vus grandir en tant que couple depuis le début ?", "it": "Come ci hai visti crescere come coppia dall''inizio?", "ko": "처음부터 우리가 커플로 성장한 모습을 어떻게 보았나요?", "nl": "Hoe heb je ons zien groeien als koppel vanaf het begin?", "zh": "自始至终，你如何看待我们作为情侣的成长？"}'),
  ('growth', 3, '{"en": "How do you think challenges contribute to our personal growth?", "es": "¿Cómo crees que los desafíos contribuyen a nuestro crecimiento personal?", "fr": "Comment pensez-vous que les défis contribuent à notre croissance personnelle ?", "it": "Come pensi che le sfide contribuiscano alla nostra crescita personale?", "ko": "도전이 우리의 개인 성장에 어떻게 기여한다 생각하나요?", "nl": "Hoe denk je dat uitdagingen bijdragen aan onze persoonlijke groei?", "zh": "你认为挑战如何促进我们的个人成长？"}'),
  ('growth', 1, '{"en": "What''s one book or podcast that inspires your personal growth?", "es": "¿Cuál es un libro o podcast que inspira tu crecimiento personal?", "fr": "Quel est un livre ou un podcast qui inspire votre croissance personnelle ?", "it": "Qual è un libro o un podcast che ispira la tua crescita personale?", "ko": "당신의 개인 성장을 고무하는 책이나 팟캐스트는 무엇인가요?", "nl": "Wat is een boek of podcast dat je persoonlijke groei inspireert?", "zh": "哪本书或播客激励了你的个人成长？"}'),
  ('growth', 2, '{"en": "What part of our relationship continues to grow and surprise you?", "es": "¿Qué parte de nuestra relación sigue creciendo y sorprendiéndote?", "fr": "Quelle partie de notre relation continue de croître et de vous surprendre ?", "it": "Quale parte della nostra relazione continua a crescere e sorprenderti?", "ko": "우리 관계의 어떤 부분이 계속 성장하며 당신을 놀라게 하나요?", "nl": "Welk deel van onze relatie blijft groeien en je verrassen?", "zh": "我们关系的哪个部分继续成长并让你感到惊讶？"}'),
  ('growth', 3, '{"en": "How does our relationship challenge you to grow as an individual?", "es": "¿Cómo desafía nuestra relación a crecer como individuo?", "fr": "En quoi notre relation vous pousse-t-elle à grandir en tant qu''individu ?", "it": "In che modo la nostra relazione ti sfida a crescere come individuo?", "ko": "우리의 관계가 당신을 개인적으로 성장하도록 어떻게 도전하나요?", "nl": "Hoe daagt onze relatie je uit om als individu te groeien?", "zh": "我们的关系如何挑战你作为一个个体去成长？"}'),
  ('growth', 1, '{"en": "What''s an experience you believe would help us grow together?", "es": "¿Qué experiencia crees que nos ayudaría a crecer juntos?", "fr": "Quelle expérience pensez-vous qui nous aiderait à grandir ensemble ?", "it": "Qual è un''esperienza che credi ci aiuterà a crescere insieme?", "ko": "함께 성장할 수 있는 경험은 무엇이라고 생각하나요?", "nl": "Welke ervaring denk je dat ons zou helpen samen te groeien?", "zh": "你认为什么样的经历能帮助我们一起成长？"}'),
  ('growth', 2, '{"en": "How do you balance personal growth with relationship growth?", "es": "¿Cómo equilibras el crecimiento personal con el crecimiento de la relación?", "fr": "Comment équilibrez-vous la croissance personnelle et la croissance relationnelle ?", "it": "Come bilanci la crescita personale con quella della relazione?", "ko": "개인 성장과 관계 성장을 어떻게 균형 잡나요?", "nl": "Hoe balanceer je persoonlijke groei met relatiegroei?", "zh": "你如何平衡个人成长与关系成长？"}'),
  ('growth', 3, '{"en": "What''s a lesson our relationship has taught you about personal growth?", "es": "¿Qué lección te ha enseñado nuestra relación sobre el crecimiento personal?", "fr": "Quelle leçon notre relation vous a-t-elle apprise sur la croissance personnelle ?", "it": "Qual è una lezione che la nostra relazione ti ha insegnato sulla crescita personale?", "ko": "우리의 관계는 개인 성장에 대해 어떤 교훈을 주었나요?", "nl": "Welke les heeft onze relatie je geleerd over persoonlijke groei?", "zh": "我们的关系教会了你关于个人成长的什么课题？"}'),
  ('growth', 2, '{"en": "What''s one way you see us supporting each other''s growth currently?", "es": "¿De qué manera ves que nos apoyamos mutuamente en nuestro crecimiento actualmente?", "fr": "Quelle est une manière dont vous nous voyez soutenir mutuellement notre croissance actuellement ?", "it": "Qual è un modo in cui vedi che ci stiamo attualmente supportando a vicenda nella crescita?", "ko": "현재 우리의 성장을 도와주는 방법은 무엇인가요?", "nl": "Op welke manier zie je ons momenteel elkaars groei ondersteunen?", "zh": "你认为我们目前相互支持成长的方式是什么？"}'),
  ('growth', 3, '{"en": "How has our relationship influenced your perspective on life goals?", "es": "¿Cómo ha influido nuestra relación en tu perspectiva sobre las metas de vida?", "fr": "Comment notre relation a-t-elle influencé votre perspective sur les objectifs de vie ?", "it": "Come ha influenzato la nostra relazione la tua prospettiva sugli obiettivi di vita?", "ko": "우리의 관계는 당신의 인생 목표에 대한 관점을 어떻게 영향을 미쳤나요?", "nl": "Hoe heeft onze relatie je kijk op levensdoelen beïnvloed?", "zh": "我们的关系如何影响你对人生目标的看法？"}'),
  ('family', 1, '{"en": "What''s a family tradition you''d love to carry on with us?", "es": "¿Cuál es una tradición familiar que te encantaría continuar con nosotros?", "fr": "Quelle tradition familiale aimeriez-vous continuer avec nous ?", "it": "Qual è una tradizione familiare che ti piacerebbe portare avanti con noi?", "ko": "함께 이어가고 싶은 가족 전통은 무엇인가요?", "nl": "Welke familietraditie zou je graag met ons voortzetten?", "zh": "你希望和我们一起延续什么家庭传统？"}'),
  ('family', 1, '{"en": "How do you like to connect with family when we''re apart?", "es": "¿Cómo te gusta conectarte con la familia cuando estamos separados?", "fr": "Comment aimez-vous vous connecter avec la famille lorsque nous sommes séparés ?", "it": "Come ti piace connetterti con la famiglia quando siamo separati?", "ko": "떨어져 있을 때 가족과 어떻게 소통하길 원하나요?", "nl": "Hoe vind je het fijn om contact te maken met familie als we gescheiden zijn?", "zh": "当我们分开时，你喜欢如何与家人联系？"}'),
  ('family', 1, '{"en": "What''s your favorite family memory as a child?", "es": "¿Cuál es tu recuerdo familiar favorito de cuando eras niño?", "fr": "Quel est votre souvenir de famille préféré en tant qu''enfant ?", "it": "Qual è il tuo ricordo di famiglia preferito da bambino?", "ko": "어린 시절 가장 좋아하는 가족 기억은 무엇인가요?", "nl": "Wat is je favoriete gezinsherinnering uit je kindertijd?", "zh": "你小时候最喜欢的家庭记忆是什么？"}'),
  ('family', 2, '{"en": "How do you think our families have influenced who you are today?", "es": "¿Cómo crees que nuestras familias han influido en quién eres hoy?", "fr": "Comment pensez-vous que nos familles ont influencé qui vous êtes aujourd''hui ?", "it": "Come pensi che le nostre famiglie abbiano influenzato chi sei oggi?", "ko": "우리 가족들이 오늘의 당신에게 어떻게 영향을 미쳤다고 생각하나요?", "nl": "Hoe denk je dat onze families invloed hebben gehad op wie je vandaag bent?", "zh": "你认为我们的家庭如何影响了今天的你？"}'),
  ('family', 2, '{"en": "What is one value you cherish about your family upbringing?", "es": "¿Cuál es un valor que aprecias de tu educación familiar?", "fr": "Quelle est une valeur que vous chérissez concernant votre éducation familiale ?", "it": "Qual è un valore che apprezzi della tua educazione familiare?", "ko": "가족 교육에서 소중히 여기는 가치는 무엇인가요?", "nl": "Wat is een waarde die je koestert uit je familiebesch upbringing?", "zh": "你珍视家庭教养的哪个价值观？"}'),
  ('family', 3, '{"en": "What family expectation do you find most challenging to live up to?", "es": "¿Qué expectativa familiar encuentras más desafiante cumplir?", "fr": "Quelle attente familiale trouvez-vous la plus difficile à respecter ?", "it": "Qual è l''aspettativa familiare che trovi più difficile da soddisfare?", "ko": "가족의 기대 중에 가장 어려운 것은 무엇인가요?", "nl": "Welke familieverwachting vind je het meest uitdagend om aan te voldoen?", "zh": "你觉得最难实现的家庭期望是什么？"}'),
  ('family', 2, '{"en": "How do you envision blending our family traditions?", "es": "¿Cómo imaginas mezclar nuestras tradiciones familiares?", "fr": "Comment envisagez-vous de fusionner nos traditions familiales ?", "it": "Come immagini di amalgamare le nostre tradizioni familiari?", "ko": "우리 가족 전통을 어떻게 융합할 계획인가요?", "nl": "Hoe zie je het samenvoegen van onze familietradities voor je?", "zh": "你如何设想融合我们的家庭传统？"}'),
  ('family', 1, '{"en": "What''s a way we can involve family more in our lives?", "es": "¿De qué manera podemos involucrar más a la familia en nuestras vidas?", "fr": "Quelle est une manière d''impliquer davantage la famille dans nos vies ?", "it": "Qual è un modo in cui possiamo coinvolgere di più la famiglia nelle nostre vite?", "ko": "우리 삶에 가족을 더 많이 참여시킬 수 있는 방법은 무엇인가요?", "nl": "Wat is een manier waarop we familie meer in ons leven kunnen betrekken?", "zh": "我们怎样才能让家庭更多地参与我们的生活？"}'),
  ('family', 3, '{"en": "How does family impact our dynamics as a couple?", "es": "¿Cómo impacta la familia en nuestra dinámica como pareja?", "fr": "Comment la famille impacte-t-elle notre dynamique en tant que couple ?", "it": "Come influisce la famiglia sulla nostra dinamica di coppia?", "ko": "가족이 우리 부부의 관계 역학에 어떻게 영향을 미치나요?", "nl": "Hoe beïnvloedt familie onze dynamiek als koppel?", "zh": "家庭如何影响我们作为夫妻的动态？"}'),
  ('family', 2, '{"en": "In what ways can we create a supportive family environment?", "es": "¿De qué manera podemos crear un entorno familiar de apoyo?", "fr": "De quelles manières pouvons-nous créer un environnement familial de soutien ?", "it": "In che modo possiamo creare un ambiente familiare di supporto?", "ko": "지원적인 가족 환경을 어떻게 만들 수 있을까요?", "nl": "Op welke manieren kunnen we een ondersteunende gezinsomgeving creëren?", "zh": "我们可以通过哪些方式创造一个支持性的家庭环境？"}'),
  ('family', 1, '{"en": "What''s a cherished story about your family you''d like to share?", "es": "¿Cuál es una historia preciada sobre tu familia que te gustaría compartir?", "fr": "Quelle est une histoire précieuse sur votre famille que vous aimeriez partager ?", "it": "Qual è una storia preziosa sulla tua famiglia che ti piacerebbe condividere?", "ko": "공유하고 싶은 가족에 대한 소중한 이야기는 무엇인가요?", "nl": "Wat is een gekoesterd verhaal over je familie dat je graag wilt delen?", "zh": "你想分享一个关于你家庭的珍贵故事吗？"}'),
  ('family', 2, '{"en": "What family tradition might you like us to start with our own family?", "es": "¿Qué tradición familiar te gustaría que empezáramos con nuestra propia familia?", "fr": "Quelle tradition familiale aimeriez-vous que nous commencions avec notre propre famille ?", "it": "Quale tradizione familiare vorresti iniziare con la nostra famiglia?", "ko": "우리 가족과 함께 시작하고 싶은 가족 전통은 무엇인가요?", "nl": "Welke familietraditie zou je willen dat we met ons eigen gezin beginnen?", "zh": "你想和我们的家庭一起开启什么家庭传统？"}'),
  ('family', 3, '{"en": "How do the roles we play in our families shape us personally?", "es": "¿Cómo nos moldean personalmente los roles que desempeñamos en nuestras familias?", "fr": "Comment les rôles que nous jouons dans nos familles nous façonnent-ils personnellement ?", "it": "Come ci plasmano personalmente i ruoli che ricopriamo nelle nostre famiglie?", "ko": "가족에서 맡은 역할이 우리에게 어떻게 영향을 주나요?", "nl": "Hoe vormen de rollen die we binnen onze families vervullen ons persoonlijk?", "zh": "我们在家庭中扮演的角色如何塑造我们自己？"}'),
  ('adventure', 1, '{"en": "What''s a local adventure you''ve always wanted us to go on?", "es": "¿Cuál es una aventura local en la que siempre has querido que fuéramos?", "fr": "Quelle est une aventure locale que vous avez toujours voulu que nous fassions ensemble ?", "it": "Qual è un''avventura locale che hai sempre voluto che intraprendessimo?", "ko": "항상 가보고 싶었던 지역 모험은 무엇인가요?", "nl": "Wat is een lokaal avontuur dat je altijd al met ons hebt willen ondernemen?", "zh": "你一直想和我们一起去进行的本地冒险是什么？"}'),
  ('adventure', 1, '{"en": "What''s your dream destination for an adventure holiday with me?", "es": "¿Cuál es tu destino soñado para unas vacaciones de aventura conmigo?", "fr": "Quelle est votre destination de rêve pour des vacances d''aventure avec moi ?", "it": "Qual è la tua destinazione da sogno per una vacanza avventurosa con me?", "ko": "나와 함께 가보고 싶은 모험 휴가의 꿈의 목적지는 어디인가요?", "nl": "Wat is je droombestemming voor een avontuurlijke vakantie met mij?", "zh": "和我一起冒险度假的梦想目的地是哪里？"}'),
  ('adventure', 2, '{"en": "What''s one daring activity you''d like to try together someday?", "es": "¿Cuál es una actividad atrevida que te gustaría probar juntos algún día?", "fr": "Quelle est une activité audacieuse que vous aimeriez essayer ensemble un jour ?", "it": "Qual è un''attività audace che ti piacerebbe provare insieme un giorno?", "ko": "언젠가 함께 시도해보고 싶은 대담한 활동은 무엇인가요?", "nl": "Wat is een gedurfde activiteit die je ooit samen zou willen proberen?", "zh": "你希望有一天我们一起尝试的大胆活动是什么？"}'),
  ('adventure', 2, '{"en": "How do you define adventure in the context of our relationship?", "es": "¿Cómo defines la aventura en el contexto de nuestra relación?", "fr": "Comment définissez-vous l''aventure dans le contexte de notre relation ?", "it": "Come definisci l''avventura nel contesto della nostra relazione?", "ko": "우리의 관계에서 모험을 어떻게 정의하나요?", "nl": "Hoe definieer je avontuur in de context van onze relatie?", "zh": "在我们的关系中，你如何定义冒险？"}'),
  ('adventure', 3, '{"en": "How do adventures help deepen our connection?", "es": "¿Cómo las aventuras ayudan a profundizar nuestra conexión?", "fr": "Comment les aventures aident-elles à approfondir notre connexion ?", "it": "Come le avventure aiutano ad approfondire la nostra connessione?", "ko": "모험이 우리의 관계를 어떻게 심화시킬 수 있나요?", "nl": "Hoe helpen avonturen onze band te verdiepen?", "zh": "冒险如何帮助加深我们的联系？"}'),
  ('adventure', 2, '{"en": "What''s an unexpected adventure that brought us closer?", "es": "¿Cuál es una aventura inesperada que nos acercó más?", "fr": "Quelle est une aventure inattendue qui nous a rapprochés ?", "it": "Qual è un''avventura inaspettata che ci ha avvicinati?", "ko": "우리를 더 가깝게 만든 예기치 못한 모험은 무엇인가요?", "nl": "Wat is een onverwacht avontuur dat ons dichterbij heeft gebracht?", "zh": "是什么意想不到的冒险让我们更亲近？"}'),
  ('adventure', 1, '{"en": "What''s a fun road trip destination you''d like to surprise me with?", "es": "¿Cuál es un destino de viaje por carretera divertido con el que te gustaría sorprenderme?", "fr": "Quelle est une destination de road trip amusante avec laquelle vous aimeriez me surprendre ?", "it": "Qual è una destinazione di viaggio su strada divertente con cui ti piacerebbe sorprendermi?", "ko": "나를 놀라게 할 재미있는 자동차 여행 목적지는 어디인가요?", "nl": "Wat is een leuke roadtripbestemming waarmee je me wilt verrassen?", "zh": "你想用哪个有趣的公路旅行目的地给我一个惊喜？"}'),
  ('adventure', 3, '{"en": "How does spontaneity influence our life''s adventures?", "es": "¿Cómo influye la espontaneidad en las aventuras de nuestra vida?", "fr": "Comment la spontanéité influence-t-elle les aventures de notre vie ?", "it": "Come influisce la spontaneità nelle avventure della nostra vita?", "ko": "즉흥성이 우리의 인생 모험에 어떻게 영향을 미치나요?", "nl": "Hoe beïnvloedt spontaniteit de avonturen in ons leven?", "zh": "自发性如何影响我们生活中的冒险经历？"}'),
  ('adventure', 2, '{"en": "What''s an adventure that pushed you out of your comfort zone with me?", "es": "¿Cuál es una aventura que te sacó de tu zona de confort conmigo?", "fr": "Quelle est une aventure qui vous a poussé hors de votre zone de confort avec moi ?", "it": "Qual è un''avventura che ti ha spinto fuori dalla tua zona di comfort con me?", "ko": "나와 함께 당신의 안락 지대를 벗어나게 만든 모험은 무엇인가요?", "nl": "Wat is een avontuur dat je met mij uit je comfortzone heeft geduwd?", "zh": "有什么冒险让你和我一起走出舒适区？"}'),
  ('adventure', 1, '{"en": "What''s a simple adventure we can have on a weekend?", "es": "¿Cuál es una aventura simple que podemos tener un fin de semana?", "fr": "Quelle est une aventure simple que nous pouvons avoir un week-end ?", "it": "Qual è una semplice avventura che possiamo fare in un fine settimana?", "ko": "주말에 할 수 있는 간단한 모험은 무엇인가요?", "nl": "Wat is een eenvoudig avontuur dat we in een weekend kunnen hebben?", "zh": "我们可以在周末进行的简单冒险是什么？"}'),
  ('adventure', 2, '{"en": "How do adventures fulfill our desire for exploration together?", "es": "¿Cómo satisfacen las aventuras nuestro deseo de exploración juntos?", "fr": "Comment les aventures comblent-elles notre désir d''exploration ensemble ?", "it": "Come le avventure soddisfano il nostro desiderio di esplorazione insieme?", "ko": "모험이 우리의 탐험 욕구를 어떻게 충족시키나요?", "nl": "Hoe vervullen avonturen onze gezamenlijke verlangen naar ontdekken?", "zh": "冒险如何满足我们一起探索的愿望？"}'),
  ('adventure', 3, '{"en": "How do you incorporate a sense of adventure in everyday life?", "es": "¿Cómo incorporas un sentido de aventura en la vida cotidiana?", "fr": "Comment intégrez-vous un sentiment d''aventure dans la vie quotidienne ?", "it": "Come incorpori un senso di avventura nella vita quotidiana?", "ko": "일상 생활에 모험의 감각을 어떻게 통합하나요?", "nl": "Hoe integreer je een gevoel van avontuur in het dagelijks leven?", "zh": "你如何在日常生活中融入冒险感？"}'),
  ('adventure', 1, '{"en": "What''s a spontaneous trip you''ve always wanted us to take?", "es": "¿Qué viaje espontáneo siempre has querido que hagamos?", "fr": "Quel voyage spontané as-tu toujours voulu que nous fassions ?", "it": "Qual è un viaggio spontaneo che hai sempre voluto che facessimo?", "ko": "함께 떠나고 싶었던 즉흥 여행이 뭐야?", "nl": "Wat is een spontane reis die je altijd al met ons wilde maken?", "zh": "你一直想要我们去的自发旅行是什么？"}'),
  ('adventure', 2, '{"en": "What type of adventures excite you the most with me by your side?", "es": "¿Qué tipo de aventuras te emocionan más conmigo a tu lado?", "fr": "Quel type d''aventures t''excite le plus avec moi à tes côtés ?", "it": "Che tipo di avventure ti eccitano di più con me al tuo fianco?", "ko": "내가 옆에 있을 때 어떤 모험이 가장 신나?", "nl": "Welk soort avonturen vind je het leukst met mij aan je zijde?", "zh": "有什么样的冒险让我陪在你身边让你最兴奋？"}'),
  ('communication', 1, '{"en": "What''s something you find easy to talk to me about?", "es": "¿Sobre qué te resulta fácil hablar conmigo?", "fr": "De quoi trouves-tu facile de me parler ?", "it": "Cosa trovi facile da dire a me?", "ko": "나에게 쉽게 말할 수 있는 것이 무엇인가요?", "nl": "Waar vind je het gemakkelijk over te praten met mij?", "zh": "有什么事情你觉得很容易和我谈论？"}'),
  ('communication', 1, '{"en": "How do you prefer to be comforted during a tough day?", "es": "¿Cómo prefieres ser consolado durante un día difícil?", "fr": "Comment préfères-tu être réconforté lors d''une journée difficile ?", "it": "Come preferisci essere confortato durante una giornata difficile?", "ko": "힘든 날에는 어떻게 위로받고 싶어?", "nl": "Hoe word je het liefst getroost op een zware dag?", "zh": "在艰难的一天，你更喜欢怎样被安慰？"}'),
  ('communication', 2, '{"en": "What''s a meaningful conversation we''ve had that you often think about?", "es": "¿Cuál es una conversación significativa que hemos tenido y que a menudo recuerdas?", "fr": "Quelle est une conversation significative que nous avons eue et à laquelle tu penses souvent ?", "it": "Qual è una conversazione significativa che abbiamo avuto e che ricordi spesso?", "ko": "자주 생각나는 의미 있는 대화가 뭐야?", "nl": "Wat is een zinvol gesprek dat we hebben gehad en waar je vaak aan denkt?", "zh": "我们曾有的一次有意义的谈话是什么，你经常想起？"}'),
  ('communication', 2, '{"en": "How can we improve our non-verbal communication with each other?", "es": "¿Cómo podemos mejorar nuestra comunicación no verbal entre nosotros?", "fr": "Comment pouvons-nous améliorer notre communication non verbale ?", "it": "Come possiamo migliorare la nostra comunicazione non verbale?", "ko": "비언어적 의사소통을 어떻게 향상시킬 수 있을까?", "nl": "Hoe kunnen we onze non-verbale communicatie met elkaar verbeteren?", "zh": "我们如何改善彼此之间的非语言交流？"}'),
  ('communication', 3, '{"en": "In what ways have our dialogues helped you grow emotionally?", "es": "¿De qué manera nuestros diálogos te han ayudado a crecer emocionalmente?", "fr": "De quelles manières nos dialogues t''ont-ils aidé à grandir émotionnellement ?", "it": "In che modo i nostri dialoghi ti hanno aiutato a crescere emotivamente?", "ko": "우리의 대화가 어떻게 감정적으로 성장하게 도움이 되었나요?", "nl": "Op welke manieren hebben onze dialogen je emotioneel helpen groeien?", "zh": "我们的对话如何帮助你在情感上成长？"}'),
  ('communication', 1, '{"en": "What’s your favorite way to say ''I love you'' without words?", "es": "¿Cuál es tu forma favorita de decir ''Te quiero'' sin palabras?", "fr": "Quelle est ta façon préférée de dire ''Je t''aime'' sans mots ?", "it": "Qual è il tuo modo preferito di dire ''Ti amo'' senza parole?", "ko": "말 없이 ''사랑해''를 표현하는 네가 가장 좋아하는 방법은?", "nl": "Wat is jouw favoriete manier om ''Ik hou van je'' te zeggen zonder woorden?", "zh": "你最喜欢用什么方式在不说话的情况下表达“我爱你”？"}'),
  ('communication', 2, '{"en": "What’s a topic you’d like to learn more about together?", "es": "¿Cuál es un tema sobre el que te gustaría aprender más juntos?", "fr": "Quel est un sujet sur lequel tu aimerais en apprendre davantage ensemble ?", "it": "Qual è un argomento su cui vorresti sapere di più insieme?", "ko": "함께 더 알고 싶은 주제는 뭐야?", "nl": "Wat is een onderwerp waar je samen meer over wilt leren?", "zh": "有什么话题你想和我一起深入了解？"}'),
  ('communication', 3, '{"en": "How do our conversations impact your personal beliefs?", "es": "¿Cómo impactan nuestras conversaciones en tus creencias personales?", "fr": "Comment nos conversations influencent-elles tes croyances personnelles ?", "it": "Come influenzano le nostre conversazioni le tue convinzioni personali?", "ko": "우리의 대화가 당신의 개인적인 믿음에 어떤 영향을 미치나요?", "nl": "Hoe beïnvloeden onze gesprekken je persoonlijke overtuigingen?", "zh": "我们的对话如何影响你的个人信仰？"}'),
  ('communication', 1, '{"en": "What''s a gesture you appreciate when having deep conversations?", "es": "¿Cuál es un gesto que aprecias al tener conversaciones profundas?", "fr": "Quel est un geste que tu apprécies lors de conversations profondes ?", "it": "Qual è un gesto che apprezzi durante le conversazioni profonde?", "ko": "깊은 대화를 할 때 고마운 제스처가 뭐야?", "nl": "Wat is een gebaar dat je waardeert bij het voeren van diepe gesprekken?", "zh": "在进行深入对话时，你欣赏什么样的举动？"}'),
  ('communication', 2, '{"en": "How has our communication style evolved since we first met?", "es": "¿Cómo ha evolucionado nuestro estilo de comunicación desde que nos conocimos?", "fr": "Comment notre style de communication a-t-il évolué depuis notre première rencontre ?", "it": "Come si è evoluto il nostro stile di comunicazione da quando ci siamo conosciuti?", "ko": "처음 만났을 때부터 우리의 의사소통 방식은 어떻게 변했나요?", "nl": "Hoe is onze communicatiestijl geëvolueerd sinds we elkaar ontmoetten?", "zh": "自从我们第一次见面以来，我们的沟通方式发生了怎样的变化？"}'),
  ('communication', 1, '{"en": "What’s a gentle way we can remind each other to listen more?", "es": "¿Cuál es una forma gentil de recordarnos mutuamente que escuchemos más?", "fr": "Quelle est une manière douce de nous rappeler mutuellement d''écouter plus ?", "it": "Qual è un modo gentile per ricordarci di ascoltare di più?", "ko": "더 많이 듣도록 서로에게 상기시킬 수 있는 부드러운 방법은 무엇인가요?", "nl": "Wat is een zachte manier om elkaar eraan te herinneren meer te luisteren?", "zh": "有什么温柔的方式可以提醒我们彼此多听？"}'),
  ('communication', 3, '{"en": "How can we create a safe space for expressing our vulnerable feelings?", "es": "¿Cómo podemos crear un espacio seguro para expresar nuestros sentimientos vulnerables?", "fr": "Comment pouvons-nous créer un espace sûr pour exprimer nos sentiments vulnérables ?", "it": "Come possiamo creare uno spazio sicuro per esprimere i nostri sentimenti vulnerabili?", "ko": "우리의 마음을 드러낼 안전한 공간을 어떻게 만들 수 있을까?", "nl": "Hoe kunnen we een veilige ruimte creëren om onze kwetsbare gevoelens te uiten?", "zh": "我们如何创造一个安全的空间来表达我们的脆弱感受？"}'),
  ('communication', 2, '{"en": "What do you consider the most important aspect of active listening?", "es": "¿Qué consideras el aspecto más importante de la escucha activa?", "fr": "Quel est à ton avis l''aspect le plus important de l''écoute active ?", "it": "Qual è l''aspetto più importante dell''ascolto attivo secondo te?", "ko": "능동적 경청의 가장 중요한 측면은 무엇이라고 생각하나요?", "nl": "Wat beschouw jij als het belangrijkste aspect van actief luisteren?", "zh": "你认为积极倾听中最重要的方面是什么？"}'),
  ('communication', 1, '{"en": "What''s a phrase that instantly makes you smile?", "es": "¿Cuál es una frase que instantáneamente te hace sonreír?", "fr": "Quelle est une phrase qui te fait instantanément sourire ?", "it": "Qual è una frase che ti fa sorridere all''istante?", "ko": "즉시 웃게 만드는 문구가 뭐야?", "nl": "Wat is een zin die je direct aan het lachen maakt?", "zh": "有什么短语能立刻让你微笑？"}'),
  ('communication', 2, '{"en": "How do you perceive our communication affecting our connection?", "es": "¿Cómo percibes que nuestra comunicación afecta nuestra conexión?", "fr": "Comment perçois-tu que notre communication affecte notre connexion ?", "it": "Come percepisci che la nostra comunicazione influenzi la nostra connessione?", "ko": "우리의 소통이 연결에 어떻게 영향을 미친다고 생각하나요?", "nl": "Hoe zie je dat onze communicatie onze verbinding beïnvloedt?", "zh": "你认为我们的沟通如何影响我们的关系？"}'),
  ('communication', 3, '{"en": "What values or principles influence the way you communicate with me?", "es": "¿Qué valores o principios influyen en la forma en que te comunicas conmigo?", "fr": "Quelles valeurs ou principes influencent la manière dont tu communiques avec moi ?", "it": "Quali valori o principi influenzano il modo in cui comunichi con me?", "ko": "어떤 가치나 원칙이 나와의 의사소통에 영향을 미치나요?", "nl": "Welke waarden of principes beïnvloeden de manier waarop je met mij communiceert?", "zh": "哪些价值观或原则影响你和我沟通的方式？"}'),
  ('communication', 1, '{"en": "What''s a song lyric that reminds you of us?", "es": "¿Cuál es una letra de canción que te recuerda a nosotros?", "fr": "Quelle est une parole de chanson qui te rappelle nous ?", "it": "Qual è un testo di canzone che ti ricorda di noi?", "ko": "우리 생각이 나는 노래 가사가 뭐야?", "nl": "Wat is een songtekst die je aan ons doet denken?", "zh": "有什么歌词让你想起我们？"}'),
  ('intimacy', 1, '{"en": "What''s a simple touch or gesture that always soothes you?", "es": "¿Cuál es un toque o gesto simple que siempre te calma?", "fr": "Quel est un toucher ou un geste simple qui t''apaise toujours ?", "it": "Qual è un semplice tocco o gesto che ti calma sempre?", "ko": "늘 마음을 녹여주는 간단한 터치나 제스처가 뭐야?", "nl": "Wat is een eenvoudig gebaar of aanraking dat je altijd kalmeert?", "zh": "有什么简单的触摸或手势总是能让你感到安慰？"}'),
  ('intimacy', 2, '{"en": "How do you think our understanding of intimacy has grown over time?", "es": "¿Cómo crees que ha crecido nuestra comprensión de la intimidad con el tiempo?", "fr": "Comment pense-tu que notre compréhension de l''intimité a évolué avec le temps ?", "it": "Come pensi che la nostra comprensione dell''intimità sia cresciuta nel tempo?", "ko": "시간이 지나면서 우리의 친밀감 이해가 어떻게 발전해 왔다고 생각하나요?", "nl": "Hoe denk je dat ons begrip van intimiteit in de loop van de tijd is gegroeid?", "zh": "你认为随着时间的推移，我们对亲密关系的理解如何增长？"}'),
  ('intimacy', 1, '{"en": "What''s a special memory of closeness that we share?", "es": "¿Cuál es un recuerdo especial de cercanía que compartimos?", "fr": "Quel est un souvenir spécial de proximité que nous partageons ?", "it": "Qual è un ricordo speciale di vicinanza che condividiamo?", "ko": "공유한 특별한 친밀감의 기억은 무엇인가요?", "nl": "Wat is een speciale herinnering van nabijheid die we delen?", "zh": "我们分享的贴近感的特别记忆是什么？"}'),
  ('intimacy', 3, '{"en": "How do you define vulnerability in our intimate moments?", "es": "¿Cómo defines la vulnerabilidad en nuestros momentos íntimos?", "fr": "Comment définis-tu la vulnérabilité dans nos moments intimes ?", "it": "Come definisci la vulnerabilità nei nostri momenti intimi?", "ko": "우리의 친밀한 순간에서 취약성을 어떻게 정의하나요?", "nl": "Hoe definieer je kwetsbaarheid in onze intieme momenten?", "zh": "你如何定义我们亲密时刻中的脆弱性？"}'),
  ('intimacy', 2, '{"en": "What’s an intimate experience that strengthened our bond?", "es": "¿Cuál es una experiencia íntima que fortaleció nuestro vínculo?", "fr": "Quelle est une expérience intime qui a renforcé notre lien ?", "it": "Qual è un''esperienza intima che ha rafforzato il nostro legame?", "ko": "우리의 유대를 강화시킨 친밀한 경험이 뭐야?", "nl": "Wat is een intieme ervaring die onze band heeft versterkt?", "zh": "有什么亲密的体验加强了我们的关系？"}'),
  ('intimacy', 1, '{"en": "What''s a small act of kindness that makes you feel cherished?", "es": "¿Cuál es un pequeño acto de bondad que te hace sentir querido?", "fr": "Quel est un petit acte de gentillesse qui te fait sentir chéri ?", "it": "Qual è un piccolo atto di gentilezza che ti fa sentire apprezzato?", "ko": "소중하다고 느끼게 해주는 작은 친절 행위는 무엇인가요?", "nl": "Wat is een klein gebaar van vriendelijkheid waardoor je je gekoesterd voelt?", "zh": "有什么小小的善意让你感到被珍爱？"}'),
  ('intimacy', 2, '{"en": "How can fostering intimacy contribute to our overall happiness?", "es": "¿Cómo puede fomentar la intimidad contribuir a nuestra felicidad general?", "fr": "Comment favoriser l''intimité peut-il contribuer à notre bonheur global ?", "it": "In che modo coltivare l''intimità può contribuire alla nostra felicità generale?", "ko": "친밀감을 키우는 것이 전체적인 행복에 어떻게 기여할 수 있을까요?", "nl": "Hoe kan het bevorderen van intimiteit bijdragen aan ons algehele geluk?", "zh": "培养亲密关系如何助于我们的整体幸福？"}'),
  ('intimacy', 3, '{"en": "What does emotional intimacy mean to you and how do we nurture it?", "es": "¿Qué significa la intimidad emocional para ti y cómo la cultivamos?", "fr": "Que signifie l''intimité émotionnelle pour toi et comment la cultivons-nous ?", "it": "Cosa significa per te l''intimità emotiva e come la coltiviamo?", "ko": "감정적 친밀감이 당신에게 어떤 의미가 있으며, 어떻게 이를 키워 나갈까요?", "nl": "Wat betekent emotionele intimiteit voor jou en hoe koesteren we het?", "zh": "情感亲密对你意味着什么，我们如何培养它？"}'),
  ('intimacy', 2, '{"en": "When was a time you felt deeply connected with me emotionally?", "es": "¿Cuándo fue un momento en el que te sentiste profundamente conectado conmigo emocionalmente?", "fr": "Quand as-tu ressenti une connexion émotionnelle profonde avec moi ?", "it": "Quando è stata una volta in cui ti sei sentito profondamente connesso con me emotivamente?", "ko": "감정적으로 깊이 연결되었다고 느꼈던 때는 언제였나요?", "nl": "Wanneer was er een moment dat je je emotioneel diep verbonden voelde met mij?", "zh": "什么时候你感觉与我有深刻的情感连接？"}'),
  ('intimacy', 1, '{"en": "What''s one word you would use to describe our intimate times together?", "es": "¿Cuál es una palabra que usarías para describir nuestros momentos íntimos juntos?", "fr": "Quel est un mot que tu utiliserais pour décrire nos moments intimes ensemble ?", "it": "Qual è una parola che useresti per descrivere i nostri momenti intimi insieme?", "ko": "우리의 친밀한 순간을 설명하는 단어는 무엇인가요?", "nl": "Welk woord zou je gebruiken om onze intieme momenten samen te beschrijven?", "zh": "用一个词来形容我们在一起的亲密时光是什么？"}'),
  ('intimacy', 3, '{"en": "How do our intimate moments reflect our true selves?", "es": "¿Cómo reflejan nuestros momentos íntimos nuestros verdaderos yo?", "fr": "Comment nos moments intimes reflètent-ils notre véritable moi ?", "it": "Come riflettono i nostri momenti intimi il nostro vero io?", "ko": "우리의 친밀한 순간이 어떻게 우리의 진정한 자아를 반영하나요?", "nl": "Hoe weerspiegelen onze intieme momenten ons ware zelf?", "zh": "我们的亲密时刻如何反映我们的真实自我？"}'),
  ('intimacy', 2, '{"en": "What role does trust play in our intimate relationship?", "es": "¿Qué papel juega la confianza en nuestra relación íntima?", "fr": "Quel rôle joue la confiance dans notre relation intime ?", "it": "Quale ruolo ha la fiducia nella nostra relazione intima?", "ko": "우리의 친밀한 관계에서 신뢰는 어떤 역할을 하나요?", "nl": "Welke rol speelt vertrouwen in onze intieme relatie?", "zh": "信任在我们的亲密关系中起什么作用？"}'),
  ('intimacy', 1, '{"en": "What''s your favorite way to start a conversation about intimacy?", "es": "¿Cuál es tu forma favorita de iniciar una conversación sobre la intimidad?", "fr": "Quelle est votre façon préférée de commencer une conversation sur l''intimité ?", "it": "Qual è il tuo modo preferito per iniziare una conversazione sull''intimità?", "ko": "친밀감에 대한 대화를 시작하는 당신의 선호 방법은 무엇인가요?", "nl": "Wat is je favoriete manier om een gesprek over intimiteit te beginnen?", "zh": "你开始关于亲密话题对话的最喜欢的方法是什么？"}'),
  ('intimacy', 2, '{"en": "How do we balance independence while maintaining closeness?", "es": "¿Cómo equilibramos la independencia mientras mantenemos la cercanía?", "fr": "Comment équilibrons-nous indépendance et proximité ?", "it": "Come possiamo bilanciare l''indipendenza mantenendo la vicinanza?", "ko": "가까움을 유지하면서 독립성을 어떻게 균형 잡나요?", "nl": "Hoe behouden we onafhankelijkheid terwijl we dicht bij elkaar blijven?", "zh": "我们如何平衡独立性同时保持亲密？"}'),
  ('intimacy', 1, '{"en": "What''s a song that sets the mood for intimate moments?", "es": "¿Cuál es una canción que crea ambiente para momentos íntimos?", "fr": "Quelle est une chanson qui met l''ambiance pour des moments intimes ?", "it": "Qual è una canzone che crea l''atmosfera giusta per momenti intimi?", "ko": "친밀한 순간에 분위기를 돋우는 노래는 무엇인가요?", "nl": "Wat is een liedje dat de sfeer voor intieme momenten bepaalt?", "zh": "有哪些歌曲为亲密时刻设定了气氛？"}'),
  ('dreams', 1, '{"en": "What''s one dream you have for our future adventures together?", "es": "¿Cuál es un sueño que tienes para nuestras futuras aventuras juntos?", "fr": "Quel est un rêve que vous avez pour nos futures aventures ensemble ?", "it": "Qual è un sogno che hai per le nostre future avventure insieme?", "ko": "우리의 미래 모험에 대해 가지고 있는 꿈은 무엇인가요?", "nl": "Wat is een droom die je hebt voor onze toekomstige avonturen samen?", "zh": "你对我们未来的冒险有什么梦想？"}'),
  ('dreams', 2, '{"en": "How does envisioning our future inspire you?", "es": "¿Cómo te inspira imaginar nuestro futuro?", "fr": "Comment imaginer notre avenir vous inspire-t-il ?", "it": "In che modo immaginare il nostro futuro ti ispira?", "ko": "우리의 미래를 상상하는 것이 어떻게 당신에게 영감을 주나요?", "nl": "Hoe inspireert het visualiseren van onze toekomst jou?", "zh": "想象我们的未来如何激励你？"}'),
  ('dreams', 1, '{"en": "What''s a dream destination you''ve always wanted us to explore?", "es": "¿Cuál es un destino de ensueño que siempre has querido que exploremos?", "fr": "Quelle est une destination de rêve que vous avez toujours voulu que nous explorions ?", "it": "Qual è una destinazione da sogno che hai sempre voluto che esplorassimo?", "ko": "당신이 항상 우리가 탐험하고 싶었던 꿈의 목적지는 어디인가요?", "nl": "Wat is een droomlocatie die je altijd al met ons wilde ontdekken?", "zh": "你一直想我们去探索的梦想目的地是什么？"}'),
  ('dreams', 3, '{"en": "How do our dreams reflect our deepest desires and aspirations?", "es": "¿Cómo reflejan nuestros sueños nuestros deseos y aspiraciones más profundos?", "fr": "Comment nos rêves reflètent-ils nos désirs et aspirations les plus profonds ?", "it": "Come riflettono i nostri sogni i nostri desideri e aspirazioni più profondi?", "ko": "우리의 꿈들이 우리의 가장 깊은 욕망과 포부를 어떻게 반영하나요?", "nl": "Hoe weerspiegelen onze dromen onze diepste verlangens en ambities?", "zh": "我们的梦想如何反映我们内心深处的渴望和抱负？"}'),
  ('dreams', 2, '{"en": "What support do you need from me to pursue your dreams?", "es": "¿Qué apoyo necesitas de mí para perseguir tus sueños?", "fr": "Quel soutien avez-vous besoin de ma part pour poursuivre vos rêves ?", "it": "Di quale supporto hai bisogno da parte mia per perseguire i tuoi sogni?", "ko": "당신의 꿈을 추구할 때 내가 제공하는 지원이 무엇인가요?", "nl": "Welke ondersteuning heb je van mij nodig om je dromen na te jagen?", "zh": "你在追求梦想时需要我提供什么支持？"}'),
  ('dreams', 1, '{"en": "What''s a small dream you would like to achieve this year?", "es": "¿Cuál es un pequeño sueño que te gustaría alcanzar este año?", "fr": "Quel est un petit rêve que vous aimeriez réaliser cette année ?", "it": "Qual è un piccolo sogno che vorresti realizzare quest''anno?", "ko": "올해 달성하고 싶은 작은 꿈은 무엇인가요?", "nl": "Wat is een kleine droom die je dit jaar zou willen bereiken?", "zh": "今年你想实现的一个小梦想是什么？"}'),
  ('dreams', 2, '{"en": "How do you imagine celebrating a fulfilled dream with me?", "es": "¿Cómo imaginas celebrar un sueño cumplido conmigo?", "fr": "Comment imaginez-vous célébrer un rêve réalisé avec moi ?", "it": "Come immagini di festeggiare un sogno realizzato con me?", "ko": "나와 함께 꿈을 이룬 것을 어떻게 축하할 것인가요?", "nl": "Hoe stel je je voor een vervulde droom met mij te vieren?", "zh": "你想象如何和我一起庆祝一个实现的梦想？"}'),
  ('dreams', 3, '{"en": "In what ways can our shared dreams strengthen our relationship?", "es": "¿De qué maneras pueden nuestros sueños compartidos fortalecer nuestra relación?", "fr": "De quelles manières nos rêves partagés peuvent-ils renforcer notre relation ?", "it": "In che modo i nostri sogni condivisi possono rafforzare la nostra relazione?", "ko": "우리의 공유된 꿈들이 우리의 관계를 어떻게 강화할 수 있나요?", "nl": "Op welke manieren kunnen onze gedeelde dromen onze relatie versterken?", "zh": "我们的共同梦想如何加强我们的关系？"}'),
  ('dreams', 2, '{"en": "What dream of yours could we start working on together right now?", "es": "¿Qué sueño tuyo podríamos empezar a trabajar juntos ahora mismo?", "fr": "Quel rêve à vous pourrions-nous commencer à travailler ensemble dès maintenant ?", "it": "Su quale tuo sogno potremmo iniziare a lavorare insieme proprio adesso?", "ko": "당신의 어떤 꿈을 지금 당장 함께 시작할 수 있을까요?", "nl": "Aan welke droom van jou kunnen we samen werken, juist nu?", "zh": "我们可以马上一起开始实现你什么梦想？"}'),
  ('dreams', 1, '{"en": "What''s a dream that makes you feel truly alive?", "es": "¿Cuál es un sueño que te hace sentir verdaderamente vivo?", "fr": "Quel est un rêve qui vous fait vous sentir vraiment vivant ?", "it": "Qual è un sogno che ti fa sentire veramente vivo?", "ko": "진정으로 살아있다고 느끼게 하는 꿈은 무엇인가요?", "nl": "Wat is een droom die je echt levend doet voelen?", "zh": "让你觉得真正活着的梦想是什么？"}'),
  ('dreams', 3, '{"en": "How do you feel your past influences your current dreams?", "es": "¿Cómo sientes que tu pasado influye en tus sueños actuales?", "fr": "Comment sentez-vous que votre passé influence vos rêves actuels ?", "it": "Come senti che il tuo passato influenza i tuoi sogni attuali?", "ko": "과거가 현재의 꿈에 어떻게 영향을 미친다고 느끼나요?", "nl": "Hoe denk je dat je verleden je huidige dromen beïnvloedt?", "zh": "你感觉过去如何影响你现在的梦想？"}'),
  ('dreams', 2, '{"en": "What fears do you have about pursuing your dreams, and how can I help?", "es": "¿Qué temores tienes acerca de perseguir tus sueños, y cómo puedo ayudar?", "fr": "Quelles sont vos peurs concernant la poursuite de vos rêves, et comment puis-je vous aider ?", "it": "Quali paure hai riguardo al perseguimento dei tuoi sogni e come posso aiutarti?", "ko": "당신의 꿈을 추구하는 것에 대한 두려움은 무엇이며, 어떻게 도와드릴까요?", "nl": "Welke angsten heb je over het nastreven van je dromen, en hoe kan ik helpen?", "zh": "你在追求梦想时有哪些恐惧，我该如何帮助？"}'),
  ('dreams', 1, '{"en": "What''s a dream from childhood you still hold dear?", "es": "¿Cuál es un sueño de la infancia que aún aprecias?", "fr": "Quel est un rêve d''enfance que vous chérissez encore ?", "it": "Qual è un sogno dell''infanzia che ancora conservi?", "ko": "아직도 소중히 생각하는 어릴 적 꿈은 무엇인가요?", "nl": "Wat is een droom uit de kindertijd die je nog steeds koestert?", "zh": "你还珍视的一个童年梦想是什么？"}'),
  ('dreams', 3, '{"en": "In what ways do our dreams align, and how can they guide our journey?", "es": "¿De qué maneras se alinean nuestros sueños y cómo pueden guiar nuestro camino?", "fr": "De quelles façons nos rêves s''alignent-ils et comment peuvent-ils guider notre voyage ?", "it": "In che modo i nostri sogni si allineano e come possono guidare il nostro viaggio?", "ko": "우리의 꿈이 어떻게 일치하고 어떻게 우리의 여정을 안내할 수 있을까요?", "nl": "Op welke manieren overlappen onze dromen, en hoe kunnen ze ons pad begeleiden?", "zh": "我们的梦想在何种方式上一致，它们如何引导我们的旅程？"}'),
  ('communication', 1, '{"en": "What''s something funny I''ve said that you still remember?", "es": "¿Cuál es algo gracioso que he dicho que todavía recuerdas?", "fr": "Quelle est une chose amusante que j''ai dite dont vous vous souvenez encore ?", "it": "Qual è qualcosa di divertente che ho detto e che ricordi ancora?", "ko": "내가 했던 말 중 아직 기억나는 재미있는 것이 있나요?", "nl": "Wat is iets grappigs dat ik heb gezegd dat je je nog herinnert?", "zh": "我说过的让你至今难忘的有趣的话是什么？"}'),
  ('communication', 2, '{"en": "How can we better support each other during stressful times?", "es": "¿Cómo podemos apoyarnos mejor durante tiempos de estrés?", "fr": "Comment pouvons-nous mieux nous soutenir pendant les périodes de stress ?", "it": "Come possiamo supportarci meglio durante i momenti di stress?", "ko": "힘든 시기에 어떻게 서로를 더 잘 지원할 수 있을까요?", "nl": "Hoe kunnen we elkaar beter ondersteunen tijdens stressvolle tijden?", "zh": "在压力时期我们如何更好地支持对方？"}'),
  ('communication', 3, '{"en": "What''s a conversation that we''ve had which changed your perspective on something important?", "es": "¿Cuál es una conversación que hemos tenido que cambió tu perspectiva sobre algo importante?", "fr": "Quelle est une conversation que nous avons eue qui a changé votre perspective sur quelque chose d''important ?", "it": "Qual è stata una conversazione che abbiamo avuto e che ha cambiato la tua prospettiva su qualcosa di importante?", "ko": "우리가 나눈 대화 중 중요한 것에 대한 당신의 관점을 바꾼 것이 있나요?", "nl": "Wat is een gesprek dat we hebben gehad dat je perspectief op iets belangrijks heeft veranderd?", "zh": "我们以前经历过哪次对话改变了你对某个重要事情的看法？"}'),
  ('intimacy', 1, '{"en": "What''s your favorite way to spend time together doing nothing?", "es": "¿Cuál es tu forma favorita de pasar tiempo juntos sin hacer nada?", "fr": "Quelle est votre façon préférée de passer du temps ensemble à ne rien faire ?", "it": "Qual è il tuo modo preferito di passare il tempo insieme senza fare nulla?", "ko": "아무것도 안 하면서 함께 시간을 보내는 것을 좋아하나요?", "nl": "Wat is je favoriete manier om samen tijd door te brengen zonder iets te doen?", "zh": "你们最喜欢的什么都不做的相处方式是什么？"}'),
  ('intimacy', 2, '{"en": "How do you feel when you receive a loving touch from me?", "es": "¿Cómo te sientes cuando recibes una caricia amorosa de mi parte?", "fr": "Comment vous sentez-vous lorsque vous recevez un geste tendre de ma part ?", "it": "Come ti senti quando ricevi un tocco amorevole da me?", "ko": "내 사랑스러운 스킨십을 받았을 때 어떤 기분이 드나요?", "nl": "Hoe voel je je als je een liefdevolle aanraking van mij ontvangt?", "zh": "当你接受到我的爱抚时你感觉如何？"}'),
  ('intimacy', 3, '{"en": "How has our physical connection evolved since we first met?", "es": "¿Cómo ha evolucionado nuestra conexión física desde que nos conocimos?", "fr": "Comment notre connexion physique a-t-elle évolué depuis notre première rencontre ?", "it": "Come è evoluta la nostra connessione fisica da quando ci siamo conosciuti?", "ko": "우리가 처음 만난 이후 우리의 신체적 연결은 어떻게 발전했나요?", "nl": "Hoe is onze fysieke connectie geëvolueerd sinds we elkaar voor het eerst ontmoetten?", "zh": "自从我们第一次见面以来，我们的身体联系如何发展？"}'),
  ('dreams', 1, '{"en": "What''s a place you dream of visiting together and why?", "es": "¿Cuál es un lugar que sueñas con visitar juntos y por qué?", "fr": "Quel est un endroit que vous rêvez de visiter ensemble et pourquoi ?", "it": "Qual è un luogo che sogni di visitare insieme e perché?", "ko": "함께 방문하기를 꿈꾸는 장소는 어디이며, 그 이유는 무엇인가요?", "nl": "Wat is een plek die je samen wilt bezoeken en waarom?", "zh": "你梦想一起去的地方是什么，为什么？"}'),
  ('dreams', 2, '{"en": "What dreams have you set aside that you wish to revisit?", "es": "¿Qué sueños has dejado de lado que deseas revisitar?", "fr": "Quels rêves avez-vous mis de côté que vous souhaitez revisiter ?", "it": "Quali sogni hai messo da parte che desideri rivisitare?", "ko": "당신이 미뤄둔 다시 방문하고 싶은 꿈은 무엇인가요?", "nl": "Welke dromen heb je opzij gezet die je opnieuw zou willen bekijken?", "zh": "你放在一边希望重新审视的梦想是什么？"}'),
  ('dreams', 3, '{"en": "How can our partnership support the pursuit of your deepest dreams?", "es": "¿Cómo puede nuestra asociación apoyar la búsqueda de tus sueños más profundos?", "fr": "Comment notre partenariat peut-il soutenir la poursuite de vos rêves les plus profonds ?", "it": "Come può il nostro partnership supportare il perseguimento dei tuoi sogni più profondi?", "ko": "우리의 파트너십이 당신의 가장 깊은 꿈을 추구하는 것을 어떻게 지원할 수 있을까요?", "nl": "Hoe kan onze samenwerking de realisatie van je diepste dromen ondersteunen?", "zh": "我们的合作如何支持你追求内心深处的梦想？"}'),
  ('memories', 1, '{"en": "What''s a humorous memory from one of our trips that still makes you laugh?", "es": "¿Cuál es un recuerdo divertido de uno de nuestros viajes que aún te hace reír?", "fr": "Quel est un souvenir amusant d''un de nos voyages qui vous fait encore rire ?", "it": "Qual è un ricordo divertente di uno dei nostri viaggi che ti fa ancora ridere?", "ko": "여행 중 당신을 아직 웃게 만드는 유머러스한 추억은 무엇인가요?", "nl": "Wat is een grappige herinnering van een van onze reizen die je nog steeds aan het lachen maakt?", "zh": "从我们的旅行中，你还会笑的幽默回忆是什么？"}'),
  ('memories', 2, '{"en": "How did a specific event in our relationship shape who we are today?", "es": "¿Cómo ha moldeado un evento específico en nuestra relación quiénes somos hoy?", "fr": "Comment un événement spécifique dans notre relation a-t-il façonné ce que nous sommes aujourd''hui ?", "it": "Come ha plasmato un evento specifico nella nostra relazione chi siamo oggi?", "ko": "우리 관계의 특정 사건이 오늘날의 우리를 어떻게 형성했나요?", "nl": "Hoe heeft een specifieke gebeurtenis in onze relatie gevormd wie we vandaag zijn?", "zh": "我们的关系中哪次具体事件塑造了今天的我们？"}'),
  ('memories', 3, '{"en": "Which past challenge in our relationship taught you the most?", "es": "¿Qué desafío pasado en nuestra relación te enseñó más?", "fr": "Quel défi passé dans notre relation vous a le plus appris ?", "it": "Quale sfida passata nella nostra relazione ti ha insegnato di più?", "ko": "우리 관계에서 과거의 어떤 도전이 당신에게 가장 많은 것을 가르쳤나요?", "nl": "Welke uitdaging uit het verleden in onze relatie heeft jou het meest geleerd?", "zh": "我们关系中哪次过去的挑战教会了你最多？"}'),
  ('values', 1, '{"en": "What''s a value we share that you''ve always appreciated?", "es": "¿Cuál es un valor que compartimos que siempre has apreciado?", "fr": "Quelle est une valeur que nous partageons que tu as toujours appréciée ?", "it": "Qual è un valore che condividiamo che hai sempre apprezzato?", "ko": "우리가 공유하는 가치 중에서 항상 소중하게 여겼던 것은 무엇인가요?", "nl": "Welke waarde delen we die je altijd hebt gewaardeerd?", "zh": "我们分享的价值观中，你一直以来都非常欣赏的是什么？"}'),
  ('values', 2, '{"en": "How do you integrate your core values into our daily life?", "es": "¿Cómo integras tus valores fundamentales en nuestra vida diaria?", "fr": "Comment intègres-tu tes valeurs fondamentales dans notre vie quotidienne ?", "it": "Come integri i tuoi valori fondamentali nella nostra vita quotidiana?", "ko": "핵심 가치를 어떻게 우리의 일상에 통합하나요?", "nl": "Hoe integreer je jouw kernwaarden in ons dagelijks leven?", "zh": "你如何将你的核心价值观融入我们的日常生活中？"}'),
  ('values', 3, '{"en": "Which of your values have been challenged most in our relationship?", "es": "¿Cuál de tus valores se ha visto más desafiado en nuestra relación?", "fr": "Laquelle de tes valeurs a été la plus mise à l''épreuve dans notre relation ?", "it": "Quale dei tuoi valori è stato messo più alla prova nella nostra relazione?", "ko": "우리 관계에서 어떤 가치가 가장 많이 도전받았나요?", "nl": "Welke van jouw waarden is het meest uitgedaagd in onze relatie?", "zh": "在我们的关系中，你的哪些价值观受到了最大挑战？"}'),
  ('fun', 1, '{"en": "What''s a game or activity you think we should try together?", "es": "¿Cuál es un juego o actividad que crees que deberíamos probar juntos?", "fr": "Quel jeu ou activité penses-tu que nous devrions essayer ensemble ?", "it": "Qual è un gioco o attività che pensi dovremmo provare insieme?", "ko": "함께 해보고 싶은 게임이나 활동이 있나요?", "nl": "Welke spel of activiteit denk je dat we samen zouden moeten proberen?", "zh": "你认为我们应该尝试一起做的游戏或活动是什么？"}'),
  ('fun', 2, '{"en": "How can we bring more spontaneous fun into our routine?", "es": "¿Cómo podemos incorporar más diversión espontánea a nuestra rutina?", "fr": "Comment pouvons-nous intégrer plus de plaisir spontané dans notre routine ?", "it": "Come possiamo portare più divertimento spontaneo nella nostra routine?", "ko": "우리의 일상에 더 많은 즉흥적인 재미를 추가할 수 있을까요?", "nl": "Hoe kunnen we meer spontane plezier in onze routine brengen?", "zh": "我们如何在日常中加入更多的即兴乐趣？"}'),
  ('fun', 3, '{"en": "What''s one adventurous experience you''d like us to share?", "es": "¿Cuál es una experiencia aventurera que te gustaría que compartiéramos?", "fr": "Quelle est une expérience aventureuse que tu aimerais que nous partagions ?", "it": "Qual è un''esperienza avventurosa che ti piacerebbe condividere?", "ko": "함께 해보고 싶은 모험적인 경험이 있나요?", "nl": "Wat is een avontuurlijke ervaring die je met ons wilt delen?", "zh": "你希望我们分享的冒险经历是什么？"}'),
  ('gratitude', 1, '{"en": "What''s something small I did recently that brought you joy?", "es": "¿Cuál es algo pequeño que hice recientemente que te trajo alegría?", "fr": "Quelle est une petite chose que j''ai faite récemment qui t''a apporté de la joie ?", "it": "Qual è una piccola cosa che ho fatto di recente che ti ha portato gioia?", "ko": "최근에 내가 했던 작은 일 중에 당신에게 기쁨을 준 것이 있나요?", "nl": "Wat is iets kleins dat ik onlangs deed dat je vreugde bracht?", "zh": "最近我做了什么小事让你感到快乐？"}'),
  ('gratitude', 2, '{"en": "How do you express gratitude in challenging circumstances?", "es": "¿Cómo expresas gratitud en circunstancias desafiantes?", "fr": "Comment exprimes-tu ta gratitude dans des circonstances difficiles ?", "it": "Come esprimi gratitudine in circostanze difficili?", "ko": "어려운 상황에서 어떻게 감사의 마음을 표현하나요?", "nl": "Hoe toon je dankbaarheid in uitdagende situaties?", "zh": "在充满挑战的情况下，你如何表达感激之情？"}'),
  ('gratitude', 3, '{"en": "What role does gratitude play in our relationship?", "es": "¿Qué papel juega la gratitud en nuestra relación?", "fr": "Quel rôle joue la gratitude dans notre relation ?", "it": "Che ruolo ha la gratitudine nella nostra relazione?", "ko": "우리 관계에서 감사는 어떤 역할을 하나요?", "nl": "Welke rol speelt dankbaarheid in onze relatie?", "zh": "感恩在我们的关系中起什么作用？"}'),
  ('conflict', 1, '{"en": "What''s one small disagreement we''ve had that you found funny later?", "es": "¿Cuál es un pequeño desacuerdo que tuvimos que encontraste divertido después?", "fr": "Quel est un petit désaccord que nous avons eu et que tu as trouvé amusant plus tard ?", "it": "Qual è un piccolo disaccordo che abbiamo avuto e che hai trovato divertente dopo?", "ko": "나중에 웃겼던 우리의 작은 의견 충돌이 있나요?", "nl": "Wat is een klein meningsverschil dat we hadden dat je later grappig vond?", "zh": "哪一个小争执你之后觉得很有趣？"}'),
  ('conflict', 2, '{"en": "How can we ensure we listen to understand rather than react during conflicts?", "es": "¿Cómo podemos asegurarnos de escuchar para entender en lugar de reaccionar durante los conflictos?", "fr": "Comment pouvons-nous nous assurer d''écouter pour comprendre plutôt que réagir lors des conflits ?", "it": "Come possiamo assicurarci di ascoltare per capire piuttosto che reagire durante i conflitti?", "ko": "갈등 중에 반응하는 대신 이해하기 위해 듣는 방법은 무엇인가요?", "nl": "Hoe kunnen we ervoor zorgen dat we luisteren om te begrijpen in plaats van te reageren tijdens conflicten?", "zh": "在冲突中，我们如何确保倾听是为了解而不是反应？"}'),
  ('conflict', 3, '{"en": "What''s a recurring conflict we face, and how would you like to address it?", "es": "¿Cuál es un conflicto recurrente al que nos enfrentamos y cómo te gustaría abordarlo?", "fr": "Quel est un conflit récurrent auquel nous faisons face, et comment aimerais-tu le résoudre ?", "it": "Qual è un conflitto ricorrente che affrontiamo e come ti piacerebbe affrontarlo?", "ko": "우리가 직면한 반복되는 갈등은 무엇이며, 어떻게 해결하고 싶나요?", "nl": "Wat is een terugkerend conflict waarmee we worden geconfronteerd, en hoe zou je het willen aanpakken?", "zh": "我们面临的一个反复出现的冲突是什么，你希望如何解决它？"}'),
  ('finances', 1, '{"en": "What''s a fun way we could save money together for a shared goal?", "es": "¿Cuál es una manera divertida de ahorrar dinero juntos para un objetivo común?", "fr": "Quelle est une façon amusante de faire des économies ensemble pour un objectif commun ?", "it": "Qual è un modo divertente per risparmiare denaro insieme per un obiettivo comune?", "ko": "공통의 목표를 위해 함께 돈을 절약할 수 있는 재미있는 방법이 있을까요?", "nl": "Wat is een leuke manier om samen geld te besparen voor een gemeenschappelijk doel?", "zh": "为共同目标存钱有什么有趣的方法？"}'),
  ('finances', 2, '{"en": "How do you feel about our approach to managing finances as a team?", "es": "¿Cómo te sientes acerca de nuestro enfoque para gestionar las finanzas como equipo?", "fr": "Que penses-tu de notre approche pour gérer les finances en équipe ?", "it": "Come ti senti riguardo al nostro approccio alla gestione delle finanze come squadra?", "ko": "팀으로서 재정을 관리하는 우리의 접근 방식에 대해 어떻게 생각하나요?", "nl": "Hoe denk je over onze aanpak om financiën als een team te beheren?", "zh": "对于我们团队管理财务的方法，你有什么感觉？"}'),
  ('finances', 3, '{"en": "Which financial decisions have been most pivotal for us?", "es": "¿Qué decisiones financieras han sido más cruciales para nosotros?", "fr": "Quelles décisions financières ont été les plus cruciales pour nous ?", "it": "Quali decisioni finanziarie sono state più cruciali per noi?", "ko": "우리에게 가장 중요한 재무 결정은 무엇인가요?", "nl": "Welke financiële beslissingen zijn het meest cruciaal voor ons geweest?", "zh": "哪些财务决策对我们来说至关重要？"}'),
  ('growth', 1, '{"en": "What''s an interest or skill you''d like us to explore together?", "es": "¿Cuál es un interés o habilidad que te gustaría que exploráramos juntos?", "fr": "Quel est un intérêt ou une compétence que tu aimerais que nous explorions ensemble ?", "it": "Qual è un interesse o abilità che ti piacerebbe esplorare insieme?", "ko": "함께 탐구하고 싶은 관심사나 기술이 있나요?", "nl": "Wat is een interesse of vaardigheid die je graag samen wilt verkennen?", "zh": "你希望我们一起探索的兴趣或技能是什么？"}'),
  ('growth', 2, '{"en": "How do you perceive your personal growth since we began our relationship?", "es": "¿Cómo percibes tu crecimiento personal desde que comenzamos nuestra relación?", "fr": "Comment perçois-tu ta croissance personnelle depuis le début de notre relation ?", "it": "Come percepisci la tua crescita personale da quando abbiamo iniziato la nostra relazione?", "ko": "우리 관계가 시작된 이후로 당신의 개인적 성장을 어떻게 느끼고 있나요?", "nl": "Hoe ervaar je je persoonlijke groei sinds we onze relatie begonnen?", "zh": "自从我们开始关系以来，你个人的成长是怎样的？"}'),
  ('growth', 3, '{"en": "How has our relationship fostered growth in ways you didn''t expect?", "es": "¿Cómo ha fomentado nuestra relación el crecimiento de formas que no esperabas?", "fr": "Comment notre relation a-t-elle favorisé une croissance de manière inattendue ?", "it": "Come ha promosso la nostra relazione una crescita in modi che non ti aspettavi?", "ko": "우리의 관계가 예상치 못한 방식으로 성장을 촉진하게 된 경우가 있었나요?", "nl": "Hoe heeft onze relatie op onverwachte manieren bijgedragen aan groei?", "zh": "我们的关系是如何在你意想不到的方式中促进成长的？"}'),
  ('family', 1, '{"en": "What''s a family tradition you''d love to start together?", "es": "¿Cuál es una tradición familiar que te encantaría comenzar juntos?", "fr": "Quelle est une tradition familiale que tu aimerais commencer ensemble ?", "it": "Qual è una tradizione familiare che ti piacerebbe iniziare insieme?", "ko": "함께 시작하고 싶은 가족 전통이 있나요?", "nl": "Welke familietraditie zou je graag samen willen beginnen?", "zh": "你想一起开始的是哪一种家庭传统？"}'),
  ('family', 2, '{"en": "How do your early family experiences influence our relationship today?", "es": "¿Cómo influyen tus experiencias familiares tempranas en nuestra relación hoy en día?", "fr": "Comment tes premières expériences familiales influencent-elles notre relation aujourd''hui ?", "it": "Come influenzano le tue prime esperienze familiari la nostra relazione oggi?", "ko": "초기의 가족 경험이 지금 우리의 관계에 어떻게 영향을 미치나요?", "nl": "Hoe beïnvloeden jouw vroege familie-ervaringen onze relatie vandaag?", "zh": "你早期的家庭经历如何影响我们今天的关系？"}'),
  ('family', 3, '{"en": "How do you envision balancing the needs of our future family and our relationship?", "es": "¿Cómo imaginas equilibrar las necesidades de nuestra futura familia con nuestra relación?", "fr": "Comment envisages-tu d''équilibrer les besoins de notre future famille et notre relation ?", "it": "Come immagini di bilanciare i bisogni della nostra futura famiglia con la nostra relazione?", "ko": "미래의 가족과 우리의 관계의 균형을 어떻게 유지할 것이라 생각하나요?", "nl": "Hoe zie je het balanceren van de behoeften van onze toekomstige familie en onze relatie voor je?", "zh": "你如何设想平衡我们未来家庭的需要与我们之间的关系？"}'),
  ('adventure', 1, '{"en": "What''s a simple adventure you''d like to embark on this month?", "es": "¿Cuál es una aventura sencilla que te gustaría emprender este mes?", "fr": "Quelle est une simple aventure que tu aimerais entreprendre ce mois-ci ?", "it": "Qual è una semplice avventura che ti piacerebbe intraprendere questo mese?", "ko": "이번 달에 함께 하고 싶은 간단한 모험은 무엇인가요?", "nl": "Wat is een eenvoudig avontuur dat je deze maand wilt aangaan?", "zh": "这个月你想开展什么简单的冒险？"}'),
  ('adventure', 2, '{"en": "How can adventure enhance our understanding of one another?", "es": "¿Cómo puede la aventura mejorar nuestra comprensión mutua?", "fr": "Comment l''aventure peut-elle améliorer notre compréhension l''un de l''autre ?", "it": "Come può l''avventura migliorare la nostra comprensione reciproca?", "ko": "모험이 우리 서로를 이해하는 데 어떻게 도움을 줄 수 있을까요?", "nl": "Hoe kan avontuur onze onderlinge begrip verbeteren?", "zh": "冒险如何增强我们对彼此的理解？"}'),
  ('adventure', 3, '{"en": "What''s an adventurous goal that challenges us to grow as a couple?", "es": "¿Cuál es un objetivo aventurero que nos desafía a crecer como pareja?", "fr": "Quel est un objectif aventureux qui nous met au défi de grandir en tant que couple ?", "it": "Qual è un obiettivo avventuroso che ci sfida a crescere come coppia?", "ko": "우리가 커플로서 성장하도록 도전하는 모험 목표는 무엇일까요?", "nl": "Wat is een avontuurlijk doel dat ons uitdaagt om te groeien als koppel?", "zh": "作为情侣，有哪些冒险目标可以挑战我们成长？"}'),
  ('communication', 1, '{"en": "What''s a simple gesture I do that reassures you?", "es": "¿Cuál es un gesto sencillo que hago que te tranquiliza?", "fr": "Quel est un geste simple que je fais qui te rassure ?", "it": "Qual è un gesto semplice che faccio che ti rassicura?", "ko": "내가 당신을 안심시키는 데 도움이 되는 간단한 행동이 있나요?", "nl": "Wat is een eenvoudig gebaar dat ik doe dat je geruststelt?", "zh": "我做的哪一个简单手势让你感到安心？"}'),
  ('communication', 2, '{"en": "How can we improve our non-verbal communication?", "es": "¿Cómo podemos mejorar nuestra comunicación no verbal?", "fr": "Comment pouvons-nous améliorer notre communication non verbale ?", "it": "Come possiamo migliorare la nostra comunicazione non verbale?", "ko": "비언어적 의사소통을 어떻게 개선할 수 있을까요?", "nl": "Hoe kunnen we onze non-verbale communicatie verbeteren?", "zh": "我们如何改善非语言交流？"}'),
  ('communication', 3, '{"en": "Which part of our communication needs the most attention, in your view?", "es": "¿Qué parte de nuestra comunicación necesita más atención, según tu opinión?", "fr": "Quelle partie de notre communication nécessite le plus d''attention selon toi ?", "it": "Quale parte della nostra comunicazione ha bisogno di più attenzione secondo te?", "ko": "우리의 의사소통 중 어떤 부분이 가장 많은 주의를 필요로 한다고 생각하나요?", "nl": "Welk onderdeel van onze communicatie heeft volgens jou de meeste aandacht nodig?", "zh": "在你看来，我们的交流中哪一部分最需要关注？"}'),
  ('intimacy', 1, '{"en": "What''s your favorite inside joke that we share?", "es": "¿Cuál es tu broma interna favorita que compartimos?", "fr": "Quelle est ta blague d''initié préférée que nous partageons ?", "it": "Qual è la tua battuta interna preferita che condividiamo?", "ko": "우리가 공유하는 가장 좋아하는 속마음 농담은 무엇인가요?", "nl": "Wat is jouw favoriete binnenpretje dat we samen delen?", "zh": "我们分享的你最喜欢的内部笑话是什么？"}'),
  ('intimacy', 2, '{"en": "In what way could we create more intimacy in our everyday routine?", "es": "¿De qué manera podríamos crear más intimidad en nuestra rutina diaria?", "fr": "De quelle manière pourrions-nous créer plus d''intimité dans notre routine quotidienne ?", "it": "In che modo potremmo creare più intimità nella nostra routine quotidiana?", "ko": "일상 속에서 더 많은 친밀감을 어떻게 만들 수 있을까요?", "nl": "Op welke manier kunnen we meer intimiteit creëren in onze dagelijkse routine?", "zh": "我们可以通过什么方式在日常中创造更多亲密感？"}'),
  ('intimacy', 3, '{"en": "What does vulnerability mean to you in our relationship?", "es": "¿Qué significa la vulnerabilidad para ti en nuestra relación?", "fr": "Que signifie la vulnérabilité pour toi dans notre relation ?", "it": "Cosa significa la vulnerabilità per te nella nostra relazione?", "ko": "우리 관계에서 취약성은 당신에게 어떤 의미인가요?", "nl": "Wat betekent kwetsbaarheid voor jou in onze relatie?", "zh": "在我们的关系中，脆弱对你意味着什么？"}'),
  ('dreams', 1, '{"en": "What''s a small dream you have for us to achieve together?", "es": "¿Cuál es un pequeño sueño que tienes para que logremos juntos?", "fr": "Quel est un petit rêve que tu as pour que nous réalisions ensemble ?", "it": "Qual è un piccolo sogno che hai per noi da realizzare insieme?", "ko": "우리가 함께 이루고 싶은 작은 꿈은 무엇인가요?", "nl": "Wat is een kleine droom die je hebt om samen te bereiken?", "zh": "你对我们一起实现的一个小梦想是什么？"}'),
  ('dreams', 2, '{"en": "How do our individual dreams intersect with our shared ones?", "es": "¿Cómo se cruzan nuestros sueños individuales con los compartidos?", "fr": "Comment nos rêves individuels se croisent-ils avec nos rêves communs ?", "it": "In che modo i nostri sogni individuali si incrociano con quelli condivisi?", "ko": "우리의 개별적인 꿈과 공동의 꿈이 어떻게 교차하나요?", "nl": "Hoe kruisen onze individuele dromen met onze gedeelde dromen?", "zh": "我们的个人梦想与共同的梦想如何相交？"}'),
  ('dreams', 3, '{"en": "In what ways can I empower you to pursue your dreams more boldly?", "es": "¿De qué maneras puedo empoderarte para que persigas tus sueños con más audacia?", "fr": "De quelles manières puis-je t''encourager à poursuivre tes rêves plus audacieusement ?", "it": "In che modo posso darti forza per perseguire i tuoi sogni con più audacia?", "ko": "당신이 더 대담하게 꿈을 추구할 수 있도록 제가 어떻게 도울 수 있을까요?", "nl": "Op welke manieren kan ik je helpen je dromen gedurfder na te streven?", "zh": "我可以通过哪些方式让你更大胆地追求你的梦想？"}'),
  ('memories', 1, '{"en": "What''s a random funny incident that happened on a casual day with me?", "es": "¿Cuál es un incidente divertido al azar que ocurrió en un día casual conmigo?", "fr": "Quel est un incident drôle et inattendu qui s''est produit lors d''une journée ordinaire avec moi ?", "it": "Qual è un episodio divertente capitato in un giorno qualunque con me?", "ko": "평범한 날에 나와 함께했던 재미있는 사건은 무엇인가요?", "nl": "Wat is een willekeurig grappig voorval dat gebeurde op een gewone dag met mij?", "zh": "在与我共度的平常日子里发生的一个有趣的小插曲是什么？"}'),
  ('memories', 2, '{"en": "How do certain memories influence your perception of our relationship?", "es": "¿Cómo influyen ciertos recuerdos en tu percepción de nuestra relación?", "fr": "Comment certains souvenirs influencent-ils ta perception de notre relation ?", "it": "In che modo certi ricordi influenzano la tua percezione della nostra relazione?", "ko": "어떤 기억들이 우리 관계에 대한 당신의 인식에 어떻게 영향을 미치나요?", "nl": "Hoe beïnvloeden bepaalde herinneringen je perceptie van onze relatie?", "zh": "某些记忆如何影响你对我们关系的看法？"}'),
  ('memories', 3, '{"en": "Which memory of us brings not just joy but also teaches a lesson?", "es": "¿Qué recuerdo de nosotros no solo trae alegría sino también enseña una lección?", "fr": "Quel souvenir de nous apporte non seulement de la joie mais aussi une leçon ?", "it": "Qual è un ricordo di noi che non solo porta gioia, ma insegna anche una lezione?", "ko": "우리의 기억 중 즐거움만이 아닌 교훈을 주는 것은 무엇인가요?", "nl": "Welke herinnering aan ons brengt niet alleen vreugde, maar leert ook een les?", "zh": "我们之间的哪个记忆不仅带来快乐还教会了一课？"}'),
  ('values', 1, '{"en": "What''s a value you admire that we both uphold?", "es": "¿Cuál es un valor que admiras y que ambos sostenemos?", "fr": "Quelle est une valeur que tu admires et que nous soutenons tous deux ?", "it": "Qual è un valore che ammiri e che entrambi sosteniamo?", "ko": "우리가 둘 다 지지하는 당신이 존경하는 가치는 무엇인가요?", "nl": "Wat is een waarde die je bewondert en die we allebei aanhangen?", "zh": "你钦佩且我们双方都坚持的一个价值是什么？"}'),
  ('values', 2, '{"en": "How can our shared values guide decisions in challenging times?", "es": "¿Cómo pueden nuestros valores compartidos guiar las decisiones en tiempos difíciles?", "fr": "Comment nos valeurs partagées peuvent-elles guider les décisions en période de défis ?", "it": "In che modo i nostri valori condivisi possono guidare le decisioni nei momenti difficili?", "ko": "우리의 공유된 가치가 어려운 시기에 어떻게 결정을 이끌 수 있나요?", "nl": "Hoe kunnen onze gedeelde waarden beslissingen sturen in uitdagende tijden?", "zh": "我们的共同价值观如何在挑战时期指导决策？"}'),
  ('values', 3, '{"en": "What''s a value conflict you''ve faced and resolved in our relationship?", "es": "¿Cuál es un conflicto de valores que enfrentaste y resolviste en nuestra relación?", "fr": "Quel est un conflit de valeurs que tu as affronté et résolu dans notre relation ?", "it": "Qual è un conflitto di valori che hai affrontato e risolto nella nostra relazione?", "ko": "우리 관계에서 직면하고 해결한 가치 갈등은 무엇인가요?", "nl": "Wat is een waardenconflict dat je hebt ervaren en opgelost in onze relatie?", "zh": "在我们的关系中你曾面临并解决的一个价值冲突是什么？"}'),
  ('fun', 1, '{"en": "What''s your favorite silly thing we do together?", "es": "¿Cuál es tu cosa tonta favorita que hacemos juntos?", "fr": "Quelle est ta chose stupide préférée que nous faisons ensemble ?", "it": "Qual è la tua cosa sciocca preferita che facciamo insieme?", "ko": "우리가 함께하는 당신이 가장 좋아하는 바보 같은 것은 무엇인가요?", "nl": "Wat is je favoriete gekke ding dat we samen doen?", "zh": "我们一起做的哪件傻事是你最喜欢的？"}'),
  ('fun', 2, '{"en": "How can integrating fun into our routine benefit our relationship?", "es": "¿Cómo puede integrar la diversión en nuestra rutina beneficiar a nuestra relación?", "fr": "Comment intégrer l''amusement dans notre routine peut-il bénéficier notre relation ?", "it": "Come può l''integrazione del divertimento nella nostra routine avvantaggiare la nostra relazione?", "ko": "루틴에 재미를 통합함으로써 우리 관계에 어떤 이점이 있을까요?", "nl": "Hoe kan het integreren van plezier in onze routine onze relatie ten goede komen?", "zh": "如何将乐趣融入我们的日常生活中对我们的关系有益？"}'),
  ('fun', 3, '{"en": "What''s one fun event you believe would create lasting joy for us?", "es": "¿Qué evento divertido crees que crearía alegría duradera para nosotros?", "fr": "Quel est un événement amusant qui, selon toi, créerait une joie durable pour nous ?", "it": "Qual è un evento divertente che credi creerebbe gioia duratura per noi?", "ko": "우리에게 지속적인 기쁨을 줄 것이라고 믿는 재미있는 이벤트는 무엇인가요?", "nl": "Wat is een leuke gebeurtenis die volgens jou blijvende vreugde voor ons zou creëren?", "zh": "你认为将为我们创造持久快乐的一个有趣事件是什么？"}'),
  ('gratitude', 1, '{"en": "What''s a simple moment today that made you feel grateful?", "es": "¿Cuál es un momento simple de hoy que te hizo sentir agradecido?", "fr": "Quel est un moment simple aujourd''hui qui t''a fait te sentir reconnaissant ?", "it": "Qual è un momento semplice oggi che ti ha fatto sentire grato?", "ko": "오늘 당신을 감사하게 만든 간단한 순간은 무엇인가요?", "nl": "Wat is een eenvoudig moment van vandaag dat je dankbaar maakte?", "zh": "今天让你感到感激的一个简单时刻是什么？"}'),
  ('gratitude', 2, '{"en": "How do you naturally express gratitude in our relationship?", "es": "¿Cómo expresas naturalmente la gratitud en nuestra relación?", "fr": "Comment exprimes-tu naturellement ta gratitude dans notre relation ?", "it": "Come esprimi naturalmente la gratitudine nella nostra relazione?", "ko": "우리 관계에서 당신은 어떻게 자연스럽게 감사를 표현하나요?", "nl": "Hoe uit je van nature dankbaarheid in onze relatie?", "zh": "在我们的关系中你自然流露感激之情的方式是什么？"}'),
  ('gratitude', 3, '{"en": "How can we cultivate a deeper culture of gratitude together?", "es": "¿Cómo podemos cultivar una cultura más profunda de gratitud juntos?", "fr": "Comment pouvons-nous cultiver ensemble une culture plus profonde de gratitude ?", "it": "Come possiamo coltivare insieme una cultura più profonda della gratitudine?", "ko": "우리가 함께 더 깊은 감사의 문화를 어떻게 길러갈 수 있을까요?", "nl": "Hoe kunnen we samen een diepere cultuur van dankbaarheid cultiveren?", "zh": "我们可以如何一起培养更深入的感恩文化？"}'),
  ('conflict', 1, '{"en": "What''s a silly argument that hindsight has shown to be inconsequential?", "es": "¿Cuál es una discusión tonta que con el tiempo se ha demostrado que es inconsecuente?", "fr": "Quelle est une dispute idiote qui, avec le recul, s''est avérée sans conséquence ?", "it": "Qual è una discussione sciocca che col senno di poi si è rivelata inconsequenziale?", "ko": "뒷날 되돌아보니 중요하지 않다고 판명된 어리석은 논쟁은 무엇인가요?", "nl": "Wat is een dom argument dat achteraf onbelangrijk bleek te zijn?", "zh": "回头看时被证明无关紧要的愚蠢争论是什么？"}'),
  ('conflict', 2, '{"en": "How do you perceive the role of conflict in our growth as a couple?", "es": "¿Cómo percibes el papel del conflicto en nuestro crecimiento como pareja?", "fr": "Comment perçois-tu le rôle du conflit dans notre croissance en tant que couple ?", "it": "In che modo percepisci il ruolo del conflitto nella nostra crescita come coppia?", "ko": "부부로서의 성장에 있어서 갈등의 역할을 어떻게 인식하나요?", "nl": "Hoe zie je de rol van conflict in onze groei als koppel?", "zh": "你如何看待冲突在我们作为情侣的成长过程中的作用？"}'),
  ('conflict', 3, '{"en": "What''s the most constructive lesson you''ve learned from our conflicts?", "es": "¿Cuál es la lección más constructiva que has aprendido de nuestros conflictos?", "fr": "Quelle est la leçon la plus constructive que tu as apprise de nos conflits ?", "it": "Qual è la lezione più costruttiva che hai imparato dai nostri conflitti?", "ko": "우리 갈등에서 배운 가장 건설적인 교훈은 무엇인가요?", "nl": "Wat is de meest constructieve les die je hebt geleerd van onze conflicten?", "zh": "从我们的冲突中你学到的最具建设性的课是什么？"}'),
  ('finances', 1, '{"en": "What''s a memorable thing we''ve saved for together and achieved?", "es": "¿Cuál es algo memorable para lo que hemos ahorrado juntos y logrado?", "fr": "Quelle est une chose mémorable pour laquelle nous avons économisé ensemble et que nous avons réalisée ?", "it": "Qual è una cosa memorabile che abbiamo risparmiato insieme e raggiunto?", "ko": "우리가 함께 저장하고 성취한 기억에 남는 것은 무엇인가요?", "nl": "Wat is een memorabel iets waar we samen voor hebben gespaard en bereikt?", "zh": "我们一起储蓄并实现的一个难忘的事情是什么？"}'),
  ('finances', 2, '{"en": "How do our financial goals align with our life aspirations?", "es": "¿Cómo se alinean nuestras metas financieras con nuestras aspiraciones de vida?", "fr": "Comment nos objectifs financiers s''alignent-ils avec nos aspirations de vie ?", "it": "In che modo i nostri obiettivi finanziari si allineano con le nostre aspirazioni di vita?", "ko": "우리의 재정적 목표와 삶의 열망이 어떻게 맞물리나요?", "nl": "Hoe sluiten onze financiële doelen aan bij onze levensaspiraties?", "zh": "我们的财务目标如何与生活理想一致？"}'),
  ('finances', 3, '{"en": "What financial legacy do you hope we establish together?", "es": "¿Qué legado financiero esperas que establezcamos juntos?", "fr": "Quel héritage financier espères-tu que nous établissions ensemble ?", "it": "Quale eredità finanziaria speri che istituiamo insieme?", "ko": "우리가 함께 구축하기를 바라는 재정적 유산은 무엇인가요?", "nl": "Wat voor financieel erfgoed hoop je dat we samen opbouwen?", "zh": "你希望我们共同建立什么样的财务遗产？"}'),
  ('growth', 1, '{"en": "What''s a small personal goal you''d like to reach with my support?", "es": "¿Cuál es una pequeña meta personal que te gustaría alcanzar con mi apoyo?", "fr": "Quel est un petit objectif personnel que tu aimerais atteindre avec mon soutien ?", "it": "Qual è un piccolo obiettivo personale che vorresti raggiungere con il mio supporto?", "ko": "내 도움으로 이루고 싶은 작은 개인 목표는 무엇인가요?", "nl": "Wat is een klein persoonlijk doel dat je met mijn ondersteuning wilt bereiken?", "zh": "在我的支持下你想达到的一个小个人目标是什么？"}'),
  ('growth', 2, '{"en": "How do you envision us nurturing individual growth within our relationship?", "es": "¿Cómo visualizas que fomentemos el crecimiento individual dentro de nuestra relación?", "fr": "Comment envisages-tu que nous encouragions la croissance individuelle au sein de notre relation ?", "it": "Come immagini che possiamo incoraggiare la crescita individuale all''interno della nostra relazione?", "ko": "우리 관계 내에서 개인의 성장을 육성하는 것을 어떻게 상상하나요?", "nl": "Hoe zie je ons het bevorderen van individuele groei binnen onze relatie?", "zh": "你如何设想我们在关系中促进个人成长？"}'),
  ('growth', 3, '{"en": "What''s one boundary you''ve learned to respect through our growth as a couple?", "es": "¿Cuál es un límite que has aprendido a respetar a través de nuestro crecimiento como pareja?", "fr": "Quelle est une limite que tu as apprise à respecter grâce à notre croissance en tant que couple ?", "it": "Qual è un confine che hai imparato a rispettare attraverso la nostra crescita come coppia?", "ko": "부부로서의 성장 과정을 통해 배운 하나의 경계는 무엇인가요?", "nl": "Wat is een grens die je hebt geleerd te respecteren door onze groei als koppel?", "zh": "在我们作为情侣的成长过程中你学会尊重的一个界限是什么？"}'),
  ('family', 1, '{"en": "What''s a family activity you envision us doing together?", "es": "¿Cuál es una actividad familiar que imaginas que hagamos juntos?", "fr": "Quelle est une activité familiale que tu nous imagines faire ensemble ?", "it": "Qual è un''attività di famiglia che immagini di fare insieme?", "ko": "우리 가족이 함께 할 수 있다고 상상하는 활동은 무엇인가요?", "nl": "Wat is een familieactiviteit die je ons samen ziet doen?", "zh": "你设想我们一起做的一个家庭活动是什么？"}'),
  ('family', 2, '{"en": "How do our family backgrounds enhance or challenge our relationship?", "es": "¿Cómo mejoran o desafían nuestras bases familiares nuestra relación?", "fr": "Comment nos contextes familiaux améliorent-ils ou défient-ils notre relation ?", "it": "In che modo i nostri contesti familiari rafforzano o sfidano la nostra relazione?", "ko": "우리의 가족 배경이 우리의 관계를 어떻게 강화하거나 도전하게 하나요?", "nl": "Hoe verbeteren of belemmeren onze familieachtergronden onze relatie?", "zh": "我们的家庭背景如何增强或挑战我们的关系？"}'),
  ('family', 3, '{"en": "How do you visualize our family dynamic evolving over time?", "es": "¿Cómo visualizas que nuestra dinámica familiar evolucione con el tiempo?", "fr": "Comment visualises-tu l''évolution de notre dynamique familiale au fil du temps ?", "it": "Come immagini che la nostra dinamica familiare evolverà nel tempo?", "ko": "시간이 지남에 따라 우리의 가족 다이나믹이 어떻게 변할 것이라고 상상하나요?", "nl": "Hoe zie je onze familiedynamiek in de loop van de tijd evolueren?", "zh": "你如何设想我们的家庭动态随着时间发展？"}'),
  ('adventure', 1, '{"en": "What''s an adventurous thing we''ve done that you''d want to repeat?", "es": "¿Cuál es algo aventurero que hemos hecho y que te gustaría repetir?", "fr": "Quelle est une aventure que nous avons menée et que tu souhaiterais répéter ?", "it": "Qual è un''attività avventurosa che abbiamo fatto e che vorresti ripetere?", "ko": "우리가 했던 모험적인 일 중 반복하고 싶은 것은 무엇인가요?", "nl": "Wat is een avontuurlijk iets dat we hebben gedaan en dat je opnieuw zou willen doen?", "zh": "我们做过的想重温的冒险经历是什么？"}'),
  ('adventure', 2, '{"en": "How does seeking adventure together influence our relationship?", "es": "¿Cómo influye en nuestra relación la búsqueda de aventuras juntos?", "fr": "Comment la recherche d''aventures ensemble influence-t-elle notre relation ?", "it": "In che modo cercare avventure insieme influenza la nostra relazione?", "ko": "함께 모험을 추구하는 것이 우리 관계에 어떻게 영향을 미치나요?", "nl": "Hoe beïnvloedt het samen op zoek gaan naar avontuur onze relatie?", "zh": "一起追求冒险如何影响我们的关系？"}'),
  ('adventure', 3, '{"en": "What element of adventure do you think has the most profound impact on us?", "es": "¿Qué elemento de la aventura crees que tiene el impacto más profundo en nosotros?", "fr": "Quel élément de l''aventure, penses-tu, a l''impact le plus profond sur nous ?", "it": "Quale elemento dell''avventura pensi abbia l''impatto più profondo su di noi?", "ko": "모험의 어떤 요소가 우리에게 가장 깊은 영향을 미친다고 생각하나요?", "nl": "Welk element van avontuur heeft volgens jou de meest diepgaande impact op ons?", "zh": "你认为冒险中的哪个元素对我们影响最大？"}'),
  ('communication', 1, '{"en": "What''s one phrase I say that makes you smile every time?", "es": "¿Cuál es una frase que digo que te hace sonreír cada vez?", "fr": "Quelle est une phrase que je dis et qui te fait sourire à chaque fois ?", "it": "Qual è una frase che dico che ti fa sorridere ogni volta?", "ko": "내가 항상 웃게 만드는 말은 무엇인가요?", "nl": "Wat is een zin die ik zeg waardoor je elke keer glimlacht?", "zh": "我说的哪句话每次都能让你微笑？"}'),
  ('communication', 2, '{"en": "How do you feel when we have uninterrupted one-on-one time to talk?", "es": "¿Cómo te sientes cuando tenemos tiempo ininterrumpido para hablar uno a uno?", "fr": "Comment te sens-tu lorsque nous avons du temps ininterrompu en tête-à-tête pour parler ?", "it": "Come ti senti quando abbiamo del tempo ininterrotto per parlare uno a uno?", "ko": "우리가 방해받지 않고 일대일로 대화할 때 어떤 느낌이 드나요?", "nl": "Hoe voel je je als we ononderbroken één-op-één tijd hebben om te praten?", "zh": "当我们有不受干扰的一对一时间聊天时，你感觉如何？"}'),
  ('communication', 3, '{"en": "What''s your perspective on the role of vulnerability in our communication?", "es": "¿Cuál es tu perspectiva sobre el papel de la vulnerabilidad en nuestra comunicación?", "fr": "Quelle est ta perspective sur le rôle de la vulnérabilité dans notre communication ?", "it": "Qual è la tua prospettiva sul ruolo della vulnerabilità nella nostra comunicazione?", "ko": "우리의 의사소통에서 취약성의 역할에 대한 당신의 관점은 무엇입니까?", "nl": "Wat is jouw perspectief op de rol van kwetsbaarheid in onze communicatie?", "zh": "你怎么看待在我们沟通中的脆弱性角色？"}'),
  ('intimacy', 1, '{"en": "What''s a small act of affection you cherish the most from me?", "es": "¿Cuál es un pequeño acto de afecto de mi parte que más aprecias?", "fr": "Quel est le petit geste d''affection de ma part que tu chéris le plus ?", "it": "Qual è un piccolo gesto d''affetto da parte mia che consideri il più prezioso?", "ko": "내가 하는 작은 애정 표현 중 가장 소중하게 여기는 것은 무엇인가요?", "nl": "Wat is een kleine blijk van genegenheid van mij die je het meest koestert?", "zh": "我做的哪一个小小的表达感情的举动是你最珍惜的？"}'),
  ('intimacy', 2, '{"en": "How does creating shared rituals enhance our intimacy?", "es": "¿Cómo mejorar nuestra intimidad al crear rituales compartidos?", "fr": "Comment la création de rituels partagés renforce-t-elle notre intimité ?", "it": "In che modo la creazione di rituali condivisi migliora la nostra intimità?", "ko": "공유된 의식을 만드는 것이 우리의 친밀감을 어떻게 향상시키나요?", "nl": "Hoe verbetert het creëren van gedeelde rituelen onze intimiteit?", "zh": "创建共同的仪式如何增强我们的亲密关系？"}'),
  ('intimacy', 3, '{"en": "In what ways have challenges deepened our emotional intimacy?", "es": "¿De qué manera los desafíos han profundizado nuestra intimidad emocional?", "fr": "De quelles manières les défis ont-ils approfondi notre intimité émotionnelle ?", "it": "In che modo le sfide hanno approfondito la nostra intimità emotiva?", "ko": "어떤 방법으로 도전이 우리의 정서적 친밀감을 깊게 했나요?", "nl": "Op welke manieren hebben uitdagingen onze emotionele intimiteit verdiept?", "zh": "挑战在何种程度上加深了我们的情感亲密度？"}'),
  ('dreams', 1, '{"en": "What''s a daydream you have about our future life together?", "es": "¿Cuál es un sueño diurno que tienes sobre nuestra vida futura juntos?", "fr": "Quel est un rêve éveillé que tu as de notre vie future ensemble ?", "it": "Qual è un sogno ad occhi aperti che hai sul nostro futuro insieme?", "ko": "우리의 미래 생활에 대한 당신의 공상은 무엇인가요?", "nl": "Wat is een dagdroom die je hebt over ons toekomstige leven samen?", "zh": "你对我们未来生活的幻想是什么？"}'),
  ('dreams', 2, '{"en": "What steps can we take to manifest one of your lifelong dreams?", "es": "¿Qué pasos podemos seguir para manifestar uno de tus sueños de toda la vida?", "fr": "Quelles étapes pouvons-nous suivre pour réaliser l''un de tes rêves de toujours ?", "it": "Quali passaggi possiamo intraprendere per realizzare uno dei tuoi sogni di una vita?", "ko": "당신의 평생 꿈 중 하나를 실현하기 위해 어떤 조치를 취할 수 있을까요?", "nl": "Welke stappen kunnen we nemen om een van je levenslange dromen te realiseren?", "zh": "我们可以采取哪些步骤来实现你的一项终生梦想？"}'),
  ('dreams', 3, '{"en": "How do you balance pursuing personal dreams with our shared ones?", "es": "¿Cómo equilibras la búsqueda de sueños personales con los nuestros compartidos?", "fr": "Comment équilibres-tu la poursuite de rêves personnels avec nos rêves partagés ?", "it": "Come equilibri la ricerca dei tuoi sogni personali con quelli condivisi?", "ko": "개인적인 꿈과 우리의 공유된 꿈을 어떻게 조화시킵니까?", "nl": "Hoe balanceer je het nastreven van persoonlijke dromen met onze gedeelde dromen?", "zh": "你如何平衡追求个人梦想与我们的共同梦想？"}'),
  ('memories', 1, '{"en": "What''s a spontaneous moment we''ve shared that stands out to you?", "es": "¿Cuál es un momento espontáneo que hemos compartido que se destaca para ti?", "fr": "Quel est un moment spontané que nous avons partagé et qui te marque particulièrement ?", "it": "Qual è un momento spontaneo che abbiamo condiviso che ti colpisce?", "ko": "우리의 즉흥적인 순간 중 당신에게 특별한 것이 무엇인가요?", "nl": "Wat is een spontaan moment dat we hebben gedeeld dat voor jou opvalt?", "zh": "我们共同经历的哪个即兴时刻让你印象深刻？"}'),
  ('memories', 2, '{"en": "How have our shared memories shaped the foundation of our relationship?", "es": "¿Cómo han dado forma nuestros recuerdos compartidos a la base de nuestra relación?", "fr": "Comment nos souvenirs partagés ont-ils façonné les bases de notre relation ?", "it": "Come hanno plasmato i nostri ricordi condivisi le fondamenta della nostra relazione?", "ko": "우리의 공유된 기억들이 우리의 관계의 기초를 어떻게 형성했나요?", "nl": "Hoe hebben onze gedeelde herinneringen de basis van onze relatie gevormd?", "zh": "我们共同的记忆是如何构建我们关系的基础的？"}'),
  ('memories', 3, '{"en": "What past memory holds more wisdom for our present relationship?", "es": "¿Qué recuerdo del pasado tiene más sabiduría para nuestra relación actual?", "fr": "Quel souvenir du passé contient plus de sagesse pour notre relation actuelle ?", "it": "Quale ricordo del passato contiene più saggezza per la nostra relazione attuale?", "ko": "우리의 현재 관계에 더 많은 지혜를 제공하는 과거의 기억은 무엇인가요?", "nl": "Welk verleden geheugen bevat meer wijsheid voor onze huidige relatie?", "zh": "哪个过去的记忆为我们目前的关系带来更多智慧？"}'),
  ('values', 1, '{"en": "What''s a shared value of ours that aligns with your true self?", "es": "¿Cuál es un valor compartido nuestro que se alinea con tu verdadero yo?", "fr": "Quelle est une de nos valeurs partagées qui s''aligne avec ton vrai moi ?", "it": "Qual è un valore condiviso tra noi che si allinea con il tuo vero io?", "ko": "우리의 공유된 가치 중 당신의 진정한 자아와 일치하는 것은 무엇인가요?", "nl": "Wat is een gedeelde waarde van ons die aansluit bij je ware zelf?", "zh": "我们共享的哪个价值观与您的真实自我一致？"}'),
  ('values', 2, '{"en": "How can we incorporate our core values into major decisions?", "es": "¿Cómo podemos incorporar nuestros valores fundamentales en las decisiones importantes?", "fr": "Comment pouvons-nous intégrer nos valeurs fondamentales dans les décisions majeures ?", "it": "Come possiamo incorporare i nostri valori fondamentali nelle decisioni importanti?", "ko": "우리의 핵심 가치를 주요 결정에 어떻게 통합할 수 있을까요?", "nl": "Hoe kunnen we onze kernwaarden integreren in grote beslissingen?", "zh": "我们如何将核心价值观融合到重大决策中？"}'),
  ('values', 3, '{"en": "Which value do you think needs more focus as we grow together?", "es": "¿Qué valor crees que necesita más enfoque a medida que crecemos juntos?", "fr": "Quelle valeur penses-tu avoir besoin de plus de focus alors que nous grandissons ensemble ?", "it": "Quale valore pensi abbia bisogno di più attenzione mentre cresciamo insieme?", "ko": "우리가 함께 성장할 때 더 중점을 두어야 할 가치가 무엇이라고 생각하나요?", "nl": "Welke waarde denk je dat meer aandacht nodig heeft terwijl we samen groeien?", "zh": "随着我们的共同成长，你认为哪个价值观需要更多关注？"}'),
  ('fun', 1, '{"en": "What''s a nostalgic game from childhood you''d love to play with me?", "es": "¿A qué juego nostálgico de la infancia te encantaría jugar conmigo?", "fr": "Quel jeu nostalgique de ton enfance aimerais-tu jouer avec moi ?", "it": "Qual è un gioco nostalgico dell''infanzia che ti piacerebbe giocare con me?", "ko": "어릴 적 당신이 나와 함께 하고 싶은 향수 어린 게임은 무엇인가요?", "nl": "Wat is een nostalgisch spel uit je jeugd dat je graag met mij wilt spelen?", "zh": "你童年时的哪个怀旧游戏你想和我一起玩？"}'),
  ('fun', 2, '{"en": "How does sharing laughter impact our bond?", "es": "¿Cómo impacta compartir risas en nuestro vínculo?", "fr": "Comment le fait de partager des rires influence-t-il notre lien ?", "it": "In che modo condividere le risate influenza il nostro legame?", "ko": "웃음을 공유하는 것이 우리의 유대에 어떻게 영향을 미치나요?", "nl": "Hoe beïnvloedt het delen van lachen onze band?", "zh": "分享笑声如何影响我们的关系？"}'),
  ('fun', 3, '{"en": "What wild adventure do you envision us having in the future?", "es": "¿Qué aventura salvaje imaginas que tendremos en el futuro?", "fr": "Quelle aventure folle envisages-tu que nous vivrons à l''avenir ?", "it": "Quale avventura selvaggia immagini che avremo in futuro?", "ko": "미래에 우리가 함께할 대단한 모험은 무엇이라고 상상하나요?", "nl": "Welk wild avontuur zie je ons in de toekomst beleven?", "zh": "你想象中的我们在未来可能会经历的疯狂冒险是什么？"}'),
  ('gratitude', 1, '{"en": "What''s a kind word I said recently that touched your heart?", "es": "¿Cuál es una palabra amable que dije recientemente que tocó tu corazón?", "fr": "Quel mot gentil ai-je dit récemment qui a touché ton cœur ?", "it": "Qual è una parola gentile che ho detto recentemente che ha toccato il tuo cuore?", "ko": "내가 최근에 한 말 중, 당신의 마음을 따뜻하게 한 것은 무엇인가요?", "nl": "Wat is een vriendelijk woord dat ik onlangs zei dat je hart raakte?", "zh": "我最近说的哪句贴心的话让你感动？"}'),
  ('gratitude', 2, '{"en": "How can practicing gratitude daily transform our relationship?", "es": "¿Cómo puede la práctica diaria de la gratitud transformar nuestra relación?", "fr": "Comment la pratique quotidienne de la gratitude peut-elle transformer notre relation ?", "it": "In che modo la pratica quotidiana della gratitudine può trasformare la nostra relazione?", "ko": "매일 감사하는 습관이 우리 관계를 어떻게 변화시킬 수 있을까요?", "nl": "Hoe kan dagelijkse beoefening van dankbaarheid onze relatie transformeren?", "zh": "每日感恩的练习如何改变我们的关系？"}'),
  ('gratitude', 3, '{"en": "How does showing gratitude deepen our emotional connection?", "es": "¿Cómo profundiza nuestra conexión emocional mostrar gratitud?", "fr": "Comment le fait de montrer de la gratitude approfondit-il notre connexion émotionnelle ?", "it": "In che modo mostrare gratitudine approfondisce la nostra connessione emotiva?", "ko": "감사를 표현하는 것이 우리의 정서적 연결을 어떻게 깊게 하나요?", "nl": "Hoe verdiept het tonen van dankbaarheid onze emotionele verbinding?", "zh": "展示感恩之情如何加深我们的情感联系？"}'),
  ('conflict', 1, '{"en": "What''s a time we resolved a conflict in a way that made you proud?", "es": "¿Cuál es una ocasión en que resolvimos un conflicto de una manera que te hizo sentir orgulloso?", "fr": "Quelle est une fois où nous avons résolu un conflit d''une manière qui t''a rendu fier ?", "it": "Qual è stata un''occasione in cui abbiamo risolto un conflitto in modo tale da renderti orgoglioso?", "ko": "우리가 갈등을 해결해 당신을 자랑스럽게 만든 경험은 무엇인가요?", "nl": "Wat is een moment dat we een conflict oplosten op een manier die je trots maakte?", "zh": "我们以让你感到自豪的方式解决问题的时刻是？"}'),
  ('conflict', 2, '{"en": "What do you think is essential for a constructive discussion during disagreements?", "es": "¿Qué crees que es esencial para una discusión constructiva durante desacuerdos?", "fr": "Qu''est-ce qui te semble essentiel pour une discussion constructive lors de désaccords ?", "it": "Cosa pensi sia essenziale per una discussione costruttiva durante i disaccordi?", "ko": "불일치 동안 건설적인 논의를 위해 무엇이 필수적이라고 생각하나요?", "nl": "Wat vind je essentieel voor een constructieve discussie tijdens meningsverschillen?", "zh": "你认为在分歧时进行建设性讨论的关键是什么？"}'),
  ('conflict', 3, '{"en": "Which conflict resolution approach has enhanced our relationship the most?", "es": "¿Qué enfoque de resolución de conflictos ha mejorado más nuestra relación?", "fr": "Quelle approche de résolution des conflits a le plus amélioré notre relation ?", "it": "Quale approccio alla risoluzione dei conflitti ha migliorato maggiormente la nostra relazione?", "ko": "우리의 관계를 가장 향상시킨 갈등 해결 접근 방식은 무엇인가요?", "nl": "Welke conflictoplossingsaanpak heeft onze relatie het meest verbeterd?", "zh": "哪种冲突解决方式最有效地改善了我们的关系？"}'),
  ('finances', 1, '{"en": "What fun, inexpensive activity would you love for us to do together?", "es": "¿Qué actividad divertida y económica te encantaría que hiciéramos juntos?", "fr": "Quelle activité amusante et peu coûteuse aimerais-tu que nous fassions ensemble ?", "it": "Quale attività divertente ed economica ti piacerebbe fare insieme?", "ko": "함께 하고 싶은 재미있고 저렴한 활동은 무엇인가요?", "nl": "Welke leuke, goedkope activiteit zou je graag samen met ons doen?", "zh": "你希望我们一起进行的有趣且经济的活动是什么？"}'),
  ('finances', 2, '{"en": "How do you feel about our current approach to budgeting?", "es": "¿Cómo te sientes acerca de nuestro enfoque actual para presupuestar?", "fr": "Que penses-tu de notre approche actuelle en matière de budget ?", "it": "Cosa pensi del nostro attuale approccio al budgeting?", "ko": "우리의 현재 예산 접근 방식에 대해 어떻게 느끼나요?", "nl": "Hoe voel je je over onze huidige aanpak van budgetteren?", "zh": "你对我们当前的预算方式有何看法？"}'),
  ('finances', 3, '{"en": "What financial principle is most important to you in our shared life?", "es": "¿Qué principio financiero es más importante para ti en nuestra vida compartida?", "fr": "Quel principe financier est le plus important pour toi dans notre vie partagée ?", "it": "Quale principio finanziario è più importante per te nella nostra vita condivisa?", "ko": "우리의 공동 생활에서 가장 중요한 금융 원칙은 무엇이라고 생각하나요?", "nl": "Welk financieel principe is het belangrijkst voor jou in ons gedeelde leven?", "zh": "在我们的共同生活中，哪个财务原则对你最重要？"}'),
  ('growth', 1, '{"en": "Where would you like to see us both grow together in the upcoming year?", "es": "¿Dónde te gustaría vernos crecer juntos en el próximo año?", "fr": "Où aimerais-tu nous voir grandir ensemble dans l''année à venir ?", "it": "Dove ti piacerebbe vederci crescere insieme nel prossimo anno?", "ko": "다음 해에 우리 둘이 함께 성장했으면 하는 부분은 무엇인가요?", "nl": "Waar zou je ons beiden samen willen zien groeien in het komende jaar?", "zh": "在新的一年里，你希望我们共同在哪方面有所进展？"}'),
  ('growth', 2, '{"en": "What area of personal development do you think impacts us most?", "es": "¿Qué área de desarrollo personal crees que nos impacta más?", "fr": "Quel domaine du développement personnel penses-tu qu''il nous impacte le plus ?", "it": "Quale area dello sviluppo personale pensi che ci influenzi di più?", "ko": "어떤 개인 개발 영역이 우리에게 가장 큰 영향을 미친다고 생각하나요?", "nl": "Welk gebied van persoonlijke ontwikkeling denk je dat ons het meest beïnvloedt?", "zh": "你认为哪个个人发展领域对我们影响最大？"}'),
  ('growth', 3, '{"en": "How do you perceive personal failures contributing to mutual growth?", "es": "¿Cómo percibes que los fracasos personales contribuyen al crecimiento mutuo?", "fr": "Comment perçois-tu que les échecs personnels contribuent à la croissance mutuelle ?", "it": "Come percepisci che i fallimenti personali contribuiscano alla crescita reciproca?", "ko": "개인적인 실패가 상호 성장에 기여한다고 생각하나요?", "nl": "Hoe zie je persoonlijke mislukkingen bijdragen aan wederzijdse groei?", "zh": "你如何看待个人失败对共同成长的贡献？"}'),
  ('family', 1, '{"en": "What''s a family activity you remember fondly from your childhood?", "es": "¿Cuál es una actividad familiar que recuerdas con cariño de tu infancia?", "fr": "Quelle est une activité familiale dont tu te souviens affectueusement de ton enfance ?", "it": "Qual è un''attività familiare che ricordi con affetto della tua infanzia?", "ko": "어린 시절에 좋았던 가족 활동은 무엇인가요?", "nl": "Wat is een gezinsactiviteit die je je met plezier herinnert uit je kindertijd?", "zh": "你童年时记忆深刻的一项家庭活动是什么？"}'),
  ('family', 2, '{"en": "How can our individual family experiences complement our relationship?", "es": "¿Cómo pueden nuestras experiencias familiares individuales complementar nuestra relación?", "fr": "Comment nos expériences familiales individuelles peuvent-elles compléter notre relation ?", "it": "Come possono le nostre esperienze familiari individuali completare la nostra relazione?", "ko": "개인의 가족 경험이 우리의 관계를 어떻게 보완할 수 있을까요?", "nl": "Hoe kunnen onze individuele familie-ervaringen onze relatie aanvullen?", "zh": "我们的个人家庭经历如何能补充我们之间的关系？"}'),
  ('family', 3, '{"en": "How do you see our family values evolving with time?", "es": "¿Cómo ves que nuestros valores familiares evolucionen con el tiempo?", "fr": "Comment vois-tu l''évolution de nos valeurs familiales avec le temps ?", "it": "Come vedi l''evolversi dei nostri valori familiari nel tempo?", "ko": "우리 가족의 가치관이 시간이 지남에 따라 어떻게 변할 것 같나요?", "nl": "Hoe zie je onze familiewaarden in de loop van de tijd evolueren?", "zh": "你认为我们的家庭价值观会随着时间如何变化？"}'),
  ('adventure', 1, '{"en": "Where''s a local place you''ve always wanted to explore with me?", "es": "¿Dónde hay un lugar local que siempre has querido explorar conmigo?", "fr": "Quel est un endroit local que tu as toujours voulu explorer avec moi ?", "it": "Qual è un posto locale che hai sempre voluto esplorare con me?", "ko": "나와 함께 탐험하고 싶었던 지역 장소는 어디인가요?", "nl": "Wat is een lokale plek die je altijd met mij hebt willen verkennen?", "zh": "你一直想和我一起探索的本地地方是哪？"}'),
  ('adventure', 2, '{"en": "How does planning an adventure together excite you for our future?", "es": "¿Cómo te emociona para nuestro futuro planear una aventura juntos?", "fr": "Comment la planification d''une aventure ensemble te passionne-t-elle pour notre avenir ?", "it": "In che modo pianificare un''avventura insieme ti entusiasma per il nostro futuro?", "ko": "함께 모험을 계획하면 미래에 대한 기대가 어떻게 생기나요?", "nl": "Hoe enthousiast maakt het plannen van een avontuur samen je voor onze toekomst?", "zh": "一起计划冒险如何激励你对我们的未来充满期待？"}'),
  ('adventure', 3, '{"en": "What unique perspectives do you gain from our shared adventures?", "es": "¿Qué perspectivas únicas obtienes de nuestras aventuras compartidas?", "fr": "Quelles perspectives uniques tires-tu de nos aventures partagées ?", "it": "Quali prospettive uniche ottieni dalle nostre avventure condivise?", "ko": "공유한 모험을 통해 얻는 독특한 시각은 무엇인가요?", "nl": "Welke unieke perspectieven verkrijg je uit onze gedeelde avonturen?", "zh": "我们共同冒险中你获得了哪些独特的观点？"}'),
  ('communication', 1, '{"en": "What''s one thing I do that makes you feel truly heard?", "es": "¿Qué hago que te hace sentir realmente escuchado?", "fr": "Quelle est une chose que je fais qui te fait te sentir vraiment écouté ?", "it": "Qual è una cosa che faccio che ti fa sentire veramente ascoltato?", "ko": "내가 하는 것 중 진정으로 당신이 들었다고 느끼는 것은 무엇인가요?", "nl": "Wat is één ding dat ik doe waardoor je je echt gehoord voelt?", "zh": "我做的哪件事让你感到被真正倾听了？"}'),
  ('communication', 1, '{"en": "How do you prefer I express my thoughts during a conversation with you?", "es": "¿Cómo prefieres que exprese mis pensamientos durante una conversación contigo?", "fr": "Comment préfères-tu que j''exprime mes pensées lors d''une conversation avec toi ?", "it": "Come preferisci che esprima i miei pensieri durante una conversazione con te?", "ko": "대화 중 내가 어떻게 생각을 표현하길 바라나요?", "nl": "Hoe heb je het liefst dat ik mijn gedachten uit tijdens een gesprek met jou?", "zh": "在与你交谈时，你更喜欢我如何表达我的想法？"}'),
  ('communication', 2, '{"en": "What''s a time when you felt our discussion could have been more effective?", "es": "¿Cuándo has sentido que nuestra discusión podría haber sido más efectiva?", "fr": "Quel est un moment où tu as senti que notre discussion aurait pu être plus efficace ?", "it": "Quando hai sentito che la nostra discussione avrebbe potuto essere più efficace?", "ko": "우리의 논의가 더 효과적일 수 있었다고 느꼈던 때는 언제인가요?", "nl": "Wanneer voelde je dat onze discussie effectiever had kunnen zijn?", "zh": "什么时候你觉得我们的讨论本可以更有效？"}'),
  ('communication', 2, '{"en": "How can we improve our communication to better understand each other?", "es": "¿Cómo podemos mejorar nuestra comunicación para entendernos mejor?", "fr": "Comment pouvons-nous améliorer notre communication pour mieux nous comprendre ?", "it": "Come possiamo migliorare la nostra comunicazione per capirci meglio?", "ko": "서로를 더 잘 이해하기 위해 통신을 어떻게 개선할 수 있을까요?", "nl": "Hoe kunnen we onze communicatie verbeteren om elkaar beter te begrijpen?", "zh": "我们如何改进沟通以更好地理解彼此？"}'),
  ('communication', 3, '{"en": "What communication barrier do you feel we need to overcome as a couple?", "es": "¿Qué barrera de comunicación sientes que necesitamos superar como pareja?", "fr": "Quelle barrière de communication sens-tu que nous devons surmonter en tant que couple ?", "it": "Quale barriera comunicativa pensi dobbiamo superare come coppia?", "ko": "커플로서 극복해야 한다고 느끼는 소통의 장애물은 무엇인가요?", "nl": "Welke communicatiebarrière voel je dat we als koppel moeten overwinnen?", "zh": "作为夫妻，你觉得我们需要克服哪个沟通障碍？"}'),
  ('communication', 3, '{"en": "What has been the most challenging conversation we''ve had, and what did you learn from it?", "es": "¿Cuál ha sido la conversación más desafiante que hemos tenido, y qué aprendiste de ella?", "fr": "Quelle a été la conversation la plus difficile que nous ayons eue, et qu''en as-tu appris ?", "it": "Qual è stata la conversazione più difficile che abbiamo avuto e cosa hai imparato da essa?", "ko": "우리가 가진 가장 어려운 대화는 무엇이었으며, 그것에서 무엇을 배웠나요?", "nl": "Wat is het meest uitdagende gesprek dat we hebben gehad en wat heb je ervan geleerd?", "zh": "我们进行的最具挑战性的话题是什么，你从中学到了什么？"}'),
  ('communication', 1, '{"en": "What''s your favorite way to have a serious but positive conversation together?", "es": "¿Cuál es tu forma favorita de tener una conversación seria pero positiva juntos?", "fr": "Quelle est ta façon préférée d''avoir une conversation sérieuse mais positive ensemble ?", "it": "Qual è il tuo modo preferito per avere una conversazione seria ma positiva insieme?", "ko": "진지하면서도 긍정적인 대화를 나누는 가장 좋아하는 방식은 무엇인가요?", "nl": "Wat is je favoriete manier om samen een serieus maar positief gesprek te voeren?", "zh": "你最喜欢和我一起进行认真但积极的对话的方式是什么？"}'),
  ('communication', 1, '{"en": "What setting do you feel most comfortable in when we''re discussing our future?", "es": "¿En qué entorno te sientes más cómodo cuando estamos discutiendo nuestro futuro?", "fr": "Dans quel cadre te sens-tu le plus à l''aise lorsque nous discutons de notre avenir ?", "it": "In quale contesto ti senti più a tuo agio quando discutiamo del nostro futuro?", "ko": "미래에 대해 이야기할 때 가장 편안한 환경은 무엇인가요?", "nl": "In welke omgeving voel je je het meest op je gemak als we onze toekomst bespreken?", "zh": "当我们讨论未来时，你在哪种环境下才感到最自在？"}'),
  ('communication', 2, '{"en": "How do you feel we can both ensure our voices are equally heard in discussions?", "es": "¿Cómo crees que ambos podemos asegurarnos de que nuestras voces se escuchen por igual en las discusiones?", "fr": "Comment penses-tu que nous pouvons nous assurer que nos voix soient entendues de manière égale lors des discussions ?", "it": "Come pensi che possiamo assicurarci che le nostre voci siano ascoltate in egual misura nelle discussioni?", "ko": "논의 중 우리의 목소리가 동등하게 들릴 수 있도록 어떻게 할 수 있을까요?", "nl": "Hoe denk je dat we ervoor kunnen zorgen dat onze stemmen beide gelijk worden gehoord in discussies?", "zh": "你觉得我们如何才能确保在讨论中彼此的声音都被平等地听到？"}'),
  ('communication', 2, '{"en": "When do you feel most connected to me emotionally during our talks?", "es": "¿Cuándo te sientes más conectado emocionalmente conmigo durante nuestras conversaciones?", "fr": "Quand te sens-tu le plus connecté émotionnellement à moi lors de nos discussions ?", "it": "Quando ti senti più connesso emotivamente a me durante le nostre conversazioni?", "ko": "우리 대화 중 언제 감정적으로 나와 가장 연결되어 있다고 느끼나요?", "nl": "Wanneer voel je je het meest emotioneel verbonden met mij tijdens onze gesprekken?", "zh": "在我们的谈话中，你什么时候感到与我情感上最为连结？"}'),
  ('communication', 3, '{"en": "If we could communicate on any topic more deeply, what would it be?", "es": "Si pudiéramos comunicar más profundamente sobre cualquier tema, ¿cuál sería?", "fr": "Si nous pouvions communiquer plus profondément sur n''importe quel sujet, quel serait-il ?", "it": "Se potessimo comunicare più profondamente su qualsiasi argomento, quale sarebbe?", "ko": "어떤 주제에 대해 더 깊이 대화할 수 있다면, 그것은 무엇일까요?", "nl": "Als we over elk onderwerp dieper zouden kunnen communiceren, wat zou het dan zijn?", "zh": "如果我们能更深入地探讨任何话题，那会是什么？"}'),
  ('communication', 1, '{"en": "What can I do to better understand your non-verbal cues?", "es": "¿Qué puedo hacer para entender mejor tus señales no verbales?", "fr": "Que puis-je faire pour mieux comprendre tes signaux non verbaux ?", "it": "Cosa posso fare per comprendere meglio i tuoi segnali non verbali?", "ko": "내가 당신의 비언어적 신호를 더 잘 이해하기 위해 무엇을 할 수 있을까요?", "nl": "Wat kan ik doen om jouw non-verbale signalen beter te begrijpen?", "zh": "我能做些什么来更好地理解你的非语言提示？"}'),
  ('communication', 1, '{"en": "How do you feel when we have long conversations?", "es": "¿Cómo te sientes cuando tenemos conversaciones largas?", "fr": "Comment te sens-tu lorsque nous avons de longues conversations ?", "it": "Come ti senti quando abbiamo conversazioni lunghe?", "ko": "긴 대화를 나눌 때 기분이 어떠신가요?", "nl": "Hoe voel je je als we lange gesprekken hebben?", "zh": "当我们进行长时间的对话时，你感觉如何？"}'),
  ('communication', 2, '{"en": "What kind of constructive feedback do you find most helpful?", "es": "¿Qué tipo de retroalimentación constructiva encuentras más útil?", "fr": "Quel type de retour constructif trouves-tu le plus utile ?", "it": "Che tipo di feedback costruttivo trovi più utile?", "ko": "가장 도움이 되는 건설적인 피드백은 어떤 것인가요?", "nl": "Welk soort constructieve feedback vind je het meest behulpzaam?", "zh": "你发现哪种建设性的反馈最有帮助？"}'),
  ('communication', 2, '{"en": "How can we turn disagreements into constructive conversations?", "es": "¿Cómo podemos convertir los desacuerdos en conversaciones constructivas?", "fr": "Comment pouvons-nous transformer les désaccords en conversations constructives ?", "it": "Come possiamo trasformare i disaccordi in conversazioni costruttive?", "ko": "의견 차이를 건설적인 대화로 전환할 수 있는 방법은 무엇인가요?", "nl": "Hoe kunnen we meningsverschillen omzetten in constructieve gesprekken?", "zh": "我们如何将分歧转变为建设性的对话？"}'),
  ('communication', 3, '{"en": "What are the unspoken things you wish I understood about how you communicate?", "es": "¿Cuáles son las cosas no dichas que deseas que entienda sobre cómo te comunicas?", "fr": "Quelles sont les choses non dites que tu aimerais que je comprenne à propos de ta façon de communiquer ?", "it": "Quali sono le cose non dette che desideri che io capisca sul tuo modo di comunicare?", "ko": "당신이 소통하는 방식에 대해 내가 이해하기를 바라는 비언어적 요소들은 무엇인가요?", "nl": "Wat zijn de onuitgesproken dingen die je wilt dat ik begrijp over hoe jij communiceert?", "zh": "关于你如何沟通，你希望我理解哪些未被说出口的事情？"}'),
  ('communication', 1, '{"en": "How do you feel about sharing your day during our daily check-ins?", "es": "¿Cómo te sientes al compartir tu día durante nuestros chequeos diarios?", "fr": "Comment te sens-tu à l''idée de partager ta journée lors de nos bilans quotidiens ?", "it": "Come ti senti nel condividere la tua giornata durante i nostri check-in giornalieri?", "ko": "우리의 일일 점검 시간 동안 하루를 공유하는 것에 대해 어떻게 느끼나요?", "nl": "Hoe voel je je bij het delen van je dag tijdens onze dagelijkse check-ins?", "zh": "在我们的日常查问中分享你的一天时，你的感觉如何？"}'),
  ('intimacy', 1, '{"en": "What small gesture do I do that makes you feel most loved?", "es": "¿Qué pequeño gesto hago que te hace sentir más amado?", "fr": "Quel petit geste fais-je qui te fait te sentir le plus aimé ?", "it": "Quale piccolo gesto faccio che ti fa sentire più amato?", "ko": "내가 하는 작은 행동 중 당신을 가장 사랑받는다고 느끼게 하는 것은 무엇인가요?", "nl": "Welk klein gebaar van mij zorgt ervoor dat je je het meest geliefd voelt?", "zh": "我做的哪个小动作让你感到最被爱？"}'),
  ('intimacy', 1, '{"en": "How do you like to show affection on a daily basis?", "es": "¿Cómo te gusta mostrar afecto diariamente?", "fr": "Comment aimes-tu montrer de l''affection au quotidien ?", "it": "Come ti piace mostrare affetto quotidianamente?", "ko": "매일 어떤 방식으로 애정을 표현하는 것을 좋아하나요?", "nl": "Hoe laat je dagelijks graag je genegenheid zien?", "zh": "你喜欢如何在日常中表示关心？"}'),
  ('intimacy', 2, '{"en": "What touch or gesture helps you feel most secure in our relationship?", "es": "¿Qué toque o gesto te ayuda a sentirte más seguro en nuestra relación?", "fr": "Quel contact ou geste t''aide à te sentir le plus en sécurité dans notre relation ?", "it": "Quale tocco o gesto ti aiuta a sentirti più sicuro nella nostra relazione?", "ko": "우리의 관계에서 가장 안전하다고 느끼게 하는 터치나 제스처는 무엇인가요?", "nl": "Welk aanraking of gebaar helpt je je het veiligst te voelen in onze relatie?", "zh": "哪种触碰或手势让你在我们的关系中感到最安全？"}'),
  ('intimacy', 2, '{"en": "How do you think we can deepen our emotional intimacy further?", "es": "¿Cómo crees que podemos profundizar aún más nuestra intimidad emocional?", "fr": "Comment penses-tu que nous pouvons approfondir notre intimité émotionnelle davantage ?", "it": "Come pensi che possiamo approfondire ulteriormente la nostra intimità emotiva?", "ko": "어떻게 하면 우리의 감정적 친밀감을 더 깊게 할 수 있을까요?", "nl": "Hoe denk je dat we onze emotionele intimiteit verder kunnen verdiepen?", "zh": "你认为我们如何能进一步加深情感亲密度？"}'),
  ('intimacy', 3, '{"en": "What fears do you have about intimacy, and how can I help alleviate them?", "es": "¿Qué miedos tienes sobre la intimidad y cómo puedo ayudar a aliviarlos?", "fr": "Quelles craintes as-tu concernant l''intimité, et comment puis-je aider à les atténuer ?", "it": "Quali paure hai riguardo l''intimità e come posso aiutare ad alleviarle?", "ko": "친밀감에 대한 두려움은 무엇이고 내가 그것을 어떻게 덜어줄 수 있을까요?", "nl": "Welke angsten heb je over intimiteit, en hoe kan ik helpen deze te verlichten?", "zh": "你对亲密关系有哪些恐惧，我能如何帮助减轻它们？"}'),
  ('intimacy', 3, '{"en": "What''s a vulnerable moment we shared that strengthened our bond?", "es": "¿Cuál es un momento vulnerable que compartimos que fortaleció nuestro vínculo?", "fr": "Quel est un moment vulnérable que nous avons partagé qui a renforcé notre lien ?", "it": "Qual è un momento di vulnerabilità che abbiamo condiviso che ha rafforzato il nostro legame?", "ko": "우리가 공유한 취약한 순간 중 우리 관계를 강화한 것이 무엇인가요?", "nl": "Wat is een kwetsbaar moment dat we deelden dat onze band versterkte?", "zh": "我们分享过的哪个脆弱时刻加强了我们的联系？"}'),
  ('intimacy', 1, '{"en": "What''s one thing we can do regularly to nurture our connection?", "es": "¿Cuál es una cosa que podemos hacer regularmente para nutrir nuestra conexión?", "fr": "Quelle est une chose que nous pouvons faire régulièrement pour nourrir notre connexion ?", "it": "Qual è una cosa che possiamo fare regolarmente per nutrire la nostra connessione?", "ko": "우리의 관계를 키우기 위해 정기적으로 할 수 있는 일은 무엇인가요?", "nl": "Wat is één ding dat we regelmatig kunnen doen om onze connectie te voeden?", "zh": "我们可以定期做些什么来培养我们的联系？"}'),
  ('intimacy', 1, '{"en": "How do you prefer for us to spend quality time together?", "es": "¿Cómo prefieres que pasemos tiempo de calidad juntos?", "fr": "Comment préfères-tu que nous passions du temps de qualité ensemble ?", "it": "Come preferisci che passiamo del tempo di qualità insieme?", "ko": "우리가 함께 질 좋은 시간을 보내는 것을 어떻게 선호하나요?", "nl": "Hoe heb je het liefst dat we samen quality time doorbrengen?", "zh": "你希望我们如何一起度过高质量的时光？"}'),
  ('intimacy', 2, '{"en": "How do you feel about our balance between physical and emotional intimacy?", "es": "¿Cómo te sientes acerca de nuestro equilibrio entre la intimidad física y emocional?", "fr": "Que penses-tu de notre équilibre entre l''intimité physique et émotionnelle ?", "it": "Cosa pensi del nostro equilibrio tra intimità fisica ed emotiva?", "ko": "신체적 친밀감과 감정적 친밀감의 균형에 대해 어떻게 생각하나요?", "nl": "Hoe vind je de balans tussen onze fysieke en emotionele intimiteit?", "zh": "你觉得我们在身体和情感亲密之间的平衡如何？"}'),
  ('intimacy', 2, '{"en": "What intimate moments make you feel closest to me?", "es": "¿Qué momentos íntimos te hacen sentir más cerca de mí?", "fr": "Quels moments intimes te font te sentir le plus proche de moi ?", "it": "Quali momenti intimi ti fanno sentire più vicino a me?", "ko": "가장 가깝게 느끼게 해주는 친밀한 순간은 무엇인가요?", "nl": "Welke intieme momenten laten je je het dichtst bij mij voelen?", "zh": "哪些亲密时刻让你觉得离我最近？"}'),
  ('intimacy', 3, '{"en": "What are some intimate experiences you dream of sharing with me?", "es": "¿Cuáles son algunas experiencias íntimas que sueñas con compartir conmigo?", "fr": "Quelles sont les expériences intimes que tu rêves de partager avec moi ?", "it": "Quali esperienze intime sogni di condividere con me?", "ko": "나와 함께 공유하기를 꿈꾸는 친밀한 경험은 무엇인가요?", "nl": "Welke intieme ervaringen droom je ervan met mij te delen?", "zh": "你梦想与我分享哪些亲密的经历？"}'),
  ('intimacy', 1, '{"en": "How do you feel about our current level of openness with each other?", "es": "¿Qué opinas sobre nuestro nivel actual de apertura el uno con el otro?", "fr": "Que penses-tu de notre niveau d''ouverture actuel l''un envers l''autre ?", "it": "Cosa pensi del nostro attuale livello di apertura l''uno con l''altro?", "ko": "현재 서로에게 개방적인 정도에 대해 어떻게 생각하나요?", "nl": "Hoe vind je ons huidige niveau van openheid naar elkaar toe?", "zh": "你对我们目前彼此的开放程度怎么看？"}'),
  ('intimacy', 1, '{"en": "What scent reminds you of me the most?", "es": "¿Qué aroma te recuerda más a mí?", "fr": "Quelle odeur te rappelle le plus moi ?", "it": "Quale profumo ti ricorda più di me?", "ko": "어떤 향기가 나를 가장 많이 생각나게 하나요?", "nl": "Welke geur herinnert je het meest aan mij?", "zh": "什么气味最能让你想起我？"}'),
  ('intimacy', 2, '{"en": "How do you feel our intimacy has evolved since we started dating?", "es": "¿Cómo sientes que nuestra intimidad ha evolucionado desde que empezamos a salir?", "fr": "Comment ressens-tu l''évolution de notre intimité depuis que nous avons commencé à sortir ensemble ?", "it": "Come senti che la nostra intimità si è evoluta da quando abbiamo iniziato a frequentarci?", "ko": "우리가 데이트를 시작한 이후로 우리의 친밀감이 어떻게 변화했다고 생각하나요?", "nl": "Hoe vind je dat onze intimiteit zich heeft ontwikkeld sinds we daten?", "zh": "你觉得自从我们开始约会后，我们的亲密关系有什么变化？"}'),
  ('intimacy', 2, '{"en": "What does an ideal intimate evening look like for you?", "es": "¿Cómo es una noche íntima ideal para ti?", "fr": "À quoi ressemble une soirée intime idéale pour toi ?", "it": "Com''è una serata intima ideale per te?", "ko": "이상적인 친밀한 저녁은 당신에게 어떤 모습인가요?", "nl": "Hoe ziet een ideale intieme avond er voor jou uit?", "zh": "对你来说，理想的亲密夜晚是什么样的？"}'),
  ('intimacy', 3, '{"en": "What secrets or stories do you hope we can share in the future to deepen our intimacy?", "es": "¿Qué secretos o historias esperas compartir en el futuro para profundizar nuestra intimidad?", "fr": "Quels secrets ou histoires espères-tu que nous puissions partager à l''avenir pour approfondir notre intimité ?", "it": "Quali segreti o storie speri di condividere in futuro per approfondire la nostra intimità?", "ko": "우리의 친밀감을 더욱 깊어지게 할 미래의 비밀이나 이야기는 무엇인가요?", "nl": "Welke geheimen of verhalen hoop je in de toekomst te delen om onze intimiteit te verdiepen?", "zh": "你希望我们在未来分享哪些秘密或故事以加深我们的亲密关系？"}'),
  ('intimacy', 1, '{"en": "What physical gesture from me makes you feel the most appreciated?", "es": "¿Qué gesto físico de mi parte te hace sentir más apreciado?", "fr": "Quel geste physique de ma part te fait te sentir le plus apprécié ?", "it": "Quale gesto fisico da parte mia ti fa sentire più apprezzato?", "ko": "내가 하는 어떤 신체적 표현이 가장 감사하게 느껴지나요?", "nl": "Welk fysiek gebaar van mij laat je je het meest gewaardeerd voelen?", "zh": "我做的哪些肢体动作让你感受到最被欣赏？"}'),
  ('dreams', 1, '{"en": "What''s one dream you''ve had since childhood that you still wish to achieve?", "es": "¿Cuál es un sueño que has tenido desde la infancia que aún deseas lograr?", "fr": "Quel est un rêve que tu as depuis l''enfance et que tu souhaites encore réaliser ?", "it": "Qual è un sogno che hai dall''infanzia e che vorresti ancora realizzare?", "ko": "어린 시절부터 간직해온 꿈 중 아직 이루고 싶은 것은 무엇인가요?", "nl": "Wat is een droom die je sinds je kindertijd hebt en die je nog steeds wilt realiseren?", "zh": "你从小就有的一个梦想是什么，你仍希望实现？"}'),
  ('dreams', 1, '{"en": "What would your dream vacation with me look like?", "es": "¿Cómo sería tu viaje de ensueño conmigo?", "fr": "À quoi ressembleraient tes vacances de rêve avec moi ?", "it": "Come sarebbe la tua vacanza da sogno con me?", "ko": "나와 함께하는 꿈의 휴가는 어떤 모습일까요?", "nl": "Hoe zou jouw droomvakantie met mij eruitzien?", "zh": "和我一起的梦想假期是什么样的？"}'),
  ('dreams', 2, '{"en": "What dreams do you have for us in the next five years?", "es": "¿Qué sueños tienes para nosotros en los próximos cinco años?", "fr": "Quels rêves as-tu pour nous dans les cinq prochaines années ?", "it": "Quali sogni hai per noi nei prossimi cinque anni?", "ko": "앞으로 5년 동안 우리를 위한 꿈은 무엇인가요?", "nl": "Welke dromen heb je voor ons in de komende vijf jaar?", "zh": "未来五年你对我们的梦想是什么？"}'),
  ('dreams', 2, '{"en": "How do you envision your ideal future, and how can we work towards it together?", "es": "¿Cómo imaginas tu futuro ideal y cómo podemos trabajar juntos para lograrlo?", "fr": "Comment envisages-tu ton avenir idéal, et comment pouvons-nous y travailler ensemble ?", "it": "Come immagini il tuo futuro ideale e come possiamo lavorarci insieme?", "ko": "당신이 생각하는 이상적인 미래는 어떤 모습이며, 그것을 위해 어떻게 함께 노력할 수 있을까요?", "nl": "Hoe zie je jouw ideale toekomst voor je, en hoe kunnen we daar samen naartoe werken?", "zh": "你如何设想理想的未来，我们如何可以一起努力实现？"}'),
  ('dreams', 3, '{"en": "What long-term dream have you never shared with anyone?", "es": "¿Qué sueño a largo plazo nunca has compartido con nadie?", "fr": "Quel rêve à long terme n''as-tu jamais partagé avec quelqu''un ?", "it": "Quale sogno a lungo termine non hai mai condiviso con nessuno?", "ko": "아직 누구에게도 말하지 않은 장기적인 꿈은 무엇인가요?", "nl": "Welk langdurig droom heb je nooit met iemand gedeeld?", "zh": "你从未与任何人分享的长期梦想是什么？"}'),
  ('dreams', 3, '{"en": "How can I support you in pursuing a dream that''s deeply personal to you?", "es": "¿Cómo puedo apoyarte en la búsqueda de un sueño que sea profundamente personal para ti?", "fr": "Comment puis-je te soutenir dans la poursuite d''un rêve qui t''est profondément personnel ?", "it": "Come posso supportarti nel perseguire un sogno che è profondamente personale per te?", "ko": "당신에게 깊이 개인적인 꿈을 추구하는 데 내가 어떻게 지원할 수 있을까요?", "nl": "Hoe kan ik je ondersteunen bij het najagen van een droom die erg persoonlijk voor je is?", "zh": "我如何支持你追求一个对你非常个人的梦想？"}'),
  ('dreams', 1, '{"en": "What''s one thing you hope will never change about our future together?", "es": "¿Qué es una cosa que esperas que nunca cambie sobre nuestro futuro juntos?", "fr": "Quelle est la chose que tu espères ne jamais voir changer à propos de notre futur ensemble ?", "it": "Qual è una cosa che speri non cambi mai nel nostro futuro insieme?", "ko": "우리 함께하는 미래에 결코 변하지 않기를 바라는 한 가지는 무엇인가요?", "nl": "Wat is een ding dat je hoopt dat nooit zal veranderen aan onze toekomst samen?", "zh": "关于我们未来的一件事你希望永远不会改变？"}'),
  ('dreams', 1, '{"en": "What new hobby or activity have you always dreamed of trying?", "es": "¿Qué nuevo pasatiempo o actividad siempre has soñado probar?", "fr": "Quel nouveau passe-temps ou activité as-tu toujours rêvé d''essayer ?", "it": "Quale nuovo hobby o attività hai sempre sognato di provare?", "ko": "항상 시도해보고 싶었던 새로운 취미나 활동은 무엇인가요?", "nl": "Welke nieuwe hobby of activiteit heb je altijd al eens willen proberen?", "zh": "你梦想尝试的新爱好或活动是什么？"}'),
  ('dreams', 2, '{"en": "What dream do you think would help us grow closer as a couple?", "es": "¿Qué sueño crees que nos ayudaría a acercarnos más como pareja?", "fr": "Quel rêve penses-tu qui nous aiderait à nous rapprocher en tant que couple ?", "it": "Quale sogno pensi che ci aiuterebbe ad avvicinarci come coppia?", "ko": "우리 커플이 더 가까워질 수 있게 도와줄 꿈은 무엇이라고 생각하나요?", "nl": "Welk droom denk je dat ons zou helpen om dichterbij elkaar te komen als koppel?", "zh": "你认为哪个梦想会帮助我们作为一对夫妇更亲近？"}'),
  ('dreams', 2, '{"en": "In what ways can we make our dreams a reality together?", "es": "¿De qué maneras podemos hacer realidad nuestros sueños juntos?", "fr": "De quelles manières pouvons-nous ensemble transformer nos rêves en réalité ?", "it": "In che modo possiamo trasformare i nostri sogni in realtà insieme?", "ko": "어떤 방법으로 함께 우리의 꿈을 현실로 만들 수 있을까요?", "nl": "Op welke manieren kunnen we onze dromen samen werkelijkheid maken?", "zh": "我们可以通过哪些方式一起实现我们的梦想？"}'),
  ('dreams', 3, '{"en": "What''s the most meaningful dream you have for us both, and why?", "es": "¿Cuál es el sueño más significativo que tienes para ambos y por qué?", "fr": "Quel est le rêve le plus significatif que tu as pour nous deux, et pourquoi ?", "it": "Qual è il sogno più significativo che hai per entrambi, e perché?", "ko": "우리 둘을 위한 가장 의미있는 꿈은 무엇이며, 그 이유는 무엇인가요?", "nl": "Wat is de meest betekenisvolle droom die je voor ons beiden hebt, en waarom?", "zh": "你对我们两人来说最有意义的梦想是什么，为什么？"}'),
  ('dreams', 1, '{"en": "What''s a shared goal you hope we can accomplish together?", "es": "¿Cuál es un objetivo compartido que esperas que podamos lograr juntos?", "fr": "Quel est un objectif partagé que tu espères que nous puissions accomplir ensemble ?", "it": "Qual è un obiettivo condiviso che speri di poter raggiungere insieme?", "ko": "우리가 함께 달성하길 바라는 공동 목표는 무엇인가요?", "nl": "Wat is een gedeeld doel dat je hoopt dat we samen kunnen bereiken?", "zh": "你希望我们能一起实现的共同目标是什么？"}'),
  ('dreams', 1, '{"en": "If you could wake up tomorrow with one dream realized, which would it be?", "es": "Si pudieras despertar mañana con un sueño realizado, ¿cuál sería?", "fr": "Si tu pouvais te réveiller demain avec un rêve réalisé, lequel serait-ce ?", "it": "Se potessi svegliarti domani con un sogno realizzato, quale sarebbe?", "ko": "내일 아침 눈을 떴을 때 한 가지 꿈이 이루어져 있다면, 무엇이었으면 좋겠나요?", "nl": "Als je morgen wakker kon worden met één gerealiseerde droom, welke zou dat zijn?", "zh": "如果明天醒来时实现了一个梦想，那会是哪一个？"}'),
  ('dreams', 2, '{"en": "How do you feel about the progress we''re making on our shared dreams?", "es": "¿Cómo te sientes acerca del progreso que estamos haciendo en nuestros sueños compartidos?", "fr": "Que penses-tu des progrès que nous faisons sur nos rêves partagés ?", "it": "Cosa pensi dei progressi che stiamo facendo nei nostri sogni condivisi?", "ko": "우리의 공동 꿈에 대한 진행 상황에 대해 어떻게 생각하나요?", "nl": "Hoe denk je over de voortgang die we maken met onze gedeelde dromen?", "zh": "你对我们在共同梦想上取得的进展有何感想？"}'),
  ('dreams', 2, '{"en": "What dream of ours do you think will require the most teamwork?", "es": "¿Qué sueño nuestro crees que requerirá más trabajo en equipo?", "fr": "Quel rêve penses-tu de nous nécessitera le plus de travail d''équipe ?", "it": "Quale dei nostri sogni pensi che richiederà più lavoro di squadra?", "ko": "우리의 꿈들 중 어떤 것이 가장 많은 팀워크가 필요할 것 같나요?", "nl": "Welke van onze dromen denk je dat het meeste teamwork vereist?", "zh": "你认为我们的哪个梦想最需要团队合作？"}'),
  ('dreams', 3, '{"en": "What does achieving your ultimate dream look like, and how do you imagine it affecting us?", "es": "¿Cómo sería alcanzar tu sueño máximo y cómo imaginas que nos afectaría?", "fr": "À quoi ressemble la réalisation de ton rêve ultime, et comment imagines-tu que cela nous affectera ?", "it": "Com''è raggiungere il tuo sogno definitivo e come immagini che ci influenzi?", "ko": "궁극적인 꿈을 이루는 것이 어떻게 보이고, 그것이 우리에게 어떻게 영향을 미칠 것이라고 상상하나요?", "nl": "Hoe ziet het behalen van jouw ultieme droom eruit, en hoe stel je je voor dat dit ons zal beïnvloeden?", "zh": "实现你最终梦想的样子如何，你想象它会如何影响我们？"}'),
  ('dreams', 1, '{"en": "What''s a fun dream we could work on together over a weekend?", "es": "¿Cuál es un sueño divertido en el que podríamos trabajar juntos durante un fin de semana?", "fr": "Quel est un rêve amusant sur lequel nous pourrions travailler ensemble pendant un week-end ?", "it": "Qual è un sogno divertente su cui potremmo lavorare insieme durante un weekend?", "ko": "주말 동안 함께 실현할 수 있는 재미있는 꿈은 무엇인가요?", "nl": "Wat is een leuke droom waar we samen aan kunnen werken in een weekend?", "zh": "周末我们可以一起实现的有趣梦想是什么？"}'),
  ('memories', 1, '{"en": "What''s your favorite memory of a spontaneous adventure we had together?", "es": "¿Cuál es tu recuerdo favorito de una aventura espontánea que tuvimos juntos?", "fr": "Quel est ton souvenir préféré d''une aventure spontanée que nous avons eue ensemble ?", "it": "Qual è il tuo ricordo preferito di un''avventura spontanea che abbiamo avuto insieme?", "ko": "함께한 즉흥적인 모험에서 가장 좋아하는 기억은 무엇인가요?", "nl": "Wat is je favoriete herinnering aan een spontane avontuur die we samen hebben gehad?", "zh": "你最喜欢的我们一起经历过的自发冒险的回忆是什么？"}'),
  ('memories', 1, '{"en": "Which of our past vacations do you remember most fondly?", "es": "¿Cuál de nuestras vacaciones pasadas recuerdas con más cariño?", "fr": "Laquelle de nos vacances passées te rappelle-tu avec le plus de tendresse ?", "it": "Quale delle nostre vacanze passate ricordi con più affetto?", "ko": "우리의 과거 휴가 중 가장 애정 어린 기억을 갖고 있는 것은 무엇인가요?", "nl": "Van welke van onze afgelopen vakanties heb je de dierbaarste herinnering?", "zh": "我们过去的假期中哪次让你记忆最美好？"}'),
  ('memories', 2, '{"en": "What''s an early memory of us that still makes you smile?", "es": "¿Cuál es un recuerdo temprano de nosotros que todavía te hace sonreír?", "fr": "Quel est un de nos premiers souvenirs qui te fait encore sourire ?", "it": "Qual è un primo ricordo di noi che ti fa ancora sorridere?", "ko": "아직도 미소 짓게 만드는 우리의 초기 기억은 무엇인가요?", "nl": "Wat is een van onze vroege herinneringen die je nog steeds doen glimlachen?", "zh": "关于我们最初的一个美好回忆是什么，仍然让你会心一笑？"}'),
  ('memories', 2, '{"en": "What memory do you think best represents the essence of our relationship?", "es": "¿Qué recuerdo crees que mejor representa la esencia de nuestra relación?", "fr": "Quel souvenir penses-tu représente le mieux l''essence de notre relation ?", "it": "Quale ricordo pensi rappresenti meglio l''essenza della nostra relazione?", "ko": "우리 관계의 본질을 가장 잘 나타내는 기억은 무엇이라고 생각하나요?", "nl": "Welk geheugen denk je dat het best de essentie van onze relatie vertegenwoordigt?", "zh": "你认为哪个记忆最能代表我们关系的本质？"}'),
  ('memories', 3, '{"en": "Which moment in our journey together has been most defining for you, and why?", "es": "¿Qué momento de nuestro viaje juntos ha sido más definitorio para ti y por qué?", "fr": "Quel moment de notre parcours ensemble a été le plus marquant pour toi, et pourquoi ?", "it": "Qual è stato il momento più significativo nel nostro viaggio insieme per te e perché?", "ko": "함께한 여정 중 당신에게 가장 정의로운 순간은 무엇이며, 그 이유는 무엇인가요?", "nl": "Welk moment in onze gezamenlijke reis is het meest bepalend voor jou geweest, en waarom?", "zh": "在我们的旅程中，哪个时刻对你最具决定性，为什么？"}'),
  ('memories', 3, '{"en": "What''s a profound memory of growth in our relationship that stands out to you?", "es": "¿Cuál es un recuerdo profundo de crecimiento en nuestra relación que destaca para ti?", "fr": "Quel est un souvenir profond de croissance dans notre relation qui te marque particulièrement ?", "it": "Qual è un ricordo profondo di crescita nella nostra relazione che ti colpisce?", "ko": "우리 관계에서 성장의 깊은 기억이 떠오르는 것이 있나요?", "nl": "Wat is een diepzinnig herinnering aan groei in onze relatie die jou opvalt?", "zh": "在我们的关系中，有什么突出的成长记忆让你特别难忘的？"}'),
  ('memories', 1, '{"en": "What''s a silly memory we share that always makes you laugh?", "es": "¿Cuál es un recuerdo tonto que compartimos que siempre te hace reír?", "fr": "Quel est un souvenir idiot que nous partageons qui te fait toujours rire ?", "it": "Qual è un ricordo sciocco che condividiamo che ti fa sempre ridere?", "ko": "저희가 공유하는 바보같은 기억 중 항상 웃게 만드는 것이 무엇인가요?", "nl": "Wat is een grappige herinnering die we delen die je altijd aan het lachen maakt?", "zh": "我们分享的哪个愚蠢的记忆总是让你发笑？"}'),
  ('memories', 1, '{"en": "What song reminds you of a special memory between us?", "es": "¿Qué canción te recuerda a un recuerdo especial entre nosotros?", "fr": "Quelle chanson te rappelle un souvenir spécial entre nous ?", "it": "Quale canzone ti ricorda un ricordo speciale tra di noi?", "ko": "우리 사이의 특별한 추억을 떠올리게 하는 노래는 무엇인가요?", "nl": "Welk liedje herinnert je aan een speciale herinnering tussen ons?", "zh": "哪首歌让你想起我们之间的特别回忆？"}'),
  ('memories', 2, '{"en": "What memory would you like to recreate or relive together?", "es": "¿Qué recuerdo te gustaría recrear o revivir juntos?", "fr": "Quel souvenir aimerais-tu recréer ou revivre ensemble ?", "it": "Quale ricordo ti piacerebbe ricreare o rivivere insieme?", "ko": "어떤 기억을 함께 재현하거나 다시 살고 싶으신가요?", "nl": "Welke herinnering zou je graag opnieuw willen creëren of herbeleven samen?", "zh": "你想和我一起重现或重温哪个记忆？"}'),
  ('memories', 2, '{"en": "How can we create more meaningful memories together going forward?", "es": "¿Cómo podemos crear recuerdos más significativos juntos en el futuro?", "fr": "Comment pouvons-nous créer des souvenirs plus significatifs ensemble à l''avenir ?", "it": "Come possiamo creare ricordi più significativi insieme andando avanti?", "ko": "앞으로 우리가 더 의미 있는 추억을 함께 만들려면 어떻게 해야 할까요?", "nl": "Hoe kunnen we samen meer betekenisvolle herinneringen creëren in de toekomst?", "zh": "我们如何在未来共同创造更有意义的记忆？"}'),
  ('memories', 3, '{"en": "What''s a cherished memory you have from your past that has shaped who you are today?", "es": "¿Cuál es un recuerdo apreciado de tu pasado que ha formado quién eres hoy?", "fr": "Quel est un souvenir précieux de ton passé qui a façonné qui tu es aujourd''hui ?", "it": "Qual è un ricordo prezioso del tuo passato che ha modellato chi sei oggi?", "ko": "당신의 과거에서 당신이 오늘날의 당신이 되도록 형성한 소중한 기억은 무엇인가요?", "nl": "Wat is een gekoesterde herinnering uit je verleden die je gevormd heeft tot wie je nu bent?", "zh": "你过去珍惜的哪个记忆塑造了今天的你？"}'),
  ('memories', 1, '{"en": "What''s one of your fondest memories from our first year together?", "es": "¿Cuál es uno de tus recuerdos más queridos de nuestro primer año juntos?", "fr": "Quel est un de tes meilleurs souvenirs de notre première année ensemble ?", "it": "Qual è uno dei tuoi ricordi più cari del nostro primo anno insieme?", "ko": "우리가 함께한 첫해 중 가장 소중한 기억 중 하나는 무엇인가요?", "nl": "Wat is een van je meest geliefde herinneringen uit ons eerste jaar samen?", "zh": "在我们在一起的第一年中，哪一个是你最珍惜的记忆？"}'),
  ('memories', 1, '{"en": "What past celebration of ours do you remember most fondly?", "es": "¿Qué celebración pasada nuestra recuerdas con más cariño?", "fr": "Quelle célébration passée de nous te souviens-tu le plus affectueusement ?", "it": "Quale celebrazione passata ricordi con più affetto?", "ko": "우리의 지난 축하 중 가장 기억에 남는 것은 무엇인가요?", "nl": "Welke afgelopen viering van ons herinner je je het meest liefdevol?", "zh": "你最怀念我们过去的哪个庆祝活动？"}'),
  ('memories', 2, '{"en": "What memory of personal achievement do you cherish the most?", "es": "¿Qué recuerdo de logro personal atesoras más?", "fr": "Quel souvenir de réussite personnelle chéris-tu le plus ?", "it": "Quale ricordo di successo personale ti sta più a cuore?", "ko": "가장 소중히 여기는 개인적 성취의 기억은 무엇인가요?", "nl": "Welke herinnering aan persoonlijke prestatie koester je het meest?", "zh": "哪段个人成就的记忆是你最珍惜的？"}'),
  ('memories', 2, '{"en": "What is a comforting memory of us that you fall back on during tough times?", "es": "¿Cuál es un recuerdo reconfortante de nosotros en el que te apoyas durante tiempos difíciles?", "fr": "Quel est un souvenir réconfortant de nous sur lequel tu reviens pendant les moments difficiles ?", "it": "Qual è un ricordo confortante di noi su cui fai affidamento nei momenti difficili?", "ko": "힘든 시기에 의지할 수 있는 우리에 대한 위로가 되는 기억은 무엇인가요?", "nl": "Wat is een troostende herinnering aan ons waar je op terugvalt tijdens zware tijden?", "zh": "在艰难时刻，你依赖的我们之间的哪个安慰记忆？"}'),
  ('memories', 3, '{"en": "What''s a deep connection we''ve shared in our relationship that strengthened our bond?", "es": "¿Qué conexión profunda hemos compartido en nuestra relación que ha fortalecido nuestro vínculo?", "fr": "Quelle est une connexion profonde que nous avons partagée dans notre relation qui a renforcé notre lien ?", "it": "Qual è una connessione profonda che abbiamo condiviso nella nostra relazione che ha rafforzato il nostro legame?", "ko": "우리 관계에서 우리가 공유하여 유대를 강화한 깊은 연결은 무엇인가요?", "nl": "Wat is een diepe verbinding die we hebben gedeeld in onze relatie die onze band heeft versterkt?", "zh": "在我们的关系中，我们分享的哪个深刻联系加强了我们的纽带？"}'),
  ('memories', 1, '{"en": "What''s a fun memory from a family gathering we''ve attended together?", "es": "¿Cuál es un recuerdo divertido de una reunión familiar a la que hemos asistido juntos?", "fr": "Quel est un souvenir amusant d''une réunion de famille à laquelle nous avons assisté ensemble ?", "it": "Qual è un ricordo divertente di una riunione familiare a cui abbiamo partecipato insieme?", "ko": "함께 참석한 가족 모임에서의 재미있는 기억은 무엇인가요?", "nl": "Wat is een leuke herinnering van een familiereünie die we samen hebben bijgewoond?", "zh": "从我们一起参加过的家庭聚会中，有什么有趣的记忆吗？"}'),
  ('values', 1, '{"en": "What''s a core value of yours that you hope I understand and respect?", "es": "¿Cuál es un valor fundamental tuyo que esperas que yo entienda y respete?", "fr": "Quelle est une valeur fondamentale à toi que tu espères que je comprenne et respecte ?", "it": "Qual è un valore fondamentale tuo che speri io capisca e rispetti?", "ko": "당신이 이해하고 존중받기를 바라는 핵심 가치관은 무엇인가요?", "nl": "Wat is een kernwaarde van jou waarvan je hoopt dat ik deze begrijp en respecteer?", "zh": "你希望我理解并尊重你的哪个核心价值观？"}'),
  ('values', 1, '{"en": "What principle do you believe defines our relationship?", "es": "¿Qué principio crees que define nuestra relación?", "fr": "Quel principe crois-tu définit notre relation ?", "it": "Quale principio credi definisca la nostra relazione?", "ko": "우리 관계를 정의한다고 믿는 원칙은 무엇인가요?", "nl": "Welk principe vind je dat onze relatie definieert?", "zh": "你认为哪个原则定义了我们的关系？"}'),
  ('values', 2, '{"en": "How do our values align, and how do they differ in a way that balances us?", "es": "¿Cómo se alinean nuestros valores y cómo difieren de una manera que nos equilibra?", "fr": "Comment nos valeurs s''alignent-elles et en quoi diffèrent-elles de manière à nous équilibrer ?", "it": "Come si allineano i nostri valori e in che modo differiscono per equilibrarci?", "ko": "우리의 가치관은 어떻게 일치하며, 어떻게 다르게 균형을 이루고 있나요?", "nl": "Hoe sluiten onze waarden op elkaar aan en hoe verschillen ze op een manier die ons in balans houdt?", "zh": "我们的价值观是如何一致的，又如何在差异中达到平衡？"}'),
  ('values', 2, '{"en": "What value is most essential to a fulfilling life together?", "es": "¿Qué valor es más esencial para una vida plena juntos?", "fr": "Quelle valeur est la plus essentielle pour une vie épanouissante ensemble ?", "it": "Qual è il valore più essenziale per una vita appagante insieme?", "ko": "함께하는 만족스러운 삶을 위해 가장 필수적인 가치는 무엇인가요?", "nl": "Welke waarde is het meest essentieel voor een vervuld leven samen?", "zh": "对于共同的充实生活，哪个价值观最为重要？"}'),
  ('values', 3, '{"en": "Which of our values do you see as fundamental to our future together?", "es": "¿Cuál de nuestros valores ves como fundamental para nuestro futuro juntos?", "fr": "Lequel de nos valeurs vois-tu comme fondamental pour notre avenir ensemble ?", "it": "Quale dei nostri valori consideri fondamentale per il nostro futuro insieme?", "ko": "우리의 가치 중 무엇이 함께하는 미래에 근본적이라고 생각하나요?", "nl": "Welke van onze waarden zie je als fundamenteel voor onze toekomst samen?", "zh": "你认为我们哪种价值观对于我们共同的未来至关重要？"}'),
  ('values', 3, '{"en": "What is a value you''ve formed based on a significant life event?", "es": "¿Cuál es un valor que has formado basado en un evento significativo en tu vida?", "fr": "Quelle est une valeur que tu as formée basée sur un événement significatif de ta vie ?", "it": "Qual è un valore che hai sviluppato basato su un evento significativo della tua vita?", "ko": "중요한 사건을 바탕으로 형성된 당신의 가치는 무엇인가요?", "nl": "Wat is een waarde die je hebt gevormd op basis van een belangrijke levensgebeurtenis?", "zh": "你基于一个重大生活事件形成的价值观是什么？"}'),
  ('values', 1, '{"en": "What do you see as my strongest personal value?", "es": "¿Cuál ves como mi valor personal más fuerte?", "fr": "Quelle est, selon toi, ma plus grande valeur personnelle ?", "it": "Qual è il mio valore personale più forte secondo te?", "ko": "당신이 보는 제 가장 강력한 개인적 가치는 무엇인가요?", "nl": "Wat zie je als mijn sterkste persoonlijke waarde?", "zh": "你认为我最强的个人价值观是什么？"}'),
  ('values', 1, '{"en": "How have your values evolved since we''ve been together?", "es": "¿Cómo han evolucionado tus valores desde que estamos juntos?", "fr": "Comment tes valeurs ont-elles évolué depuis que nous sommes ensemble ?", "it": "Come sono evoluti i tuoi valori da quando siamo insieme?", "ko": "우리가 함께한 이후 당신의 가치관은 어떻게 변화했나요?", "nl": "Hoe zijn je waarden geëvolueerd sinds we samen zijn?", "zh": "自从我们在一起以来，你的价值观是如何演变的？"}'),
  ('values', 2, '{"en": "Which shared value do you think will guide us most in the years ahead?", "es": "¿Qué valor compartido crees que nos guiará más en los próximos años?", "fr": "Quelle valeur partagée penses-tu nous guidera le plus dans les années à venir ?", "it": "Quale valore condiviso pensi che ci guiderà di più negli anni a venire?", "ko": "향후 몇 년 동안 우리를 가장 잘 이끌어 줄 것이라 생각하는 공유 가치는 무엇인가요?", "nl": "Welke gedeelde waarde denk je dat ons de komende jaren het meest zal begeleiden?", "zh": "你认为哪个共同的价值观会在未来几年中最能指导我们？"}'),
  ('values', 2, '{"en": "What''s a value you want to instill in our family life together?", "es": "¿Qué valor quieres inculcar en nuestra vida familiar juntos?", "fr": "Quelle est une valeur que tu veux inculquer dans notre vie de famille ensemble ?", "it": "Qual è un valore che vuoi instillare nella nostra vita familiare insieme?", "ko": "우리의 가족 생활에 주입하고 싶은 가치는 무엇인가요?", "nl": "Welke waarde wil je in ons gezinsleven samen opvoeden?", "zh": "你希望在我们共同的家庭生活中灌输什么价值观？"}'),
  ('values', 3, '{"en": "How do your personal values influence your vision for us as a couple?", "es": "¿Cómo influyen tus valores personales en tu visión de nosotros como pareja?", "fr": "Comment tes valeurs personnelles influencent-elles ta vision de nous en tant que couple ?", "it": "Come influenzano i tuoi valori personali la tua visione di noi come coppia?", "ko": "당신의 개인적 가치관이 우리 커플로서의 비전과 어떻게 관련되나요?", "nl": "Hoe beïnvloeden je persoonlijke waarden je visie voor ons als koppel?", "zh": "你的个人价值观如何影响你对我们的情侣关系的愿景？"}'),
  ('values', 1, '{"en": "What''s a value you admire in others and hope to embody yourself?", "es": "¿Cuál es un valor que admiras en otros y esperas encarnar tú mismo?", "fr": "Quelle est une valeur que tu admires chez les autres et espères incarner toi-même ?", "it": "Qual è un valore che ammiri negli altri e che speri di incarnare tu stesso?", "ko": "다른 사람에게서 존경하며 스스로 구현하고자 하는 가치는 무엇인가요?", "nl": "Wat is een waarde die je bewondert in anderen en hoopt zelf te belichamen?", "zh": "你钦佩他人的哪个价值观，并希望在自己身上实现？"}'),
  ('values', 1, '{"en": "What value do we share that you think will stand the test of time?", "es": "¿Qué valor compartimos que crees que resistirá la prueba del tiempo?", "fr": "Quelle est une valeur que nous partageons et qui, selon toi, résistera à l''épreuve du temps ?", "it": "Qual è un valore che condividiamo e che pensi resisterà alla prova del tempo?", "ko": "우리가 공유하며 시간이 지나도 변치 않을 것이라 믿는 가치는 무엇인가요?", "nl": "Welke waarde delen we die je denkt de tand des tijds zal doorstaan?", "zh": "我们共享的哪个价值观你认为能经受住时间的考验？"}'),
  ('values', 2, '{"en": "How do we ensure that our individual values enhance rather than conflict with our partnership?", "es": "¿Cómo nos aseguramos de que nuestros valores individuales mejoren en lugar de entrar en conflicto con nuestra asociación?", "fr": "Comment nous assurons-nous que nos valeurs individuelles améliorent notre partenariat plutôt que d''être en conflit avec lui ?", "it": "Come ci assicuriamo che i nostri valori individuali migliorino invece di entrare in conflitto con la nostra collaborazione?", "ko": "우리 개인의 가치가 충돌하지 않고 파트너십을 더 강화하도록 하려면 어떻게 해야 할까요?", "nl": "Hoe zorgen we ervoor dat onze persoonlijke waarden onze samenwerking versterken in plaats van ermee in conflict te komen?", "zh": "我们如何确保个人价值观促进而不是与我们的合作对立？"}'),
  ('values', 2, '{"en": "What''s a value that you''ve learned from your family that you want to bring into our life together?", "es": "¿Cuál es un valor que has aprendido de tu familia y que quieres traer a nuestra vida juntos?", "fr": "Quelle est une valeur que tu as apprise de ta famille et que tu veux apporter dans notre vie ensemble ?", "it": "Qual è un valore che hai appreso dalla tua famiglia e che vuoi portare nella nostra vita insieme?", "ko": "가족에게 배운 가치 중 우리 삶에 가져가고 싶은 것이 있나요?", "nl": "Wat is een waarde die je van je familie hebt geleerd en die je in ons leven samen wilt brengen?", "zh": "你从家庭中学到并希望带入我们共同生活的价值观是什么？"}'),
  ('values', 3, '{"en": "Which value do you think will be most challenging to uphold, and how do we support each other in it?", "es": "¿Qué valor crees que será más difícil de mantener y cómo podemos apoyarnos mutuamente en ello?", "fr": "Quelle valeur penses-tu sera la plus difficile à maintenir, et comment pouvons-nous nous soutenir mutuellement à cet égard ?", "it": "Quale valore pensi sarà il più difficile da mantenere e come possiamo supportarci a vicenda in questo?", "ko": "어떤 가치를 가장 지키기 어려울 것이라 생각하며, 그 가치에 대해 서로 어떻게 지원할 수 있을까요?", "nl": "Welke waarde denk je dat het moeilijkst zal zijn om te handhaven, en hoe steunen we elkaar daarin?", "zh": "你认为哪种价值观最难坚持，我们如何在这方面互相支持？"}'),
  ('values', 1, '{"en": "How does our value of trust manifest in our daily life?", "es": "¿Cómo se manifiesta nuestro valor de confianza en nuestra vida diaria?", "fr": "Comment notre valeur de confiance se manifeste-t-elle dans notre vie quotidienne ?", "it": "Come si manifesta il nostro valore di fiducia nella nostra vita quotidiana?", "ko": "우리의 신뢰 가치가 일상 생활에서 어떻게 나타나나요?", "nl": "Hoe manifesteert onze waarde van vertrouwen zich in ons dagelijks leven?", "zh": "我们的信任价值如何在我们的日常生活中体现？"}'),
  ('fun', 1, '{"en": "What''s your favorite game or activity for us to play together?", "es": "¿Cuál es tu juego o actividad favorita para que juguemos juntos?", "fr": "Quel est ton jeu ou activité préféré à faire ensemble ?", "it": "Qual è il tuo gioco o attività preferito da fare insieme?", "ko": "함께 할 수 있는 당신이 가장 좋아하는 게임이나 활동은 무엇인가요?", "nl": "Wat is je favoriete spel of activiteit om samen te doen?", "zh": "我们一起玩的最喜欢的游戏或活动是什么？"}'),
  ('fun', 1, '{"en": "What''s the most spontaneous thing we''ve ever done together?", "es": "¿Qué es lo más espontáneo que hemos hecho juntos?", "fr": "Quelle est la chose la plus spontanée que nous ayons jamais faite ensemble ?", "it": "Qual è la cosa più spontanea che abbiamo mai fatto insieme?", "ko": "우리가 함께 했던 가장 자발적인 일은 무엇인가요?", "nl": "Wat is het meest spontane dat we ooit samen hebben gedaan?", "zh": "我们一起做过的最即兴的事情是什么？"}'),
  ('fun', 2, '{"en": "What''s an adventure you''ve always wanted to embark on with me?", "es": "¿Qué aventura siempre has querido emprender conmigo?", "fr": "Quelle aventure as-tu toujours voulu tenter avec moi ?", "it": "Qual è un''avventura che hai sempre voluto intraprendere con me?", "ko": "나와 함께 하고 싶었던 모험은 어떤 것인가요?", "nl": "Wat is een avontuur dat je altijd al met mij hebt willen aangaan?", "zh": "你一直想和我一起进行的冒险是什么？"}'),
  ('fun', 2, '{"en": "What is a new hobby we could explore together to add more fun to our lives?", "es": "¿Cuál es un nuevo hobby que podríamos explorar juntos para añadir más diversión a nuestras vidas?", "fr": "Quel nouveau passe-temps pourrions-nous explorer ensemble pour ajouter plus de plaisir à nos vies ?", "it": "Qual è un nuovo hobby che potremmo esplorare insieme per aggiungere più divertimento alle nostre vite?", "ko": "우리의 삶에 더 많은 재미를 더하기 위해 함께 시작할 수 있는 새로운 취미는 무엇입니까?", "nl": "Wat is een nieuwe hobby die we samen kunnen verkennen om meer plezier aan ons leven toe te voegen?", "zh": "我们可以一起探索的能为我们的生活增添乐趣的新爱好是什么？"}'),
  ('fun', 3, '{"en": "What does fun mean to you on a deeper level, and how do you think it affects our relationship?", "es": "¿Qué significa la diversión para ti a un nivel más profundo y cómo crees que afecta nuestra relación?", "fr": "Que signifie le divertissement pour toi à un niveau plus profond et comment penses-tu que cela affecte notre relation ?", "it": "Cosa significa per te il divertimento a un livello più profondo e come pensi che influisca sulla nostra relazione?", "ko": "더 깊은 차원에서 당신에게 재미란 무엇이며, 그것이 우리 관계에 어떤 영향을 미친다고 생각하나요?", "nl": "Wat betekent plezier voor jou op een dieper niveau en hoe denk je dat het onze relatie beïnvloedt?", "zh": "在更深层次上，乐趣对你意味着什么，你认为它如何影响我们的关系？"}'),
  ('fun', 3, '{"en": "What familiar yet profound fun experience do you believe we could share that would bring us closer?", "es": "¿Qué experiencia divertida, familiar pero profunda crees que podríamos compartir que nos acercaría más?", "fr": "Quelle expérience amusante, familière mais profonde crois-tu que nous pourrions partager pour nous rapprocher davantage ?", "it": "Quale esperienza di divertimento familiare ma profonda credi che potremmo condividere che ci avvicinerebbe di più?", "ko": "우리에게 더 가까워질 수 있는 익숙하면서도 심오한 즐거운 경험이 무엇이라고 생각하나요?", "nl": "Welke bekende maar diepgaande leuke ervaring denk je dat we kunnen delen om dichter bij elkaar te komen?", "zh": "你认为我们可以分享的熟悉而深刻的有趣经历是什么，可以让我们更加亲近？"}'),
  ('fun', 1, '{"en": "What classic movie do you love watching together on a cozy night in?", "es": "¿Qué película clásica te encanta ver juntos en una noche acogedora?", "fr": "Quel film classique aimes-tu regarder ensemble lors d''une soirée douillette ?", "it": "Quale film classico ti piace guardare insieme durante una serata accogliente?", "ko": "포근한 밤에 함께 보고 싶은 고전 영화는 무엇입니까?", "nl": "Welke klassieke film vind je leuk om samen te kijken op een gezellige avond binnen?", "zh": "在一个舒适的夜晚，你喜欢一起观看哪部经典电影？"}'),
  ('fun', 1, '{"en": "What''s one dance move you''d like us to perfect together?", "es": "¿Cuál es un paso de baile que te gustaría que perfeccionáramos juntos?", "fr": "Quel pas de danse aimerais-tu que nous perfectionnions ensemble ?", "it": "Qual è un passo di danza che ti piacerebbe perfezionare insieme a me?", "ko": "함께 완벽하게 하고 싶은 춤 동작이 있나요?", "nl": "Wat is een dansbeweging die je graag samen perfect zou willen krijgen?", "zh": "你想和我一起完美掌握的舞蹈动作是什么？"}'),
  ('fun', 2, '{"en": "How can we incorporate more playfulness into our everyday routine?", "es": "¿Cómo podemos incorporar más alegría en nuestra rutina diaria?", "fr": "Comment pouvons-nous incorporer plus de jeu dans notre routine quotidienne ?", "it": "Come possiamo incorporare più gioco nella nostra routine quotidiana?", "ko": "우리의 일상에 더 많은 놀이를 어떻게 통합할 수 있을까요?", "nl": "Hoe kunnen we meer speelsheid in onze dagelijkse routine integreren?", "zh": "我们怎样才能在日常生活中加入更多的趣味？"}'),
  ('fun', 2, '{"en": "What fun thing did you enjoy doing as a child that you''d like us to try together?", "es": "¿Qué cosa divertida disfrutabas hacer de niño que te gustaría que intentáramos juntos?", "fr": "Quelle chose amusante aimais-tu faire enfant que tu aimerais que nous essayions ensemble ?", "it": "Qual è qualcosa di divertente che ti piaceva fare da bambino che vorresti provassimo insieme?", "ko": "어릴 때 즐겼던 재미있는 일이 무엇이며, 우리가 함께 시도해보고 싶은 것은 무엇인가요?", "nl": "Welke leuke dingen deed je vroeger als kind waar je graag samen mee aan de slag wilt?", "zh": "你儿时喜欢做的有趣事情中有哪些你希望我们一起尝试的？"}'),
  ('fun', 3, '{"en": "What does living a fun and satisfying life mean to you, and how can I be part of it?", "es": "¿Qué significa para ti vivir una vida divertida y satisfactoria, y cómo puedo ser parte de ello?", "fr": "Que signifie pour toi vivre une vie amusante et satisfaisante et comment puis-je en faire partie ?", "it": "Cosa significa per te vivere una vita divertente e soddisfacente e come posso farne parte?", "ko": "재미있고 만족스러운 삶을 사는 것이 당신에게 무엇을 의미하며, 제가 어떻게 그 일부가 될 수 있을까요?", "nl": "Wat betekent het voor jou om een leuk en bevredigend leven te leiden en hoe kan ik daar deel van uitmaken?", "zh": "对你来说，过一个有趣和令人满意的生活意味着什么，我怎样才能成为其中的一部分？"}'),
  ('fun', 1, '{"en": "What''s your idea of the perfect fun-filled day with me?", "es": "¿Cuál es tu idea de un día perfecto lleno de diversión conmigo?", "fr": "Quelle est ton idée de la journée parfaite remplie de plaisir avec moi ?", "it": "Qual è la tua idea di una giornata perfetta piena di divertimento con me?", "ko": "당신이 생각하는 나와 함께하는 완벽하고 재미있는 하루는 어떤 모습인가요?", "nl": "Wat is jouw idee van de perfecte dag vol plezier met mij?", "zh": "你认为和我一起度过的完美快乐一天是什么样的？"}'),
  ('fun', 1, '{"en": "What fun recipe would you love for us to cook together?", "es": "¿Qué receta divertida te encantaría que cocináramos juntos?", "fr": "Quelle recette amusante aimerais-tu que nous cuisinions ensemble ?", "it": "Quale ricetta divertente ti piacerebbe cucinare insieme a me?", "ko": "함께 요리하고 싶은 재미있는 요리법은 무엇인가요?", "nl": "Welk leuk recept zou je graag samen willen koken?", "zh": "你希望我们一起做什么有趣的菜？"}'),
  ('fun', 2, '{"en": "What fun adventure should we plan before the year ends?", "es": "¿Qué aventura divertida deberíamos planear antes de que termine el año?", "fr": "Quelle aventure amusante devrions-nous planifier avant la fin de l''année ?", "it": "Quale avventura divertente dovremmo pianificare prima che l''anno finisca?", "ko": "올해가 가기 전에 어떤 재미있는 모험을 계획해야 할까요?", "nl": "Welk leuk avontuur moeten we plannen voordat het jaar eindigt?", "zh": "在年底前我们应该计划哪些有趣的冒险？"}'),
  ('fun', 2, '{"en": "If we wrote and acted out a short skit right now, what would it be about?", "es": "Si escribiéramos e interpretáramos un pequeño sketch ahora, ¿de qué trataría?", "fr": "Si nous écrivions et jouions une petite scène maintenant, de quoi parlerait-elle ?", "it": "Se scrivessimo e recitassimo ora un breve sketch, di cosa parlerebbe?", "ko": "지금 짧은 스킷을 쓴다면 그것은 어떤 내용일까요?", "nl": "Als we nu een korte sketch zouden schrijven en uitvoeren, waar zou dat dan over gaan?", "zh": "如果我们现在写并表演一个简短的滑稽戏，它会是什么主题？"}'),
  ('fun', 3, '{"en": "What profound aspect of life do you find the most fun, and how can we explore it together?", "es": "¿Qué aspecto profundo de la vida encuentras más divertido y cómo podemos explorarlo juntos?", "fr": "Quel aspect profond de la vie trouves-tu le plus amusant et comment pouvons-nous l''explorer ensemble ?", "it": "Qual è l''aspetto profondo della vita che trovi più divertente e come possiamo esplorarlo insieme?", "ko": "삶의 어떤 심오한 부분이 가장 재미있다고 생각하며, 그것을 우리가 함께 어떻게 탐험할 수 있을까요?", "nl": "Welk diepgaand aspect van het leven vind je het leukst en hoe kunnen we dat samen verkennen?", "zh": "你觉得生活中最有趣的深刻方面是什么，我们如何可以一起探索它？"}'),
  ('gratitude', 1, '{"en": "What''s one small thing I did for you recently that you''re thankful for?", "es": "¿Cuál es una pequeña cosa que hice por ti recientemente por la que estás agradecido?", "fr": "Quelle est la petite chose que j''ai faite pour toi récemment et pour laquelle tu es reconnaissant ?", "it": "Qual è una piccola cosa che ho fatto per te di recente di cui sei grato?", "ko": "최근에 내가 당신을 위해 했던 작은 일 중 감사한 것은 무엇인가요?", "nl": "Wat is één klein ding dat ik onlangs voor je deed waar je dankbaar voor bent?", "zh": "最近我为你做的哪一件小事让你感到感激？"}'),
  ('gratitude', 1, '{"en": "What little habits of mine are you most grateful for?", "es": "¿Por cuáles de mis pequeños hábitos estás más agradecido?", "fr": "Pour quelles petites habitudes miennes es-tu le plus reconnaissant ?", "it": "Quali piccoli miei abitudini apprezzi di più?", "ko": "나의 어떤 작은 습관이 가장 고마운가요?", "nl": "Voor welke kleine gewoonten van mij ben je het meest dankbaar?", "zh": "你最感激我哪一个小习惯？"}'),
  ('gratitude', 2, '{"en": "How do you think practicing gratitude impacts our relationship?", "es": "¿Cómo crees que practicar la gratitud impacta nuestra relación?", "fr": "Comment penses-tu que pratiquer la gratitude impacte notre relation ?", "it": "Come pensi che praticare la gratitudine influisca sulla nostra relazione?", "ko": "감사를 실천하는 것이 우리의 관계에 어떤 영향을 미친다고 생각하나요?", "nl": "Hoe denk je dat het beoefenen van dankbaarheid invloed heeft op onze relatie?", "zh": "你认为践行感恩对我们的关系有什么影响？"}'),
  ('gratitude', 2, '{"en": "What moment of gratitude have you experienced lately that stands out to you?", "es": "¿Qué momento de gratitud has experimentado últimamente que te resalta?", "fr": "Quel moment de gratitude as-tu vécu récemment qui t''a marqué ?", "it": "Qual è un momento di gratitudine che hai vissuto di recente che ti ha colpito?", "ko": "최근에 경험한 감사의 순간 중 인상 깊었던 것은 무엇인가요?", "nl": "Welke ervaring van dankbaarheid die je onlangs hebt gehad, valt je op?", "zh": "最近你经历的哪一个感恩时刻让你印象深刻？"}'),
  ('gratitude', 3, '{"en": "What are you most grateful for in the season of life we''re currently in?", "es": "¿Por qué estás más agradecido en esta etapa de la vida en la que nos encontramos?", "fr": "Pour quoi es-tu le plus reconnaissant dans la période de vie où nous nous trouvons actuellement ?", "it": "Di cosa sei più grato nella fase di vita in cui ci troviamo attualmente?", "ko": "현재 우리가 처해 있는 삶의 시기에 대해 무엇에 가장 감사하나요?", "nl": "Waar ben je het meest dankbaar voor in de levensfase waarin we ons nu bevinden?", "zh": "在我们目前处于的生活阶段中你最感激什么？"}'),
  ('gratitude', 3, '{"en": "What difficult experience are you grateful for because of the growth it spurred?", "es": "¿Por qué experiencia difícil estás agradecido por el crecimiento que generó?", "fr": "Pour quelle expérience difficile es-tu reconnaissant en raison de la croissance qu''elle a engendrée ?", "it": "Quale esperienza difficile ti ha reso grato per la crescita che ha innescato?", "ko": "성장을 촉진한 어려운 경험에 대해 감사하다고 느낀 경험은 무엇인가요?", "nl": "Voor welke moeilijke ervaring ben je dankbaar vanwege de groei die het heeft gestimuleerd?", "zh": "你感激哪一段困难的经历，因为它促成了你的成长？"}'),
  ('gratitude', 1, '{"en": "What''s a daily ritual or routine that fills you with gratitude?", "es": "¿Cuál es un ritual o rutina diaria que te llena de gratitud?", "fr": "Quel rituel ou routine quotidien te remplit de gratitude ?", "it": "Qual è un rituale o routine quotidiana che ti riempie di gratitudine?", "ko": "감사함을 느끼게 해주는 일일 의식이나 습관은 무엇인가요?", "nl": "Wat is een dagelijks ritueel of routine dat je met dankbaarheid vult?", "zh": "哪一个日常仪式或惯例让你充满感激之情？"}'),
  ('gratitude', 1, '{"en": "What''s something about your environment that you''re thankful for every day?", "es": "¿Qué hay en tu entorno por lo que te sientes agradecido todos los días?", "fr": "Y a-t-il quelque chose dans ton environnement pour lequel tu es reconnaissant chaque jour ?", "it": "C''è qualcosa nel tuo ambiente di cui sei grato ogni giorno?", "ko": "일상적으로 감사하게 여기는 환경의 어떤 것이 있나요?", "nl": "Wat in je omgeving ben je dagelijks dankbaar voor?", "zh": "你每天都感激你的环境中的哪一方面？"}'),
  ('gratitude', 2, '{"en": "How can we create more space for gratitude in our daily interactions?", "es": "¿Cómo podemos crear más espacio para la gratitud en nuestras interacciones diarias?", "fr": "Comment pouvons-nous créer plus d''espace pour la gratitude dans nos interactions quotidiennes ?", "it": "Come possiamo creare più spazio per la gratitudine nelle nostre interazioni quotidiane?", "ko": "일상 상호작용에서 더 많은 감사의 여지를 어떻게 만들 수 있을까요?", "nl": "Hoe kunnen we meer ruimte voor dankbaarheid creëren in onze dagelijkse interacties?", "zh": "我们怎样才能在日常互动中创造更多的感恩空间？"}'),
  ('gratitude', 2, '{"en": "How has expressing gratitude changed your outlook on life?", "es": "¿Cómo ha cambiado expresar gratitud tu perspectiva de la vida?", "fr": "Comment le fait d''exprimer de la gratitude a-t-il changé ta vision de la vie ?", "it": "Come ha cambiato la tua visione della vita esprimere gratitudine?", "ko": "감사를 표현하는 것이 삶에 대한 당신의 관점을 어떻게 바꾸었나요?", "nl": "Hoe heeft het uiten van dankbaarheid je kijk op het leven veranderd?", "zh": "表达感激如何改变了你对生活的看法？"}'),
  ('gratitude', 3, '{"en": "When was a time you felt profound gratitude during a moment of struggle?", "es": "¿Cuándo fue un momento en el que sentiste una gratitud profunda durante una lucha?", "fr": "Quand as-tu ressenti une gratitude profonde au cours d''un moment de lutte ?", "it": "Qual è stato un momento in cui hai provato una gratitudine profonda durante una difficoltà?", "ko": "고난의 순간에 깊은 감사를 느꼈던 때가 언제였나요?", "nl": "Wanneer heb je tijdens een moment van strijd diepgaande dankbaarheid gevoeld?", "zh": "在奋斗时你曾感受到深深的感激之情吗？"}'),
  ('gratitude', 1, '{"en": "What thank-you gesture from me has meant the most to you?", "es": "¿Qué gesto de agradecimiento de mi parte ha significado más para ti?", "fr": "Quel geste de remerciement de ma part a le plus compté pour toi ?", "it": "Quale gesto di ringraziamento da parte mia ha significato di più per te?", "ko": "내가 한 감사의 몸짓 중 당신에게 가장 큰 의미가 있었던 것은 무엇인가요?", "nl": "Welke dankbare gebaar van mij heeft het meeste voor je betekend?", "zh": "我哪一个感谢的表示对你意义最大？"}'),
  ('gratitude', 1, '{"en": "What part of your childhood are you most thankful for?", "es": "¿Qué parte de tu infancia es por la que estás más agradecido?", "fr": "Pour quelle partie de ton enfance es-tu le plus reconnaissant ?", "it": "Qual è la parte della tua infanzia per cui sei più grato?", "ko": "당신이 어린 시절에 가장 감사한 부분은 무엇인가요?", "nl": "Voor welk deel van je kindertijd ben je het meest dankbaar?", "zh": "你对童年的哪一部分最感激？"}'),
  ('gratitude', 2, '{"en": "Which act of kindness shown to us as a couple makes you feel grateful?", "es": "¿Qué acto de bondad mostrado hacia nosotros como pareja te hace sentir agradecido?", "fr": "Quel acte de gentillesse montré envers nous en tant que couple te rend reconnaissant ?", "it": "Quale atto di gentilezza mostrato a noi come coppia ti fa sentire grato?", "ko": "우리 커플에게 보여진 어떤 친절한 행동이 당신을 감사하게 만드나요?", "nl": "Welk vriendelijk gebaar naar ons als koppel toe maakt je dankbaar?", "zh": "哪种对我们夫妻表现出的善意让你感激不已？"}'),
  ('gratitude', 2, '{"en": "What does gratitude mean to you, beyond mere thankfulness?", "es": "¿Qué significa la gratitud para ti, más allá de un simple agradecimiento?", "fr": "Que signifie la gratitude pour toi, au-delà de la simple reconnaissance ?", "it": "Cosa significa per te la gratitudine, al di là del semplice ringraziamento?", "ko": "단순한 감사함을 넘어, 감사는 당신에게 어떤 의미인가요?", "nl": "Wat betekent dankbaarheid voor jou, verder dan enkel dankbaarheid?", "zh": "除了简单的感谢之外，感恩对你意味着什么？"}'),
  ('gratitude', 3, '{"en": "How can I better support you in recognizing and savoring life''s everyday blessings?", "es": "¿Cómo puedo apoyarte mejor para reconocer y saborear las bendiciones cotidianas de la vida?", "fr": "Comment puis-je mieux te soutenir pour reconnaître et savourer les bénédictions quotidiennes de la vie ?", "it": "Come posso supportarti meglio nel riconoscere e assaporare le benedizioni quotidiane della vita?", "ko": "일상의 축복을 인식하고 누릴 수 있도록 어떻게 더 잘 지원할 수 있을까요?", "nl": "Hoe kan ik jou beter ondersteunen in het herkennen en koesteren van de dagelijkse zegeningen in het leven?", "zh": "我怎样才能更好地支持你去认识并享受生活中的日常祝福？"}'),
  ('gratitude', 1, '{"en": "What''s a hobby or activity you feel grateful to have in your life?", "es": "¿Cuál es un pasatiempo o actividad por la que te sientes agradecido de tener en tu vida?", "fr": "Quel est un loisir ou une activité pour lesquels tu te sens reconnaissant dans ta vie ?", "it": "Qual è un hobby o un''attività per cui ti senti grato nella tua vita?", "ko": "당신의 삶에서 감사하게 생각하는 취미나 활동은 무엇인가요?", "nl": "Welk hobby of activiteit ben je dankbaar voor in je leven?", "zh": "生活中有哪些让你感激的爱好或活动？"}'),
  ('conflict', 1, '{"en": "What''s a positive lesson you''ve learned from one of our disagreements?", "es": "¿Cuál es una lección positiva que has aprendido de uno de nuestros desacuerdos?", "fr": "Quelle est une leçon positive que tu as apprise d''un de nos désaccords ?", "it": "Qual è una lezione positiva che hai imparato da uno dei nostri disaccordi?", "ko": "우리의 의견 충돌에서 배운 긍정적인 교훈은 무엇인가요?", "nl": "Wat is een positieve les die je hebt geleerd uit een van onze meningsverschillen?", "zh": "你从我们的某次争论中学到的积极教训是什么？"}'),
  ('conflict', 1, '{"en": "How do you like to cool off after we''ve had a disagreement?", "es": "¿Cómo prefieres relajarte después de que hayamos tenido un desacuerdo?", "fr": "Comment aimes-tu te détendre après un de nos désaccords ?", "it": "Come ti piace rilassarti dopo che abbiamo avuto un disaccordo?", "ko": "우리의 의견 충돌 후, 어떻게 식혀주기를 좋아하나요?", "nl": "Hoe koel je het liefst af nadat we een meningsverschil hebben gehad?", "zh": "我们发生争执后，你喜欢怎样冷静下来？"}'),
  ('conflict', 2, '{"en": "What resolution strategy have you found most effective in our past conflicts?", "es": "¿Qué estrategia de resolución has encontrado más efectiva en nuestros conflictos pasados?", "fr": "Quelle stratégie de résolution as-tu trouvée la plus efficace dans nos conflits passés ?", "it": "Quale strategia di risoluzione hai trovato più efficace nei nostri conflitti passati?", "ko": "과거의 갈등에서 가장 효과적이었던 해결 전략은 무엇인가요?", "nl": "Welke oplossingsstrategie heb je het meest effectief gevonden in onze eerdere conflicten?", "zh": "在过去的冲突中，你发现哪种解决策略最为有效？"}'),
  ('conflict', 2, '{"en": "How can we ensure our conflicts remain constructive rather than hurtful?", "es": "¿Cómo podemos asegurarnos de que nuestros conflictos permanezcan constructivos en lugar de ser perjudiciales?", "fr": "Comment pouvons-nous nous assurer que nos conflits restent constructifs plutôt que nuisibles ?", "it": "Come possiamo garantire che i nostri conflitti rimangano costruttivi piuttosto che dannosi?", "ko": "우리의 갈등이 해롭지 않고 건설적으로 유지되도록 어떻게 보장할 수 있을까요?", "nl": "Hoe kunnen we ervoor zorgen dat onze conflicten constructief blijven in plaats van schadelijk?", "zh": "我们如何确保冲突保持建设性而不是有害的？"}'),
  ('conflict', 3, '{"en": "What core belief or value do you feel gets challenged the most during conflicts, and how do we navigate it?", "es": "¿Cuál crees que es la creencia o valor fundamental que más se desafía durante los conflictos y cómo lo navegamos?", "fr": "Quelle croyance ou valeur fondamentale penses-tu être la plus mise à l''épreuve lors des conflits, et comment la gérons-nous ?", "it": "Quale convinzione o valore fondamentale pensi sia messo più alla prova durante i conflitti, e come lo affrontiamo?", "ko": "갈등 중에 가장 도전받는 핵심 신념이나 가치관은 무엇이라고 생각하며, 어떻게 그 상황을 헤쳐나가나요?", "nl": "Welke kernwaarde of overtuiging wordt volgens jou het meest uitgedaagd tijdens conflicten, en hoe navigeren we dit?", "zh": "在冲突中，你觉得哪种核心信念或价值观受到的挑战最大，我们该如何应对？"}'),
  ('conflict', 3, '{"en": "How can I best support you when conflicts arise in other areas of your life?", "es": "¿Cómo puedo apoyarte mejor cuando surjan conflictos en otras áreas de tu vida?", "fr": "Comment puis-je te soutenir au mieux lorsque des conflits surgissent dans d''autres domaines de ta vie ?", "it": "Come posso supportarti al meglio quando sorgono conflitti in altre aree della tua vita?", "ko": "당신 삶의 다른 영역에서 갈등이 발생할 때, 어떻게 가장 잘 지원해줄 수 있을까요?", "nl": "Hoe kan ik jou het beste ondersteunen wanneer er conflicten in andere delen van je leven zijn?", "zh": "在你生活的其他领域发生冲突时，我该如何更好地支持你？"}'),
  ('conflict', 1, '{"en": "What''s one way we maintain our connection even when we disagree?", "es": "¿Cuál es una manera en la que mantenemos nuestra conexión incluso cuando no estamos de acuerdo?", "fr": "Quelle est une manière de maintenir notre connexion même lorsque nous ne sommes pas d''accord ?", "it": "Qual è un modo per mantenere la nostra connessione anche quando non siamo d''accordo?", "ko": "의견이 다를 때에도 우리의 연결을 유지하는 방법은 무엇인가요?", "nl": "Wat is een manier waarop we onze verbinding onderhouden, zelfs als we het oneens zijn?", "zh": "即使我们意见不一致，我们用什么方式维持我们的联系？"}'),
  ('conflict', 1, '{"en": "When''s the best time for us to have important discussions after a disagreement?", "es": "¿Cuándo es el mejor momento para que tengamos discusiones importantes después de un desacuerdo?", "fr": "Quel est le meilleur moment pour que nous ayons des discussions importantes après un désaccord ?", "it": "Qual è il momento migliore per noi per avere discussioni importanti dopo un disaccordo?", "ko": "의견 충돌 후 중요한 논의를 하기 위한 가장 좋은 시점은 언제인가요?", "nl": "Wat is het beste moment voor ons om belangrijke discussies te voeren na een meningsverschil?", "zh": "我们在争执过后进行重要讨论的最佳时机是什么时候？"}'),
  ('conflict', 2, '{"en": "What role does empathy play in how you approach resolving conflicts?", "es": "¿Qué papel juega la empatía en cómo abordas la resolución de conflictos?", "fr": "Quel rôle joue l''empathie dans la manière dont tu abordes la résolution des conflits ?", "it": "Che ruolo gioca l''empatia nel modo in cui affronti la risoluzione dei conflitti?", "ko": "갈등을 해결하는 방법에서 공감은 어떤 역할을 하나요?", "nl": "Welke rol speelt empathie in jouw benadering van conflictoplossing?", "zh": "同理心在你处理冲突的方式中发挥什么作用？"}'),
  ('conflict', 2, '{"en": "What signs do you notice that indicate we''re beginning to resolve a conflict positively?", "es": "¿Qué señales notas que indican que estamos comenzando a resolver un conflicto positivamente?", "fr": "Quels signes remarques-tu qui indiquent que nous commençons à résoudre un conflit positivement ?", "it": "Quali segnali noti che indicano che stiamo iniziando a risolvere un conflitto positivamente?", "ko": "우리가 긍정적으로 갈등을 해결하기 시작했다는 징후는 무엇인가요?", "nl": "Welke signalen merk je op die aangeven dat we een conflict positief beginnen op te lossen?", "zh": "你注意到哪些迹象表明我们开始积极地解决冲突？"}'),
  ('conflict', 3, '{"en": "What mindset shift do you think would help us resolve conflicts more effectively?", "es": "¿Qué cambio de mentalidad crees que nos ayudará a resolver los conflictos de manera más efectiva?", "fr": "Quel changement de mentalité penses-tu nous aiderait à résoudre les conflits plus efficacement ?", "it": "Quale cambiamento di mentalità pensi che ci aiuterebbe a risolvere i conflitti in modo più efficace?", "ko": "갈등을 더 효과적으로 해결할 수 있도록 돕는 마음가짐의 변화는 무엇이라고 생각하나요?", "nl": "Welke mindsetverschuiving zou volgens jou helpen om conflicten effectiever op te lossen?", "zh": "你认为改变哪种心态会帮助我们更有效地解决冲突？"}'),
  ('conflict', 1, '{"en": "How do you feel when we work together to solve a problem?", "es": "¿Cómo te sientes cuando trabajamos juntos para resolver un problema?", "fr": "Comment te sens-tu lorsque nous travaillons ensemble pour résoudre un problème ?", "it": "Come ti senti quando lavoriamo insieme per risolvere un problema?", "ko": "문제를 해결하기 위해 함께 일할 때 기분이 어떠신가요?", "nl": "Hoe voel je je als we samenwerken om een probleem op te lossen?", "zh": "当我们一起解决问题时，你感觉如何？"}'),
  ('conflict', 1, '{"en": "What words from me during a conflict make you feel understood?", "es": "¿Qué palabras mías durante un conflicto te hacen sentir comprendido?", "fr": "Quelles paroles de ma part lors d''un conflit te font te sentir compris ?", "it": "Quali parole da parte mia durante un conflitto ti fanno sentire compreso?", "ko": "갈등 중에 나로부터 어떤 말이 당신을 이해받는다고 느끼게 하나요?", "nl": "Welke woorden van mij tijdens een conflict zorgen ervoor dat je je begrepen voelt?", "zh": "在冲突中，我的话让你感到被理解？"}'),
  ('conflict', 2, '{"en": "How do you think we can turn common points of tension into growth opportunities?", "es": "¿Cómo crees que podemos convertir los puntos comunes de tensión en oportunidades de crecimiento?", "fr": "Comment penses-tu que nous pouvons transformer les points de tension courants en opportunités de croissance ?", "it": "Come pensi che possiamo trasformare i punti di tensione comuni in opportunità di crescita?", "ko": "일반적인 긴장 지점을 성장의 기회로 바꿀 수 있는 방법은 무엇이라고 생각하나요?", "nl": "Hoe denk je dat we gemeenschappelijke spanningspunten kunnen omzetten in groeikansen?", "zh": "你认为我们怎样才能把常见的紧张点转化为成长的机会？"}'),
  ('conflict', 2, '{"en": "What aspect of our relationship do you think handles conflict well, and what can be improved?", "es": "¿Qué aspecto de nuestra relación crees que maneja bien los conflictos y qué se puede mejorar?", "fr": "Quel aspect de notre relation gère bien les conflits, selon toi, et qu''est-ce qui peut être amélioré ?", "it": "Quale aspetto della nostra relazione pensi che gestisca bene i conflitti, e cosa può essere migliorato?", "ko": "우리 관계의 어떤 측면이 갈등을 잘 다룬다고 생각하며, 무엇을 개선할 수 있을까요?", "nl": "Welk aspect van onze relatie gaat goed om met conflicten, en wat kan verbeterd worden?", "zh": "你认为我们关系中的哪个方面能很好地处理冲突，哪些方面需要改进？"}'),
  ('conflict', 3, '{"en": "When has a conflict been a turning point for deeper understanding in our relationship?", "es": "¿Cuándo ha sido un conflicto un punto de inflexión para un entendimiento más profundo en nuestra relación?", "fr": "Quand un conflit a-t-il été un tournant pour une compréhension plus profonde dans notre relation ?", "it": "Quando un conflitto è stato un punto di svolta per una comprensione più profonda nella nostra relazione?", "ko": "어떤 갈등이 우리 관계에서 더 깊은 이해를 위한 전환점이 된 적이 있나요?", "nl": "Wanneer was een conflict een keerpunt voor een dieper begrip in onze relatie?", "zh": "什么时候冲突成为我们关系中更深刻理解的转折点？"}'),
  ('finances', 1, '{"en": "What''s one financial goal you hope we can accomplish together?", "es": "¿Cuál es un objetivo financiero que esperas que podamos lograr juntos?", "fr": "Quel est un objectif financier que tu espères que nous pourrons atteindre ensemble ?", "it": "Qual è un obiettivo finanziario che speri possiamo raggiungere insieme?", "ko": "함께 달성하기를 바라는 재정적 목표는 무엇인가요?", "nl": "Wat is een financieel doel dat je hoopt dat we samen kunnen bereiken?", "zh": "你希望我们能一起实现的一个财政目标是什么？"}'),
  ('finances', 1, '{"en": "How can we make budgeting a more cooperative activity?", "es": "¿Cómo podemos hacer que el presupuesto sea una actividad más cooperativa?", "fr": "Comment pouvons-nous rendre la budgétisation plus coopérative ?", "it": "Come possiamo rendere il bilancio un''attività più cooperativa?", "ko": "예산 관리가 보다 협력적인 활동이 되도록 하려면 어떻게 해야 할까요?", "nl": "Hoe kunnen we van budgetteren een meer gezamenlijke activiteit maken?", "zh": "我们如何使预算成为一种更具合作性的活动？"}'),
  ('finances', 2, '{"en": "How do financial matters fit into your vision for our future?", "es": "¿Cómo encajan los asuntos financieros en tu visión de nuestro futuro?", "fr": "Quelle place les questions financières occupent-elles dans ta vision de notre avenir ?", "it": "In che modo le questioni finanziarie si inseriscono nella tua visione del nostro futuro?", "ko": "재정 문제는 우리의 미래에 대한 당신의 비전에 어떻게 어울리나요?", "nl": "Hoe passen financiële zaken in jouw visie voor onze toekomst?", "zh": "金融事务如何融入你对我们未来的愿景？"}'),
  ('finances', 2, '{"en": "How do you feel when we discuss our long-term financial plans?", "es": "¿Cómo te sientes cuando discutimos nuestros planes financieros a largo plazo?", "fr": "Comment te sens-tu lorsque nous discutons de nos plans financiers à long terme ?", "it": "Come ti senti quando discutiamo dei nostri piani finanziari a lungo termine?", "ko": "장기 금융 계획에 대해 논의할 때 기분이 어떠신가요?", "nl": "Hoe voel je je als we onze langetermijn financiële plannen bespreken?", "zh": "当我们讨论长期财务计划时，你有什么感受？"}'),
  ('finances', 3, '{"en": "What underlying financial priorities should we align with to ensure stability and happiness?", "es": "¿Qué prioridades financieras subyacentes deberíamos alinear para asegurar la estabilidad y la felicidad?", "fr": "Quelles priorités financières sous-jacentes devrions-nous aligner pour assurer la stabilité et le bonheur ?", "it": "Quali priorità finanziarie sottostanti dovremmo allineare per garantire stabilità e felicità?", "ko": "안정성과 행복을 보장하기 위해 어떤 재정적 우선순위를 맞춰야 할까요?", "nl": "Welke onderliggende financiële prioriteiten moeten we afstemmen om stabiliteit en geluk te waarborgen?", "zh": "我们应该实现哪些潜在的财务优先事项以确保稳定和幸福？"}'),
  ('finances', 3, '{"en": "How do you view the relationship between our values and our spending habits?", "es": "¿Cómo ves la relación entre nuestros valores y nuestros hábitos de gasto?", "fr": "Comment vois-tu la relation entre nos valeurs et nos habitudes de dépenses ?", "it": "Come vedi la relazione tra i nostri valori e le nostre abitudini di spesa?", "ko": "우리의 가치관과 소비 습관 간의 관계를 어떻게 보시나요?", "nl": "Hoe zie je de relatie tussen onze waarden en onze uitgavenpatronen?", "zh": "你如何看待我们的价值观与消费习惯之间的关系？"}'),
  ('finances', 1, '{"en": "What saving strategy do you feel most comfortable with for us as a couple?", "es": "¿Con qué estrategia de ahorro te sientes más cómodo para nosotros como pareja?", "fr": "Quelle stratégie d''épargne te semble la plus confortable pour nous en tant que couple ?", "it": "Con quale strategia di risparmio ti senti più a tuo agio per noi come coppia?", "ko": "우리 커플을 위해 가장 편안한 저축 전략은 무엇이라고 생각하나요?", "nl": "Met welke spaarstrategie voel je je het meest comfortabel voor ons als koppel?", "zh": "作为情侣，你对哪种储蓄策略感到最舒适？"}'),
  ('finances', 1, '{"en": "What leisure activity do you think provides the most value for money when we spend time together?", "es": "¿Qué actividad de ocio crees que proporciona el mayor valor por dinero cuando pasamos tiempo juntos?", "fr": "Quelle activité de loisir penses-tu offre le meilleur rapport qualité-prix lorsque nous passons du temps ensemble ?", "it": "Quale attività ricreativa pensi fornisca il miglior rapporto qualità-prezzo quando trascorriamo del tempo insieme?", "ko": "함께 시간을 보낼 때 가장 가성비가 높은 여가 활동은 무엇이라고 생각하나요?", "nl": "Welke vrijetijdsactiviteit biedt volgens jou de meeste waarde voor je geld wanneer we samen tijd doorbrengen?", "zh": "你认为我们在一起时，哪种休闲活动最物有所值？"}'),
  ('finances', 2, '{"en": "What does financial independence mean to you personally, and in our relationship?", "es": "¿Qué significa la independencia financiera para ti personalmente y en nuestra relación?", "fr": "Que signifie l''indépendance financière pour toi personnellement et dans notre relation ?", "it": "Cosa significa per te l''indipendenza finanziaria personalmente e nella nostra relazione?", "ko": "개인적으로, 그리고 우리 관계에서, 재정적 독립은 당신에게 무엇을 의미하나요?", "nl": "Wat betekent financiële onafhankelijkheid voor jou persoonlijk, en in onze relatie?", "zh": "在你个人和我们的关系中，财务独立意味着什么？"}'),
  ('finances', 2, '{"en": "In what way can our financial choices enhance our relationship and life satisfaction?", "es": "¿De qué manera pueden nuestras decisiones financieras mejorar nuestra relación y satisfacción con la vida?", "fr": "De quelle manière nos choix financiers peuvent-ils améliorer notre relation et notre satisfaction de vie ?", "it": "In che modo le nostre scelte finanziarie possono migliorare la nostra relazione e la soddisfazione della vita?", "ko": "우리의 재정적 선택이 우리의 관계와 삶의 만족도를 어떻게 향상시킬 수 있을까요?", "nl": "Op welke manier kunnen onze financiële keuzes onze relatie en levensvoldoening verbeteren?", "zh": "我们的财务选择可以怎样提升我们的关系与生活满意度？"}'),
  ('finances', 3, '{"en": "What has been a financial decision we''ve made that had a significant impact on our relationship?", "es": "¿Cuál ha sido una decisión financiera que hemos tomado que tuvo un impacto significativo en nuestra relación?", "fr": "Quelle décision financière avons-nous prise qui a eu un impact significatif sur notre relation ?", "it": "Qual è stata una decisione finanziaria che abbiamo preso che ha avuto un impatto significativo sulla nostra relazione?", "ko": "우리 관계에 중요한 영향을 미쳤던 재정적 결정은 무엇이었나요?", "nl": "Wat is een financiële beslissing die we hebben genomen die een significante impact had op onze relatie?", "zh": "我们做过的哪一个财务决定对我们的关系产生了重大影响？"}'),
  ('finances', 1, '{"en": "What''s an indulgence you''d like to save up for with me?", "es": "¿Cuál es un capricho para el que te gustaría ahorrar conmigo?", "fr": "Quelle indulgence aimerais-tu économiser pour que nous puissions la partager ?", "it": "Qual è un lusso per cui ti piacerebbe risparmiare con me?", "ko": "저축하고 싶은 사치품이 있나요?", "nl": "Wat is een luxe waar je voor wilt sparen met mij?", "zh": "你想和我一起存钱来享受的是什么？"}'),
  ('finances', 1, '{"en": "How do you feel about planning for a big financial purchase, such as a home?", "es": "¿Cómo te sientes acerca de planificar una gran compra financiera, como una casa?", "fr": "Que penses-tu de planifier un gros achat financier, comme une maison ?", "it": "Come ti senti riguardo alla pianificazione di un grande acquisto finanziario, come una casa?", "ko": "집과 같은 큰 재정적인 구매 계획에 대해 어떻게 생각하나요?", "nl": "Hoe voel je je over het plannen van een grote financiële aankoop, zoals een huis?", "zh": "你觉得计划购买大额物品，比如房子，怎么样？"}'),
  ('finances', 2, '{"en": "How do we determine the right balance between saving and enjoying life''s pleasures?", "es": "¿Cómo determinamos el equilibrio adecuado entre ahorrar y disfrutar de los placeres de la vida?", "fr": "Comment déterminons-nous le bon équilibre entre épargner et profiter des plaisirs de la vie ?", "it": "Come determiniamo il giusto equilibrio tra risparmiare e godere dei piaceri della vita?", "ko": "저축과 생활의 즐거움 사이의 균형을 어떻게 결정하나요?", "nl": "Hoe bepalen we de juiste balans tussen sparen en genieten van het leven?", "zh": "我们如何在储蓄和享受生活乐趣之间找到正确的平衡？"}'),
  ('finances', 2, '{"en": "What financial achievement are you most proud of, individually or as a couple?", "es": "¿De qué logro financiero estás más orgulloso, individualmente o como pareja?", "fr": "De quelle réussite financière es-tu le plus fier, individuellement ou en couple ?", "it": "Quale successo finanziario ti rende più orgoglioso, individualmente o come coppia?", "ko": "개인적으로 또는 커플로서 가장 자랑스러운 재정적 성취는 무엇인가요?", "nl": "Welke financiële prestatie ben je het meest trots op, individueel of als stel?", "zh": "你最引以为豪的财务成就是什么？可以是个人的或作为情侣的。"}'),
  ('finances', 3, '{"en": "How can we ensure our financial decisions reflect our shared priorities and dreams?", "es": "¿Cómo podemos asegurarnos de que nuestras decisiones financieras reflejen nuestras prioridades y sueños compartidos?", "fr": "Comment pouvons-nous nous assurer que nos décisions financières reflètent nos priorités et rêves communs ?", "it": "Come possiamo assicurarci che le nostre decisioni finanziarie riflettano le nostre priorità e sogni condivisi?", "ko": "우리의 재정적 결정이 공통된 우선순위와 꿈을 반영하도록 어떻게 보장할 수 있나요?", "nl": "Hoe kunnen we ervoor zorgen dat onze financiële beslissingen onze gedeelde prioriteiten en dromen weerspiegelen?", "zh": "我们如何确保我们的财务决策反映我们共同的优先事项和梦想？"}'),
  ('growth', 1, '{"en": "What''s one skill you really want to grow in, and how can I support you?", "es": "¿Cuál es una habilidad en la que realmente deseas crecer y cómo puedo apoyarte?", "fr": "Quelle compétence veux-tu vraiment développer, et comment puis-je t''aider ?", "it": "Qual è una capacità che vuoi davvero crescere e come posso supportarti?", "ko": "정말 발전시키고 싶은 기술은 무엇이며, 내가 어떻게 도와줄 수 있을까요?", "nl": "Wat is een vaardigheid waarin je echt wilt groeien, en hoe kan ik je steunen?", "zh": "你想增长的技能是什么，我该如何支持你？"}'),
  ('growth', 1, '{"en": "What personal achievements would you like us to celebrate together?", "es": "¿Qué logros personales te gustaría que celebremos juntos?", "fr": "Quels exploits personnels aimerais-tu que nous célébrions ensemble ?", "it": "Quali successi personali vorresti che celebrassimo insieme?", "ko": "함께 축하하고 싶은 개인적인 성취는 무엇인가요?", "nl": "Welke persoonlijke prestaties zou je graag samen willen vieren?", "zh": "你想和我一起庆祝哪些个人成就？"}'),
  ('growth', 2, '{"en": "How do you envision our personal growth affecting our growth as a couple?", "es": "¿Cómo visualizas que nuestro crecimiento personal afecte nuestro crecimiento como pareja?", "fr": "Comment envisages-tu que notre croissance personnelle affecte notre croissance en tant que couple ?", "it": "Come immagini che la nostra crescita personale influenzi la nostra crescita come coppia?", "ko": "개인적 성장이 우리 커플의 성장에 어떤 영향을 미친다고 생각하나요?", "nl": "Hoe zie je onze persoonlijke groei onze groei als koppel beïnvloeden?", "zh": "你认为我们的个人成长将如何影响我们作为情侣的成长？"}'),
  ('growth', 2, '{"en": "What area of growth do you think could bring us closer if we focus on it together?", "es": "¿Qué área de crecimiento crees que podría acercarnos si nos enfocamos juntos en ella?", "fr": "Quelle zone de croissance penses-tu pourrait nous rapprocher si nous nous concentrons ensemble dessus ?", "it": "Quale area di crescita pensi potrebbe avvicinarci se ci concentriamo insieme su di essa?", "ko": "함께 집중하면 우리를 더 가까이 해줄 성장의 영역은 무엇이라고 생각하나요?", "nl": "Welk gebied van groei denk je dat ons dichterbij zou kunnen brengen als we daar samen op focussen?", "zh": "你认为如果我们共同关注哪个成长领域会让我们关系更加亲密？"}'),
  ('growth', 3, '{"en": "How do you feel we can learn from past mistakes to fuel our future growth?", "es": "¿Cómo crees que podemos aprender de los errores del pasado para impulsar nuestro crecimiento futuro?", "fr": "Comment penses-tu que nous pouvons tirer des leçons des erreurs passées pour alimenter notre croissance future ?", "it": "Come pensi che possiamo imparare dagli errori passati per alimentare la nostra crescita futura?", "ko": "과거의 실수에서 무엇을 배워서 우리의 미래 성장을 추진할 수 있을까요?", "nl": "Hoe denk je dat we kunnen leren van fouten uit het verleden om onze toekomstige groei te stimuleren?", "zh": "你认为我们如何能从过去的错误中学习，以促进未来的成长？"}'),
  ('growth', 3, '{"en": "What''s the biggest lesson you think you''ve learned from our relationship so far?", "es": "¿Cuál es la mayor lección que crees que has aprendido de nuestra relación hasta ahora?", "fr": "Quelle est la plus grande leçon que tu penses avoir tirée de notre relation jusqu''à présent ?", "it": "Qual è la lezione più grande che pensi di aver imparato dalla nostra relazione finora?", "ko": "지금까지 우리 관계에서 배운 가장 큰 교훈은 무엇인가요?", "nl": "Wat is de grootste les die je denkt te hebben geleerd uit onze relatie tot nu toe?", "zh": "到目前为止，你认为从我们的关系中学到的最大教训是什么？"}'),
  ('growth', 1, '{"en": "What''s a personal goal you''re currently striving for, and how can I help?", "es": "¿Cuál es un objetivo personal por el que estás luchando actualmente y cómo puedo ayudar?", "fr": "Quel est un objectif personnel pour lequel tu travailles actuellement, et comment puis-je t''aider ?", "it": "Qual è un obiettivo personale per il quale stai lottando attualmente, e come posso aiutarti?", "ko": "현재 당신이 노력하고 있는 개인 목표는 무엇이며, 제가 어떻게 도울 수 있을까요?", "nl": "Wat is een persoonlijk doel waar je momenteel naar streeft, en hoe kan ik helpen?", "zh": "你目前正在努力的个人目标是什么，我可以如何帮助你？"}'),
  ('growth', 1, '{"en": "What would you like to learn together this year?", "es": "¿Qué te gustaría que aprendiéramos juntos este año?", "fr": "Qu''aimerais-tu que nous apprenions ensemble cette année ?", "it": "Cosa ti piacerebbe che imparassimo insieme quest''anno?", "ko": "올해 함께 배우고 싶은 것은 무엇인가요?", "nl": "Wat zou je dit jaar graag samen willen leren?", "zh": "你今年想和我一起学习什么？"}'),
  ('growth', 2, '{"en": "How do you maintain motivation in areas of personal growth you''re passionate about?", "es": "¿Cómo mantienes la motivación en las áreas de crecimiento personal que te apasionan?", "fr": "Comment maintiens-tu ta motivation dans les domaines de croissance personnelle qui te passionnent ?", "it": "Come mantieni la motivazione nelle aree di crescita personale che ti appassionano?", "ko": "열정을 가진 개인 성장 분야에서 어떻게 동기를 유지하나요?", "nl": "Hoe behoud je motivatie in de gebieden van persoonlijke groei waar je gepassioneerd over bent?", "zh": "在你所热衷的个人成长领域，你是如何保持动力的？"}'),
  ('growth', 2, '{"en": "What upcoming challenge do you see as an opportunity for growth?", "es": "¿Qué desafío próximo ves como una oportunidad para crecer?", "fr": "Quel défi à venir vois-tu comme une opportunité de croissance ?", "it": "Quale sfida imminente vedi come un''opportunità per crescere?", "ko": "다가오는 도전 중 무엇을 성장의 기회로 보나요?", "nl": "Welke aankomende uitdaging zie je als een kans voor groei?", "zh": "你认为即将到来的哪个挑战是一个成长的机会？"}'),
  ('growth', 3, '{"en": "What internal barriers do you feel you need to overcome to help our relationship flourish?", "es": "¿Qué barreras internas sientes que necesitas superar para ayudar a que nuestra relación florezca?", "fr": "Quelles barrières internes ressens-tu devoir surmonter pour aider notre relation à s''épanouir ?", "it": "Quali barriere interne senti di dover superare per aiutare la nostra relazione a fiorire?", "ko": "우리 관계가 번창하도록 극복해야 한다고 느끼는 내부 장애물은 무엇인가요?", "nl": "Welke interne barrières denk je dat je moet overwinnen om onze relatie te laten bloeien?", "zh": "你觉得需要克服哪些内心障碍才能帮助我们的关系发展？"}'),
  ('growth', 1, '{"en": "What''s one new experience you''d like us to try together for personal growth?", "es": "¿Cuál es una nueva experiencia que te gustaría que probemos juntos para el crecimiento personal?", "fr": "Quelle nouvelle expérience aimerais-tu que nous essayions ensemble pour notre croissance personnelle ?", "it": "Quale nuova esperienza ti piacerebbe che provassimo insieme per la crescita personale?", "ko": "개인적 성장을 위해 함께 해보고 싶은 새로운 경험은 무엇인가요?", "nl": "Welke nieuwe ervaring zou je samen willen proberen voor persoonlijke groei?", "zh": "为了个人成长，你想和我一起尝试什么新体验？"}'),
  ('growth', 1, '{"en": "How have you seen our relationship grow over the past year?", "es": "¿Cómo has visto crecer nuestra relación durante el último año?", "fr": "Comment as-tu vu notre relation croître au cours de l''année écoulée ?", "it": "Come hai visto crescere la nostra relazione nell''ultimo anno?", "ko": "지난 1년 동안 우리의 관계가 어떻게 성장했다고 생각하나요?", "nl": "Hoe heb je onze relatie het afgelopen jaar zien groeien?", "zh": "在过去的一年中，你怎么看待我们的关系发展？"}'),
  ('growth', 2, '{"en": "In what ways do you think our differences contribute to our collective growth?", "es": "¿De qué maneras crees que nuestras diferencias contribuyen a nuestro crecimiento colectivo?", "fr": "De quelles manières penses-tu que nos différences contribuent à notre croissance collective ?", "it": "In che modo pensi che le nostre differenze contribuiscano alla nostra crescita collettiva?", "ko": "우리의 차이점이 공동 성장을 어떻게 기여한다고 생각하나요?", "nl": "Op welke manieren denk je dat onze verschillen bijdragen aan onze collectieve groei?", "zh": "你认为我们的差异是如何促成我们集体成长的？"}'),
  ('growth', 2, '{"en": "What role do you see lifelong learning playing in our relationship?", "es": "¿Qué papel ves que juega el aprendizaje continuo en nuestra relación?", "fr": "Quel rôle vois-tu que l''apprentissage tout au long de la vie joue dans notre relation ?", "it": "Che ruolo vedi giocare l''apprendimento continuo nella nostra relazione?", "ko": "우리 관계에서 평생 학습이 어떤 역할을 한다고 보나요?", "nl": "Welke rol zie je voor levenslang leren in onze relatie?", "zh": "你认为终身学习在我们关系中起什么作用？"}'),
  ('growth', 3, '{"en": "How do you think we can transform individual weaknesses into collective strengths?", "es": "¿Cómo crees que podemos transformar las debilidades individuales en fortalezas colectivas?", "fr": "Comment penses-tu que nous pouvons transformer les faiblesses individuelles en forces collectives ?", "it": "Come pensi che possiamo trasformare le debolezze individuali in punti di forza collettivi?", "ko": "개인적 약점을 공동의 강점으로 어떻게 전환할 수 있을까요?", "nl": "Hoe denk je dat we individuele zwaktes kunnen omzetten in collectieve sterktes?", "zh": "你认为我们如何能将个人的弱点转化为共同的优势？"}'),
  ('family', 1, '{"en": "What''s one family tradition you''d like to start with me?", "es": "¿Cuál es una tradición familiar que te gustaría comenzar conmigo?", "fr": "Quelle tradition familiale aimerais-tu commencer avec moi ?", "it": "Qual è una tradizione familiare che ti piacerebbe iniziare con me?", "ko": "함께 시작하고 싶은 가족 전통은 무엇인가요?", "nl": "Welke familietraditie zou je graag met mij willen beginnen?", "zh": "你想和我开始什么家庭传统？"}'),
  ('family', 1, '{"en": "What family customs or traditions do you cherish the most?", "es": "¿Qué costumbres o tradiciones familiares aprecias más?", "fr": "Quelles coutumes ou traditions familiales chéris-tu le plus ?", "it": "Quali usanze o tradizioni familiari apprezzi di più?", "ko": "가장 소중히 여기는 가족 문화나 전통은 무엇인가요?", "nl": "Welke familie gewoontes of tradities koester je het meest?", "zh": "你最珍惜哪些家庭习俗或传统？"}'),
  ('family', 2, '{"en": "How do you think we can blend our family traditions into something new and meaningful?", "es": "¿Cómo crees que podemos fusionar nuestras tradiciones familiares en algo nuevo y significativo?", "fr": "Comment penses-tu que nous pouvons fusionner nos traditions familiales en quelque chose de nouveau et significatif ?", "it": "Come pensi che possiamo fondere le nostre tradizioni familiari in qualcosa di nuovo e significativo?", "ko": "우리의 가족 전통을 새롭고 의미 있는 것으로 어떻게 융합할 수 있을까요?", "nl": "Hoe denk je dat we onze familietradities kunnen combineren tot iets nieuws en betekenisvols?", "zh": "你认为我们如何能融合我们的家庭传统为新的、有意义的东西？"}'),
  ('family', 2, '{"en": "What lessons have you learned from your family that you''d like to pass on?", "es": "¿Qué lecciones has aprendido de tu familia que te gustaría transmitir?", "fr": "Quelles leçons as-tu apprises de ta famille que tu aimerais transmettre ?", "it": "Quali lezioni hai appreso dalla tua famiglia che ti piacerebbe trasmettere?", "ko": "가족에게 배운 교훈 중 어떤 것을 전하고 싶나요?", "nl": "Welke lessen heb je van je familie geleerd die je graag door zou willen geven?", "zh": "从家庭中学到的哪些经验是你想传承下去的？"}'),
  ('family', 3, '{"en": "What is your vision for our future family life together?", "es": "¿Cuál es tu visión para nuestra vida familiar futura juntos?", "fr": "Quelle est ta vision de notre future vie de famille ensemble ?", "it": "Qual è la tua visione per la nostra futura vita familiare insieme?", "ko": "함께하는 미래의 가족 생활에 대한 당신의 비전은 무엇인가요?", "nl": "Wat is jouw visie voor ons toekomstige gezinsleven samen?", "zh": "你对我们未来的家庭生活有什么设想？"}'),
  ('family', 3, '{"en": "What deeper understanding about family do you hope to gain as we build one?", "es": "¿Qué comprensión más profunda sobre la familia esperas obtener mientras creamos la nuestra?", "fr": "Quelle compréhension plus profonde de la famille espères-tu acquérir alors que nous en construisons une ?", "it": "Quale comprensione più profonda della famiglia speri di ottenere mentre ne costruiamo una?", "ko": "가정을 이루면서 가족에 대해 더 깊이 이해하고 싶은 점은 무엇인가요?", "nl": "Welke diepere inzichten over familie hoop je te verwerven terwijl we er een opbouwen?", "zh": "在建立家庭的过程中，你希望获得哪些对家庭的深入理解？"}'),
  ('family', 1, '{"en": "What''s a family recipe you''d like us to perfect together?", "es": "¿Cuál es una receta familiar que te gustaría que perfeccionáramos juntos?", "fr": "Quelle recette familiale aimerais-tu que nous perfectionnions ensemble ?", "it": "Qual è una ricetta di famiglia che ti piacerebbe perfezionare insieme?", "ko": "함께 완벽히 해보고 싶은 가족 요리법은 무엇인가요?", "nl": "Wat is een familierecept dat je graag samen zou willen perfectioneren?", "zh": "你想和我一起完善什么家庭菜谱？"}'),
  ('family', 1, '{"en": "What family event do you look forward to the most each year?", "es": "¿Qué evento familiar esperas con más ganas cada año?", "fr": "Quel événement familial attends-tu avec le plus d''impatience chaque année ?", "it": "Qual è l''evento familiare che aspetti con più ansia ogni anno?", "ko": "매년 가장 기대되는 가족 행사는 무엇인가요?", "nl": "Naar welk familie-evenement kijk je elk jaar het meest uit?", "zh": "每年你最期待的家庭活动是什么？"}'),
  ('family', 2, '{"en": "How do you think we can support each other''s family bonds?", "es": "¿Cómo crees que podemos apoyar los lazos familiares del otro?", "fr": "Comment penses-tu que nous pouvons soutenir les liens familiaux de l''autre?", "it": "Come pensi che possiamo sostenere i legami familiari l''uno dell''altro?", "ko": "서로의 가족 유대를 어떻게 지원할 수 있을까요?", "nl": "Hoe denk je dat we elkaars familiebanden kunnen ondersteunen?", "zh": "你认为我们如何支持彼此的家庭纽带？"}'),
  ('family', 2, '{"en": "What important values do you hope to instill in our family?", "es": "¿Qué valores importantes esperas inculcar en nuestra familia?", "fr": "Quelles valeurs importantes espères-tu inculquer dans notre famille?", "it": "Quali valori importanti speri di instillare nella nostra famiglia?", "ko": "우리 가정에 어떤 중요한 가치를 심어주고 싶나요?", "nl": "Welke belangrijke waarden hoop je in onze familie te verankeren?", "zh": "你希望在我们的家庭中灌输哪些重要价值观？"}'),
  ('family', 3, '{"en": "What family dynamics from your upbringing have shaped your vision for our family?", "es": "¿Qué dinámicas familiares de tu crianza han dado forma a tu visión para nuestra familia?", "fr": "Quelles dynamiques familiales de ton enfance ont façonné ta vision pour notre famille?", "it": "Quali dinamiche familiari della tua educazione hanno plasmato la tua visione per la nostra famiglia?", "ko": "당신의 성장 배경 중 어떤 가족 역동성이 우리 가족의 비전에 영향을 미쳤나요?", "nl": "Welke familiedynamiek uit je opvoeding heeft je visie voor onze familie gevormd?", "zh": "你从小在家庭中的哪些动态塑造了你对我们家庭的愿景？"}'),
  ('family', 1, '{"en": "What''s a family outing you''ve been wanting to go on with us?", "es": "¿Cuál es una salida familiar a la que has querido ir con nosotros?", "fr": "Quelle sortie familiale as-tu envie de faire avec nous?", "it": "Qual è un''uscita familiare a cui desideri partecipare con noi?", "ko": "우리와 함께 가고 싶었던 가족 나들이는 무엇인가요?", "nl": "Wat is een familie-uitje waar je graag met ons naartoe zou willen gaan?", "zh": "你一直想和我们一起去的家庭出游是什么？"}'),
  ('family', 1, '{"en": "If we hosted a family gathering, what theme would you choose?", "es": "Si organizáramos una reunión familiar, ¿qué tema elegirías?", "fr": "Si nous organisions une réunion de famille, quel thème choisirais-tu?", "it": "Se ospitassimo un incontro di famiglia, quale tema sceglieresti?", "ko": "우리가 가족 모임을 연다면, 어떤 테마를 선택하겠어요?", "nl": "Als we een familiebijeenkomst zouden organiseren, welk thema zou je dan kiezen?", "zh": "如果我们举办一次家庭聚会，你会选择什么主题？"}'),
  ('family', 2, '{"en": "What family milestone are you excited to celebrate with me?", "es": "¿Qué hito familiar te emociona celebrar conmigo?", "fr": "Quel jalon familial es-tu enthousiaste à célébrer avec moi?", "it": "Quale traguardo familiare sei entusiasta di celebrare con me?", "ko": "함께 축하하고 싶은 가족의 중요한 순간은 무엇인가요?", "nl": "Welke familiekijkpost ben je enthousiast om met mij te vieren?", "zh": "你对和我一起庆祝哪个家庭里程碑感到兴奋？"}'),
  ('family', 2, '{"en": "How can we create a nurturing environment for our extended family?", "es": "¿Cómo podemos crear un ambiente acogedor para nuestra familia extendida?", "fr": "Comment pouvons-nous créer un environnement bienveillant pour notre famille élargie?", "it": "Come possiamo creare un ambiente accogliente per la nostra famiglia allargata?", "ko": "우리의 대가족을 위한 따뜻한 환경을 어떻게 만들 수 있을까요?", "nl": "Hoe kunnen we een verzorgende omgeving creëren voor onze uitgebreide familie?", "zh": "我们如何为我们的大家庭创造一个温馨的环境？"}'),
  ('family', 3, '{"en": "What legacy do you hope our family will be remembered for in the future?", "es": "¿Qué legado esperas que nuestra familia sea recordada en el futuro?", "fr": "Quel héritage espères-tu que notre famille laissera pour l''avenir?", "it": "Quale lascito speri che la nostra famiglia sarà ricordata in futuro?", "ko": "우리 가족이 앞으로 어떤 유산으로 기억되길 원하시나요?", "nl": "Welke erfenis hoop je dat onze familie in de toekomst herinnerd zal worden?", "zh": "你希望我们的家庭在未来因为什么遗产而被铭记？"}'),
  ('adventure', 1, '{"en": "What''s one new adventure you''ve never tried but want to do with me?", "es": "¿Cuál es una nueva aventura que nunca has probado pero quieres hacer conmigo?", "fr": "Quelle est une nouvelle aventure que tu n''as jamais essayée mais que tu veux faire avec moi?", "it": "Qual è una nuova avventura che non hai mai provato ma che vuoi fare con me?", "ko": "한 번도 시도해보지 않았지만 나와 함께 하고 싶은 새로운 모험은 무엇인가요?", "nl": "Wat is een nieuw avontuur dat je nog nooit hebt geprobeerd, maar dat je met mij wilt doen?", "zh": "有什么新的冒险你从未尝试过但想和我一起去做？"}'),
  ('adventure', 1, '{"en": "What''s been your favorite adventurous date we''ve had together?", "es": "¿Cuál ha sido tu cita aventurera favorita que hemos tenido juntos?", "fr": "Quelle a été ta sortie aventure préférée que nous avons eue ensemble?", "it": "Qual è stato il tuo appuntamento avventuroso preferito che abbiamo avuto insieme?", "ko": "우리가 함께했던 모험적인 데이트 중 가장 좋아하는 순간은 무엇인가요?", "nl": "Wat is je favoriete avontuurlijke date die we samen hebben gehad?", "zh": "我们一起经历过的冒险约会中你最喜欢的是哪一次？"}'),
  ('adventure', 2, '{"en": "What adventure do you think would push us just beyond our comfort zone?", "es": "¿Qué aventura crees que nos empujaría justo más allá de nuestra zona de confort?", "fr": "Quelle aventure penses-tu nous pousserait juste au-delà de notre zone de confort?", "it": "Quale avventura pensi che ci spingerebbe appena oltre la nostra zona di comfort?", "ko": "우리의 편안한 영역을 조금 더 넘어설 수 있게 할 모험은 무엇이라고 생각하나요?", "nl": "Welk avontuur denk je dat ons net buiten onze comfortzone zou duwen?", "zh": "你认为什么冒险会让我们刚好超越舒适区？"}'),
  ('adventure', 2, '{"en": "What''s the most inspiring adventure story you''ve ever heard or read?", "es": "¿Cuál es la historia de aventura más inspiradora que has escuchado o leído?", "fr": "Quelle est l''histoire d''aventure la plus inspirante que tu aies jamais entendue ou lue?", "it": "Qual è la storia di avventura più ispiratrice che tu abbia mai sentito o letto?", "ko": "당신이 듣거나 읽은 것 중 가장 감명 깊었던 모험 이야기는 무엇인가요?", "nl": "Wat is het meest inspirerende avontuurverhaal dat je ooit hebt gehoord of gelezen?", "zh": "你听过或读过的最鼓舞人心的冒险故事是什么？"}'),
  ('adventure', 3, '{"en": "What do you believe is the ultimate adventure we can embark on together in life?", "es": "¿Qué crees que es la aventura definitiva que podemos emprender juntos en la vida?", "fr": "Quelle est pour toi l''aventure ultime que nous pouvons entreprendre ensemble dans la vie?", "it": "Qual è secondo te l''avventura definitiva che possiamo intraprendere insieme nella vita?", "ko": "우리가 인생에서 함께 시작할 수 있는 궁극적인 모험은 무엇이라고 생각하나요?", "nl": "Wat geloof je is het ultieme avontuur dat we samen in het leven kunnen aangaan?", "zh": "你认为我们在生活中可以一起踏上的终极冒险是什么？"}'),
  ('adventure', 3, '{"en": "How do you see adventure influencing our relationship long-term?", "es": "¿Cómo ves que la aventura influya en nuestra relación a largo plazo?", "fr": "Comment vois-tu l''aventure influencer notre relation à long terme?", "it": "Come vedi l''avventura influenzare la nostra relazione a lungo termine?", "ko": "모험이 우리 관계에 장기적으로 어떤 영향을 미칠 것이라고 보나요?", "nl": "Hoe zie je avontuur onze relatie op lange termijn beïnvloeden?", "zh": "你怎么看待冒险对我们关系的长期影响？"}'),
  ('adventure', 1, '{"en": "What''s a spontaneous trip you''d love for us to take one weekend?", "es": "¿Cuál es un viaje espontáneo que te encantaría que hiciéramos un fin de semana?", "fr": "Quel est un voyage spontané que tu aimerais que nous fassions un week-end?", "it": "Qual è un viaggio spontaneo che ti piacerebbe fare insieme un fine settimana?", "ko": "우리가 주말에 떠나고 싶은 즉흥 여행은 무엇인가요?", "nl": "Wat is een spontane reis die je graag met ons zou willen maken in een weekend?", "zh": "你希望我们某个周末去一次什么即兴旅行？"}'),
  ('adventure', 1, '{"en": "What adventurous activity would you like to learn or try next?", "es": "¿Qué actividad aventurera te gustaría aprender o intentar a continuación?", "fr": "Quelle activité aventureuse aimerais-tu apprendre ou essayer ensuite?", "it": "Quale attività avventurosa ti piacerebbe imparare o provare dopo?", "ko": "다음으로 배우거나 시도하고 싶은 모험적인 활동은 무엇인가요?", "nl": "Welke avontuurlijke activiteit zou je graag willen leren of proberen?", "zh": "你想学习或尝试的下一个冒险活动是什么？"}'),
  ('adventure', 2, '{"en": "How can we make everyday life feel like an adventure together?", "es": "¿Cómo podemos hacer que la vida cotidiana se sienta como una aventura juntos?", "fr": "Comment pouvons-nous rendre la vie quotidienne aussi aventureuse qu''une aventure ensemble?", "it": "Come possiamo rendere la vita quotidiana un''avventura insieme?", "ko": "일상 생활을 함께 모험처럼 느끼게 하려면 어떻게 해야 할까요?", "nl": "Hoe kunnen we het dagelijks leven laten voelen als een avontuur samen?", "zh": "我们如何让日常生活感觉像一个冒险？"}'),
  ('adventure', 2, '{"en": "What travel destination do you think will be an adventure of a lifetime for us?", "es": "¿Qué destino de viaje crees que será una aventura de una vida para nosotros?", "fr": "Quelle destination de voyage penses-tu être une aventure de toute une vie pour nous?", "it": "Quale destinazione di viaggio pensi possa essere l''avventura di una vita per noi?", "ko": "우리에게 평생의 모험이 될 여행지는 어디일까요?", "nl": " welke reisbestemming denk je dat het avontuur van ons leven zal zijn?", "zh": "你认为哪个旅行目的地会是我们一生的冒险？"}'),
  ('adventure', 3, '{"en": "How does adventure relate to your personal growth philosophy?", "es": "¿Cómo se relaciona la aventura con tu filosofía de crecimiento personal?", "fr": "Comment l''aventure se rattache-t-elle à ta philosophie de croissance personnelle?", "it": "In che modo l''avventura è collegata alla tua filosofia di crescita personale?", "ko": "모험은 당신의 개인 성장 철학과 어떻게 관련이 있나요?", "nl": "Hoe verhoudt avontuur zich tot je persoonlijke groeifilosofie?", "zh": "冒险如何与您的个人成长哲学相关联？"}'),
  ('adventure', 1, '{"en": "What''s an adventure activity you''d like to plan for next year?", "es": "¿Qué actividad de aventura te gustaría planificar para el próximo año?", "fr": "Quelle activité aventureuse aimerais-tu planifier pour l''année prochaine?", "it": "Quale attività avventurosa ti piacerebbe pianificare per il prossimo anno?", "ko": "내년에 계획하고 싶은 모험 활동은 무엇인가요?", "nl": "Wat is een avontuurlijke activiteit die je graag zou plannen voor volgend jaar?", "zh": "您想为明年计划什么冒险活动？"}'),
  ('adventure', 1, '{"en": "What''s an adventurous skill I could help you learn?", "es": "¿Qué habilidad aventurera podría ayudarte a aprender?", "fr": "Quelle compétence aventureuse pourrais-je t''aider à apprendre?", "it": "Quale abilità avventurosa potrei aiutarti a imparare?", "ko": "내가 당신에게 배울 수 있도록 도울 수 있는 모험적인 기술은 무엇인가요?", "nl": "Welke avontuurlijke vaardigheid zou ik je kunnen helpen leren?", "zh": "我可以帮助你学习的冒险技能是什么？"}'),
  ('adventure', 2, '{"en": "How do you balance adventure with the rest of our responsibilities?", "es": "¿Cómo equilibras la aventura con el resto de nuestras responsabilidades?", "fr": "Comment équilibrer l''aventure avec le reste de nos responsabilités?", "it": "Come bilanci l''avventura con il resto delle nostre responsabilità?", "ko": "모험과 우리의 다른 책임들 사이의 균형을 어떻게 맞추나요?", "nl": "Hoe balanceer je avontuur met de rest van onze verantwoordelijkheden?", "zh": "你如何平衡冒险和我们其他责任？"}'),
  ('adventure', 2, '{"en": "What does an adventurous lifestyle look like for you, and how can we achieve it together?", "es": "¿Cómo es un estilo de vida aventurero para ti y cómo podemos lograrlo juntos?", "fr": "À quoi ressemble un style de vie aventureux pour toi, et comment pouvons-nous y parvenir ensemble?", "it": "Come appare uno stile di vita avventuroso per te e come possiamo raggiungerlo insieme?", "ko": "당신에게 모험적인 삶은 어떤 모습이고, 그것을 함께 어떻게 이룰 수 있을까요?", "nl": "Hoe ziet een avontuurlijke levensstijl er voor jou uit, en hoe kunnen we die samen bereiken?", "zh": "冒险的生活方式对你来说是什么样的，我们如何一起实现它？"}'),
  ('adventure', 3, '{"en": "What adventure do you think will bring us a deeper understanding of each other?", "es": "¿Qué aventura crees que nos traerá una comprensión más profunda del uno al otro?", "fr": "Quelle aventure penses-tu nous apportera une compréhension plus approfondie l''un de l''autre?", "it": "Quale avventura pensi che ci porterà a una comprensione più profonda l''uno dell''altro?", "ko": "어떤 모험이 서로를 더 깊이 이해하게 만들 것이라고 생각하나요?", "nl": "Welk avontuur, denk je, zal ons een dieper begrip van elkaar geven?", "zh": "你认为什么冒险会让我们对彼此有更深的理解？"}'),
  ('adventure', 2, '{"en": "What''s one spontaneous thing you''d love to do together?", "es": "¿Cuál es una cosa espontánea que te encantaría hacer juntos?", "fr": "Quelle est une chose spontanée que tu aimerais faire ensemble?", "it": "Qual è una cosa spontanea che ti piacerebbe fare insieme?", "ko": "함께 하고 싶은 즉흥적인 일이 무엇인가요?", "nl": "Wat is iets spontaans dat je graag samen zou willen doen?", "zh": "你们想一起做的一件即兴的事情是什么？"}'),
  ('adventure', 2, '{"en": "How do you feel when we explore new places together?", "es": "¿Cómo te sientes cuando exploramos nuevos lugares juntos?", "fr": "Comment te sens-tu quand nous explorons de nouveaux endroits ensemble?", "it": "Come ti senti quando esploriamo nuovi luoghi insieme?", "ko": "새로운 장소를 함께 탐험할 때 기분이 어떠신가요?", "nl": "Hoe voel je je als we samen nieuwe plekken ontdekken?", "zh": "当我们一起探索新地方时，你感觉如何？"}'),
  ('adventure', 3, '{"en": "What does adventure mean to you in our relationship?", "es": "¿Qué significa la aventura para ti en nuestra relación?", "fr": "Que signifie l''aventure pour toi dans notre relation?", "it": "Cosa significa l''avventura per te nella nostra relazione?", "ko": "우리의 관계에서 모험이 당신에게 의미하는 바는 무엇인가요?", "nl": "Wat betekent avontuur voor jou in onze relatie?", "zh": "在我们的关系中，冒险对你意味着什么？"}'),
  ('adventure', 3, '{"en": "How can we incorporate more adventure into our everyday lives?", "es": "¿Cómo podemos incorporar más aventura en nuestra vida diaria?", "fr": "Comment pouvons-nous intégrer plus d''aventure dans notre quotidien?", "it": "Come possiamo incorporare più avventura nella nostra vita quotidiana?", "ko": "일상 생활에 더 많은 모험을 어떻게 통합할 수 있을까요?", "nl": "Hoe kunnen we meer avontuur in ons dagelijks leven integreren?", "zh": "我们如何在日常生活中融入更多的冒险？"}'),
  ('adventure', 1, '{"en": "If you could show me the wonders of one city, which would it be?", "es": "Si pudieras mostrarme las maravillas de una ciudad, ¿cuál sería?", "fr": "Si tu pouvais me montrer les merveilles d''une ville, laquelle serait-ce?", "it": "Se potessi mostrarmi le meraviglie di una città, quale sarebbe?", "ko": "한 도시의 경이로움을 보여줄 수 있다면, 어떤 도시가 될까요?", "nl": "Als je me de wonderen van één stad zou kunnen laten zien, welke zou dat dan zijn?", "zh": "如果你可以向我展示一个城市的奇观，那会是哪一个？"}'),
  ('adventure', 1, '{"en": "What small adventure can we plan for the upcoming weekend?", "es": "¿Qué pequeña aventura podemos planear para el próximo fin de semana?", "fr": "Quelle petite aventure pouvons-nous planifier pour le week-end prochain?", "it": "Quale piccola avventura possiamo pianificare per il prossimo fine settimana?", "ko": "다가오는 주말에 어떤 작은 모험을 계획할 수 있을까요?", "nl": "Welk klein avontuur kunnen we voor het komende weekend plannen?", "zh": "我们可以为即将到来的周末计划什么小冒险？"}'),
  ('adventure', 2, '{"en": "What''s a place you feel we haven''t explored enough together?", "es": "¿Cuál es un lugar que sientes que no hemos explorado lo suficiente juntos?", "fr": "Quel est un endroit que tu sens que nous n''avons pas assez exploré ensemble ?", "it": "Qual è un luogo che pensi non abbiamo esplorato abbastanza insieme?", "ko": "우리가 함께 충분히 탐험하지 못한 곳이 어디라고 생각하나요?", "nl": "Wat is een plek die je vindt dat we samen nog niet genoeg hebben verkend?", "zh": "你觉得我们还没有一起充分探索的地方是哪里？"}'),
  ('adventure', 1, '{"en": "Which type of adventure do you think would surprise me about you?", "es": "¿Qué tipo de aventura crees que me sorprendería sobre ti?", "fr": "Quel type d''aventure penses-tu qui me surprendrait à propos de toi ?", "it": "Quale tipo di avventura pensi che mi sorprenderei di te?", "ko": "어떤 종류의 모험이 당신에 대해 나를 놀라게 할 것이라고 생각하나요?", "nl": "Welk soort avontuur denk je dat mij over jou zou verrassen?", "zh": "你认为哪种冒险会让我对你感到惊讶？"}'),
  ('adventure', 2, '{"en": "How does going on adventures strengthen our bond in your view?", "es": "¿Cómo fortalece nuestro vínculo el salir de aventuras desde tu punto de vista?", "fr": "Comment aller à l''aventure renforce-t-il notre lien selon toi ?", "it": "In che modo andare all''avventura rafforza il nostro legame secondo te?", "ko": "모험을 통해 우리의 유대감을 어떻게 강화할 수 있다고 생각하나요?", "nl": "Hoe versterkt avonturen beleven volgens jou onze band?", "zh": "从你的角度来看，外出冒险如何加强我们的关系？"}'),
  ('adventure', 3, '{"en": "What''s a daring adventure you''ve always wanted to tackle with me?", "es": "¿Cuál es una aventura atrevida que siempre has querido emprender conmigo?", "fr": "Quelle est une aventure audacieuse que tu as toujours voulu entreprendre avec moi ?", "it": "Qual è un''avventura audace che hai sempre voluto affrontare con me?", "ko": "당신이 항상 나와 함께 도전해보고 싶었던 대담한 모험은 무엇인가요?", "nl": "Wat is een gedurfde avontuur die je altijd met mij hebt willen aangaan?", "zh": "你一直想和我一起进行的大胆冒险是什么？"}'),
  ('adventure', 1, '{"en": "What are some childhood adventure dreams you''d like to fulfill with me?", "es": "¿Cuáles son algunos sueños de aventuras de la infancia que te gustaría cumplir conmigo?", "fr": "Quels sont quelques rêves d''aventures d''enfance que tu aimerais réaliser avec moi ?", "it": "Quali sono alcuni sogni d''avventura d''infanzia che ti piacerebbe realizzare con me?", "ko": "당신이 나와 함께 이루고 싶은 어린 시절의 모험 꿈은 무엇인가요?", "nl": "Wat zijn enkele avonturendromen uit je kindertijd die je graag met mij zou willen vervullen?", "zh": "你想和我一起实现的童年冒险梦想有哪些？"}'),
  ('adventure', 3, '{"en": "When do you feel the most alive on our adventures and why?", "es": "¿Cuándo te sientes más vivo en nuestras aventuras y por qué?", "fr": "Quand te sens-tu le plus vivant pendant nos aventures et pourquoi ?", "it": "Quando ti senti più vivo nelle nostre avventure e perché?", "ko": "우리의 모험에서 언제 가장 생생함을 느끼고 그 이유는 무엇인가요?", "nl": "Wanneer voel je je het meest levend tijdens onze avonturen en waarom?", "zh": "在我们的冒险中，你什么时候感到最有活力，为什么？"}'),
  ('adventure', 2, '{"en": "How do you think we could make our routine more adventurous?", "es": "¿Cómo crees que podríamos hacer nuestra rutina más aventurera?", "fr": "Comment penses-tu que nous pourrions rendre notre routine plus aventureuse ?", "it": "Come pensi che potremmo rendere la nostra routine più avventurosa?", "ko": "우리의 일상을 더 모험적으로 만들기 위해 어떻게 하면 좋을까요?", "nl": "Hoe denk je dat we onze routine avontuurlijker kunnen maken?", "zh": "你认为我们如何能让我们的日常生活更加冒险？"}'),
  ('adventure', 1, '{"en": "Which adventure from a movie or book would you want to experience together?", "es": "¿Qué aventura de una película o libro te gustaría experimentar juntos?", "fr": "Quelle aventure d''un film ou d''un livre aimerais-tu vivre ensemble ?", "it": "Quale avventura di un film o di un libro vorresti vivere insieme?", "ko": "영화나 책에서 어떤 모험을 함께 경험하고 싶나요?", "nl": "Welk avontuur uit een film of boek zou je samen willen beleven?", "zh": "你想和我一起体验哪部电影或书中的冒险？"}'),
  ('adventure', 2, '{"en": "What''s the most adventurous thing we''ve done that you''d love to repeat?", "es": "¿Cuál es la cosa más aventurera que hemos hecho y que te encantaría repetir?", "fr": "Quelle est la chose la plus aventureuse que nous ayons faite et que tu aimerais répéter ?", "it": "Qual è la cosa più avventurosa che abbiamo fatto che ti piacerebbe ripetere?", "ko": "우리가 했던 것 중 가장 모험적인 일이 무엇이고 다시 하고 싶나요?", "nl": "Wat is het avontuurlijkste dat we hebben gedaan dat je graag zou herhalen?", "zh": "我们做过的最冒险的事情是什么，你愿意再体验一次？"}'),
  ('adventure', 2, '{"en": "How can we balance safety and adventure in our plans?", "es": "¿Cómo podemos equilibrar la seguridad y la aventura en nuestros planes?", "fr": "Comment pouvons-nous équilibrer la sécurité et l''aventure dans nos plans ?", "it": "Come possiamo bilanciare la sicurezza e l''avventura nei nostri piani?", "ko": "우리의 계획에서 안전과 모험을 어떻게 균형 잡을 수 있을까요?", "nl": "Hoe kunnen we veiligheid en avontuur in onze plannen in balans brengen?", "zh": "我们怎么能在计划中平衡安全和冒险？"}'),
  ('adventure', 3, '{"en": "What adventure do you think would deepen our understanding of each other?", "es": "¿Qué aventura crees que profundizaría nuestra comprensión mutua?", "fr": "Quelle aventure penses-tu qui approfondirait notre compréhension mutuelle ?", "it": "Quale avventura pensi che approfondirebbe la nostra comprensione reciproca?", "ko": "어떤 모험이 우리의 상호 이해를 깊게 할 것이라고 생각하나요?", "nl": "Welke avontuur denk je dat onze wederzijdse begrip zou verdiepen?", "zh": "你认为哪次冒险会加深我们对彼此的理解？"}'),
  ('communication', 1, '{"en": "What''s one thing I do that makes you feel truly heard?", "es": "¿Qué es lo que hago que te hace sentir verdaderamente escuchado?", "fr": "Quelle est la chose que je fais qui te fait vraiment sentir écouté?", "it": "Qual è una cosa che faccio che ti fa sentire veramente ascoltato?", "ko": "내가 하는 것 중 당신이 진정으로 듣고 있다고 느끼게 하는 것은 무엇인가요?", "nl": "Wat is één ding dat ik doe waardoor je je echt gehoord voelt?", "zh": "我做的哪件事情让你感到真正被倾听了？"}'),
  ('gratitude', 1, '{"en": "What''s a small gesture I''ve done recently that you appreciated?", "es": "¿Cuál es un pequeño gesto que hice recientemente que apreciaste?", "fr": "Quel petit geste ai-je fait récemment que tu as apprécié?", "it": "Qual è un piccolo gesto che ho fatto di recente che hai apprezzato?", "ko": "최근에 내가 한 작은 행동 중에 고마웠던 게 무엇인가요?", "nl": "Wat is een klein gebaar dat ik recentelijk heb gedaan dat je waardeerde?", "zh": "我最近做过的哪个小动作让你觉得很欣赏？"}'),
  ('conflict', 1, '{"en": "How do you know when I''m upset without me saying a word?", "es": "¿Cómo sabes que estoy molesto sin que yo diga una palabra?", "fr": "Comment sais-tu que je suis contrarié sans que je dise un mot?", "it": "Come fai a sapere quando sono arrabbiato senza che io dica una parola?", "ko": "내가 아무 말도 하지 않아도 내가 화가 났다는 걸 어떻게 아나요?", "nl": "Hoe weet je wanneer ik van streek ben zonder dat ik een woord zeg?", "zh": "我不说话的时候，你怎么知道我不高兴了？"}'),
  ('growth', 1, '{"en": "What''s a new skill you''d love us to learn together?", "es": "¿Cuál es una nueva habilidad que te gustaría que aprendiéramos juntos?", "fr": "Quelle nouvelle compétence aimerais-tu que nous apprenions ensemble?", "it": "Qual è una nuova abilità che ti piacerebbe che imparassimo insieme?", "ko": "우리가 함께 배우고 싶은 새로운 기술이 무엇인가요?", "nl": "Wat is een nieuwe vaardigheid die je graag samen met mij zou willen leren?", "zh": "你想和我一起学习哪项新技能？"}'),
  ('intimacy', 1, '{"en": "What''s your favorite way of connecting with me after a long day?", "es": "¿Cuál es tu forma favorita de conectarte conmigo después de un largo día?", "fr": "Quelle est ta façon préférée de te connecter avec moi après une longue journée?", "it": "Qual è il tuo modo preferito di connetterti con me dopo una lunga giornata?", "ko": "긴 하루 후에 나와 연결되는 당신의 좋아하는 방법은 무엇인가요?", "nl": "Wat is jouw favoriete manier om contact met mij te maken na een lange dag?", "zh": "劳累一天后，你最喜欢和我互动的方式是什么？"}'),
  ('dreams', 1, '{"en": "If we could change one thing about our future plans, what would it be?", "es": "Si pudiéramos cambiar una cosa sobre nuestros planes futuros, ¿cuál sería?", "fr": "Si nous pouvions changer une chose à propos de nos plans futurs, quelle serait-elle?", "it": "Se potessimo cambiare una cosa dei nostri piani futuri, quale sarebbe?", "ko": "우리의 미래 계획 중 한 가지를 바꿀 수 있다면 무엇일까요?", "nl": "Als we één ding aan onze toekomstige plannen konden veranderen, wat zou dat dan zijn?", "zh": "如果我们能改变未来计划中的一件事，那会是什么？"}'),
  ('memories', 1, '{"en": "What''s a memory of us that always makes you smile?", "es": "¿Cuál es un recuerdo nuestro que siempre te hace sonreír?", "fr": "Quel est un souvenir de nous qui te fait toujours sourire?", "it": "Qual è un ricordo di noi che ti fa sempre sorridere?", "ko": "우리의 기억 중 항상 미소를 짓게 만드는 것은 무엇인가요?", "nl": "Wat is een herinnering aan ons dat je altijd doet glimlachen?", "zh": "我们之间的哪个回忆总能让你微笑？"}'),
  ('values', 1, '{"en": "What principle do you think is the foundation of our relationship?", "es": "¿Qué principio crees que es la base de nuestra relación?", "fr": "Quel principe penses-tu être le fondement de notre relation?", "it": "Quale principio pensi sia il fondamento della nostra relazione?", "ko": "우리 관계의 기초가 되는 원칙은 무엇이라고 생각하나요?", "nl": "Welke principe vind je de basis van onze relatie?", "zh": "你认为我们关系的基础是什么原则？"}'),
  ('fun', 1, '{"en": "What''s an adventure we''ve never discussed but you''re curious about?", "es": "¿Cuál es una aventura de la que nunca hemos hablado, pero te da curiosidad?", "fr": "Quelle est une aventure dont nous n''avons jamais discuté, mais qui t''intrigue?", "it": "Qual è un''avventura di cui non abbiamo mai parlato, ma che ti incuriosisce?", "ko": "우리가 논의하지 않았지만 호기심이 생기는 모험은 무엇인가요?", "nl": "Wat is een avontuur dat we nooit besproken hebben, maar dat je nieuwsgierig maakt?", "zh": "我们从未讨论过但你感兴趣的冒险是什么？"}'),
  ('finances', 1, '{"en": "What financial goal do you find most exciting for us to achieve?", "es": "¿Cuál es el objetivo financiero que te parece más emocionante lograr juntos?", "fr": "Quel objectif financier trouves-tu le plus excitant à atteindre pour nous?", "it": "Qual è l''obiettivo finanziario che trovi più entusiasmante da raggiungere per noi?", "ko": "함께 달성하기 가장 흥미로운 재정 목표는 무엇인가요?", "nl": "Welk financieel doel vind je het spannendst voor ons om te bereiken?", "zh": "你认为我们最令人兴奋的经济目标是什么？"}'),
  ('family', 1, '{"en": "What''s one thing you''ve learned from my family that you appreciate?", "es": "¿Qué es algo que has aprendido de mi familia y que aprecias?", "fr": "Quelle est une chose que tu as apprise de ma famille que tu apprécies?", "it": "Qual è una cosa che hai imparato dalla mia famiglia che apprezzi?", "ko": "내 가족에게서 배운 것 중 가장 감사한 것은 무엇인가요?", "nl": "Wat is één ding dat je hebt geleerd van mijn familie dat je waardeert?", "zh": "你从我的家人那里学到什么并感到感激？"}'),
  ('adventure', 1, '{"en": "What''s an activity you''ve always wanted to try with me, even if it sounds daring or unusual?", "es": "¿Cuál es una actividad que siempre has querido probar conmigo, incluso si parece atrevida o inusual?", "fr": "Quelle est une activité que tu as toujours voulu essayer avec moi, même si elle paraît audacieuse ou inhabituelle?", "it": "Qual è un''attività che hai sempre voluto provare con me, anche se sembra audace o insolita?", "ko": "과감하거나 이색적이더라도 나와 함께 하고 싶은 활동은 무엇인가요?", "nl": "Wat is een activiteit die je altijd al met mij hebt willen proberen, zelfs als het gedurfd of ongebruikelijk klinkt?", "zh": "你一直想和我尝试的活动是什么，即使它听起来大胆或不寻常？"}'),
  ('communication', 1, '{"en": "What''s your favorite way for us to sort out misunderstandings?", "es": "¿Cuál es tu forma favorita de resolver los malentendidos entre nosotros?", "fr": "Quelle est ta manière préférée de résoudre les malentendus entre nous?", "it": "Qual è il tuo modo preferito per risolvere i malintesi tra noi?", "ko": "우리 사이의 오해를 풀기 위한 당신이 선호하는 방법은 무엇인가요?", "nl": "Wat is jouw favoriete manier om misverstanden tussen ons op te lossen?", "zh": "你最喜欢用什么方式来解决我们之间的误会？"}'),
  ('gratitude', 1, '{"en": "What’s something about our relationship that you’re grateful for right now?", "es": "¿Qué es algo sobre nuestra relación que agradeces en este momento?", "fr": "Quelle est une chose à propos de notre relation pour laquelle tu es reconnaissant en ce moment?", "it": "Qual è qualcosa della nostra relazione per cui sei grato in questo momento?", "ko": "현재 우리 관계에서 감사한 점은 무엇인가요?", "nl": "Wat is iets aan onze relatie waar je nu dankbaar voor bent?", "zh": "你现在对我们的关系最感激的是什么？"}'),
  ('conflict', 2, '{"en": "What''s a conflict resolution strategy you believe works well for us?", "es": "¿Cuál es una estrategia de resolución de conflictos que crees que funciona bien para nosotros?", "fr": "Quelle est une stratégie de résolution de conflits que tu crois efficace pour nous?", "it": "Qual è una strategia di risoluzione dei conflitti che credi funzioni bene per noi?", "ko": "우리에게 효과적이라고 믿는 갈등 해결 전략은 무엇인가요?", "nl": "Wat is een strategie voor conflictbeheersing die volgens jou goed voor ons werkt?", "zh": "你认为对我们有效的冲突解决策略是什么？"}'),
  ('growth', 2, '{"en": "How do you see our relationship evolving in the next three years?", "es": "¿Cómo ves que nuestra relación evolucione en los próximos tres años?", "fr": "Comment vois-tu notre relation évoluer dans les trois prochaines années?", "it": "Come vedi l''evoluzione della nostra relazione nei prossimi tre anni?", "ko": "앞으로 3년 동안 우리 관계가 어떻게 발전할 것이라고 보나요?", "nl": "Hoe zie je onze relatie zich in de komende drie jaar ontwikkelen?", "zh": "你认为我们的关系在未来三年会如何发展？"}'),
  ('intimacy', 2, '{"en": "In what ways can we deepen our emotional connection?", "es": "¿De qué maneras podemos profundizar nuestra conexión emocional?", "fr": "De quelles manières pouvons-nous approfondir notre connexion émotionnelle?", "it": "In quali modi possiamo approfondire la nostra connessione emotiva?", "ko": "우리의 정서적 연결을 어떻게 더 깊게 할 수 있을까요?", "nl": "Op welke manieren kunnen we onze emotionele band verdiepen?", "zh": "我们可以通过哪些方式加深我们的情感联系？"}'),
  ('dreams', 2, '{"en": "What''s a dream you think we share but haven''t yet explored together?", "es": "¿Cuál es un sueño que crees que compartimos pero que aún no hemos explorado juntos?", "fr": "Quel est un rêve que tu penses que nous partageons mais que nous n''avons pas encore exploré ensemble?", "it": "Qual è un sogno che pensi condividiamo ma che non abbiamo ancora esplorato insieme?", "ko": "공유하긴 했지만 아직 함께 탐험하지 않은 꿈은 무엇이라고 생각하나요?", "nl": "Wat is een droom die we volgens jou delen maar die we nog niet samen hebben verkend?", "zh": "你认为我们共有但尚未共同探索的梦想是什么？"}'),
  ('memories', 2, '{"en": "Which memory with me do you think has been a defining moment in our relationship?", "es": "¿Qué recuerdo conmigo crees que ha sido un momento decisivo en nuestra relación?", "fr": "Quel souvenir avec moi penses-tu avoir été un moment déterminant dans notre relation?", "it": "Quale ricordo con me pensi che sia stato un momento determinante nella nostra relazione?", "ko": "우리 관계의 결정적 순간이라고 생각하는 나와의 기억은 무엇인가요?", "nl": "Welke herinnering met mij denk je dat een bepalend moment in onze relatie is geweest?", "zh": "你认为和我在一起的哪段记忆是我们关系中的决定性时刻？"}'),
  ('values', 2, '{"en": "Which of our shared values would you like to pass on to a future generation?", "es": "¿Cuál de nuestros valores compartidos te gustaría transmitir a la próxima generación?", "fr": "Quelle de nos valeurs partagées aimerais-tu transmettre à une future génération?", "it": "Quali dei nostri valori condivisi vorresti trasmettere a una futura generazione?", "ko": "우리의 공유 가치 중 어떤 것을 미래 세대에 전하고 싶나요?", "nl": "Welke van onze gedeelde waarden zou je willen doorgeven aan een toekomstige generatie?", "zh": "你想将我们共有的哪项价值传递给下一代？"}'),
  ('fun', 2, '{"en": "What''s a fun twist on a traditional date night you''d like us to try?", "es": "¿Cuál es una variación divertida en una cita nocturna tradicional que te gustaría que intentáramos?", "fr": "Quelle est une variation amusante sur une soirée traditionnelle que tu aimerais que nous essayions?", "it": "Qual è una variazione divertente di una serata tradizionale che ti piacerebbe provassimo?", "ko": "전통적인 데이트 밤에 즐거운 변화를 주고 싶은 것은 무엇인가요?", "nl": "Wat is een leuke draai aan een traditionele date-avond die je graag zou willen uitproberen?", "zh": "你想让我们尝试什么有趣的传统约会之夜变化？"}'),
  ('finances', 2, '{"en": "How do you envision balancing saving and spending for experiences with me?", "es": "¿Cómo imaginas equilibrar el ahorro y el gasto para vivir experiencias conmigo?", "fr": "Comment envisages-tu de concilier l''épargne et la dépense pour vivre des expériences avec moi?", "it": "Come immagini di bilanciare il risparmio e la spesa per esperienze insieme a me?", "ko": "나와의 경험을 위한 저축과 지출의 균형을 어떻게 상상하나요?", "nl": "Hoe zie je het balanceren van sparen en uitgeven voor ervaringen met mij?", "zh": "你如何设想在积蓄与和我一起体验的花费间做到平衡？"}'),
  ('family', 2, '{"en": "How do you feel we integrate both of our family traditions into our own?", "es": "¿Cómo sientes que integramos las tradiciones de ambas familias en las nuestras?", "fr": "Comment sens-tu que nous intégrons les traditions de nos deux familles dans les nôtres?", "it": "Come senti che integriamo le tradizioni di entrambe le nostre famiglie nelle nostre?", "ko": "우리 양가의 가족 전통을 어떻게 우리의 것으로 통합하고 있다고 느끼나요?", "nl": "Hoe voel je dat we de tradities van onze beide families in die van ons integreren?", "zh": "你觉得我们是如何将双方的家庭传统纳入自己的传统？"}'),
  ('adventure', 2, '{"en": "What''s a place in nature you''ve never been but would love to explore with me?", "es": "¿Cuál es un lugar en la naturaleza donde nunca has estado pero que te encantaría explorar conmigo?", "fr": "Quel est un endroit dans la nature où tu n''es jamais allé mais que tu adorerais explorer avec moi?", "it": "Qual è un luogo nella natura in cui non sei mai stato ma che ti piacerebbe esplorare con me?", "ko": "아직 가보지 못했지만 나와 함께 탐험해보고 싶은 자연 속 장소가 있나요?", "nl": "Wat is een plek in de natuur waar je nog nooit bent geweest maar graag met mij zou willen verkennen?", "zh": "你从未去过但很想和我一起探索的大自然某个地方是哪里？"}'),
  ('communication', 2, '{"en": "How can we improve the way we express tough love to each other?", "es": "¿Cómo podemos mejorar la forma en que expresamos el amor difícil el uno al otro?", "fr": "Comment pouvons-nous améliorer la façon dont nous exprimons l''amour exigeant l''un envers l''autre?", "it": "Come possiamo migliorare il modo in cui esprimiamo l''amore duro l''uno con l''altro?", "ko": "우리가 서로에게 어려운 사랑을 표현하는 방법을 어떻게 개선할 수 있을까요?", "nl": "Hoe kunnen we de manier verbeteren waarop we elkaar moeilijke liefde tonen?", "zh": "我们如何改进彼此表达艰难爱的方式？"}'),
  ('gratitude', 2, '{"en": "What''s a quality in me that you’re thankful I bring to our partnership?", "es": "¿Cuál es una cualidad en mí que agradeces que aporte a nuestra relación?", "fr": "Quelle est une qualité en moi que tu es reconnaissant que j''apporte à notre partenariat?", "it": "Qual è una qualità in me che sei grato che porti alla nostra collaborazione?", "ko": "내 파트너십에 기여하는 나의 특성 중 감사하게 여기는 것이 무엇인가요?", "nl": "Wat is een kwaliteit in mij waar je dankbaar voor bent dat ik in onze relatie inbreng?", "zh": "我有什么特质让你感谢我对我们关系的贡献？"}'),
  ('conflict', 3, '{"en": "What''s a past conflict that transformed our relationship for the better?", "es": "¿Cuál es un conflicto pasado que transformó nuestra relación para mejor?", "fr": "Quel est un conflit passé qui a transformé notre relation pour le mieux?", "it": "Qual è un conflitto passato che ha trasformato la nostra relazione in meglio?", "ko": "과거의 어떤 갈등이 우리의 관계를 더 나아지게 했나요?", "nl": "Wat is een verleden conflict dat onze relatie ten goede heeft veranderd?", "zh": "过去的哪场冲突让我们的关系变得更好？"}'),
  ('growth', 3, '{"en": "What''s a life challenge you believe we''ve navigated well together, and why?", "es": "¿Cuál es un desafío de la vida que crees que hemos navegado bien juntos, y por qué?", "fr": "Quel est un défi de la vie que tu penses que nous avons bien géré ensemble, et pourquoi?", "it": "Qual è una sfida della vita che credi abbiamo affrontato bene insieme, e perché?", "ko": "잘 헤쳐 나갔다고 믿는 인생의 도전은 무엇이며, 왜 그렇게 생각하나요?", "nl": "Wat is een levensuitdaging waarvan je denkt dat we die goed samen hebben doorstaan, en waarom?", "zh": "你认为我们一起很好地应对了哪个生活挑战，为什么？"}'),
  ('intimacy', 3, '{"en": "What’s a deeper level of intimacy you hope to achieve with me?", "es": "¿Cuál es un nivel más profundo de intimidad que esperas lograr conmigo?", "fr": "Quel est un niveau plus profond d''intimité que tu espères atteindre avec moi?", "it": "Qual è un livello più profondo di intimità che speri di raggiungere con me?", "ko": "나와 함께 이루기 희망하는 더 깊은 수준의 친밀감은 무엇인가요?", "nl": "Wat is een dieper niveau van intimiteit dat je hoopt met mij te bereiken?", "zh": "你希望与我达到的更深层次的亲密感是什么？"}'),
  ('dreams', 3, '{"en": "What''s a long-term dream that feels daunting but thrilling to pursue with me?", "es": "¿Cuál es un sueño a largo plazo que se siente desafiante pero emocionante de perseguir conmigo?", "fr": "Quel est un rêve à long terme qui semble intimidant mais excitant à poursuivre avec moi?", "it": "Qual è un sogno a lungo termine che sembra impegnativo ma emozionante da perseguire con me?", "ko": "함께 하기에는 벅차 보이지만 설레는 장기적인 꿈은 무엇인가요?", "nl": "Wat is een langetermijndroom die ontmoedigend maar spannend aanvoelt om met mij na te jagen?", "zh": "你认为追求和我一起实现的长期梦想中，哪个感觉既艰巨又令人兴奋？"}'),
  ('memories', 3, '{"en": "How do you think our shared history shapes our present and future relationship?", "es": "¿Cómo crees que nuestra historia compartida da forma a nuestra relación presente y futura?", "fr": "Comment penses-tu que notre histoire commune façonne notre relation présente et future?", "it": "Come pensi che la nostra storia condivisa formi la nostra relazione presente e futura?", "ko": "우리의 공유 역사가 현재와 미래의 관계를 어떻게 형성한다고 생각하나요?", "nl": "Hoe denk je dat onze gedeelde geschiedenis onze huidige en toekomstige relatie vormgeeft?", "zh": "你认为我们的共同历史如何影响我们现在和未来的关系？"}'),
  ('values', 3, '{"en": "How have our values been tested and proven over the course of our relationship?", "es": "¿Cómo han sido probados y demostrados nuestros valores a lo largo de nuestra relación?", "fr": "Comment nos valeurs ont-elles été testées et prouvées au cours de notre relation?", "it": "Come sono stati messi alla prova e dimostrati i nostri valori nel corso della nostra relazione?", "ko": "우리의 가치관이 관계를 통해 어떻게 시험되고 증명되었나요?", "nl": "Hoe zijn onze waarden getest en bewezen tijdens onze relatie?", "zh": "在我们的关系中，我们的价值观是如何在考验中得到证明的？"}'),
  ('fun', 3, '{"en": "What''s a playful activity that could become a unique tradition for us?", "es": "¿Cuál es una actividad lúdica que podría convertirse en una tradición única para nosotros?", "fr": "Quelle activité ludique pourrait devenir une tradition unique pour nous?", "it": "Qual è un''attività giocosa che potrebbe diventare una tradizione unica per noi?", "ko": "우리만의 독특한 전통이 될 수 있는 재미있는 활동은 무엇인가요?", "nl": "Wat is een speelse activiteit die een unieke traditie voor ons zou kunnen worden?", "zh": "什么样的有趣活动可以成为我们独特的传统？"}'),
  ('intimacy', 1, '{"en": "How do you feel most connected to me during our daily routine?", "es": "¿Cuándo te sientes más conectado conmigo durante nuestra rutina diaria?", "fr": "Quand te sens-tu le plus connecté à moi pendant notre routine quotidienne?", "it": "Quando ti senti più connesso a me durante la nostra routine quotidiana?", "ko": "일상에서 나와 가장 연결된 느낌을 받을 때는 언제인가요?", "nl": "Wanneer voel je je het meest verbonden met mij tijdens onze dagelijkse routine?", "zh": "在日常生活中，您何时感到与我联系最紧密？"}'),
  ('family', 1, '{"en": "What is a family tradition from your childhood that we might incorporate into our lives?", "es": "¿Cuál es una tradición familiar de tu infancia que podríamos incorporar a nuestras vidas?", "fr": "Quelle est une tradition familiale de ton enfance que nous pourrions intégrer dans nos vies?", "it": "Qual è una tradizione familiare della tua infanzia che potremmo integrare nelle nostre vite?", "ko": "어린 시절의 가족 전통 중 우리 삶에 통합할 수 있는 것이 무엇인가요?", "nl": "Wat is een familietraditie uit je jeugd die we in ons leven kunnen opnemen?", "zh": "您童年时的家庭传统中有哪些可以融入我们的生活？"}'),
  ('values', 1, '{"en": "What small moments bring you a sense of purpose in our relationship?", "es": "¿Qué pequeños momentos te brindan un sentido de propósito en nuestra relación?", "fr": "Quels petits moments te donnent un sentiment de but dans notre relation?", "it": "Quali piccoli momenti ti danno un senso di scopo nella nostra relazione?", "ko": "관계에서 어떤 작은 순간들이 목적감을 주나요?", "nl": "Welke kleine momenten geven je een gevoel van doel in onze relatie?", "zh": "在我们的关系中，哪些小细节让您觉得有意义？"}'),
  ('finances', 1, '{"en": "How do you imagine our financial priorities changing in the next five years?", "es": "¿Cómo imaginas que cambien nuestras prioridades financieras en los próximos cinco años?", "fr": "Comment imagines-tu que nos priorités financières changent dans les cinq prochaines années?", "it": "Come immagini che cambieranno le nostre priorità finanziarie nei prossimi cinque anni?", "ko": "앞으로 5년 동안 우리의 재정적 우선순위가 어떻게 변할 것이라고 상상하나요?", "nl": "Hoe stel je je voor dat onze financiële prioriteiten de komende vijf jaar veranderen?", "zh": "您如何想象我们未来五年的财务优先事项会有怎样的变化？"}'),
  ('communication', 1, '{"en": "What''s one thing I do that makes you feel truly heard?", "es": "¿Qué es lo que hago que te hace sentir verdaderamente escuchado(a)?", "fr": "Quelle est la chose que je fais qui te fait te sentir vraiment entendu(e)?", "it": "Qual è una cosa che faccio che ti fa sentire veramente ascoltato?", "ko": "제가 하는 일 중 당신이 진정으로 들었다고 느끼게 해주는 것은 무엇인가요?", "nl": "Wat is er één ding dat ik doe waardoor je echt gehoord voelt?", "zh": "我做的哪一件事让您觉得自己被真正倾听了？"}'),
  ('dreams', 1, '{"en": "What is a seemingly small dream you''ve had that we could work towards together?", "es": "¿Cuál es un sueño aparentemente pequeño que has tenido y que podríamos lograr juntos?", "fr": "Quel est un rêve apparemment petit que tu as eu et pour lequel nous pourrions travailler ensemble?", "it": "Qual è un sogno apparentemente piccolo che hai avuto e su cui potremmo lavorare insieme?", "ko": "당신이 가진 작은 꿈 중 우리가 함께 노력할 수 있는 것은 무엇인가요?", "nl": "Wat is een ogenschijnlijk kleine droom die je hebt gehad en waar we samen naartoe kunnen werken?", "zh": "您曾经梦想过的一个看似微不足道的愿望，我们可以一起努力实现吗？"}'),
  ('memories', 1, '{"en": "Which memory with me makes you smile the most and why?", "es": "¿Qué recuerdo conmigo te hace sonreír más y por qué?", "fr": "Quel souvenir avec moi te fait le plus sourire et pourquoi?", "it": "Quale ricordo con me ti fa sorridere di più e perché?", "ko": "나와 함께한 어느 기억이 당신을 가장 많이 미소짓게 하며, 그 이유는 무엇인가요?", "nl": "Welke herinnering met mij maakt je het meest aan het lachen en waarom?", "zh": "与我一起的哪段记忆让您最开心？为什么？"}'),
  ('fun', 1, '{"en": "What is a new activity you''d like us to try for a fun date?", "es": "¿Cuál es una nueva actividad que te gustaría que probáramos para una cita divertida?", "fr": "Quelle nouvelle activité aimerais-tu que nous essayions pour un rendez-vous amusant?", "it": "Qual è una nuova attività che ti piacerebbe provare per un appuntamento divertente?", "ko": "재미있는 데이트를 위해 우리가 시도해 보고 싶은 새로운 활동은 무엇인가요?", "nl": "Wat is een nieuwe activiteit die je graag zou willen proberen voor een leuke date?", "zh": "您希望我们尝试什么新的活动来增加约会的乐趣？"}'),
  ('gratitude', 1, '{"en": "What is a small thing I did recently that you''re thankful for?", "es": "¿Cuál es una pequeña cosa que hice recientemente por la que estás agradecido(a)?", "fr": "Quelle petite chose ai-je faite récemment pour laquelle tu es reconnaissant(e)?", "it": "Qual è una piccola cosa che ho fatto di recente per cui sei grato?", "ko": "제가 최근에 한 일 중에 당신이 감사하게 생각하는 작은 일은 무엇인가요?", "nl": "Wat is een kleinigheidje dat ik onlangs heb gedaan waar je dankbaar voor bent?", "zh": "最近我为您做的哪件小事让您感到感激？"}'),
  ('conflict', 1, '{"en": "What''s a non-verbal cue I give that helps you know when I''m upset?", "es": "¿Cuál es una señal no verbal que te doy que te ayuda a saber cuándo estoy molesto(a)?", "fr": "Quel indice non verbal je donne qui t''aide à savoir quand je suis contrarié(e)?", "it": "Qual è un segnale non verbale che do che ti aiuta a capire quando sono turbato?", "ko": "제가 기분이 상했을 때 당신이 알아차릴 수 있는 비언어적 신호는 무엇인가요?", "nl": "Wat is een non-verbale aanwijzing die ik geef waardoor je weet wanneer ik van streek ben?", "zh": "我给出的哪些非语言暗示可以帮助您知道我什么时候心情不好？"}'),
  ('growth', 1, '{"en": "What is a personal goal you have that I can support you in achieving?", "es": "¿Cuál es un objetivo personal que tienes y que puedo ayudarte a lograr?", "fr": "Quel est un objectif personnel que tu as et que je peux t''aider à atteindre?", "it": "Qual è un obiettivo personale che hai e che posso aiutarti a raggiungere?", "ko": "당신이 가진 개인적인 목표 중 제가 달성하도록 도와줄 수 있는 것은 무엇인가요?", "nl": "Wat is een persoonlijk doel dat je hebt waarbij ik je kan helpen om te behalen?", "zh": "您有哪些个人目标需要我帮助实现？"}'),
  ('adventure', 1, '{"en": "What adventure do you see us taking together in the next few years?", "es": "¿Qué aventura ves que emprendemos juntos en los próximos años?", "fr": "Quelle aventure vois-tu que nous entreprenons ensemble dans les prochaines années?", "it": "Quale avventura vedi intraprendere insieme nei prossimi anni?", "ko": "앞으로 몇 년 동안 우리가 함께할 모험은 무엇이라고 생각하나요?", "nl": "Welk avontuur zie je ons de komende jaren samen aangaan?", "zh": "您认为在接下来的几年里我们会经历哪些冒险？"}'),
  ('values', 1, '{"en": "Which of your core values do I embody well, and how does it affect our relationship?", "es": "¿Cuál de tus valores fundamentales reflejo bien, y cómo afecta a nuestra relación?", "fr": "Quelle valeur fondamentale incarné-je bien, et comment cela affecte-t-il notre relation?", "it": "Quale dei tuoi valori fondamentali incarna bene e come ciò influisce sulla nostra relazione?", "ko": "제가 잘 구현하고 있는 당신의 핵심 가치는 무엇이며, 그것은 우리의 관계에 어떻게 영향을 미치나요?", "nl": "Welke van je kernwaarden belichaam ik goed en hoe beïnvloedt dat onze relatie?", "zh": "我很好地体现了您哪一项核心价值观，这对我们的关系有何影响？"}'),
  ('intimacy', 1, '{"en": "In what ways can we enhance our emotional intimacy on a daily basis?", "es": "¿De qué maneras podemos mejorar nuestra intimidad emocional a diario?", "fr": "De quelles manières pouvons-nous améliorer notre intimité émotionnelle au quotidien?", "it": "In quali modi possiamo migliorare la nostra intimità emotiva ogni giorno?", "ko": "어떤 방법으로 일상적으로 우리 사이의 감정적인 친밀감을 향상시킬 수 있을까요?", "nl": "Op welke manieren kunnen we onze emotionele intimiteit dagelijks verbeteren?", "zh": "我们如何在日常生活中提升我们的情感亲密度？"}'),
  ('family', 2, '{"en": "How do you envision balancing both of our families if we have a special event or holiday?", "es": "¿Cómo imaginas equilibrar a ambas familias si tenemos un evento especial o festivo?", "fr": "Comment envisages-tu de faire l''équilibre entre nos deux familles si nous avons un événement spécial ou une fête?", "it": "Come immagini di bilanciare entrambe le famiglie se abbiamo un evento speciale o una festa?", "ko": "특별한 행사나 휴일이 있을 때 양가 가족의 균형을 어떻게 상상하나요?", "nl": "Hoe stel je je voor om beide families in balans te houden als we een speciaal evenement of feestdag hebben?", "zh": "如果我们有特别活动或假期，您如何设想平衡双方家庭？"}'),
  ('intimacy', 2, '{"en": "What''s one intimate moment we''ve shared that you''d like to recreate or change in the future?", "es": "¿Cuál es un momento íntimo que hemos compartido que te gustaría recrear o cambiar en el futuro?", "fr": "Quel est un moment intime que nous avons partagé et que tu aimerais recréer ou changer dans le futur?", "it": "Qual è un momento intimo che abbiamo condiviso che ti piacerebbe ricreare o cambiare in futuro?", "ko": "함께 공유했던 친밀한 순간 중 미래에 다시 만들거나 변화시키고 싶은 것은 무엇인가요?", "nl": "Wat is een intiem moment dat we hebben gedeeld en dat je in de toekomst opnieuw zou willen creëren of veranderen?", "zh": "我们曾经分享过的哪一刻亲密时光让您想要在未来重现或改变？"}'),
  ('values', 2, '{"en": "How do our shared values enhance or challenge our relationship?", "es": "¿Cómo nuestros valores compartidos mejoran o desafían nuestra relación?", "fr": "Comment nos valeurs communes améliorent-elles ou mettent-elles au défi notre relation?", "it": "In che modo i nostri valori condivisi migliorano o mettono alla prova la nostra relazione?", "ko": "공유된 가치관이 우리 관계를 어떻게 강화하거나 도전하게 하나요?", "nl": "Hoe verbeteren of dagen onze gedeelde waarden onze relatie uit?", "zh": "我们共享的价值观如何增强或挑战我们的关系？"}'),
  ('finances', 2, '{"en": "How would you feel if one of us made a significant career change that impacted our income?", "es": "¿Cómo te sentirías si alguno de nosotros hiciera un cambio significativo de carrera que impactara en nuestros ingresos?", "fr": "Comment te sentirais-tu si l''un de nous faisait un changement de carrière significatif qui affectait nos revenus?", "it": "Come ti sentiresti se uno di noi facesse un cambiamento di carriera significativo che influenzasse il nostro reddito?", "ko": "우리 중 한 사람이 소득에 영향을 주는 중요한 직업 변화가 있을 경우 어떻게 느끼겠나요?", "nl": "Hoe zou je je voelen als een van ons een significante carrièreverandering doormaakt die ons inkomen beïnvloedt?", "zh": "如果我们中的一人做出了重大的职业改变，影响了我们的收入，您会有什么感受？"}'),
  ('communication', 2, '{"en": "In what situations do you feel our communication could be improved, and how?", "es": "¿En qué situaciones sientes que nuestra comunicación podría mejorar y cómo?", "fr": "Dans quelles situations ressens-tu que notre communication pourrait s''améliorer, et comment?", "it": "In quali situazioni senti che la nostra comunicazione potrebbe migliorare e come?", "ko": "어떤 상황에서 우리의 소통이 개선될 수 있다고 느끼며, 어떻게 가능할까요?", "nl": "In welke situaties denk je dat onze communicatie kan verbeteren, en hoe dan?", "zh": "在什么情况下您觉得我们的沟通可以改善？如何改进？"}'),
  ('dreams', 2, '{"en": "How do you imagine our dreams evolving if we decided to move to a new country together?", "es": "¿Cómo imaginas que evolucionen nuestros sueños si decidimos mudarnos juntos a un nuevo país?", "fr": "Comment imagines-tu l''évolution de nos rêves si nous décidons de déménager ensemble dans un nouveau pays?", "it": "Come immagini che evolveranno i nostri sogni se decidiamo di trasferirci insieme in un nuovo paese?", "ko": "함께 새로운 나라로 이사하기로 결정하면 우리의 꿈이 어떻게 발전할 것이라고 상상하나요?", "nl": "Hoe stel je je voor dat onze dromen evolueren als we samen besluiten om naar een nieuw land te verhuizen?", "zh": "如果我们决定一起迁居到新的国家，您如何想象我们的梦想会如何演变？"}'),
  ('memories', 2, '{"en": "Is there a past challenging moment we overcame that reshaped our relationship positively?", "es": "¿Hubo algún momento desafiante en el pasado que superamos y que cambió positivamente nuestra relación?", "fr": "Y a-t-il un moment difficile du passé que nous avons surmonté et qui a positivement transformé notre relation?", "it": "C''è stato un momento difficile del passato che abbiamo superato e che ha trasformato positivamente la nostra relazione?", "ko": "과거에 우리가 극복해서 관계를 긍정적으로 변화시킨 어려운 순간이 있었나요?", "nl": "Is er een uitdagend moment uit het verleden dat we hebben overwonnen dat onze relatie positief heeft veranderd?", "zh": "是否有过去我们克服的挑战时刻，从而积极地改变了我们的关系？"}'),
  ('fun', 2, '{"en": "What new hobby would you like us to explore together that could deepen our bond?", "es": "¿Qué nuevo pasatiempo te gustaría que exploremos juntos que podría profundizar nuestro vínculo?", "fr": "Quel nouveau passe-temps aimerais-tu que nous explorions ensemble qui pourrait renforcer notre lien?", "it": "Quale nuovo hobby ti piacerebbe esplorare insieme che potrebbe approfondire il nostro legame?", "ko": "우리의 유대를 강화할 수 있는 새로운 취미 활동은 무엇을 함께 탐구하고 싶나요?", "nl": "Welke nieuwe hobby zou je graag samen willen verkennen die onze band zou kunnen verdiepen?", "zh": "您希望我们一起探索什么新的爱好，以加深我们的关系？"}'),
  ('gratitude', 2, '{"en": "How does expressing gratitude between us reinforce our connection?", "es": "¿Cómo refuerza nuestra conexión expresarnos gratitud mutuamente?", "fr": "Comment le fait d''exprimer notre gratitude renforce-t-il notre connexion?", "it": "Come rafforza la nostra connessione esprimere gratitudine tra di noi?", "ko": "우리 사이에서 감사의 표현이 어떻게 우리 관계를 강화하나요?", "nl": "Hoe versterkt het uiten van dankbaarheid tussen ons onze verbinding?", "zh": "在我们之间表达感激之情如何加强我们的联系？"}'),
  ('conflict', 2, '{"en": "What is one conflict we resolved that taught us something valuable about our relationship?", "es": "¿Cuál es un conflicto que resolvimos que nos enseñó algo valioso sobre nuestra relación?", "fr": "Quel est un conflit que nous avons résolu qui nous a enseigné quelque chose de précieux sur notre relation?", "it": "Qual è un conflitto che abbiamo risolto che ci ha insegnato qualcosa di prezioso sulla nostra relazione?", "ko": "우리가 해결해서 관계에 대해 가치 있는 것을 배운 갈등은 무엇인가요?", "nl": "Wat is een conflict dat we hebben opgelost dat ons iets waardevols heeft geleerd over onze relatie?", "zh": "我们曾解决的冲突中，有哪一个教会了我们一些关于关系的宝贵经验？"}'),
  ('growth', 2, '{"en": "How do you see our relationship contributing to our personal growth over the next decade?", "es": "¿Cómo ves que nuestra relación contribuya a nuestro crecimiento personal durante la próxima década?", "fr": "Comment vois-tu notre relation contribuer à notre croissance personnelle au cours de la prochaine décennie?", "it": "Come vedi la nostra relazione contribuire alla nostra crescita personale nel prossimo decennio?", "ko": "우리 관계가 향후 10년 동안 개인적 성장에 어떻게 기여할 것이라고 보나요?", "nl": "Hoe zie je onze relatie bijdragen aan onze persoonlijke groei in het komende decennium?", "zh": "您认为我们的关系将在未来十年中如何促进我们的个人成长？"}'),
  ('adventure', 2, '{"en": "What''s an unusual adventure you see us embarking upon that few couples dare to try?", "es": "¿Cuál es una aventura inusual que ves que emprendemos y que pocas parejas se atreven a intentar?", "fr": "Quelle est une aventure inhabituelle que tu nous vois entreprendre et que peu de couples osent essayer?", "it": "Qual è un''avventura insolita che vedi intraprendere e che poche coppie osano provare?", "ko": "몇몇 커플들만이 감히 시도하는 특이한 모험을 우리가 감행할 것이라고 생각하나요?", "nl": "Wat is een ongebruikelijk avontuur dat je ziet dat we ondernemen dat weinig paren durven te proberen?", "zh": "您希望我们尝试哪些不同寻常的冒险，很少有情侣敢于尝试？"}'),
  ('intimacy', 3, '{"en": "How do you perceive our physical affection as a reflection of our deeper connection, and what might enhance it?", "es": "¿Cómo percibes nuestro afecto físico como un reflejo de nuestra conexión más profunda, y qué podría mejorarlo?", "fr": "Comment perçois-tu notre affection physique comme un reflet de notre connexion plus profonde, et qu''est-ce qui pourrait l''améliorer?", "it": "Come percepisci il nostro affetto fisico come riflesso del nostro legame più profondo e cosa potrebbe migliorarlo?", "ko": "우리의 신체적 애정이 깊은 관계의 반영으로 보이며, 이를 향상시킬 수 있는 방법은 무엇인가요?", "nl": "Hoe zie je onze fysieke genegenheid als een weerspiegeling van onze diepere verbinding, en wat zou het kunnen verbeteren?", "zh": "您如何看待我们身体上的亲密表现为更深层次关系的反映，如何进一步改善？"}'),
  ('family', 3, '{"en": "What long-term vision do you have for the role of family in our lives, and how do we align or differ in that vision?", "es": "¿Cuál es la visión a largo plazo que tienes para el papel de la familia en nuestras vidas, y cómo nos alineamos o diferimos en esa visión?", "fr": "Quelle vision à long terme as-tu sur le rôle de la famille dans nos vies, et comment nous alignons-nous ou différons-nous dans cette vision?", "it": "Qual è la tua visione a lungo termine per il ruolo della famiglia nelle nostre vite e come ci allineiamo o differiamo in quella visione?", "ko": "우리 삶에서 가족의 역할에 대한 장기적인 비전은 무엇이며, 그 비전에 대해 우리는 어떻게 일치하거나 다른가요?", "nl": "Welke langetermijnvisie heb je voor de rol van familie in ons leven, en hoe stemmen we daarin overeen of verschillen we daarin?", "zh": "您对我们生活中家庭的角色有何长期愿景？我们在这个愿景上如何保持一致或存在差异？"}'),
  ('values', 3, '{"en": "How do you wrestle with times when our personal values do not align, and what approach do you find most constructive for reconciliation?", "es": "¿Cómo lidias con los momentos en que nuestros valores personales no están alineados, y qué enfoque encuentras más constructivo para la reconciliación?", "fr": "Comment fais-tu face aux moments où nos valeurs personnelles ne sont pas alignées, et quelle approche trouves-tu la plus constructive pour la réconciliation?", "it": "Come affronti i momenti in cui i nostri valori personali non sono allineati e quale approccio trovi più costruttivo per la riconciliazione?", "ko": "우리의 개인적인 가치관이 일치하지 않는 순간을 어떻게 극복하며, 화해를 위한 가장 건설적인 접근법은 무엇이라고 생각하나요?", "nl": "Hoe ga je om met momenten waarop onze persoonlijke waarden niet op één lijn liggen, en welke benadering vind je het meest constructief voor verzoening?", "zh": "当我们个人价值观不一致时，您如何应对？您认为哪种方式最有利于和解？"}'),
  ('finances', 3, '{"en": "In what ways can money be a tool for empowerment or a source of stress in our relationship, and how can we consciously navigate this duality?", "es": "¿De qué maneras el dinero puede ser una herramienta de empoderamiento o una fuente de estrés en nuestra relación, y cómo podemos navegar conscientemente esta dualidad?", "fr": "De quelles manières l''argent peut-il être un outil d''autonomisation ou une source de stress dans notre relation, et comment pouvons-nous naviguer consciemment cette dualité?", "it": "In che modo il denaro può essere uno strumento di empowerment o una fonte di stress nella nostra relazione, e come possiamo navigare consapevolmente questa dualità?", "ko": "돈이 우리의 관계에서 권한 부여의 도구 또는 스트레스의 원천이 될 수 있는 방법은 무엇이며, 이 이중성을 의식적으로 어떻게 탐색할 수 있을까요?", "nl": "Op welke manieren kan geld een hulpmiddel zijn voor empowerment of een bron van stress in onze relatie, en hoe kunnen we bewust met deze dualiteit omgaan?", "zh": "金钱如何在我们的关系中作为赋权工具或压力源？我们如何有意识地驾驭这两面性？"}'),
  ('communication', 3, '{"en": "How can we create a safe space for expressing not just our thoughts but our vulnerabilities without fear of judgment?", "es": "¿Cómo podemos crear un espacio seguro para expresar no solo nuestros pensamientos sino también nuestras vulnerabilidades sin temor al juicio?", "fr": "Comment pouvons-nous créer un espace sûr pour exprimer non seulement nos pensées mais aussi nos vulnérabilités sans crainte de jugement?", "it": "Come possiamo creare uno spazio sicuro per esprimere non solo i nostri pensieri ma anche le nostre vulnerabilità senza paura del giudizio?", "ko": "우리의 생각뿐만 아니라 취약점을 판단에 대한 두려움 없이 표현할 수 있는 안전한 공간을 어떻게 만들 수 있을까요?", "nl": "Hoe kunnen we een veilige ruimte creëren om niet alleen onze gedachten maar ook onze kwetsbaarheden te uiten zonder angst voor oordeel?", "zh": "我们如何创造一个安全的空间来表达我们的想法和脆弱性，而不必担心被评判？"}'),
  ('dreams', 3, '{"en": "How can we ensure that the pursuit of individual dreams enhances rather than detracts from our partnership?", "es": "¿Cómo podemos asegurar que la búsqueda de sueños individuales enriquezca en lugar de restar valor a nuestra relación?", "fr": "Comment pouvons-nous nous assurer que la poursuite de rêves individuels enrichit plutôt qu''elle ne diminue notre partenariat?", "it": "Come possiamo assicurarci che la ricerca dei sogni individuali arricchisca piuttosto che sminuire il nostro rapporto?", "ko": "개인의 꿈을 추구하는 것이 우리의 파트너십을 강화하고 손상시키지 않도록 어떻게 보장할 수 있을까요?", "nl": "Hoe kunnen we ervoor zorgen dat het nastreven van individuele dromen ons partnerschap verrijkt in plaats van vermindert?", "zh": "我们如何确保追求个人梦想是在增强而不是削弱我们的关系？"}'),
  ('growth', 3, '{"en": "What is a challenging experience in our relationship that you think catalyzed our personal growth and understanding of one another?", "es": "¿Cuál es una experiencia desafiante en nuestra relación que crees que catalizó nuestro crecimiento personal y comprensión mutua?", "fr": "Quelle est une expérience difficile dans notre relation qui, selon toi, a catalysé notre croissance personnelle et la compréhension mutuelle?", "it": "Qual è un''esperienza impegnativa nella nostra relazione che pensi abbia catalizzato la nostra crescita personale e comprensione reciproca?", "ko": "관계에서 우리가 개인의 성장과 상호 이해를 촉진시킨 도전적 경험은 무엇이라고 생각하나요?", "nl": "Wat is een uitdagende ervaring in onze relatie waarvan je denkt dat deze onze persoonlijke groei en onderling begrip heeft gekatalyseerd?", "zh": "在我们的关系中，您认为哪一段挑战经历促成了我们的个人成长与相互理解？"}'),
  ('communication', 1, '{"en": "What''s one thing I do that makes you feel truly heard?", "es": "¿Qué es lo que hago que te hace sentir realmente escuchado?", "fr": "Quelle est la chose que je fais qui te fait te sentir vraiment entendu?", "it": "Qual è una cosa che faccio che ti fa sentire veramente ascoltato?", "ko": "내가 당신을 진정으로 이해하고 있다고 느끼게 하는 한 가지는 무엇인가요?", "nl": "Wat is één ding dat ik doe waardoor je je echt gehoord voelt?", "zh": "我做的哪一件事情让你感到被真正倾听了？"}'),
  ('dreams', 1, '{"en": "If you could invent a new world holiday, what would it celebrate and how would we spend it together?", "es": "Si pudieras inventar un nuevo festivo mundial, ¿qué celebraría y cómo lo pasaríamos juntos?", "fr": "Si tu pouvais inventer une nouvelle fête mondiale, que célébrerait-elle et comment la passerions-nous ensemble ?", "it": "Se potessi inventare una nuova festività mondiale, cosa celebrerebbe e come la trascorreremmo insieme?", "ko": "새로운 세계 휴일을 발명할 수 있다면 무엇을 축하하고 어떻게 함께 보낼까요?", "nl": "Als je een nieuwe wereldwijde feestdag zou kunnen uitvinden, wat zou het vieren en hoe zouden we het samen doorbrengen?", "zh": "如果你可以发明一个新的世界节日，你会庆祝什么，我们会怎么一起度过？"}'),
  ('memories', 1, '{"en": "What''s a small, seemingly trivial moment in our relationship that you cherish?", "es": "¿Cuál es un pequeño momento, aparentemente trivial, en nuestra relación que atesoras?", "fr": "Quel est un petit moment apparemment trivial dans notre relation que tu chéris ?", "it": "Qual è un piccolo momento apparentemente banale nella nostra relazione che apprezzi?", "ko": "우리 관계에서 사소해 보이지만 소중히 여기는 작은 순간은 무엇인가요?", "nl": "Wat is een klein, ogenschijnlijk onbeduidend moment in onze relatie dat je koestert?", "zh": "在我们的关系中，哪一个看似微不足道的小瞬间是你珍惜的？"}'),
  ('fun', 1, '{"en": "If we could be characters in any fictional universe for a week, which would you choose and why?", "es": "Si pudiéramos ser personajes de cualquier universo ficticio por una semana, ¿cuál elegirías y por qué?", "fr": "Si nous pouvions être des personnages dans n''importe quel univers fictif pendant une semaine, lequel choisirais-tu et pourquoi ?", "it": "Se potessimo essere personaggi in qualsiasi universo fittizio per una settimana, quale sceglieresti e perché?", "ko": "우리가 일주일 동안 어떤 허구의 세계 속 인물이 될 수 있다면 무엇을 선택하고 왜 그런가요?", "nl": "Als we een week lang personages in een fictief universum konden zijn, welk universum zou je kiezen en waarom?", "zh": "如果我们可以在任何虚构的宇宙中做一个星期的角色，你会选择哪一个，为什么？"}'),
  ('adventure', 1, '{"en": "What''s one region of the world you''ve always wanted to explore together and why?", "es": "¿Cuál es una región del mundo que siempre has querido explorar juntos y por qué?", "fr": "Quelle est une région du monde que tu as toujours voulu explorer ensemble et pourquoi ?", "it": "Qual è una regione del mondo che hai sempre voluto esplorare insieme e perché?", "ko": "함께 탐험하고 싶었던 세계의 지역은 어디이고 그 이유는 무엇인가요?", "nl": "Welke regio van de wereld heb je altijd willen verkennen samen en waarom?", "zh": "你一直想和我一起探索的世界哪个地区，为什么？"}'),
  ('values', 1, '{"en": "If you could have dinner with one influential person (alive or deceased), who would it be, and what would you want to discuss?", "es": "Si pudieras cenar con una persona influyente (viva o fallecida), ¿quién sería y qué quisieras discutir?", "fr": "Si tu pouvais dîner avec une personne influente (vivante ou décédée), qui serait-ce et de quoi voudrais-tu parler ?", "it": "Se potessi cenare con una persona influente (viva o morta), chi sarebbe e di cosa vorresti discutere?", "ko": "영향력 있는 사람 (생존 유무 상관없음)과 저녁 식사를 할 수 있다면 누구이며 어떤 이야기를 하고 싶나요?", "nl": "Als je met één invloedrijk persoon (levend of overleden) zou kunnen dineren, wie zou het zijn en wat zou je willen bespreken?", "zh": "如果你能和一个有影响力的人（无论生死）共进晚餐，那会是谁，你想讨论什么？"}'),
  ('gratitude', 1, '{"en": "What’s an everyday thing we share that you’re grateful for?", "es": "¿Cuál es una cosa cotidiana que compartimos por la que estás agradecido?", "fr": "Quelle est une chose quotidienne que nous partageons pour laquelle tu es reconnaissant ?", "it": "Qual è una cosa quotidiana che condividiamo di cui sei grato?", "ko": "우리가 공유하는 매일의 작은 순간 중 어떤 것에 감사하고 있나요?", "nl": "Wat is iets dagelijks dat we delen waar je dankbaar voor bent?", "zh": "我们日常分享的事情中，你感激哪一件？"}'),
  ('intimacy', 1, '{"en": "What’s one simple gesture from me that makes you feel loved?", "es": "¿Cuál es un gesto sencillo de mi parte que te hace sentir amado?", "fr": "Quel est un geste simple de ma part qui te fait te sentir aimé ?", "it": "Qual è un gesto semplice da parte mia che ti fa sentire amato?", "ko": "내가 하는 간단한 행동 중 어떤 것이 당신을 사랑받고 있다고 느끼게 합니까?", "nl": "Wat is een eenvoudig gebaar van mij waardoor je je geliefd voelt?", "zh": "我一个简单的举动让你感到被爱的是哪一个？"}'),
  ('conflict', 1, '{"en": "What''s a past disagreement we handled well that taught us a valuable lesson?", "es": "¿Cuál es un desacuerdo pasado que manejamos bien y que nos enseñó una valiosa lección?", "fr": "Quel est un désaccord passé que nous avons bien géré et qui nous a appris une leçon précieuse ?", "it": "Qual è un disaccordo passato che abbiamo gestito bene e che ci ha insegnato una lezione preziosa?", "ko": "우리가 잘 처리하여 소중한 교훈을 배운 과거의 불일치는 무엇인가요?", "nl": "Wat is een meningsverschil uit het verleden dat we goed hebben aangepakt en ons een waardevolle les heeft geleerd?", "zh": "我们过去处理得很好的分歧，给了我们什么宝贵的教训？"}'),
  ('finances', 1, '{"en": "What''s a small but meaningful purchase we''ve made together that stands out to you?", "es": "¿Cuál es una compra pequeña pero significativa que hemos hecho juntos y que destaca para ti?", "fr": "Quel est un achat petit mais significatif que nous avons fait ensemble qui se distingue pour toi ?", "it": "Qual è un piccolo ma significativo acquisto che abbiamo fatto insieme che spicca per te?", "ko": "우리가 함께 했던 작지만 의미 있는 구매 중 당신에게 두드러지는 것은 무엇인가요?", "nl": "Wat is een kleine maar betekenisvolle aankoop die we samen hebben gedaan en die voor jou opvalt?", "zh": "我们一起做过的小而有意义的购买中，你印象深刻的是哪项？"}'),
  ('growth', 1, '{"en": "What skill or hobby you''ve never tried would you like us to explore together?", "es": "¿Qué habilidad o pasatiempo que nunca has intentado te gustaría que exploráramos juntos?", "fr": "Quelle compétence ou loisir que tu n''as jamais essayé voudrais-tu que nous explorions ensemble ?", "it": "Quale competenza o hobby che non hai mai provato vorresti esplorare insieme?", "ko": "한 번도 시도해보지 않은 기술이나 취미 중에서 함께 탐험하고 싶은 것은 무엇인가요?", "nl": "Welke vaardigheid of hobby die je nog nooit geprobeerd hebt, zou je graag samen willen ontdekken?", "zh": "你从未尝试过的技能或爱好中，哪个是你希望我们一起探索的？"}'),
  ('family', 1, '{"en": "If we could create a new family tradition, what would it be?", "es": "Si pudiéramos crear una nueva tradición familiar, ¿cuál sería?", "fr": "Si nous pouvions créer une nouvelle tradition familiale, quelle serait-elle ?", "it": "Se potessimo creare una nuova tradizione familiare, quale sarebbe?", "ko": "우리가 새로운 가족 전통을 만들 수 있다면 그것은 무엇일까요?", "nl": "Als we een nieuwe familietraditie zouden kunnen creëren, wat zou dat dan zijn?", "zh": "如果我们可以创建一个新的家庭传统，那会是什么？"}'),
  ('adventure', 1, '{"en": "What''s one spontaneous activity you''ve always wanted us to try?", "es": "¿Cuál es una actividad espontánea que siempre has querido que intentemos?", "fr": "Quelle est une activité spontanée que tu as toujours voulu que nous essayions ?", "it": "Qual è un''attività spontanea che hai sempre voluto provare?", "ko": "항상 우리가 시도해보고 싶었던 즉흥적인 활동은 무엇인가요?", "nl": "Wat is één spontane activiteit die je altijd al hebt willen proberen?", "zh": "你一直想让我们尝试的一个自发的活动是什么？"}'),
  ('fun', 1, '{"en": "If our relationship was made into a board game, what would be the goal to win?", "es": "Si nuestra relación se convirtiera en un juego de mesa, ¿cuál sería el objetivo para ganar?", "fr": "Si notre relation était transformée en jeu de société, quel serait l''objectif pour gagner ?", "it": "Se la nostra relazione fosse trasformata in un gioco da tavolo, quale sarebbe l''obiettivo per vincere?", "ko": "우리의 관계가 보드 게임으로 만들어진다면 승리하기 위한 목표는 무엇일까요?", "nl": "Als onze relatie een bordspel zou zijn, wat zou dan het doel zijn om te winnen?", "zh": "如果我们的关系被做成一个桌游，胜利的目标会是什么？"}'),
  ('intimacy', 2, '{"en": "What''s a way we could make our intimate time together more meaningful?", "es": "¿Cuál es una manera en que podríamos hacer que nuestro tiempo íntimo juntos sea más significativo?", "fr": "Quelle est une façon de rendre notre temps intime ensemble plus significatif ?", "it": "Qual è un modo per rendere il nostro tempo intimo insieme più significativo?", "ko": "우리의 친밀한 시간을 더욱 의미 있게 만들 수 있는 방법은 무엇일까요?", "nl": "Wat is een manier waarop we onze intieme tijd samen betekenisvoller kunnen maken?", "zh": "我们可以怎样让在一起的亲密时光更有意义？"}'),
  ('dreams', 2, '{"en": "If you could see a glimpse of our life together 20 years from now, what moment would you want to witness and why?", "es": "Si pudieras ver un vistazo de nuestra vida juntos dentro de 20 años, ¿qué momento querrías presenciar y por qué?", "fr": "Si tu pouvais voir un aperçu de notre vie ensemble dans 20 ans, quel moment voudrais-tu voir et pourquoi ?", "it": "Se potessi vedere uno scorcio della nostra vita insieme tra 20 anni, quale momento vorresti vedere e perché?", "ko": "20년 후 우리의 삶을 조금이나마 엿볼 수 있다면, 어떤 순간을 보고 싶고 왜 그런가요?", "nl": "Als je een glimp van ons leven samen over 20 jaar zou kunnen zien, welk moment zou je dan willen aanschouwen en waarom?", "zh": "如果你能看到我们未来20年生活的一瞥，你希望目睹什么瞬间，为什么？"}'),
  ('memories', 2, '{"en": "Which of our achievements as a couple would you frame as a metaphorical trophy and why?", "es": "¿Cuál de nuestros logros como pareja enmarcarías como un trofeo metafórico y por qué?", "fr": "Lequel de nos succès en tant que couple encadrerais-tu comme un trophée métaphorique et pourquoi ?", "it": "Quale dei nostri successi come coppia incorniceresti come un trofeo metaforico e perché?", "ko": "우리 커플의 성취 중에서 비유적인 트로피로 만들어 놓고 싶은 것은 무엇이며, 그 이유는?", "nl": "Welke van onze prestaties als koppel zou je inlijsten als een metaforische trofee en waarom?", "zh": "作为夫妻，我们的哪些成就你愿意制成象征性的奖杯，为什么？"}'),
  ('values', 2, '{"en": "If a movie was made about our values, what would be the central message and the title?", "es": "Si se hiciera una película sobre nuestros valores, ¿cuál sería el mensaje central y el título?", "fr": "Si un film était réalisé sur nos valeurs, quel en serait le message central et le titre ?", "it": "Se venisse realizzato un film sui nostri valori, quale sarebbe il messaggio centrale e il titolo?", "ko": "우리의 가치관에 관한 영화가 만들어진다면 중심 메시지와 제목은 무엇일까요?", "nl": "Als er een film zou worden gemaakt over onze waarden, wat zou dan de centrale boodschap en de titel zijn?", "zh": "如果有一部关于我们价值观的电影，它的核心信息和标题是什么？"}'),
  ('communication', 2, '{"en": "What''s a question you wish I would ask you more often?", "es": "¿Cuál es una pregunta que desearías que te hiciera más a menudo?", "fr": "Quelle est une question que tu aimerais que je te pose plus souvent ?", "it": "Qual è una domanda che vorresti che ti facessi più spesso?", "ko": "내가 당신에게 자주 했으면 하는 질문은 무엇인가요?", "nl": "Wat is een vraag die je graag wilt dat ik vaker stel?", "zh": "你希望我更经常问你的一个问题是什么？"}'),
  ('fun', 2, '{"en": "If we could own a unique business together without financial risk, what would it be?", "es": "Si pudiéramos tener un negocio único juntos sin riesgo financiero, ¿cuál sería?", "fr": "Si nous pouvions posséder une entreprise unique ensemble sans risque financier, quel serait-elle ?", "it": "Se potessimo avere un''attività unica insieme senza rischi finanziari, quale sarebbe?", "ko": "우리가 함께 재정적 위험 없이 독특한 사업을 소유할 수 있다면 무엇일까요?", "nl": "Als we samen een unieke onderneming zonder financieel risico zouden kunnen bezitten, wat zou dat dan zijn?", "zh": "如果我们可以在没有财务风险的情况下共同拥有一家独特的企业，它会是什么？"}'),
  ('adventure', 2, '{"en": "If you could design a treasure hunt for us, what would be the final prize?", "es": "Si pudieras diseñar una búsqueda del tesoro para nosotros, ¿cuál sería el premio final?", "fr": "Si tu pouvais concevoir une chasse au trésor pour nous, quel serait le prix final ?", "it": "Se potessi progettare una caccia al tesoro per noi, quale sarebbe il premio finale?", "ko": "우리 둘을 위한 보물찾기를 디자인할 수 있다면, 최종 보상은 무엇일까요?", "nl": "Als je een speurtocht voor ons zou kunnen ontwerpen, wat zou dan de hoofdprijs zijn?", "zh": "如果你可以为我们设计一个寻宝活动，最终奖品会是什么？"}'),
  ('growth', 2, '{"en": "What’s an adventurous personal goal we''ve never discussed that you''d like to pursue together?", "es": "¿Cuál es un objetivo personal aventurero que nunca hemos discutido que te gustaría perseguir juntos?", "fr": "Quel est un objectif personnel aventureux dont nous n''avons jamais discuté que tu aimerais poursuivre ensemble ?", "it": "Qual è un obiettivo personale avventuroso di cui non abbiamo mai discusso che vorresti perseguire insieme?", "ko": "우리가 한 번도 논의해보지 않은 모험적인 개인 목표 중에서 함께 추구해보고 싶은 건 무엇인가요?", "nl": "Wat is een avontuurlijk persoonlijk doel dat we nooit hebben besproken en dat je graag samen zou willen nastreven?", "zh": "我们从未讨论过的冒险个人目标中你想一起追求的是哪一个？"}'),
  ('family', 2, '{"en": "If you could create a mythical family heirloom, what powers would it have and whom would it benefit?", "es": "Si pudieras crear una reliquia familiar mítica, ¿qué poderes tendría y a quién beneficiaría?", "fr": "Si tu pouvais créer un héritage familial mythique, quels pouvoirs aurait-il et à qui profiterait-il ?", "it": "Se potessi creare un cimelio di famiglia mitico, quali poteri avrebbe e a chi gioverebbe?", "ko": "신화적인 가족 유산을 만들 수 있다면 어떤 능력이 있고 누구에게 혜택을 줄까요?", "nl": "Als je een mythisch familie-erfstuk zou kunnen creëren, welke krachten zou het hebben en wie zou er baat bij hebben?", "zh": "如果你可以创造一个神话般的家庭传家宝，它会有什么能力，受益对象是谁？"}'),
  ('gratitude', 2, '{"en": "What’s one unique trait about our relationship you’re most thankful for today?", "es": "¿Cuál es una característica única de nuestra relación por la que estás más agradecido hoy?", "fr": "Quelle est une caractéristique unique de notre relation pour laquelle tu es le plus reconnaissant aujourd''hui ?", "it": "Qual è una caratteristica unica della nostra relazione di cui sei più grato oggi?", "ko": "오늘 당신이 가장 감사하게 여기는 우리 관계의 독특한 특성은 무엇인가요?", "nl": "Wat is één unieke eigenschap van onze relatie waar je vandaag het meest dankbaar voor bent?", "zh": "今天你最感激我们的关系中的哪个独特特点？"}'),
  ('conflict', 2, '{"en": "What constructive argument have we had that you''re now grateful for?", "es": "¿Qué discusión constructiva hemos tenido por la que ahora estás agradecido?", "fr": "Quelle discussion constructive avons-nous eue dont tu es maintenant reconnaissant ?", "it": "Qual è un argomento costruttivo che abbiamo affrontato per cui ora sei grato?", "ko": "당신이 지금 감사하게 생각하는 건설적인 논쟁은 무엇인가요?", "nl": "Welke constructieve discussie hebben we gehad waar je nu dankbaar voor bent?", "zh": "我们进行过的富有建设性的争论中，你现在感激的是哪一个？"}'),
  ('finances', 2, '{"en": "If we could invest all our savings into one cause, what would it be?", "es": "Si pudiéramos invertir todos nuestros ahorros en una causa, ¿cuál sería?", "fr": "Si nous pouvions investir toutes nos économies dans une cause, laquelle serait-ce ?", "it": "Se potessimo investire tutti i nostri risparmi in una causa, quale sarebbe?", "ko": "우리의 모든 저축을 한 가지 목적에 투자할 수 있다면, 그것은 무엇일까요?", "nl": "Als we al onze besparingen in één zaak zouden kunnen investeren, wat zou dat dan zijn?", "zh": "如果我们可以把所有存款投资于一个事业，那会是什么？"}'),
  ('intimacy', 2, '{"en": "What’s a shared experience we’ve had that brought us closer on an emotional level?", "es": "¿Cuál es una experiencia compartida que hemos tenido que nos ha acercado más a nivel emocional?", "fr": "Quelle est une expérience partagée que nous avons eue qui nous a rapprochés sur le plan émotionnel ?", "it": "Qual è un''esperienza condivisa che abbiamo avuto che ci ha avvicinato a livello emotivo?", "ko": "우리를 감정적으로 더 가깝게 만든 공유 경험은 무엇인가요?", "nl": "Wat is een gedeelde ervaring die we hebben gehad die ons dichter bij elkaar heeft gebracht op emotioneel niveau?", "zh": "我们曾有的共同经历中，哪一个让我们的情感关系更深？"}'),
  ('dreams', 3, '{"en": "What is a dream you''ve been reluctant to share, and why does it matter to you?", "es": "¿Cuál es un sueño que has sido reacio a compartir y por qué te importa?", "fr": "Quel est un rêve que tu as hésité à partager et pourquoi te tient-il à cœur ?", "it": "Qual è un sogno che hai esitato a condividere e perché ti interessa?", "ko": "공유하기 주저했던 꿈은 무엇이며, 왜 그 꿈이 당신에게 중요합니까?", "nl": "Wat is een droom die je aarzelde te delen en waarom is het belangrijk voor je?", "zh": "你不愿分享的梦想是什么，为什么对你很重要？"}'),
  ('memories', 3, '{"en": "If you could relive one significant moment in our relationship again fully, what would it be and why?", "es": "Si pudieras revivir un momento significativo en nuestra relación nuevamente por completo, ¿cuál sería y por qué?", "fr": "Si tu pouvais revivre un moment significatif de notre relation à nouveau entièrement, lequel serait-ce et pourquoi ?", "it": "Se potessi rivivere completamente un momento significativo della nostra relazione, quale sarebbe e perché?", "ko": "우리의 관계에서 의미 있는 순간 하나를 완전히 다시 살릴 수 있다면, 그 순간은 무엇이며 왜인가요?", "nl": "Als je een belangrijk moment in onze relatie helemaal opnieuw zou kunnen beleven, wat zou dat dan zijn en waarom?", "zh": "如果你能完全重温我们关系中的一个重要时刻，那会是什么，为什么？"}'),
  ('values', 3, '{"en": "What values do you think have evolved in our relationship and why?", "es": "¿Qué valores crees que han evolucionado en nuestra relación y por qué?", "fr": "Quels valeurs penses-tu avoir évoluées dans notre relation et pourquoi ?", "it": "Quali valori pensi che siano evoluti nella nostra relazione e perché?", "ko": "우리 관계에서 발전한 가치관은 무엇이며 그 이유는 무엇인가요?", "nl": "Welke waarden denk je dat zijn geëvolueerd in onze relatie en waarom?", "zh": "你认为我们的关系中哪些价值观已经发展，为什么？"}'),
  ('communication', 3, '{"en": "What’s a fear or vulnerability that you’ve overcome through our conversations?", "es": "¿Cuál es un miedo o vulnerabilidad que has superado a través de nuestras conversaciones?", "fr": "Quelle est une peur ou une vulnérabilité que tu as surmontée grâce à nos conversations ?", "it": "Qual è una paura o vulnerabilità che hai superato attraverso le nostre conversazioni?", "ko": "우리의 대화를 통해 극복한 두려움이나 취약점은 무엇인가요?", "nl": "Wat is een angst of kwetsbaarheid die je hebt overwonnen door onze gesprekken?", "zh": "通过我们的对话，你克服的恐惧或脆弱是什么？"}'),
  ('finances', 3, '{"en": "How do you envision our financial health supporting our dreams in the long term?", "es": "¿Cómo imaginas que nuestra salud financiera apoye nuestros sueños a largo plazo?", "fr": "Comment envisages-tu que notre santé financière soutienne nos rêves à long terme ?", "it": "Come immagini che la nostra salute finanziaria sostenga i nostri sogni a lungo termine?", "ko": "완경하는 건강한 재정 상태가 장기적으로 우리의 꿈을 어떻게 지원할 것이라고 보십니까?", "nl": "Hoe zie je dat onze financiële gezondheid onze dromen op de lange termijn ondersteunt?", "zh": "你如何设想我们的财务状况在长期内支持我们的梦想？"}'),
  ('growth', 3, '{"en": "What kind of legacy do you want our relationship to leave behind, both personally and for others?", "es": "¿Qué tipo de legado deseas que nuestra relación deje atrás, tanto personal como para otros?", "fr": "Quel genre d''héritage veux-tu que notre relation laisse derrière, tant personnellement que pour les autres ?", "it": "Che tipo di eredità vuoi che la nostra relazione lasci indietro, sia personalmente che per gli altri?", "ko": "개인적으로나 다른 사람들이 볼 때, 우리 관계가 어떤 유산을 남기기를 원하십니까?", "nl": "Wat voor soort nalatenschap wil je dat onze relatie achterlaat, zowel persoonlijk als voor anderen?", "zh": "你希望我们的关系留下怎样的遗产，不仅对我们个人，亦对他人？"}'),
  ('adventure', 3, '{"en": "What challenge or unknown future adventure excites you about our shared future?", "es": "¿Qué desafío o aventura futura desconocida te entusiasma sobre nuestro futuro compartido?", "fr": "Quel défi ou aventure future inconnue t''enthousiasme à propos de notre futur commun ?", "it": "Quali sfide o avventure future sconosciute ti entusiasmano riguardo al nostro futuro condiviso?", "ko": "우리의 공유된 미래에 대한 도전 또는 알려지지 않은 미래의 모험 중 당신을 흥분시키는 것은 무엇입니까?", "nl": "Welke uitdaging of onbekende toekomstige avontuur vind je spannend over onze gezamenlijke toekomst?", "zh": "关于我们的共同未来，什么挑战或未知的冒险让你感到兴奋？"}'),
  ('communication', 1, '{"en": "What''s one thing I do that makes you feel truly heard?", "es": "¿Qué es una cosa que hago que te hace sentir verdaderamente escuchado?", "fr": "Quelle est la chose que je fais qui te fait sentir vraiment écouté ?", "it": "Qual è una cosa che faccio che ti fa sentire veramente ascoltato?", "ko": "내가 당신이 진정으로 들린다고 느끼게 하는 일이 무엇입니까?", "nl": "Wat is iets dat ik doe waardoor je je echt gehoord voelt?", "zh": "我做的哪件事让你感到真正被倾听？"}'),
  ('intimacy', 1, '{"en": "What small gesture do I do that makes you feel most loved?", "es": "¿Qué pequeño gesto hago que te hace sentir más amado?", "fr": "Quel petit geste je fais qui te fait te sentir le plus aimé ?", "it": "Quale piccolo gesto faccio che ti fa sentire più amato?", "ko": "내 작은 행동 중 언제 가장 큰 사랑을 느끼나요?", "nl": "Welk klein gebaar van mij laat je je het meest geliefd voelen?", "zh": "我做的什么小动作让你觉得最被爱？"}'),
  ('dreams', 1, '{"en": "If you could try a job for a month that you haven''t done before, what would it be, and why?", "es": "Si pudieras probar un trabajo durante un mes que no has hecho antes, ¿cuál sería y por qué?", "fr": "Si tu pouvais essayer un travail pendant un mois que tu n''as jamais fait auparavant, quel serait-il et pourquoi ?", "it": "Se potessi provare un lavoro per un mese che non hai mai fatto prima, quale sarebbe e perché?", "ko": "한 달 동안 해보지 않은 일을 시도할 수 있다면 무엇을 하겠습니까, 그리고 왜 그럴까요?", "nl": "Als je een maand lang een baan zou kunnen proberen die je nog nooit eerder hebt gedaan, wat zou dat dan zijn en waarom?", "zh": "如果你可以尝试一个月你以前未做过的工作，那会是什么，为什么？"}'),
  ('memories', 1, '{"en": "What was your favorite game or activity you enjoyed as a child and why?", "es": "¿Cuál era tu juego o actividad favorita que disfrutaste cuando eras niño y por qué?", "fr": "Quel était ton jeu ou activité préféré que tu apprécies enfant et pourquoi ?", "it": "Qual era il tuo gioco o attività preferita che ti piaceva da bambino e perché?", "ko": "어릴 때 좋아하던 게임이나 활동은 무엇이었고 그 이유는 무엇인가요?", "nl": "Wat was je favoriete spel of activiteit als kind en waarom?", "zh": "你小时候最喜欢的游戏或活动是什么，为什么？"}'),
  ('values', 1, '{"en": "What core value do you think has influenced our relationship the most so far?", "es": "¿Qué valor esencial crees que ha influido más en nuestra relación hasta ahora?", "fr": "Quelle valeur fondamentale penses-tu avoir le plus influencé notre relation jusqu''à présent ?", "it": "Qual è il valore fondamentale che pensi abbia influenzato maggiormente la nostra relazione fino ad ora?", "ko": "지금까지 우리 관계에 가장 큰 영향을 미친 핵심 가치는 무엇이라고 생각합니까?", "nl": "Welke kernwaarde denk je heeft het meest invloed gehad op onze relatie tot nu toe?", "zh": "你认为迄今为止对我们的关系影响最大的是哪个核心价值？"}'),
  ('fun', 1, '{"en": "What''s a hobby you think would be fun for us to try together?", "es": "¿Cuál es un pasatiempo que crees que sería divertido intentar juntos?", "fr": "Quel passe-temps penses-tu qu''il serait amusant de faire ensemble ?", "it": "Qual è un hobby che pensi sarebbe divertente provare insieme?", "ko": "우리 둘이 함께하면 재미있을 것 같은 취미가 무엇인가요?", "nl": "Welke hobby denk je dat leuk zou zijn om samen uit te proberen?", "zh": "你认为我们一起尝试什么爱好会很有趣？"}'),
  ('gratitude', 1, '{"en": "What''s something mundane that I do, which you''re grateful for?", "es": "¿Qué es algo mundano que hago por lo cual estás agradecido?", "fr": "Qu''est-ce que je fais de banal pour lequel tu es reconnaissant ?", "it": "Qual è una cosa banale che faccio di cui sei riconoscente?", "ko": "내가 하는 평범한 일 중에 당신이 고마워하는 것에는 무엇이 있습니까?", "nl": "Wat is iets alledaags dat ik doe waar je dankbaar voor bent?", "zh": "我做的哪件平凡事让你心存感激？"}'),
  ('conflict', 1, '{"en": "What''s your ideal way for us to navigate disagreements when they arise?", "es": "¿Cuál es tu manera ideal para que manejemos los desacuerdos cuando surjan?", "fr": "Quelle est ta manière idéale de gérer nos désaccords lorsqu''ils surviennent ?", "it": "Qual è il modo ideale per noi di affrontare i disaccordi quando si presentano?", "ko": "불일치가 발생했을 때 우리가 이를 처리하는 이상적인 방법은 무엇이라고 생각합니까?", "nl": "Wat is jouw ideale manier voor ons om meningsverschillen te navigeren wanneer ze zich voordoen?", "zh": "当出现分歧时，你理想的处理方式是什么？"}'),
  ('finances', 1, '{"en": "What''s one small purchase you made this year that brought you a lot of joy?", "es": "¿Cuál es una pequeña compra que hiciste este año y que te trajo mucha felicidad?", "fr": "Quel petit achat as-tu fait cette année qui t''a apporté beaucoup de joie ?", "it": "Qual è un piccolo acquisto che hai fatto quest''anno che ti ha portato molta gioia?", "ko": "올해 당신에게 큰 기쁨을 준 작은 구매가 있다면 무엇입니까?", "nl": "Wat is een kleine aankoop die je dit jaar deed en die je veel vreugde bracht?", "zh": "你今年买的哪个小物件给你带来了很多快乐？"}'),
  ('growth', 1, '{"en": "What''s a new skill you''d like to learn this year, and how can I support you?", "es": "¿Qué nueva habilidad te gustaría aprender este año y cómo puedo apoyarte?", "fr": "Quelle nouvelle compétence aimerais-tu apprendre cette année et comment puis-je te soutenir ?", "it": "Qual è una nuova abilità che ti piacerebbe imparare quest''anno e come posso supportarti?", "ko": "올해 배우고 싶은 새로운 기술은 무엇이며, 내가 어떻게 도울 수 있을까요?", "nl": "Welke nieuwe vaardigheid zou je dit jaar graag willen leren en hoe kan ik je ondersteunen?", "zh": "你今年想学什么新技能，我该如何支持你？"}'),
  ('family', 1, '{"en": "What''s a family tradition you''d like us to start together?", "es": "¿Cuál es una tradición familiar que te gustaría que empezáramos juntos?", "fr": "Quelle tradition familiale aimerais-tu que nous commencions ensemble ?", "it": "Qual è una tradizione familiare che ti piacerebbe iniziare insieme?", "ko": "함께 시작하고 싶은 가족 전통이 있다면 무엇인가요?", "nl": "Welke familietraditie zou je graag samen willen beginnen?", "zh": "你希望我们一起开始什么家庭传统？"}'),
  ('adventure', 1, '{"en": "If we were to take a spontaneous road trip, what''s one unexpected place you''d like to explore?", "es": "Si hiciéramos un viaje por carretera espontáneo, ¿cuál es un lugar inesperado que te gustaría explorar?", "fr": "Si nous faisions un road trip spontané, quel serait un endroit inattendu que tu aimerais explorer ?", "it": "Se facessimo un viaggio su strada spontaneo, quale sarebbe un luogo inaspettato che ti piacerebbe esplorare?", "ko": "즉흥적인 로드 트립을 갈 경우 탐험하고 싶은 예상치 못한 장소는 어디입니까?", "nl": "Als we een spontane roadtrip zouden maken, welke onverwachte plek zou je dan willen verkennen?", "zh": "如果我们进行一次自发的公路旅行，你想探索哪个意想不到的地方？"}'),
  ('communication', 2, '{"en": "Can you describe a time when I surprised you with my understanding or support?", "es": "¿Puedes describir un momento en el que te sorprendí con mi comprensión o apoyo?", "fr": "Peux-tu décrire un moment où je t''ai surpris par ma compréhension ou mon soutien ?", "it": "Puoi descrivermi un momento in cui ti ho sorpreso con la mia comprensione o supporto?", "ko": "내 이해심 혹은 지지로 당신을 놀라게 한 순간을 설명해 줄 수 있나요?", "nl": "Kun je een moment beschrijven waarop ik je verraste met mijn begrip of steun?", "zh": "你能描述一下我用我的理解或支持让你感到惊讶的时刻吗？"}'),
  ('intimacy', 2, '{"en": "In what ways do you feel that our physical connection has evolved since we first met?", "es": "¿De qué maneras sientes que nuestra conexión física ha evolucionado desde que nos conocimos?", "fr": "De quelles manières sens-tu que notre connexion physique a évolué depuis notre rencontre ?", "it": "In che modo senti che la nostra connessione fisica è evoluta da quando ci siamo incontrati?", "ko": "우리의 신체적 관계가 처음 만났을 때부터 어떻게 발전해 왔다고 느끼나요?", "nl": "Op welke manieren vind je dat onze fysieke connectie is geëvolueerd sinds we elkaar hebben ontmoet?", "zh": "你觉得自我们相遇以来，我们的身体连接有什么变化？"}'),
  ('dreams', 2, '{"en": "What challenge would you like us to overcome together in the next five years?", "es": "¿Qué desafío te gustaría que superáramos juntos en los próximos cinco años?", "fr": "Quel défi aimerais-tu que nous surmontions ensemble dans les cinq prochaines années ?", "it": "Quale sfida ti piacerebbe che superassimo insieme nei prossimi cinque anni?", "ko": "앞으로 다섯 년간 우리 둘이 함께 극복하고 싶은 도전이 무엇인가요?", "nl": "Welke uitdaging zou je willen dat we samen overwinnen in de komende vijf jaar?", "zh": "未来五年中，你希望我们一起克服什么挑战？"}'),
  ('memories', 2, '{"en": "What''s a shared experience that has impacted the way you see our future together?", "es": "¿Cuál es una experiencia compartida que ha impactado la forma en que ves nuestro futuro juntos?", "fr": "Quelle expérience partagée a influencé la façon dont tu envisages notre avenir ensemble ?", "it": "Qual è un''esperienza condivisa che ha influenzato il tuo modo di vedere il nostro futuro insieme?", "ko": "우리의 미래를 보는 방식에 영향을 미친 공유 경험은 무엇인가요?", "nl": "Welke gedeelde ervaring heeft invloed gehad op hoe je onze toekomst samen ziet?", "zh": "哪种共同经历影响了你对我们未来的看法？"}'),
  ('values', 2, '{"en": "Is there a value or belief that you think guides the way we solve problems together?", "es": "¿Hay un valor o creencia que crees que guía la forma en que resolvemos problemas juntos?", "fr": "Y a-t-il une valeur ou une croyance que tu penses guider la façon dont nous résolvons les problèmes ensemble ?", "it": "C''è un valore o una credenza che pensi guidi il modo in cui risolviamo i problemi insieme?", "ko": "문제를 함께 해결하는 방식에 영향을 미친다고 생각하는 가치관이나 신념이 있나요?", "nl": "Is er een waarde of overtuiging die volgens jou de manier leidt waarop we samen problemen oplossen?", "zh": "你认为是哪种价值观或信念指导我们解决问题的方式？"}'),
  ('fun', 2, '{"en": "What''s an unusual activity from your bucket list that we could share?", "es": "¿Cuál es una actividad inusual de tu lista de deseos que podríamos compartir?", "fr": "Quelle est une activité inhabituelle sur ta liste de choses à faire que nous pourrions partager ?", "it": "Qual è un''attività insolita della tua lista dei desideri che potremmo condividere?", "ko": "우리가 함께할 수 있는 당신의 버킷리스트에 있는 특별한 활동은 무엇인가요?", "nl": "Wat is een ongebruikelijke activiteit van jouw bucketlist die we samen kunnen delen?", "zh": "你愿意与我分享的清单上不寻常的活动是什么？"}'),
  ('gratitude', 2, '{"en": "What moment of kindness from me stood out to you recently and why?", "es": "¿Qué momento de amabilidad por mi parte te ha destacado recientemente y por qué?", "fr": "Quel moment de gentillesse de ma part t''a récemment marqué et pourquoi ?", "it": "Quale momento di gentilezza da parte mia ti ha colpito recentemente e perché?", "ko": "최근 내가 베푼 친절 중 눈에 띈 것이 있다면 그것이 무엇인지 그리고 그 이유는 무엇인지요?", "nl": "Welk moment van vriendelijkheid van mij is je recentelijk opgevallen en waarom?", "zh": "近期我做过的哪一刻善举让你印象深刻，为什么？"}'),
  ('conflict', 2, '{"en": "How have past conflicts between us strengthened our relationship?", "es": "¿Cómo han fortalecido nuestra relación los conflictos pasados entre nosotros?", "fr": "Comment les conflits passés entre nous ont-ils renforcé notre relation ?", "it": "In che modo i conflitti del passato tra noi hanno rafforzato la nostra relazione?", "ko": "과거 우리의 갈등이 어떻게 우리 관계를 강화했나요?", "nl": "Hoe hebben eerdere conflicten tussen ons onze relatie versterkt?", "zh": "过去的冲突如何增强了我们的关系？"}'),
  ('finances', 2, '{"en": "What financial habits do you think we should focus on to improve our future stability?", "es": "¿Qué hábitos financieros crees que deberíamos enfocarnos para mejorar nuestra estabilidad futura?", "fr": "Quels habitudes financières penses-tu que nous devrions adopter pour améliorer notre stabilité future ?", "it": "Quali abitudini finanziarie pensi che dovremmo adottare per migliorare la nostra stabilità futura?", "ko": "우리의 미래 안정성을 개선하기 위해 집중해야 할 재정습관은 무엇이라고 생각하나요?", "nl": "Welke financiële gewoontes denk je dat we moeten verbeteren voor toekomstige stabiliteit?", "zh": "你认为我们应该关注哪些财务习惯来改善未来的稳定性？"}'),
  ('growth', 2, '{"en": "What aspect of our relationship do you feel has grown the most over the past year?", "es": "¿Qué aspecto de nuestra relación sientes que ha crecido más durante el último año?", "fr": "Quel aspect de notre relation penses-tu a le plus évolué l''année dernière ?", "it": "Quale aspetto della nostra relazione ritieni sia cresciuto di più nell''ultimo anno?", "ko": "지난 해 동안 우리 관계의 어느 면이 가장 많이 성장했다고 느끼나요?", "nl": "Welk aspect van onze relatie denk je heeft het meest gegroeid in het afgelopen jaar?", "zh": "你觉得过去一年中我们关系的哪个方面成长最大？"}'),
  ('family', 2, '{"en": "What role does your family history play in how you approach challenges in our relationship?", "es": "¿Qué papel juega tu historia familiar en cómo enfrentas los desafíos en nuestra relación?", "fr": "Quel rôle joue ton histoire familiale dans la façon dont tu abordes les défis dans notre relation ?", "it": "Che ruolo gioca la tua storia familiare nel modo in cui affronti le sfide nella nostra relazione?", "ko": "당신의 가족사가 우리 관계에서의 도전을 어떻게 다루는 데 어떤 역할을 하나요?", "nl": "Welke rol speelt jouw familiegeschiedenis in de manier waarop je uitdagingen in onze relatie benadert?", "zh": "你的家庭背景在你处理我们关系中的挑战时起什么作用？"}'),
  ('adventure', 2, '{"en": "What adventure did you dream about as a kid that you''d love to experience with me?", "es": "¿Qué aventura soñabas cuando eras niño y te gustaría experimentar conmigo?", "fr": "Quelle aventure rêvais-tu enfant que tu aimerais vivre avec moi ?", "it": "Quale avventura sognavi da bambino che ti piacerebbe vivere con me?", "ko": "어렸을 때 꿈꿨던 모험 중 나와 함께 경험하고 싶은 것은 무엇인가요?", "nl": "Welke avontuur droomde je als kind over dat je graag met mij zou willen ervaren?", "zh": "孩提时你梦想的什么冒险，你想和我一起体验？"}'),
  ('communication', 3, '{"en": "How can we create a safe space for sharing our deepest fears and desires?", "es": "¿Cómo podemos crear un espacio seguro para compartir nuestros miedos y deseos más profundos?", "fr": "Comment pouvons-nous créer un espace sûr pour partager nos peurs et désirs les plus profonds ?", "it": "Come possiamo creare uno spazio sicuro per condividere le nostre paure e desideri più profondi?", "ko": "우리가 가장 깊은 두려움과 욕망을 공유할 수 있는 안전한 공간을 어떻게 만들 수 있을까요?", "nl": "Hoe kunnen we een veilige ruimte creëren om onze diepste angsten en verlangens te delen?", "zh": "我们如何创造一个安全的空间来分享我们最深的恐惧和欲望？"}'),
  ('intimacy', 3, '{"en": "In what ways can we deepen our emotional intimacy and truly connect beyond words?", "es": "¿De qué maneras podemos profundizar nuestra intimidad emocional y conectar verdaderamente más allá de las palabras?", "fr": "De quelles manières pouvons-nous approfondir notre intimité émotionnelle et nous connecter véritablement au-delà des mots ?", "it": "In che modo possiamo approfondire la nostra intimità emotiva e connetterci veramente al di là delle parole?", "ko": "우리가 감정의 친밀함을 심화하고 말 이상으로 진정으로 연결할 수 있는 방법은 무엇인가요?", "nl": "Op welke manieren kunnen we onze emotionele intimiteit verdiepen en echt verbinden voorbij woorden?", "zh": "我们如何能够加深情感亲密，并在言语之外实现真正的联系？"}'),
  ('dreams', 3, '{"en": "How has my support influenced your dreams and aspirations over time?", "es": "¿Cómo ha influido mi apoyo en tus sueños y aspiraciones a lo largo del tiempo?", "fr": "Comment mon soutien a-t-il influencé tes rêves et aspirations au fil du temps ?", "it": "In che modo il mio supporto ha influenzato i tuoi sogni e aspirazioni nel tempo?", "ko": "내 지원이 시간이 지남에 따라 당신의 꿈과 열망에 어떻게 영향을 미쳤나요?", "nl": "Hoe heeft mijn steun je dromen en aspiraties in de loop van de tijd beïnvloed?", "zh": "我的支持是如何影响你的梦想和志向的？"}'),
  ('conflict', 3, '{"en": "What underlying patterns do we need to address to improve our conflict resolution?", "es": "¿Qué patrones subyacentes necesitamos abordar para mejorar nuestra resolución de conflictos?", "fr": "Quels schémas sous-jacents devons-nous aborder pour améliorer notre résolution de conflits ?", "it": "Quali schemi sottostanti dobbiamo affrontare per migliorare la nostra risoluzione dei conflitti?", "ko": "우리의 갈등 해결을 개선하기 위해 다루어야 할 근본 패턴은 무엇인가요?", "nl": "Welke onderliggende patronen moeten we aanpakken om onze conflictoplossing te verbeteren?", "zh": "我们需要解决哪些潜在模式以改善我们的冲突解决能力？"}'),
  ('values', 3, '{"en": "Do you think our personal values have the power to reshape the path of our relationship?", "es": "¿Crees que nuestros valores personales tienen el poder de redefinir el camino de nuestra relación?", "fr": "Penses-tu que nos valeurs personnelles ont le pouvoir de redéfinir le chemin de notre relation ?", "it": "Pensi che i nostri valori personali abbiano il potere di ridefinire il percorso della nostra relazione?", "ko": "우리의 개인 가치관이 우리의 관계의 경로를 재정의할 힘이 있다고 생각하나요?", "nl": "Denk je dat onze persoonlijke waarden de kracht hebben om het pad van onze relatie opnieuw vorm te geven?", "zh": "你认为我们的个人价值观有能力重塑我们关系的道路吗？"}'),
  ('finances', 3, '{"en": "How do personal financial goals intersect with our vision as a couple?", "es": "¿Cómo se cruzan los objetivos financieros personales con nuestra visión como pareja?", "fr": "Comment les objectifs financiers personnels se croisent avec notre vision en tant que couple ?", "it": "Come si intersecano gli obiettivi finanziari personali con la nostra visione come coppia?", "ko": "개인의 재정 목표가 우리 커플의 비전과 어떻게 교차하나요?", "nl": "Hoe kruisen persoonlijke financiële doelen met onze visie als stel?", "zh": "个人财务目标如何与我们的伴侣愿景相交？"}'),
  ('growth', 3, '{"en": "What growth do you hope to see in our relationship when looking back a decade from now?", "es": "¿Qué crecimiento esperas ver en nuestra relación al mirar hacia atrás dentro de una década?", "fr": "Quelle croissance espères-tu voir dans notre relation en regardant en arrière dans dix ans ?", "it": "Quale crescita speri di vedere nella nostra relazione guardando indietro tra dieci anni?", "ko": "십 년 후 우리의 관계를 돌아볼 때 어떤 성장을 기대하나요?", "nl": "Welke groei hoop je te zien in onze relatie als je over een decennium terugkijkt?", "zh": "十年后回顾过去，你希望在我们的关系中看到什么进步？"}'),
  ('family', 3, '{"en": "How do you envision us influencing and shaping the dynamics of our own future family?", "es": "¿Cómo nos imaginas influyendo y dando forma a la dinámica de nuestra propia futura familia?", "fr": "Comment nous imagines-tu influencer et façonner la dynamique de notre propre future famille ?", "it": "Come ci immagini influenzare e plasmare la dinamica della nostra futura famiglia?", "ko": "미래의 우리 가족의 역동성을 우리가 어떻게 영향을 미치고 형성할 것이라고 상상하나요?", "nl": "Hoe stel je je voor dat we de dynamiek van onze eigen toekomstige familie beïnvloeden en vormgeven?", "zh": "你如何设想我们影响并塑造我们自己的未来家庭的动态？"}'),
  ('adventure', 3, '{"en": "What''s an adventure that feels both daunting and exhilarating, that you''d love to embark on with me?", "es": "¿Cuál es una aventura que se siente desafiante y emocionante, que te encantaría emprender conmigo?", "fr": "Quelle est une aventure qui semble à la fois intimidante et exaltante, que tu aimerais entreprendre avec moi ?", "it": "Qual è un''avventura che sembra sia intimidatoria che esaltante che ti piacerebbe intraprendere con me?", "ko": "함께 시작하고 싶은, 두렵지만 흥분되는 그런 모험은 무엇인가요?", "nl": "Wat is een avontuur dat zowel ontmoedigend als opwindend voelt, dat je graag samen met mij zou willen aangaan?", "zh": "什么样的冒险感觉既令人生畏又令人振奋，你想与我一起开始吗？"}')
